window.ADRIVE_THEME_DATA=window.ADRIVE_THEME_DATA||{};window.ADRIVE_THEME_DATA[4]=[{"id":100800101,"themeId":4,"group":1008001,"chapter":8,"chapters":[8],"q":"Водитель красного автомобиля совершил вынужденную остановку, вызванную технической неисправностью. Должен ли он в показанной ситуации включить аварийную световую сигнализацию и выставить знак аварийной остановки?","a":["Да, должен.","Должен только в тёмное время суток, если дорога не освещена.","Не должен, так как в этом месте остановка не запрещена."],"c":0,"e":"<p>В данной ситуации, несмотря на то, что остановка в показанном месте разрешена, водитель совершил вынужденную остановку на проезжей части дороги, поэтому необходимо включить аварийную световую сигнализацию и выставить знак аварийной остановки.</p>","image":"assets/adrive-questions/q100800101.jpg"},{"id":100800102,"themeId":4,"group":1008001,"chapter":8,"chapters":[8],"q":"Водитель красного автомобиля совершил вынужденную остановку, вызванную технической неисправностью. Должен ли он в показанной ситуации включить аварийную световую сигнализацию и выставить знак аварийной остановки?","a":["Да, должен.","Должен только в тёмное время суток, если дорога не освещена.","Нет, не должен."],"c":2,"e":"<p>В данной ситуации водитель совершил вынужденную остановку не на проезжей части дороги в месте, где разрешена остановка транспортных средств. Поэтому нет необходимости включать аварийную световую сигнализацию и выставлять знак аварийной остановки.</p>","image":"assets/adrive-questions/q100800102.jpg"},{"id":100800201,"themeId":4,"group":1008002,"chapter":8,"chapters":[8],"q":"Водитель красного автомобиля совершил вынужденную остановку, вызванную технической неисправностью. Должен ли он в показанной ситуации включить аварийную световую сигнализацию и выставить знак аварийной остановки?","a":["Да, должен.","Должен только вне населённых пунктов.","Должен включить только аварийную световую сигнализацию.","Нет, не должен."],"c":3,"e":"<p>В данной ситуации водитель совершил вынужденную остановку на обочине, где разрешена остановка транспортных средств. Поэтому нет необходимости включать аварийную световую сигнализацию и выставлять знак аварийной остановки.</p>","image":"assets/adrive-questions/q100800201.jpg"},{"id":100800202,"themeId":4,"group":1008002,"chapter":8,"chapters":[8],"q":"Водитель красного автомобиля совершил вынужденную остановку на обочине дороги. Должен ли он в показанной ситуации включить аварийную световую сигнализацию и выставить знак аварийной остановки?","a":["Да, должен.","Должен только вне населённых пунктов.","Должен включить только аварийную световую сигнализацию.","Должен, если время вынужденной остановки превысит 5 минут.","Нет, не должен."],"c":4,"e":"<p>В данной ситуации водитель совершил вынужденную остановку на обочине, где разрешена остановка транспортных средств. Дорожный знак 3.28 «Стоянка запрещена» не запрещает остановку. Поэтому нет необходимости включать аварийную световую сигнализацию и выставлять знак аварийной остановки.</p>","image":"assets/adrive-questions/q100800202.jpg"},{"id":100800301,"themeId":4,"group":1008003,"chapter":8,"chapters":[8],"q":"Что должно быть включено на буксируемом автомобиле при буксировке в светлое время суток?","a":["Габаритные огни.","Ближний свет фар.","Противотуманные фонари.","Аварийная световая сигнализация."],"c":3,"e":"<p>Аварийная световая сигнализация должна быть включена на буксируемом механическом транспортном средстве. При отсутствии или неисправности аварийной световой сигнализации на буксируемом механическом транспортном средстве на его задней части слева должен быть закреплён знак аварийной остановки.</p> <p>Эта мера необходима для того, чтобы информировать участников дорожного движения о повышенной опасности в связи с ограниченной скоростью движения сцепленных транспортных средств, их худшей манёвренностью, увеличением тормозного пути.</p>","image":null},{"id":100800302,"themeId":4,"group":1008003,"chapter":8,"chapters":[8],"q":"Должна ли быть включена аварийная световая сигнализация на буксируемом указанным способом легковом автомобиле?","a":["Да, должна.","Нет, не должна."],"c":0,"e":"<p>Аварийная световая сигнализация должна быть включена на буксируемом механическом транспортном средстве. При отсутствии или неисправности аварийной световой сигнализации на буксируемом механическом транспортном средстве на его задней части слева должен быть закреплён знак аварийной остановки.</p> <p>Эта мера необходима для того, чтобы информировать участников дорожного движения о повышенной опасности в связи с ограниченной скоростью движения сцепленных транспортных средств, их худшей манёвренностью.</p>","image":"assets/adrive-questions/q100800302.jpg"},{"id":100800401,"themeId":4,"group":1008004,"chapter":8,"chapters":[8],"q":"В каком случае на буксируемом автомобиле должна быть включена аварийная световая сигнализация?","a":["Только при буксировке неисправного автомобиля.","Только при буксировке автомобиля, в котором отсутствует водитель.","Только при буксировке в тёмное время суток и в условиях недостаточной видимости.","Должна быть включена в любом случае."],"c":3,"e":"<p>Аварийная световая сигнализация должна быть включена на буксируемом механическом транспортном средстве. При отсутствии или неисправности аварийной световой сигнализации на буксируемом механическом транспортном средстве на его задней части слева должен быть закреплён знак аварийной остановки.</p> <p>Эта мера необходима для того, чтобы информировать участников дорожного движения о повышенной опасности в связи с ограниченной скоростью движения сцепленных транспортных средств, их худшей манёвренностью, увеличением тормозного пути.</p>","image":null},{"id":100800402,"themeId":4,"group":1008004,"chapter":8,"chapters":[8],"q":"Аварийная световая сигнализация должна быть включена в показанной ситуации:","a":["На зелёном автомобиле.","На красном автомобиле.","На обоих автомобилях."],"c":1,"e":"<p>Аварийная световая сигнализация должна быть включена на буксируемом механическом транспортном средстве (в данном случае — на красном автомобиле). При отсутствии или неисправности аварийной световой сигнализации на буксируемом механическом транспортном средстве на его задней части слева должен быть закреплён знак аварийной остановки.</p> <p>Эта мера необходима для того, чтобы информировать участников дорожного движения о повышенной опасности в связи с ограниченной скоростью движения сцепленных транспортных средств, их худшей манёвренностью.</p>","image":"assets/adrive-questions/q100800402.jpg"},{"id":100800501,"themeId":4,"group":1008005,"chapter":8,"chapters":[8],"q":"В каком из перечисленных случаев водитель обязан включить аварийную световую сигнализацию?","a":["В случае ослепления водителя светом фар.","В случае буксировки — на буксируемом транспортном средстве.","Для предупреждения участников дорожного движения об опасности для движения.","Во всех перечисленных случаях."],"c":3,"e":"<p>Аварийная световая сигнализация должна быть включена в случаях:</p> <ul><li>дорожно-транспортного происшествия;</li> <li>вынужденной остановки транспортного средства на проезжей части дороги и в местах, где остановка запрещена;</li> <li>ослепления водителя светом фар;</li> <li>буксировки механического транспортного средства — на буксируемом механическом транспортном средстве;</li> <li>остановки, стоянки транспортного средства в тёмное время суток на неосвещённых участках дороги (кроме жилых зон) и (или) при недостаточной видимости дороги при неисправных габаритных и стояночных огнях;</li> <li>движения на транспортном средстве с технической неисправностью, указанной в приложении 4 Правил дорожного движения, если движение не запрещено Правилами дорожного движения;</li> <li>предупреждения участников дорожного движения об опасности для движения;</li> <li>посадки (высадки) групп детей в перевозящие их автобусы — на автобусах;</li> <li>приближения трамвая к зоне остановочного пункта трамвая, обозначенной дорожными знаками 5.13.1 «Остановочный пункт трамвая» , 5.13.2 «Место остановки трамвая» и (или) горизонтальной дорожной разметкой 1.17.2 , и во время нахождения его в этой зоне — на трамваях. На трамваях, не оборудованных аварийной световой сигнализацией, должен быть включён световой указатель правого поворота.</li></ul>","image":null},{"id":100800502,"themeId":4,"group":1008005,"chapter":8,"chapters":[8],"q":"В каком из перечисленных случаев водитель обязан включить аварийную световую сигнализацию?","a":["В случае дорожно-транспортного происшествия.","В случае буксировки — на буксирующем транспортном средстве.","В случае остановки на обочине в тёмное время суток на освещённом участке дороги при неисправных габаритных и стояночных огнях.","Во всех перечисленных случаях."],"c":0,"e":"<p>Аварийная световая сигнализация должна быть включена в случаях:</p> <ul><li>дорожно-транспортного происшествия;</li> <li>вынужденной остановки транспортного средства на проезжей части дороги и в местах, где остановка запрещена;</li> <li>ослепления водителя светом фар;</li> <li>буксировки механического транспортного средства — на буксируемом механическом транспортном средстве;</li> <li>остановки, стоянки транспортного средства в тёмное время суток на неосвещённых участках дороги (кроме жилых зон) и (или) при недостаточной видимости дороги при неисправных габаритных и стояночных огнях;</li> <li>движения на транспортном средстве с технической неисправностью, указанной в приложении 4 Правил дорожного движения, если движение не запрещено Правилами дорожного движения;</li> <li>предупреждения участников дорожного движения об опасности для движения;</li> <li>посадки (высадки) групп детей в перевозящие их автобусы — на автобусах;</li> <li>приближения трамвая к зоне остановочного пункта трамвая, обозначенной дорожными знаками 5.13.1 «Остановочный пункт трамвая» , 5.13.2 «Место остановки трамвая» и (или) горизонтальной дорожной разметкой 1.17.2 , и во время нахождения его в этой зоне — на трамваях. На трамваях, не оборудованных аварийной световой сигнализацией, должен быть включён световой указатель правого поворота.</li></ul>","image":null},{"id":100800601,"themeId":4,"group":1008006,"chapter":8,"chapters":[8],"q":"В каком из перечисленных случаев водитель обязан включить аварийную световую сигнализацию?","a":["В случае буксировки — на буксируемом транспортном средстве.","В случае остановки в условиях недостаточной видимости дороги при неисправных габаритных и стояночных огнях.","В случае движения на транспортном средстве с неисправностью, указанной в Правилах дорожного движения, если движение не запрещено.","Во всех перечисленных случаях."],"c":3,"e":"<p>Аварийная световая сигнализация должна быть включена в случаях:</p> <ul><li>дорожно-транспортного происшествия;</li> <li>вынужденной остановки транспортного средства на проезжей части дороги и в местах, где остановка запрещена;</li> <li>ослепления водителя светом фар;</li> <li>буксировки механического транспортного средства — на буксируемом механическом транспортном средстве;</li> <li>остановки, стоянки транспортного средства в тёмное время суток на неосвещённых участках дороги (кроме жилых зон) и (или) при недостаточной видимости дороги при неисправных габаритных и стояночных огнях;</li> <li>движения на транспортном средстве с технической неисправностью, указанной в приложении 4 Правил дорожного движения, если движение не запрещено Правилами дорожного движения;</li> <li>предупреждения участников дорожного движения об опасности для движения;</li> <li>посадки (высадки) групп детей в перевозящие их автобусы — на автобусах;</li> <li>приближения трамвая к зоне остановочного пункта трамвая, обозначенной дорожными знаками 5.13.1 «Остановочный пункт трамвая» , 5.13.2 «Место остановки трамвая» и (или) горизонтальной дорожной разметкой 1.17.2 , и во время нахождения его в этой зоне — на трамваях. На трамваях, не оборудованных аварийной световой сигнализацией, должен быть включён световой указатель правого поворота.</li></ul>","image":null},{"id":100800602,"themeId":4,"group":1008006,"chapter":8,"chapters":[8],"q":"В каком из перечисленных случаев водитель обязан включить аварийную световую сигнализацию?","a":["В случае ослепления водителя светом фар.","В случае остановки в местах, где она запрещена.","В случае буксировки — на буксирующем транспортном средстве.","Во всех перечисленных случаях."],"c":0,"e":"<p>Аварийная световая сигнализация должна быть включена в случаях:</p> <ul><li>дорожно-транспортного происшествия;</li> <li>вынужденной остановки транспортного средства на проезжей части дороги и в местах, где остановка запрещена;</li> <li>ослепления водителя светом фар;</li> <li>буксировки механического транспортного средства — на буксируемом механическом транспортном средстве;</li> <li>остановки, стоянки транспортного средства в тёмное время суток на неосвещённых участках дороги (кроме жилых зон) и (или) при недостаточной видимости дороги при неисправных габаритных и стояночных огнях;</li> <li>движения на транспортном средстве с технической неисправностью, указанной в приложении 4 Правил дорожного движения, если движение не запрещено Правилами дорожного движения;</li> <li>предупреждения участников дорожного движения об опасности для движения;</li> <li>посадки (высадки) групп детей в перевозящие их автобусы — на автобусах;</li> <li>приближения трамвая к зоне остановочного пункта трамвая, обозначенной дорожными знаками 5.13.1 «Остановочный пункт трамвая» , 5.13.2 «Место остановки трамвая» и (или) горизонтальной дорожной разметкой 1.17.2 , и во время нахождения его в этой зоне — на трамваях. На трамваях, не оборудованных аварийной световой сигнализацией, должен быть включён световой указатель правого поворота.</li></ul>","image":null},{"id":100800701,"themeId":4,"group":1008007,"chapter":8,"chapters":[8],"q":"В каком из перечисленных случаев водитель не обязан включить аварийную световую сигнализацию?","a":["В случае ослепления водителя светом фар.","В случае буксировки — на буксирующем транспортном средстве.","В случае вынужденной остановки в местах, где остановка запрещена.","В случае дорожно-транспортного происшествия вне проезжей части дороги."],"c":1,"e":"<p>Аварийная световая сигнализация должна быть включена в случаях:</p> <ul><li>дорожно-транспортного происшествия;</li> <li>вынужденной остановки транспортного средства на проезжей части дороги и в местах, где остановка запрещена;</li> <li>ослепления водителя светом фар;</li> <li>буксировки механического транспортного средства — на буксируемом механическом транспортном средстве;</li> <li>остановки, стоянки транспортного средства в тёмное время суток на неосвещённых участках дороги (кроме жилых зон) и (или) при недостаточной видимости дороги при неисправных габаритных и стояночных огнях;</li> <li>движения на транспортном средстве с технической неисправностью, указанной в приложении 4 Правил дорожного движения, если движение не запрещено Правилами дорожного движения;</li> <li>предупреждения участников дорожного движения об опасности для движения;</li> <li>посадки (высадки) групп детей в перевозящие их автобусы — на автобусах;</li> <li>приближения трамвая к зоне остановочного пункта трамвая, обозначенной дорожными знаками 5.13.1 «Остановочный пункт трамвая» , 5.13.2 «Место остановки трамвая» и (или) горизонтальной дорожной разметкой 1.17.2 , и во время нахождения его в этой зоне — на трамваях. На трамваях, не оборудованных аварийной световой сигнализацией, должен быть включён световой указатель правого поворота.</li></ul>","image":null},{"id":100800702,"themeId":4,"group":1008007,"chapter":8,"chapters":[8],"q":"В каком из перечисленных случаев водитель не обязан включить аварийную световую сигнализацию?","a":["В случае буксировки — на буксируемом транспортном средстве.","В случае остановки в тёмное время суток на неосвещённом участке дороги в жилой зоне при неисправных габаритных и стояночных огнях.","В случае остановки в условиях недостаточной видимости дороги при неисправных габаритных и стояночных огнях.","В случае движения на транспортном средстве с неисправностью, указанной в Правилах дорожного движения, если движение не запрещено."],"c":1,"e":"<p>Аварийная световая сигнализация должна быть включена в случаях:</p> <ul><li>дорожно-транспортного происшествия;</li> <li>вынужденной остановки транспортного средства на проезжей части дороги и в местах, где остановка запрещена;</li> <li>ослепления водителя светом фар;</li> <li>буксировки механического транспортного средства — на буксируемом механическом транспортном средстве;</li> <li>остановки, стоянки транспортного средства в тёмное время суток на неосвещённых участках дороги (кроме жилых зон) и (или) при недостаточной видимости дороги при неисправных габаритных и стояночных огнях;</li> <li>движения на транспортном средстве с технической неисправностью, указанной в приложении 4 Правил дорожного движения, если движение не запрещено Правилами дорожного движения;</li> <li>предупреждения участников дорожного движения об опасности для движения;</li> <li>посадки (высадки) групп детей в перевозящие их автобусы — на автобусах;</li> <li>приближения трамвая к зоне остановочного пункта трамвая, обозначенной дорожными знаками 5.13.1 «Остановочный пункт трамвая» , 5.13.2 «Место остановки трамвая» и (или) горизонтальной дорожной разметкой 1.17.2 , и во время нахождения его в этой зоне — на трамваях. На трамваях, не оборудованных аварийной световой сигнализацией, должен быть включён световой указатель правого поворота.</li></ul>","image":null},{"id":100800801,"themeId":4,"group":1008008,"chapter":8,"chapters":[8],"q":"В каком из перечисленных случаев водитель обязан включить аварийную световую сигнализацию?","a":["При движении задним ходом.","При развороте в ограниченном пространстве при однократном включении передачи заднего хода.","При движении транспортного средства с технической неисправностью, указанной в Правилах дорожного движения, если движение не запрещено к месту стоянки или ремонта.","Во всех случаях водитель не обязан включать аварийную световую сигнализацию."],"c":2,"e":"<p>Аварийная световая сигнализация должна быть включена в случаях:</p> <ul><li>дорожно-транспортного происшествия;</li> <li>вынужденной остановки транспортного средства на проезжей части дороги и в местах, где остановка запрещена;</li> <li>ослепления водителя светом фар;</li> <li>буксировки механического транспортного средства — на буксируемом механическом транспортном средстве;</li> <li>остановки, стоянки транспортного средства в тёмное время суток на неосвещённых участках дороги (кроме жилых зон) и (или) при недостаточной видимости дороги при неисправных габаритных и стояночных огнях;</li> <li>движения на транспортном средстве с технической неисправностью, указанной в приложении 4 Правил дорожного движения, если движение не запрещено Правилами дорожного движения;</li> <li>предупреждения участников дорожного движения об опасности для движения;</li> <li>посадки (высадки) групп детей в перевозящие их автобусы — на автобусах;</li> <li>приближения трамвая к зоне остановочного пункта трамвая, обозначенной дорожными знаками 5.13.1 «Остановочный пункт трамвая» , 5.13.2 «Место остановки трамвая» и (или) горизонтальной дорожной разметкой 1.17.2 , и во время нахождения его в этой зоне — на трамваях. На трамваях, не оборудованных аварийной световой сигнализацией, должен быть включён световой указатель правого поворота.</li></ul>","image":null},{"id":100800901,"themeId":4,"group":1008009,"chapter":8,"chapters":[8],"q":"Обязательно ли включать аварийную световую сигнализацию при движении задним ходом?","a":["Да, обязательно.","Не обязательно, но рекомендуется.","Обязательно, кроме прилегающей территории."],"c":1,"e":"<p>Аварийную световую сигнализацию рекомендуется включать в случае движения транспортного средства задним ходом. Включение аварийной световой сигнализации не даёт водителю преимущества, а лишь дополнительно информирует водителей транспортных средств о возникновении у них на пути препятствия для дорожного движения, а также привлекает внимание других участников дорожного движения, сигнализируя о возникшей опасности для движения.</p>","image":null},{"id":100800902,"themeId":4,"group":1008009,"chapter":8,"chapters":[8],"q":"Обязательно ли включать аварийную световую сигнализацию при движении задним ходом?","a":["Не обязательно, но рекомендуется.","Обязательно, если водитель движется по дороге с односторонним движением.","Обязательно, если водитель не видит дорожную обстановку позади автомобиля."],"c":0,"e":"<p>Аварийную световую сигнализацию рекомендуется включать в случае движения транспортного средства задним ходом. Включение аварийной световой сигнализации не даёт водителю преимущества, а лишь дополнительно информирует других участников дорожного движения о возникновении у них препятствия на пути движения.</p>","image":null},{"id":100801001,"themeId":4,"group":1008010,"chapter":8,"chapters":[8],"q":"Должен ли быть выставлен знак аварийной остановки в показанной ситуации при дорожно-транспортном происшествии, если на транспортных средствах включена аварийная световая сигнализация?","a":["Да, должен.","Нет, не должен, так как транспортные средства находятся вне проезжей части дороги.","По усмотрению водителей."],"c":0,"e":"<p>После включения аварийной световой сигнализации, а также при её отсутствии или неисправности должен быть незамедлительно выставлен знак аварийной остановки (в тёмное время суток в дополнение к знаку аварийной остановки может быть выставлен фонарь с мигающим красным светом):</p> <ul><li>при дорожно-транспортном происшествии;</li> <li>при вынужденной остановке транспортного средства на проезжей части дороги и в местах, где остановка запрещена, за исключением прекращения движения транспортного средства в связи со скоплением остановившихся на проезжей части дороги других транспортных средств;</li> <li>в случае остановки, стоянки транспортного средства в тёмное время суток на неосвещённых участках дороги (кроме жилых зон) и (или) при недостаточной видимости дороги при неисправных габаритных и стояночных огнях.</li></ul>","image":"assets/adrive-questions/q100801001.jpg"},{"id":100801002,"themeId":4,"group":1008010,"chapter":8,"chapters":[8],"q":"Должен ли быть выставлен знак аварийной остановки в показанной ситуации при дорожно-транспортном происшествии, если на транспортных средствах включена аварийная световая сигнализация?","a":["Да, должен.","Нет, не должен, так как он затруднит проезд перекрёстка другим транспортным средствам.","По усмотрению водителей."],"c":0,"e":"<p>После включения аварийной световой сигнализации, а также при её отсутствии или неисправности должен быть незамедлительно выставлен знак аварийной остановки (в тёмное время суток в дополнение к знаку аварийной остановки может быть выставлен фонарь с мигающим красным светом):</p> <ul><li>при дорожно-транспортном происшествии;</li> <li>при вынужденной остановке транспортного средства на проезжей части дороги и в местах, где остановка запрещена, за исключением прекращения движения транспортного средства в связи со скоплением остановившихся на проезжей части дороги других транспортных средств;</li> <li>в случае остановки, стоянки транспортного средства в тёмное время суток на неосвещённых участках дороги (кроме жилых зон) и (или) при недостаточной видимости дороги при неисправных габаритных и стояночных огнях.</li></ul>","image":"assets/adrive-questions/q100801002.jpg"},{"id":100801101,"themeId":4,"group":1008011,"chapter":8,"chapters":[8],"q":"Водитель жёлтого автомобиля совершил вынужденную остановку у правого края проезжей части дороги. Должен ли он в показанной ситуации включить аварийную световую сигнализацию и выставить знак аварийной остановки?","a":["Да, должен.","Нет, не должен.","Должен только включить аварийную световую сигнализацию."],"c":0,"e":"<p>В данной ситуации водитель совершил вынужденную остановку на проезжей части дороги, поэтому необходимо включить аварийную световую сигнализацию и выставить знак аварийной остановки.</p>","image":"assets/adrive-questions/q100801101.jpg"},{"id":100801102,"themeId":4,"group":1008011,"chapter":8,"chapters":[8],"q":"Водитель автомобиля совершил вынужденную остановку в полосе движения при ослеплении его светом фар встречного автомобиля. Должен ли он в такой ситуации включить аварийную световую сигнализацию и выставить знак аварийной остановки?","a":["Да, должен.","Нет, не должен.","Должен только включить аварийную световую сигнализацию."],"c":2,"e":"<p>Включение аварийной световой сигнализации предупреждает других участников дорожного движения о возникновении в процессе движения ситуации, которая требует повышенного внимания. Запрещается при этом перестраиваться и покидать полосу движения. Знак аварийной остановки не устанавливается ввиду кратковременного ухудшения зрения водителя, нахождение на проезжей части дороги в таком состоянии крайне опасно!</p>","image":null},{"id":100801201,"themeId":4,"group":1008012,"chapter":8,"chapters":[8],"q":"Водитель легкового автомобиля совершил вынужденную остановку на обочине. Должен ли он в показанной ситуации включить аварийную световую сигнализацию и выставить знак аварийной остановки?","a":["Да, должен.","Нет, не должен.","Должен только включить аварийную световую сигнализацию."],"c":0,"e":"<p>В данной ситуации водитель совершил вынужденную остановку на обочине, но установленный дорожный знак запрещает остановку. Поэтому необходимо включить аварийную световую сигнализацию и выставить знак аварийной остановки.</p>","image":"assets/adrive-questions/q100801201.jpg"},{"id":100801202,"themeId":4,"group":1008012,"chapter":8,"chapters":[8],"q":"Вы совершаете вынужденную остановку в населённом пункте на проезжей части дороги после совершения разворота. Должны ли Вы в показанной ситуации после остановки включить аварийную световую сигнализацию и выставить знак аварийной остановки?","a":["Да, должны.","Нет, не должны.","Должны только включить аварийную световую сигнализацию."],"c":0,"e":"<p>В данной ситуации Вы совершаете вынужденную остановку на проезжей части дороги, поэтому необходимо включить аварийную световую сигнализацию и выставить знак аварийной остановки.</p>","image":"assets/adrive-questions/q100801202.jpg"},{"id":100801401,"themeId":4,"group":1008014,"chapter":8,"chapters":[8],"q":"Водитель автомобиля совершил вынужденную остановку у левого края проезжей части дороги с двусторонним движением в населённом пункте. В какой из показанных точек он должен установить знак аварийной остановки?","a":["В точке «А».","В точке «Б».","В любой из показанных точек на усмотрение водителя."],"c":1,"e":"<p>Знак аварийной остановки следует устанавливать с наиболее вероятного направления появления транспортных средств, когда положение остановившегося транспортного средства не соответствует его предшествовавшему направлению движения.</p>","image":"assets/adrive-questions/q100801401.jpg"},{"id":100801402,"themeId":4,"group":1008014,"chapter":8,"chapters":[8],"q":"Водитель автомобиля совершил вынужденную остановку у левого края проезжей части дороги в населённом пункте. В какой из показанных точек он должен установить знак аварийной остановки?","a":["В точке «А».","В точке «Б».","В любой из показанных точек на усмотрение водителя."],"c":0,"e":"<p>Знак аварийной остановки следует устанавливать в попутном направлении со стороны приближающихся ТС, если транспортное средство остановилось в направлении движения. Так как в показанной ситуации транспортное средство остановлено на участке дороги с односторонним движением, знак аварийной остановки следует установить позади транспортного средства.</p>","image":"assets/adrive-questions/q100801402.jpg"},{"id":100801501,"themeId":4,"group":1008015,"chapter":8,"chapters":[8],"q":"На каком минимальном расстоянии от транспортного средства при вынужденной остановке в показанной ситуации должен быть установлен знак аварийной остановки?","a":["5 метров.","15 метров.","30 метров.","40 метров.","50 метров."],"c":3,"e":"<p>Знак аварийной остановки и фонарь с мигающим красным светом устанавливаются на расстоянии, обеспечивающем в конкретной дорожно-транспортной обстановке своевременное предупреждение других водителей об опасности, но не менее 15 метров от транспортного средства в населённых пунктах и не менее 40 метров — вне населённых пунктов. В целях обеспечения безопасности дорожного движения рекомендуется, по возможности, устанавливать знак аварийной остановки на большем расстоянии, чем указано.</p>","image":"assets/adrive-questions/q100801501.jpg"},{"id":100801502,"themeId":4,"group":1008015,"chapter":8,"chapters":[8],"q":"На каком минимальном расстоянии от транспортного средства при вынужденной остановке в населённом пункте должен быть установлен знак аварийной остановки?","a":["5 метров.","15 метров.","30 метров.","40 метров.","50 метров."],"c":1,"e":"<p>Знак аварийной остановки и фонарь с мигающим красным светом устанавливаются на расстоянии, обеспечивающем в конкретной дорожно-транспортной обстановке своевременное предупреждение других водителей об опасности, но не менее 15 метров от транспортного средства в населённых пунктах и не менее 40 метров — вне населённых пунктов. В целях обеспечения безопасности дорожного движения рекомендуется, по возможности, устанавливать знак аварийной остановки на большем расстоянии, чем указано.</p>","image":"assets/adrive-questions/q100801502.jpg"},{"id":100801601,"themeId":4,"group":1008016,"chapter":8,"chapters":[8],"q":"На каком минимальном расстоянии от транспортного средства при вынужденной остановке вне населённого пункта должен быть установлен знак аварийной остановки?","a":["5 метров.","15 метров.","30 метров.","40 метров.","50 метров."],"c":3,"e":"<p>Знак аварийной остановки и фонарь с мигающим красным светом устанавливаются на расстоянии, обеспечивающем в конкретной дорожно-транспортной обстановке своевременное предупреждение других водителей об опасности, но не менее 15 метров от транспортного средства в населённых пунктах и не менее 40 метров — вне населённых пунктов. В целях обеспечения безопасности дорожного движения рекомендуется, по возможности, устанавливать знак аварийной остановки на большем расстоянии, чем указано.</p>","image":"assets/adrive-questions/q100801601.jpg"},{"id":100801602,"themeId":4,"group":1008016,"chapter":8,"chapters":[8],"q":"На каком расстоянии от транспортного средства при вынужденной остановке вне населённого пункта в показанной ситуации должен быть установлен знак аварийной остановки?","a":["В точке «А», соответствующей расстоянию 15 метров.","В точке «Б», соответствующей расстоянию 40 метров.","В точке «В» на участке дороги до начала закругления."],"c":2,"e":"<p>Знак аварийной остановки и фонарь с мигающим красным светом устанавливаются на расстоянии, обеспечивающем в конкретной дорожно-транспортной обстановке своевременное предупреждение других водителей об опасности (на прямом участке дороге знак не будет виден, если поставить его на закруглении дороги (точка «Б») или за ним (точка «А»)), но не менее 15 метров от транспортного средства в населённых пунктах и не менее 40 метров — вне населённых пунктов. В целях обеспечения безопасности дорожного движения рекомендуется, по возможности, устанавливать знак аварийной остановки на большем расстоянии, чем указано.</p>","image":"assets/adrive-questions/q100801602.jpg"},{"id":100801801,"themeId":4,"group":1008018,"chapter":8,"chapters":[8],"q":"На каком расстоянии от транспортного средства при вынужденной остановке вне населённого пункта должен устанавливаться знак аварийной остановки?","a":["Не более 15 метров.","Не менее 15 метров.","Не более 40 метров.","Не менее 40 метров."],"c":3,"e":"<p>Знак аварийной остановки и фонарь с мигающим красным светом устанавливаются на расстоянии, обеспечивающем в конкретной дорожно-транспортной обстановке своевременное предупреждение других водителей об опасности, но не менее 15 метров от транспортного средства в населённых пунктах и не менее 40 метров — вне населённых пунктов. В целях обеспечения безопасности дорожного движения рекомендуется, по возможности, устанавливать знак аварийной остановки на большем расстоянии, чем указано.</p>","image":null},{"id":100801802,"themeId":4,"group":1008018,"chapter":8,"chapters":[8],"q":"На каком расстоянии от транспортного средства при вынужденной остановке в населённом пункте должен устанавливаться знак аварийной остановки?","a":["Не более 15 метров.","Не менее 15 метров.","Не более 40 метров.","Не менее 40 метров."],"c":1,"e":"<p>Знак аварийной остановки и фонарь с мигающим красным светом устанавливаются на расстоянии, обеспечивающем в конкретной дорожно-транспортной обстановке своевременное предупреждение других водителей об опасности, но не менее 15 метров от транспортного средства в населённых пунктах и не менее 40 метров — вне населённых пунктов. В целях обеспечения безопасности дорожного движения рекомендуется, по возможности, устанавливать знак аварийной остановки на большем расстоянии, чем указано.</p>","image":null},{"id":100801901,"themeId":4,"group":1008019,"chapter":8,"chapters":[8],"q":"В каком месте на буксируемом автомобиле при неисправности аварийной световой сигнализации должен быть закреплён знак аварийной остановки?","a":["На задней части слева.","На задней части справа.","На задней части по центру."],"c":0,"e":"<p>При отсутствии или неисправности аварийной световой сигнализации на буксируемом механическом транспортном средстве или транспортном средстве, движущемся с технической неисправностью, на его задней части слева должен быть закреплён знак аварийной остановки.<br> При неисправности аварийной световой сигнализации или её отсутствии установка знака аварийной остановки на задней части буксируемого механического ТС позволяет информировать водителей о том, что производится буксировка, и обеспечить тем самым дополнительное условие безопасности.</p>","image":null},{"id":100801902,"themeId":4,"group":1008019,"chapter":8,"chapters":[8],"q":"Что должен выполнить водитель буксируемого автомобиля, у которого неисправна аварийная световая сигнализация, до начала буксировки?","a":["Подать звуковой сигнал.","Включить ближний свет фар или противотуманные фары.","Закрепить на задней части автомобиля слева знак аварийной остановки.","Закрепить на задней части автомобиля опознавательный знак «Транспортное средство большой длины»."],"c":2,"e":"<p>При отсутствии или неисправности аварийной световой сигнализации на буксируемом механическом транспортном средстве или транспортном средстве, движущемся с технической неисправностью, на его задней части слева должен быть закреплён знак аварийной остановки.<br> При неисправности аварийной световой сигнализации или её отсутствии установка знака аварийной остановки на задней части буксируемого механического ТС позволяет информировать водителей о том, что производится буксировка, и обеспечить тем самым дополнительное условие безопасности.</p>","image":null},{"id":100802001,"themeId":4,"group":1008020,"chapter":8,"chapters":[8],"q":"Какой из показанных опознавательных знаков должен быть закреплён на задней части автомобиля слева при его буксировке с неисправной аварийной световой сигнализацией?","a":["Первый.","Второй.","Третий."],"c":1,"e":"<p>При отсутствии или неисправности аварийной световой сигнализации на буксируемом механическом транспортном средстве или транспортном средстве, движущемся с технической неисправностью, на его задней части слева должен быть закреплён знак аварийной остановки, изображённый под номером 2.<br> При неисправности аварийной световой сигнализации или её отсутствии установка знака аварийной остановки на задней части буксируемого механического ТС позволяет информировать водителей о том, что производится буксировка, и обеспечить тем самым дополнительное условие безопасности.</p>","image":"assets/adrive-questions/q100802001.jpg"},{"id":100802002,"themeId":4,"group":1008020,"chapter":8,"chapters":[8],"q":"Какой из показанных опознавательных знаков должен быть закреплён на задней части автомобиля слева при его буксировке с неисправной аварийной световой сигнализацией?","a":["Первый.","Второй.","Третий."],"c":2,"e":"<p>При отсутствии или неисправности аварийной световой сигнализации на буксируемом механическом транспортном средстве или транспортном средстве, движущемся с технической неисправностью, на его задней части слева должен быть закреплён знак аварийной остановки, изображённый под номером 3.<br> При неисправности аварийной световой сигнализации или её отсутствии установка знака аварийной остановки на задней части буксируемого механического ТС позволяет информировать водителей о том, что производится буксировка, и обеспечить тем самым дополнительное условие безопасности.</p>","image":"assets/adrive-questions/q100802002.jpg"},{"id":100900101,"themeId":4,"group":1009001,"chapter":9,"chapters":[9],"q":"Обязан ли водитель при повороте направо подавать сигнал световым указателем поворота в показанной ситуации?","a":["Да, обязан.","Нет, не обязан."],"c":0,"e":"<p>Перед поворотом налево или направо водитель обязан подавать сигнал световыми указателями поворота соответствующего направления, а если они отсутствуют или неисправны либо включена аварийная световая сигнализация, — рукой, убедившись, что его действия будут безопасны и не создадут препятствия для дорожного движения.</p>","image":"assets/adrive-questions/q100900101.jpg"},{"id":100900102,"themeId":4,"group":1009001,"chapter":9,"chapters":[9],"q":"Обязан ли водитель при повороте налево подавать сигнал световым указателем поворота в показанной ситуации?","a":["Да, обязан.","Нет, не обязан."],"c":0,"e":"<p>Перед поворотом налево или направо водитель обязан подавать сигнал световыми указателями поворота соответствующего направления, а если они отсутствуют или неисправны либо включена аварийная световая сигнализация, — рукой, убедившись, что его действия будут безопасны и не создадут препятствия для дорожного движения.</p>","image":"assets/adrive-questions/q100900102.jpg"},{"id":100900103,"themeId":4,"group":1009001,"chapter":9,"chapters":[9],"q":"Обязан ли водитель при повороте направо подавать сигнал световым указателем поворота в показанной ситуации?","a":["Да, обязан.","Нет, не обязан."],"c":0,"e":"<p>Перед поворотом налево или направо водитель обязан подавать сигнал световыми указателями поворота соответствующего направления, а если они отсутствуют или неисправны либо включена аварийная световая сигнализация, — рукой, убедившись, что его действия будут безопасны и не создадут препятствия для дорожного движения.</p>","image":"assets/adrive-questions/q100900103.jpg"},{"id":100900141,"themeId":4,"group":1009001,"chapter":9,"chapters":[9],"q":"Обязаны ли Вы при въезде на перекрёсток, где организовано круговое движение, подать сигнал световыми указателями поворота?","a":["Да, обязаны.","Нет, в этом случае подача сигнала световыми указателями поворота не производится."],"c":1,"e":"<p>При въезде на перекрёсток, где организовано круговое движение, подача сигнала световыми указателями поворота не производится.<br> При перестроении на таком перекрёстке и перед съездом с него сигнал подавать необходимо.</p>","image":"assets/adrive-questions/q100900141.jpg"},{"id":100900201,"themeId":4,"group":1009002,"chapter":9,"chapters":[9],"q":"Обязаны ли Вы подавать сигнал световым указателем поворота в показанной ситуации при движении по главной дороге?","a":["Да, обязаны.","Нет, не обязаны."],"c":0,"e":"<p>Перед поворотом налево или направо водитель обязан подавать сигнал световыми указателями поворота соответствующего направления, а если они отсутствуют или неисправны либо включена аварийная световая сигнализация, — рукой, убедившись, что его действия будут безопасны и не создадут препятствия для дорожного движения.</p>","image":"assets/adrive-questions/q100900201.jpg"},{"id":100900202,"themeId":4,"group":1009002,"chapter":9,"chapters":[9],"q":"Обязаны ли Вы подавать сигнал световым указателем поворота в показанной ситуации при движении по главной дороге?","a":["Да, обязаны.","Нет, не обязаны."],"c":0,"e":"<p>Перед поворотом налево или направо водитель обязан подавать сигнал световыми указателями поворота соответствующего направления, а если они отсутствуют или неисправны либо включена аварийная световая сигнализация, — рукой, убедившись, что его действия будут безопасны и не создадут препятствия для дорожного движения.</p>","image":"assets/adrive-questions/q100900202.jpg"},{"id":100900203,"themeId":4,"group":1009002,"chapter":9,"chapters":[9],"q":"Требуется ли в показанной ситуации включать световой указатель поворота соответствующего направления при повороте налево?","a":["Да, требуется.","Требуется только при приближении к перекрёстку транспортных средств справа.","Нет, не требуется."],"c":0,"e":"<p>Перед поворотом налево или направо, разворотом водитель обязан подавать сигнал световыми указателями поворота соответствующего направления.</p>","image":"assets/adrive-questions/q100900203.jpg"},{"id":100900301,"themeId":4,"group":1009003,"chapter":9,"chapters":[9],"q":"Должны ли Вы подавать сигнал световым указателем поворота при движении по дороге в показанной ситуации?","a":["Да, должны.","Нет, не должны."],"c":1,"e":"<p>В показанной ситуации водитель двигается по криволинейному участку дороги. Не следует подавать сигнал поворота, если ТС движется по криволинейному участку дороги без изменения полосы движения. Подача сигнала поворота в такой ситуации может ввести в заблуждение других участников дорожного движения, поскольку может быть воспринята как намерение перестроиться на другую полосу движения, съехать с дороги или остановиться.</p>","image":"assets/adrive-questions/q100900301.jpg"},{"id":100900302,"themeId":4,"group":1009003,"chapter":9,"chapters":[9],"q":"Должны ли Вы подавать сигнал световым указателем поворота в показанной ситуации, если Вы на перекрёстке съезжаете с главной дороги?","a":["Да, должны.","Нет, не должны."],"c":1,"e":"<p>В показанной ситуации водитель намеревается продолжить движение прямо, поэтому подавать сигнал световым указателем поворота не требуется.</p>","image":"assets/adrive-questions/q100900302.jpg"},{"id":100900401,"themeId":4,"group":1009004,"chapter":9,"chapters":[9],"q":"В каком из перечисленных случаев водитель обязан подавать сигнал световыми указателями поворота соответствующего направления?","a":["Перед торможением.","Перед поворотом дороги.","Перед началом движения.","Во всех перечисленных случаях."],"c":2,"e":"<p>Согласно Правилам дорожного движения, перед началом движения, перестроением, выездом на трамвайные пути попутного направления, съездом с них, поворотом налево или направо, разворотом и остановкой водитель обязан подавать сигнал световыми указателями поворота соответствующего направления, а если они отсутствуют или неисправны либо включена аварийная световая сигнализация, — рукой, убедившись, что его действия будут безопасны и не создадут препятствия для дорожного движения.</p> <p>Перед поворотом дороги вне перекрёстка сигнал поворота подавать не следует.</p>","image":null},{"id":100900402,"themeId":4,"group":1009004,"chapter":9,"chapters":[9],"q":"В каком из перечисленных случаев водитель не обязан подавать сигнал световыми указателями поворота соответствующего направления?","a":["Перед остановкой.","Перед разворотом.","Перед поворотом дороги.","Перед началом движения."],"c":2,"e":"<p>Согласно Правилам дорожного движения, перед началом движения, перестроением, выездом на трамвайные пути попутного направления, съездом с них, поворотом налево или направо, разворотом и остановкой водитель обязан подавать сигнал световыми указателями поворота соответствующего направления, а если они отсутствуют или неисправны либо включена аварийная световая сигнализация, — рукой, убедившись, что его действия будут безопасны и не создадут препятствия для дорожного движения.</p> <p>Не следует подавать сигнал поворота, если ТС движется по криволинейному участку дороги без изменения полосы движения. Подача сигнала поворота в такой ситуации может ввести в заблуждение других участников дорожного движения, поскольку может быть воспринята как намерение перестроиться на другую полосу движения, съехать с дороги или остановиться.</p>","image":null},{"id":100900403,"themeId":4,"group":1009004,"chapter":9,"chapters":[9],"q":"Обязаны ли Вы, управляя легковым автомобилем, показывать сигнал поворота при остановке у левого края проезжей части дороги?","a":["Да, обязаны.","Нет, не обязаны, при отсутствии позади движущихся попутных транспортных средств."],"c":0,"e":"<p>Перед перестроением, а также перед остановкой, водитель обязан подавать сигнал световыми указателями поворота соответствующего направления, убедившись, что его действия будут безопасны и не создадут препятствия для дорожного движения.</p>","image":"assets/adrive-questions/q100900403.jpg"},{"id":100900501,"themeId":4,"group":1009005,"chapter":9,"chapters":[9],"q":"Какому сигналу соответствует жест, показанный водителем автомобиля?","a":["Сигналу торможения.","Сигналу левого светового указателя поворота.","Сигналу правого светового указателя поворота."],"c":1,"e":"<p>Согласно Правилам дорожного движения, сигналу левого светового указателя поворота соответствует левая рука, вытянутая в сторону, или правая рука, вытянутая в сторону и согнутая в локте под прямым углом вверх.</p>","image":"assets/adrive-questions/q100900501.jpg"},{"id":100900502,"themeId":4,"group":1009005,"chapter":9,"chapters":[9],"q":"О чём может предупреждать водитель, подавая такой жест вытянутой левой рукой?","a":["О намерении развернуться.","О намерении повернуть налево.","О намерении перестроиться на соседнюю полосу слева.","О намерении остановиться у левого края проезжей части дороги.","О намерении выполнить любое из перечисленных действий."],"c":4,"e":"<p>Согласно Правилам дорожного движения, сигналу левого светового указателя поворота соответствует левая рука, вытянутая в сторону, или правая рука, вытянутая в сторону и согнутая в локте под прямым углом вверх.</p>","image":"assets/adrive-questions/q100900502.jpg"},{"id":100900601,"themeId":4,"group":1009006,"chapter":9,"chapters":[9],"q":"Какому сигналу соответствует жест, показанный водителем мотоцикла?","a":["Сигналам торможения.","Сигналу левого светового указателя поворота.","Сигналу правого светового указателя поворота."],"c":1,"e":"<p>Согласно Правилам дорожного движения, сигналу левого светового указателя поворота соответствует левая рука, вытянутая в сторону, или правая рука, вытянутая в сторону и согнутая в локте под прямым углом вверх.</p>","image":"assets/adrive-questions/q100900601.jpg"},{"id":100900602,"themeId":4,"group":1009006,"chapter":9,"chapters":[9],"q":"О чём может предупреждать водитель, подавая такой жест правой рукой?","a":["О намерении развернуться.","О намерении повернуть налево.","О намерении перестроиться на соседнюю полосу слева.","О намерении начать движение от правого края проезжей части дороги.","О намерении выполнить любое из перечисленных действий."],"c":4,"e":"<p>Согласно Правилам дорожного движения, сигналу левого светового указателя поворота соответствует левая рука, вытянутая в сторону, или правая рука, вытянутая в сторону и согнутая в локте под прямым углом вверх.</p>","image":"assets/adrive-questions/q100900602.jpg"},{"id":100900701,"themeId":4,"group":1009007,"chapter":9,"chapters":[9],"q":"Какому сигналу соответствует жест, показанный водителем красного автомобиля?","a":["Сигналам торможения.","Сигналу левого светового указателя поворота.","Сигналу правого светового указателя поворота."],"c":2,"e":"<p>Согласно Правилам дорожного движения, сигналу правого светового указателя поворота соответствует правая рука, вытянутая в сторону, или левая рука, вытянутая в сторону и согнутая в локте под прямым углом вверх.</p>","image":"assets/adrive-questions/q100900701.jpg"},{"id":100900702,"themeId":4,"group":1009007,"chapter":9,"chapters":[9],"q":"О чём может предупреждать водитель, подавая такой жест левой рукой?","a":["О намерении повернуть направо.","О намерении остановиться на правой обочине дороги.","О намерении перестроиться на соседнюю полосу справа.","О намерении выполнить любое из перечисленных действий."],"c":3,"e":"<p>Согласно Правилам дорожного движения, сигналу правого светового указателя поворота соответствует правая рука, вытянутая в сторону, или левая рука, вытянутая в сторону и согнутая в локте под прямым углом вверх.</p>","image":"assets/adrive-questions/q100900702.jpg"},{"id":100900703,"themeId":4,"group":1009007,"chapter":9,"chapters":[9],"q":"Как водителю жёлтого автомобиля расценить жест, подаваемый водителем белого автомобиля?","a":["Водителю необходима помощь.","Водитель предупреждает о движении задним ходом.","Водитель предупреждает об опасности для движения.","Водитель собирается начать движение с левой обочины."],"c":3,"e":"<p>Согласно Правилам дорожного движения, сигналу правого светового указателя поворота соответствует правая рука, вытянутая в сторону, или левая рука, вытянутая в сторону и согнутая в локте под прямым углом вверх.</p>","image":"assets/adrive-questions/q100900703.jpg"},{"id":100900801,"themeId":4,"group":1009008,"chapter":9,"chapters":[9],"q":"Какому сигналу соответствует жест, показанный водителем мотоцикла?","a":["Сигналам торможения.","Сигналу левого светового указателя поворота.","Сигналу правого светового указателя поворота."],"c":2,"e":"<p>Согласно Правилам дорожного движения, сигналу правого светового указателя поворота соответствует правая рука, вытянутая в сторону, или левая рука, вытянутая в сторону и согнутая в локте под прямым углом вверх.</p>","image":"assets/adrive-questions/q100900801.jpg"},{"id":100900802,"themeId":4,"group":1009008,"chapter":9,"chapters":[9],"q":"О чём предупреждает водитель мотоцикла, подавая такой жест правой рукой?","a":["О повороте налево на перекрёстке.","О торможении перед перекрёстком.","О повороте направо на перекрёстке.","О том, что он уступает дорогу водителю жёлтого автомобиля."],"c":2,"e":"<p>Согласно Правилам дорожного движения, сигналу правого светового указателя поворота соответствует правая рука, вытянутая в сторону, или левая рука, вытянутая в сторону и согнутая в локте под прямым углом вверх.</p>","image":"assets/adrive-questions/q100900802.jpg"},{"id":100900901,"themeId":4,"group":1009009,"chapter":9,"chapters":[9],"q":"О чём предупреждает водитель мотоцикла, подавая такой жест левой рукой?","a":["О торможении.","О намерении развернуться.","О намерении совершить объезд препятствия."],"c":0,"e":"<p>Согласно Правилам дорожного движения, сигнал торможения подаётся поднятой вверх левой или правой рукой. Указанный сигнал используется также в случае торможения без намерения осуществить манёвр.</p>","image":"assets/adrive-questions/q100900901.jpg"},{"id":100900902,"themeId":4,"group":1009009,"chapter":9,"chapters":[9],"q":"Какому сигналу соответствует жест, показанный водителем красного автомобиля?","a":["Сигналу торможения.","Сигналу левого светового указателя поворота.","Сигналу правого светового указателя поворота."],"c":0,"e":"<p>Согласно Правилам дорожного движения, сигнал торможения подаётся поднятой вверх левой или правой рукой. Указанный сигнал используется также в случае торможения без намерения осуществить манёвр.</p>","image":"assets/adrive-questions/q100900902.jpg"},{"id":100901001,"themeId":4,"group":1009010,"chapter":9,"chapters":[9],"q":"Как необходимо подавать сигнал световым указателем поворота при выполнении разворота так, как показано на рисунке?","a":["Включить левый сигнал поворота.","Включить правый сигнал поворота, перед поворотом рулевого колеса влево включить левый сигнал поворота."],"c":0,"e":"<p>Отклонение вправо водитель производит, не осуществляя поворот направо, поэтому включение правого сигнала поворота не требуется, так как это может ввести в заблуждение других участников дорожного движения относительно его намерений.</p> <p>По сути, выполняется только один манёвр — разворот. Поэтому перед выполнением этого манёвра необходимо заблаговременно включить левый световой сигнал поворота.</p>","image":"assets/adrive-questions/q100901001.jpg"},{"id":100901002,"themeId":4,"group":1009010,"chapter":9,"chapters":[9],"q":"Как необходимо подавать сигнал световым указателем поворота при выполнении разворота от правого края проезжей части дороги?","a":["Заблаговременно включить левый сигнал поворота.","Заблаговременно включить правый сигнал поворота, перед поворотом рулевого колеса влево включить левый сигнал поворота.","Не включать сигнал заблаговременно, включить левый сигнал только в момент начала выполнения разворота."],"c":0,"e":"<p>Отклонение вправо водитель производит в пределах занимаемой полосы движения, поэтому включение правого сигнала поворота не требуется, так как это может ввести в заблуждение других участников дорожного движения относительно его намерений.</p> <p>По сути, выполняется только один манёвр — разворот. Поэтому перед выполнением этого манёвра необходимо заблаговременно включить левый световой сигнал поворота.</p>","image":"assets/adrive-questions/q100901002.jpg"},{"id":100901101,"themeId":4,"group":1009011,"chapter":9,"chapters":[9],"q":"В какой из указанных точек водитель синего автомобиля должен подать сигнал световыми указателями правого поворота?","a":["В точке «А».","В точке «Б».","В точке «В»."],"c":1,"e":"<p>Согласно Правилам дорожного движения, подача сигнала световыми указателями поворота или рукой должна производиться до начала маневрирования таким образом, чтобы другие участники дорожного движения имели возможность безопасного продолжения движения.<br> При этом сигнал торможения не должен подаваться, если он может ввести в заблуждение других участников дорожного движения.</p> <p>Слишком раннее включение указателя поворота в некоторых ситуациях может дезинформировать других водителей, а слишком позднее — не обеспечит его своевременное восприятие.</p>","image":"assets/adrive-questions/q100901101.jpg"},{"id":100901102,"themeId":4,"group":1009011,"chapter":9,"chapters":[9],"q":"Должен ли водитель красного автомобиля при движении через перекрёсток по указанной траектории подавать сигнал световыми указателями правого поворота?","a":["Нет, не должен.","Да, на начальной стадии движения."],"c":0,"e":"<p>Не следует подавать сигнал поворота, если ТС движется без изменения полосы движения. Подача сигнала поворота в такой ситуации может ввести в заблуждение других участников дорожного движения, поскольку может быть воспринята как намерение перестроиться на другую полосу движения, съехать с дороги или остановиться.</p>","image":"assets/adrive-questions/q100901102.jpg"},{"id":100901103,"themeId":4,"group":1009011,"chapter":9,"chapters":[9],"q":"Вам необходимо остановиться за перекрёстком в жилой зоне перед синим автомобилем. Когда следует включить световой указатель правого поворота?","a":["Только после проезда перекрёстка.","Заблаговременно, до проезда перекрёстка.","В показанной ситуации не следует включать световой указатель правого поворота."],"c":0,"e":"<p>Перед остановкой водитель обязан заблаговременно подавать сигнал световыми указателями поворота. При этом сигнал не должен подаваться, если он может ввести в заблуждение других участников дорожного движения.</p> <p>В данной ситуации водитель чёрного автомобиля может воспринять включение сигнала до перекрёстка как намерение повернуть направо.</p>","image":"assets/adrive-questions/q100901103.jpg"},{"id":100901141,"themeId":4,"group":1009011,"chapter":9,"chapters":[9],"q":"В какой из показанных точек водитель должен подать сигнал световыми указателями правого поворота при движении по показанной траектории?","a":["В точке «А».","В точке «Б»."],"c":1,"e":"<p>При въезде на перекрёсток, где организовано круговое движение, подача сигнала световыми указателями поворота не производится.<br> При перестроении на таком перекрёстке и перед съездом с него сигнал подавать необходимо.</p> <p>Поэтому в показанной ситуации водитель должен подать сигнал световыми указателями поворота в точке «Б».</p>","image":"assets/adrive-questions/q100901141.jpg"},{"id":100901201,"themeId":4,"group":1009012,"chapter":9,"chapters":[9],"q":"В каком месте водитель белого автомобиля может прекратить подачу сигнала поворота рукой?","a":["Только в точке «А».","Только в точке «Б».","В точке «А» или «Б»."],"c":2,"e":"<p>Согласно Правилам дорожного движения, подача сигнала световыми указателями поворота или рукой должна производиться до начала маневрирования таким образом, чтобы другие участники дорожного движения имели возможность безопасного продолжения движения, и прекращаться немедленно после завершения маневрирования (подача сигнала рукой может быть закончена непосредственно перед маневрированием).</p>","image":"assets/adrive-questions/q100901201.jpg"},{"id":100901202,"themeId":4,"group":1009012,"chapter":9,"chapters":[9],"q":"После проезда какой из обозначенных точек водитель нарушит Правила дорожного движения, если не прекратит подачу сигнала поворота рукой?","a":["После проезда точки «А».","После проезда точки «Б»."],"c":1,"e":"<p>Согласно Правилам дорожного движения, подача сигнала световыми указателями поворота или рукой должна производиться до начала маневрирования таким образом, чтобы другие участники дорожного движения имели возможность безопасного продолжения движения, и прекращаться немедленно после завершения маневрирования (подача сигнала рукой может быть закончена непосредственно перед маневрированием).</p>","image":"assets/adrive-questions/q100901202.jpg"},{"id":100901301,"themeId":4,"group":1009013,"chapter":9,"chapters":[9],"q":"В какой точке водитель красного автомобиля должен прекратить подачу сигнала световыми указателями поворота?","a":["В точке «А».","В точке «Б»."],"c":0,"e":"<p>Согласно Правилам дорожного движения, подача сигнала световыми указателями поворота или рукой должна производиться до начала маневрирования таким образом, чтобы другие участники дорожного движения имели возможность безопасного продолжения движения, и прекращаться немедленно после завершения маневрирования (подача сигнала рукой может быть закончена непосредственно перед маневрированием).<br> Очевидно, что автомобиль от точки «А» до точки «Б» движется по прямой, то есть после завершения манёвра, поэтому световой указатель поворота следует выключить в точке «А».</p>","image":"assets/adrive-questions/q100901301.jpg"},{"id":100901302,"themeId":4,"group":1009013,"chapter":9,"chapters":[9],"q":"В какой точке водитель легкового автомобиля должен прекратить подачу сигнала световыми указателями поворота?","a":["В точке «А».","В точке «Б».","В точке «В»."],"c":2,"e":"<p>Согласно Правилам дорожного движения, подача сигнала световыми указателями поворота или рукой должна производиться до начала маневрирования таким образом, чтобы другие участники дорожного движения имели возможность безопасного продолжения движения, и прекращаться немедленно после завершения маневрирования (подача сигнала рукой может быть закончена непосредственно перед маневрированием).</p>","image":"assets/adrive-questions/q100901302.jpg"},{"id":100901401,"themeId":4,"group":1009014,"chapter":9,"chapters":[9],"q":"Водитель красного автомобиля подал сигнал световыми указателями поворота перед выполнением обгона. Как долго он должен подаваться?","a":["На протяжении выполнения обгона.","До момента начала перестроения в правую полосу.","До момента завершения перестроения на встречную полосу."],"c":2,"e":"<p>Согласно Правилам дорожного движения, подача сигнала световыми указателями поворота или рукой должна производиться до начала маневрирования таким образом, чтобы другие участники дорожного движения имели возможность безопасного продолжения движения, и прекращаться немедленно после завершения маневрирования (подача сигнала рукой может быть закончена непосредственно перед маневрированием).<br> В показанной ситуации после перестроения на встречную полосу движения водитель должен прекратить подачу световым указателем поворота.</p>","image":"assets/adrive-questions/q100901401.jpg"},{"id":100901402,"themeId":4,"group":1009014,"chapter":9,"chapters":[9],"q":"Обязательно ли в показанной ситуации перед съездом на обочину для остановки включать правый световой указатель поворота, если на дороге в пределах видимости отсутствуют транспортные средства и пешеходы?","a":["Да, обязательно.","Нет, не обязательно."],"c":0,"e":"<p>Перед остановкой, в том числе на обочине, водитель обязан включать указатель поворота соответствующего направления.</p>","image":"assets/adrive-questions/q100901402.jpg"},{"id":100901403,"themeId":4,"group":1009014,"chapter":9,"chapters":[9],"q":"Когда водитель синего автомобиля обязан прекратить подачу левого сигнала световыми указателями поворота в показанной ситуации, совершая обгон?","a":["Сразу после окончания опережения.","Сразу после перестроения на левую полосу движения.","Сразу после возвращения в ранее занимаемую полосу движения."],"c":1,"e":"<p>Подача сигнала световыми указателями поворота должна производиться заблаговременно до начала маневрирования и прекращаться немедленно после завершения маневрирования, то есть сразу после перестроения на левую полосу движения.</p>","image":"assets/adrive-questions/q100901403.jpg"},{"id":100901501,"themeId":4,"group":1009015,"chapter":9,"chapters":[9],"q":"Когда должна прекращаться подача сигнала световыми указателями поворота соответствующего направления при маневрировании?","a":["Перед началом маневрирования.","В момент выполнения маневрирования.","Немедленно после завершения маневрирования."],"c":2,"e":"<p>Согласно Правилам дорожного движения, подача сигнала световыми указателями поворота или рукой должна производиться до начала маневрирования таким образом, чтобы другие участники дорожного движения имели возможность безопасного продолжения движения, и прекращаться немедленно после завершения маневрирования (подача сигнала рукой может быть закончена непосредственно перед маневрированием).</p>","image":null},{"id":100901502,"themeId":4,"group":1009015,"chapter":9,"chapters":[9],"q":"В какой момент может прекращаться подача сигнала соответствующего направления рукой при маневрировании?","a":["Непосредственно перед маневрированием.","Немедленно после завершения маневрирования.","В любой из перечисленных моментов."],"c":2,"e":"<p>Согласно Правилам дорожного движения, подача сигнала световыми указателями поворота или рукой должна производиться до начала маневрирования таким образом, чтобы другие участники дорожного движения имели возможность безопасного продолжения движения, и прекращаться немедленно после завершения маневрирования (подача сигнала рукой может быть закончена непосредственно перед маневрированием).</p>","image":null},{"id":100901503,"themeId":4,"group":1009015,"chapter":9,"chapters":[9],"q":"Когда водитель синего автомобиля обязан прекратить подачу левого сигнала световыми указателями поворота в показанной ситуации?","a":["Сразу после окончания опережения.","Сразу после перестроения на левую полосу движения.","Сразу после возвращения в ранее занимаемую полосу движения."],"c":1,"e":"<p>Подача сигнала световыми указателями поворота должна производиться заблаговременно до начала маневрирования и прекращаться немедленно после завершения маневрирования, то есть сразу после перестроения на левую полосу движения.</p>","image":"assets/adrive-questions/q100901503.jpg"},{"id":100901641,"themeId":4,"group":1009016,"chapter":9,"chapters":[9],"q":"Обязаны ли Вы перед выездом на трамвайные пути попутного направления (с целью последующего поворота налево на перекрёстке) подать сигнал световыми указателями левого поворота?","a":["Да, обязаны.","Нет, не обязаны. Подать сигнал поворота следует только перед поворотом налево."],"c":0,"e":"<p>Перед выездом на трамвайные пути попутного направления, съездом с них водитель обязан убедиться, что его действия будут безопасны и не создадут препятствия и опасности для дорожного движения, подать сигнал световыми указателями поворота соответствующего направления.</p>","image":"assets/adrive-questions/q100901641.jpg"},{"id":100901642,"themeId":4,"group":1009016,"chapter":9,"chapters":[9],"q":"Обязаны ли Вы перед выездом на трамвайные пути попутного направления (с целью объезда препятствия) подать сигнал световыми указателями левого поворота?","a":["Да, обязаны.","Нет, не обязаны, если Вы выедете на трамвайный путь частично."],"c":0,"e":"<p>Перед выездом на трамвайные пути попутного направления, съездом с них водитель обязан убедиться, что его действия будут безопасны и не создадут препятствия и опасности для дорожного движения, подать сигнал световыми указателями поворота соответствующего направления.</p>","image":"assets/adrive-questions/q100901642.jpg"},{"id":100901643,"themeId":4,"group":1009016,"chapter":9,"chapters":[9],"q":"Обязаны ли Вы после выполнения опережения перед съездом с трамвайных путей подать сигнал световыми указателями правого поворота?","a":["Да, обязаны.","Нет, не обязаны."],"c":0,"e":"<p>Перед выездом на трамвайные пути попутного направления, съездом с них водитель обязан убедиться, что его действия будут безопасны и не создадут препятствия и опасности для дорожного движения, подать сигнал световыми указателями поворота соответствующего направления.</p>","image":"assets/adrive-questions/q100901643.jpg"},{"id":100901701,"themeId":4,"group":1009017,"chapter":9,"chapters":[9],"q":"Каким образом должна производиться подача сигнала световыми указателями поворота до начала маневрирования?","a":["Чтобы другие участники дорожного движения имели возможность безопасного продолжения движения.","Чтобы другие участники дорожного движения имели возможность предотвратить возникновение аварийной ситуации.","Чтобы другие участники дорожного движения имели возможность остановиться, не прибегая к экстренному торможению."],"c":0,"e":"<p>Согласно Правилам дорожного движения, подача сигнала световыми указателями поворота или рукой должна производиться до начала маневрирования таким образом, чтобы другие участники дорожного движения имели возможность безопасного продолжения движения, и прекращаться немедленно после завершения маневрирования (подача сигнала рукой может быть закончена непосредственно перед маневрированием).</p> <p>Слишком раннее включение указателя поворота в некоторых ситуациях может дезинформировать других водителей, а слишком позднее — не обеспечит его своевременное восприятие.</p>","image":null},{"id":100901702,"themeId":4,"group":1009017,"chapter":9,"chapters":[9],"q":"Каким образом должна производиться подача сигнала световыми указателями поворота при маневрировании?","a":["До начала маневрирования таким образом, чтобы другие участники дорожного движения имели возможность безопасного продолжения движения.","В момент начала маневрирования таким образом, чтобы другие участники дорожного движения имели возможность безопасного продолжения движения.","После завершения маневрирования таким образом, чтобы другие участники дорожного движения имели возможность безопасного продолжения движения."],"c":0,"e":"<p>Согласно Правилам дорожного движения, подача сигнала световыми указателями поворота или рукой должна производиться до начала маневрирования таким образом, чтобы другие участники дорожного движения имели возможность безопасного продолжения движения, и прекращаться немедленно после завершения маневрирования (подача сигнала рукой может быть закончена непосредственно перед маневрированием).</p> <p>Слишком раннее включение указателя поворота в некоторых ситуациях может дезинформировать других водителей, а слишком позднее — не обеспечит его своевременное восприятие.</p>","image":null},{"id":100901801,"themeId":4,"group":1009018,"chapter":9,"chapters":[9],"q":"Водитель какого автомобиля в показанной обстановке обязан уступить дорогу?","a":["Водитель жёлтого автомобиля, совершающий разворот.","Водитель красного автомобиля, начинающего движение после стоянки."],"c":1,"e":"<p>Согласно Правилам дорожного движения, после остановки или стоянки водитель транспортного средства, начинающего движение, обязан уступить дорогу движущимся транспортным средствам. Водитель красного автомобиля, подавший световой сигнал указателем поворота, перед началом движения с места остановки (стоянки) у тротуара должен убедиться в том, что он не создаёт препятствие для движения другим участникам дорожного движения. Это значит, что он не должен начинать движение, если его действия вынудят других участников дорожного движения изменить скорость или направление движения.</p>","image":"assets/adrive-questions/q100901801.jpg"},{"id":100901802,"themeId":4,"group":1009018,"chapter":9,"chapters":[9],"q":"Водитель какого автомобиля в показанной обстановке обязан уступить дорогу?","a":["Водитель жёлтого автомобиля, начинающего движение после стоянки.","Водитель красного автомобиля, совершающий разворот на прилегающей территории."],"c":0,"e":"<p>Согласно Правилам дорожного движения, после остановки или стоянки водитель транспортного средства, начинающего движение, обязан уступить дорогу движущимся транспортным средствам. Водитель жёлтого автомобиля перед началом движения с места остановки (стоянки) должен убедиться в том, что он не создаёт препятствие для движения другим участникам дорожного движения. Это значит, что он не должен начинать движение, если его действия вынудят участников дорожного движения изменить скорость или направление движения.</p>","image":"assets/adrive-questions/q100901802.jpg"},{"id":100901901,"themeId":4,"group":1009019,"chapter":9,"chapters":[9],"q":"При съезде на обочину водитель пересекает путь движения пешехода, велосипедиста и всадника. Кому в такой ситуации он обязан уступить дорогу (предоставить преимущество)?","a":["Пешеходу и велосипедисту.","Пешеходу, движущемуся по обочине в попутном направлении.","Велосипедисту, движущемуся по обочине навстречу движению.","Всаднику, движущемуся по краю проезжей части дороги в попутном направлении.","Всем перечисленным участникам движения."],"c":4,"e":"<p>Согласно Правилам дорожного движения, при съезде с проезжей части дороги водитель обязан уступить дорогу (предоставить преимущество) пешеходам, всадникам, водителям средств персональной мобильности и велосипедистам, путь движения которых он пересекает.</p>","image":null},{"id":100901902,"themeId":4,"group":1009019,"chapter":9,"chapters":[9],"q":"При съезде на специальную площадку, отведённую для стоянки транспортных средств, водитель красного автомобиля пересекает путь движения пешехода, идущего к своему автомобилю. Кто в такой ситуации обязан уступить дорогу (предоставить преимущество)?","a":["Пешеход.","Водитель красного автомобиля."],"c":1,"e":"<p>При съезде с проезжей части дороги водитель обязан предоставить преимущество пешеходам, путь движения которых он пересекает.</p>","image":"assets/adrive-questions/q100901902.jpg"},{"id":100902001,"themeId":4,"group":1009020,"chapter":9,"chapters":[9],"q":"Кто в показанной ситуации должен уступить дорогу?","a":["Водитель жёлтого автомобиля.","Водитель красного автомобиля."],"c":1,"e":"<p>Согласно Правилам дорожного движения, при перестроении водитель должен уступить дорогу транспортным средствам, движущимся попутно, без изменения их направления движения. Таким образом, в показанной ситуации уступить дорогу должен водитель красного автомобиля.</p>","image":"assets/adrive-questions/q100902001.jpg"},{"id":100902002,"themeId":4,"group":1009020,"chapter":9,"chapters":[9],"q":"Кто в показанной ситуации должен уступить дорогу?","a":["Водитель жёлтого автомобиля.","Водитель зелёного автомобиля."],"c":0,"e":"<p>Согласно Правилам дорожного движения, при перестроении водитель должен уступить дорогу транспортным средствам, движущимся попутно, без изменения их направления движения. Таким образом, в показанной ситуации уступить дорогу должен водитель жёлтого автомобиля.</p>","image":"assets/adrive-questions/q100902002.jpg"},{"id":100902003,"themeId":4,"group":1009020,"chapter":9,"chapters":[9],"q":"Обязаны ли Вы при управлении легковым автомобилем, осуществляя перестроение перед поворотом направо, уступить дорогу велосипедисту?","a":["Да, обязаны.","Нет, не обязаны."],"c":0,"e":"<p>При перестроении водитель должен уступить дорогу транспортным средствам, движущимся попутно, без изменения их направления движения.</p>","image":"assets/adrive-questions/q100902003.jpg"},{"id":100902101,"themeId":4,"group":1009021,"chapter":9,"chapters":[9],"q":"Водители белого и зелёного автомобилей решили перестроиться во вторую полосу. Кто в показанной ситуации должен уступить дорогу?","a":["Водитель белого автомобиля.","Водитель зелёного автомобиля."],"c":0,"e":"<p>Согласно Правилам дорожного движения, при одновременном перестроении транспортных средств, движущихся попутно, водитель должен уступить дорогу транспортному средству, находящемуся справа.</p>","image":"assets/adrive-questions/q100902101.jpg"},{"id":100902102,"themeId":4,"group":1009021,"chapter":9,"chapters":[9],"q":"Водитель жёлтого автомобиля решил перестроиться в третью полосу для последующей остановки у тротуара, а водитель зелёного автомобиля — во вторую полосу для объезда стоящего синего автомобиля. Кто в показанной ситуации должен уступить дорогу?","a":["Водитель жёлтого автомобиля.","Водитель зелёного автомобиля."],"c":1,"e":"<p>Согласно Правилам дорожного движения, при одновременном перестроении транспортных средств, движущихся попутно, водитель должен уступить дорогу транспортному средству, находящемуся справа.</p>","image":"assets/adrive-questions/q100902102.jpg"},{"id":100902201,"themeId":4,"group":1009022,"chapter":9,"chapters":[9],"q":"Кто в показанной ситуации должен уступить дорогу?","a":["Водитель синего легкового автомобиля.","Водитель жёлтого легкового автомобиля, съезжающий с трамвайных путей."],"c":1,"e":"<p>При съезде с трамвайных путей водитель должен уступить дорогу транспортным средствам, движущимся попутно, без изменения их направления движения.</p>","image":"assets/adrive-questions/q100902201.jpg"},{"id":100902202,"themeId":4,"group":1009022,"chapter":9,"chapters":[9],"q":"Кто в показанной ситуации обязан уступить дорогу?","a":["Водитель синего автомобиля, съезжающий с трамвайных путей.","Водитель белого автомобиля, выезжающий на трамвайные пути."],"c":0,"e":"<p>При одновременном перестроении транспортных средств, движущихся попутно, водитель должен уступить дорогу транспортному средству, находящемуся справа. Этим правилом должен руководствоваться водитель, транспортное средство которого съезжает с трамвайных путей.</p>","image":"assets/adrive-questions/q100902202.jpg"},{"id":100902301,"themeId":4,"group":1009023,"chapter":9,"chapters":[9],"q":"В каких направлениях из показанных стрелками водителю автомобиля скорой медицинской помощи разрешается продолжить движение?","a":["Только в направлениях «А» и «Б».","Только в направлениях «А», «Б» и «В».","Во всех показанных направлениях."],"c":2,"e":"<p>Водитель транспортного средства оперативного назначения при включении маячков синего цвета вправе отступать от требования занять соответствующее крайнее положение на проезжей части дороги, предназначенной для движения в данном направлении, и может продолжить движение в любом направлении.<br> При этом он обязан заблаговременно подавать сигнал световыми указателями поворота соответствующего направления.</p> <p>Водители прочих транспортных средств обязаны уступить ему дорогу и обеспечить беспрепятственный проезд.</p>","image":"assets/adrive-questions/q100902301.jpg"},{"id":100902302,"themeId":4,"group":1009023,"chapter":9,"chapters":[9],"q":"Кто в показанной ситуации пользуется преимуществом?","a":["Водитель синего легкового автомобиля.","Водитель автомобиля скорой медицинской помощи."],"c":1,"e":"<p>Водитель транспортного средства оперативного назначения при включении маячков синего цвета вправе отступать от требования уступить дорогу транспортным средствам, движущимся попутно, без изменения их направления движения.</p> <p>Водитель синего автомобиля в свою очередь обязан ему уступить дорогу и обеспечить беспрепятственный проезд.</p>","image":"assets/adrive-questions/q100902302.jpg"},{"id":100902401,"themeId":4,"group":1009024,"chapter":9,"chapters":[9],"q":"Разрешено ли перестроение на перекрёстке, на котором не организовано круговое движение?","a":["Разрешено при опережении.","Разрешено для объезда препятствия.","Разрешено в обоих случаях.","Запрещено."],"c":3,"e":"<p>Согласно Правилам дорожного движения, перестроение транспортных средств на перекрёстке запрещается, кроме перекрёстка, на котором организовано круговое движение. Для разворота, поворота налево или направо перестроение ТС должно быть выполнено до перекрёстка. Перестроение ТС из одной полосы в другую на перекрёстке не обеспечивает безопасность дорожного движения и поэтому запрещается.</p>","image":null},{"id":100902402,"themeId":4,"group":1009024,"chapter":9,"chapters":[9],"q":"На каких перекрёстках разрешается перестроение транспортных средств?","a":["На перекрёстках со сложной планировкой.","На перекрёстках со смещенными съездами.","На перекрёстках, где главная дорога меняет направление.","На перекрёстках, на которых организовано круговое движение."],"c":3,"e":"<p>Согласно Правилам дорожного движения, перестроение транспортных средств на перекрёстке запрещается, кроме перекрёстка, на котором организовано круговое движение. Выезд на перекрёсток, где организовано круговое движение, разрешается из любой полосы движения. При этом необходимо учитывать дальнейшее собственное направление движения, чтобы выполнить минимальное число перестроений при движении по кругу и не создать препятствие ТС, движущимся по соседним полосам.</p>","image":null},{"id":100902403,"themeId":4,"group":1009024,"chapter":9,"chapters":[9],"q":"Разрешено ли производить перестроение на перекрёстке?","a":["Да, если перекрёсток находится в жилой зоне.","Да, при опережении тихоходных транспортных средств.","Да, на перекрёстке, на котором организовано круговое движение.","Разрешено во всех перечисленных случаях."],"c":2,"e":"<p>Согласно Правилам дорожного движения, перестроение транспортных средств на перекрёстке запрещается, кроме перекрёстка, на котором организовано круговое движение. Выезд на перекрёсток, где организовано круговое движение, разрешается из любой полосы движения. При этом необходимо учитывать дальнейшее собственное направление движения, чтобы выполнить минимальное число перестроений при движении по кругу и не создать препятствие ТС, движущимся по соседним полосам.</p>","image":null},{"id":100902452,"themeId":4,"group":1009024,"chapter":9,"chapters":[9],"q":"Разрешено ли Вам совершить перестроение на перекрёстке, на котором организовано круговое движение, в показанной ситуации?","a":["Разрешено.","Запрещено."],"c":0,"e":"<p><strong>Перестроение</strong> транспортных средств на перекрёстках, на которых организовано круговое движение, <strong>не запрещается</strong>.</p>","image":"assets/adrive-questions/q100902452.jpg"},{"id":100902501,"themeId":4,"group":1009025,"chapter":9,"chapters":[9],"q":"В каком случае водителю красного автомобиля разрешается перестроиться на правую полосу движения, если полосы движения равномерно заняты движущимися транспортными средствами?","a":["Для объезда неподвижного препятствия.","Для последующей остановки на обочине.","Для последующего поворота направо на ближайшем перекрёстке.","Разрешается во всех перечисленных случаях."],"c":3,"e":"<p>Согласно Правилам дорожного движения, перестраиваться на соседнюю полосу движения на дороге с двумя и более полосами движения в одном направлении, обозначенными горизонтальной дорожной разметкой, когда эти полосы равномерно заняты движущимися транспортными средствами, разрешается только для поворота налево или направо, разворота, остановки или объезда препятствия.</p>","image":"assets/adrive-questions/q100902501.jpg"},{"id":100902502,"themeId":4,"group":1009025,"chapter":9,"chapters":[9],"q":"В каком случае водителю зелёного автомобиля разрешается перестроиться на левую полосу движения, если полосы движения равномерно заняты движущимися транспортными средствами?","a":["Для опережения.","Для улучшения обзорности.","Для разворота в ближайшем разрешённом месте.","Разрешается во всех перечисленных случаях."],"c":2,"e":"<p>Согласно Правилам дорожного движения, перестраиваться на соседнюю полосу движения на дороге с двумя и более полосами движения в одном направлении, обозначенными горизонтальной дорожной разметкой, когда эти полосы равномерно заняты движущимися транспортными средствами, разрешается только для поворота налево или направо, разворота, остановки или объезда препятствия.</p>","image":"assets/adrive-questions/q100902502.jpg"},{"id":100902601,"themeId":4,"group":1009026,"chapter":9,"chapters":[9],"q":"Из-за препятствия в левой полосе движения образовался затор. Каким автомобилям в показанной ситуации водитель жёлтого автомобиля должен дать возможность перестроиться в правую полосу?","a":["Зелёному автомобилю.","Зелёному и красному автомобилям.","Всем автомобилям, стоящим в заторе."],"c":0,"e":"<p>Согласно Правилам дорожного движения, если на дороге, имеющей две и более полосы движения в одном направлении, из-за препятствия на одной из них образовался затор, водитель каждого транспортного средства, движущегося по соседней полосе движения, должен дать возможность перестроиться на его полосу одному из стоящих в заторе транспортных средств. Требование дать возможность для перестроения стоящих в заторе ТС на полосу, на которой нет препятствия для дорожного движения, направлено на увеличение пропускной способности дорог, профилактику образования протяжённых заторов, обеспечение безопасности дорожного движения.</p>","image":"assets/adrive-questions/q100902601.jpg"},{"id":100902602,"themeId":4,"group":1009026,"chapter":9,"chapters":[9],"q":"Из-за препятствия во второй полосе движения образовался затор. Водители каких автомобилей в показанной ситуации должны дать возможность перестроиться в свою полосу одному из стоящих в заторе транспортных средств?","a":["Водитель жёлтого автомобиля.","Водитель зелёного автомобиля.","Водители обоих автомобилей."],"c":2,"e":"<p>Согласно Правилам дорожного движения, если на дороге, имеющей две и более полосы движения в одном направлении, из-за препятствия на одной из них образовался затор, водитель каждого транспортного средства, движущегося по соседней полосе движения, должен дать возможность перестроиться на его полосу одному из стоящих в заторе транспортных средств. Требование дать возможность для перестроения стоящих в заторе ТС на полосу, на которой нет препятствия для дорожного движения, направлено на увеличение пропускной способности дорог.</p> <p>При наличии трёх полос движения и препятствия на средней из них ликвидация затора достигается предоставлением возможности поочередно каждому из стоящих в заторе ТС непосредственно перед препятствием перестроиться на любую из смежных полос.</p>","image":"assets/adrive-questions/q100902602.jpg"},{"id":100902701,"themeId":4,"group":1009027,"chapter":9,"chapters":[9],"q":"Разрешается ли Вам, управляя легковым автомобилем, выполнить поворот направо из занимаемой полосы движения в показанной ситуации?","a":["Запрещается.","Разрешается, если не будет создано препятствия и опасности для движения автомобилей в правой полосе движения."],"c":0,"e":"<p>Согласно Правилам дорожного движения, перед разворотом, поворотом налево или направо водитель обязан, не создавая препятствия и опасности для движения других участников дорожного движения, занять соответствующее крайнее положение на проезжей части дороги, предназначенной для движения в данном направлении. В показанной ситуации водитель не занял крайнее правое положение на дороге, поэтому поворот направо будет запрещён.</p>","image":"assets/adrive-questions/q100902701.jpg"},{"id":100902702,"themeId":4,"group":1009027,"chapter":9,"chapters":[9],"q":"Водитель какого автомобиля выполняет разворот, не нарушая Правила дорожного движения?","a":["Водитель белого автомобиля.","Водитель синего автомобиля.","Водители обоих автомобилей.","Водители обоих автомобилей нарушают Правила дорожного движения."],"c":1,"e":"<p>Согласно Правилам дорожного движения, перед разворотом, поворотом налево или направо водитель обязан, не создавая препятствия и опасности для движения других участников дорожного движения, занять соответствующее крайнее положение на проезжей части дороги, предназначенной для движения в данном направлении. Крайнее левое положение на проезжей части дороги занял только водитель синего легкового автомобиля.</p>","image":"assets/adrive-questions/q100902702.jpg"},{"id":100902703,"themeId":4,"group":1009027,"chapter":9,"chapters":[9],"q":"Разрешено ли водителю жёлтого автомобиля повернуть налево на ближайшем перекрёстке из занимаемой полосы движения?","a":["Да, разрешено.","Нет, не разрешено."],"c":1,"e":"<p>Согласно Правилам дорожного движения, перед разворотом, поворотом налево или направо водитель обязан, не создавая препятствия и опасности для движения других участников дорожного движения, занять соответствующее крайнее положение на проезжей части дороги, предназначенной для движения в данном направлении. В показанной ситуации водитель двигается по участку дороги с односторонним движением, и для поворота налево ему необходимо занять крайнее левое положение.</p>","image":"assets/adrive-questions/q100902703.jpg"},{"id":100902704,"themeId":4,"group":1009027,"chapter":9,"chapters":[9],"q":"В каких направлениях разрешено продолжить движение водителю синего легкового автомобиля в показанной ситуации?","a":["Только направо.","Прямо и направо.","Прямо на разворот.","Прямо, направо и на разворот.","Во всех направлениях."],"c":1,"e":"<p>В показанной ситуации дорожный знак 5.7.1 «Выезд на дорогу с односторонним движением» информирует водителей о выезде на дорогу, по которой движение транспортных средств разрешено только в направлении, указанном на знаке.</p> <p>Поэтому водителю синего легкового автомобиля разрешено продолжить движение с крайней правой полосы прямо и направо. Развернуться можно было бы только с левой полосы движения.</p>","image":"assets/adrive-questions/q100902704.jpg"},{"id":100902761,"themeId":4,"group":1009027,"chapter":9,"chapters":[9],"q":"В каком направлении из перечисленных Вам разрешено продолжить движение в показанной ситуации?","a":["Только прямо.","Прямо и на разворот.","Прямо, направо и на разворот."],"c":0,"e":"<p>Несмотря на то, что на перекрёстке нанесена разметка 1.11, дорожный знак «<strong>4.1.1 Движение прямо</strong>» запрещает выполнение правого поворота, а также разворота.</p>","image":"assets/adrive-questions/q100902761.jpg"},{"id":100902801,"themeId":4,"group":1009028,"chapter":9,"chapters":[9],"q":"Водитель синего автомобиля остановился перед перекрёстком в крайней левой полосе движения с включёнными левыми световыми указателями поворота. Разрешено ли водителю жёлтого автомобиля осуществить поворот налево в такой ситуации со второй полосы?","a":["Запрещено.","Разрешено, если перед перекрёстком нет встречных автомобилей."],"c":0,"e":"<p>Согласно Правилам дорожного движения, перед разворотом, поворотом налево или направо водитель обязан, не создавая препятствия и опасности для движения других участников дорожного движения, занять соответствующее крайнее положение на проезжей части дороги, предназначенной для движения в данном направлении.</p> <p>В показанной ситуации водитель жёлтого автомобиля для поворота налево должен занять крайнее левое положение на дороге, с данной полосы движения поворот налево будет запрещён.</p>","image":"assets/adrive-questions/q100902801.jpg"},{"id":100902802,"themeId":4,"group":1009028,"chapter":9,"chapters":[9],"q":"Разрешено ли водителю красного автомобиля повернуть налево так, как показано на рисунке?","a":["Запрещено.","Разрешено, убедившись, что жёлтый автомобиль разворачивается на перекрёстке."],"c":0,"e":"<p>Согласно Правилам дорожного движения, перед разворотом, поворотом налево или направо водитель обязан, не создавая препятствия и опасности для движения других участников дорожного движения, занять соответствующее крайнее положение на проезжей части дороги, предназначенной для движения в данном направлении.</p> <p>В показанной ситуации водитель красного легкового автомобиля для поворота налево должен занять крайнее левое положение на дороге, с данной полосы движения поворот налево будет запрещён.</p>","image":"assets/adrive-questions/q100902802.jpg"},{"id":100902803,"themeId":4,"group":1009028,"chapter":9,"chapters":[9],"q":"Правильно ли мотоциклисты осуществляют поворот налево?","a":["Правильно мотоциклист «А».","Правильно мотоциклист «Б».","Правильно оба мотоциклиста."],"c":0,"e":"<p>Перед разворотом, поворотом налево или направо водитель обязан, не создавая препятствия и опасности для движения других участников дорожного движения, занять соответствующее крайнее положение на проезжей части дороги, предназначенной для движения в данном направлении.</p> <p>Это правило в полной мере касается и движения мотоциклистов.</p>","image":"assets/adrive-questions/q100902803.jpg"},{"id":100902834,"themeId":4,"group":1009028,"chapter":9,"chapters":[9],"q":"В каком направлении разрешено продолжить движение водителю синего легкового автомобиля?","a":["Только налево.","Направо и налево.","Налево и на разворот.","Направо, налево и на разворот.","Во всех направлениях."],"c":2,"e":"<p>Дорожный знак 4.1.6 «Движение направо или налево» разрешает движение в направлениях, указанных стрелками, а также разворот.</p> <p>Так как легковой автомобиль находится во второй полосе движения, поворот направо ему запрещён.</p>","image":"assets/adrive-questions/q100902834.jpg"},{"id":100902901,"themeId":4,"group":1009029,"chapter":9,"chapters":[9],"q":"По какой траектории водителю жёлтого автомобиля разрешается повернуть направо?","a":["По траектории «А».","По траектории «Б».","По любой траектории из указанных, не создавая помех попутно движущимся транспортным средствам."],"c":0,"e":"<p>Согласно Правилам дорожного движения, перед разворотом, поворотом налево или направо водитель обязан, не создавая препятствия и опасности для движения других участников дорожного движения, занять соответствующее крайнее положение на проезжей части дороги, предназначенной для движения в данном направлении.<br> В показанной ситуации водитель для поворота направо должен занять крайнее правое положение на дороге, то есть двигаться по траектории «А».</p>","image":"assets/adrive-questions/q100902901.jpg"},{"id":100902903,"themeId":4,"group":1009029,"chapter":9,"chapters":[9],"q":"В каких направлениях Вам разрешено продолжить движение в показанной ситуации?","a":["Только прямо.","Только направо.","Прямо или направо.","Во всех направлениях.","Движение в показанной ситуации запрещено."],"c":2,"e":"<p>В показанной ситуации регулировщик, осуществляющий регулирование дорожного движения на перекрёстке, обращён к Вам левым боком с вытянутой рукой вперёд. При таком сигнале регулировщика Вам разрешено движение во всех направлениях.</p> <p>Но, учитывая тот факт, что Вы находитесь в крайней правой полосе на дороге с двумя полосами движения попутного направления, разрешено из занимаемой полосы продолжать движение только прямо или направо.</p>","image":"assets/adrive-questions/q100902903.jpg"},{"id":100902932,"themeId":4,"group":1009029,"chapter":9,"chapters":[9],"q":"По какой траектории водителю зелёного автомобиля разрешается выехать на перекрёсток, на котором организовано круговое движение?","a":["По траектории «А».","По траектории «Б».","По любой траектории из указанных."],"c":2,"e":"<p>Согласно Правилам дорожного движения, перед разворотом, поворотом налево или направо водитель обязан, не создавая препятствия и опасности для движения других участников дорожного движения, занять соответствующее крайнее положение на проезжей части дороги, предназначенной для движения в данном направлении, кроме случаев, когда поворот при въезде на перекрёсток и выезде с него совершается в тех местах, где организовано круговое движение. Перед перекрёстком, на котором организовано круговое движение, водитель ТС не обязан занимать крайнее положение, соответствующее его дальнейшему движению, поскольку он в процессе движения по кругу может перестраиваться из одной полосы в другую.</p>","image":"assets/adrive-questions/q100902932.jpg"},{"id":100902951,"themeId":4,"group":1009029,"chapter":9,"chapters":[9],"q":"Разрешено ли Вам выполнить поворот направо из занимаемой полосы движения в показанной ситуации, если Вы находитесь на перекрёстке, на котором организовано круговое движение?","a":["Разрешено.","Запрещено, так как необходимо заблаговременно занять крайнее правое положение на проезжей части дороги."],"c":0,"e":"<p>На перекрёстках, где организовано круговое движение, <strong>допускается съезд с любой полосы движения</strong>, если иной порядок не организован применением дорожных знаков и (или) дорожной разметки.</p>","image":"assets/adrive-questions/q100902951.jpg"},{"id":100903001,"themeId":4,"group":1009030,"chapter":9,"chapters":[9],"q":"Нарушит ли Правила дорожного движения водитель легкового автомобиля, совершив поворот налево в показанной ситуации?","a":["Да, нарушит.","Нет, не нарушит."],"c":1,"e":"<p>Согласно Правилам дорожного движения, перед разворотом, поворотом налево или направо водитель обязан, не создавая препятствия и опасности для движения других участников дорожного движения, занять соответствующее крайнее положение на проезжей части дороги, предназначенной для движения в данном направлении.</p> <p>В показанной ситуации водитель двигается по участку дороги с односторонним движением, и для поворота налево он занял крайнее левое положение.</p>","image":"assets/adrive-questions/q100903001.jpg"},{"id":100903002,"themeId":4,"group":1009030,"chapter":9,"chapters":[9],"q":"Разрешается ли Вам при включении разрешающего сигнала светофора совершить поворот налево в показанной ситуации из занимаемой полосы движения?","a":["Да, разрешается.","Нет, не разрешается."],"c":1,"e":"<p>Согласно Правилам дорожного движения, перед разворотом, поворотом налево или направо водитель обязан, не создавая препятствия и опасности для движения других участников дорожного движения, занять соответствующее крайнее положение на проезжей части дороги, предназначенной для движения в данном направлении.</p> <p>В показанной ситуации Вы двигаетесь по участку дороги с односторонним движением, и для поворота налево Вам необходимо было занять крайнее левое положение.</p>","image":"assets/adrive-questions/q100903002.jpg"},{"id":100903003,"themeId":4,"group":1009030,"chapter":9,"chapters":[9],"q":"В каких направлениях Вам разрешено продолжить движение в показанной ситуации?","a":["Только прямо.","Прямо или направо.","Налево и на разворот.","Прямо, налево и на разворот.","Во всех направлениях."],"c":0,"e":"<p>В показанной ситуации регулировщик, осуществляющий регулирование дорожного движения на перекрёстке, обращён к Вам боком, и его руки опущены. При таком сигнале регулировщика Вам разрешено движение прямо и направо.<br> Но, учитывая тот факт, что Вы находитесь на второй полосе на дороге с двумя полосами движения в попутном направлении, Вам разрешено движение только прямо.</p>","image":"assets/adrive-questions/q100903003.jpg"},{"id":100903004,"themeId":4,"group":1009030,"chapter":9,"chapters":[9],"q":"В каких направлениях Вам, управляя легковым автомобилем, разрешено продолжить движение из занимаемой полосы движения?","a":["Только налево.","Только направо.","Направо или налево."],"c":0,"e":"<p>Находясь в крайней левой полосе движения, Вы можете продолжить движение на показанном перекрёстке только налево.</p> <p>Поворот направо должен осуществляться из крайней правой полосы движения.</p>","image":"assets/adrive-questions/q100903004.jpg"},{"id":100903101,"themeId":4,"group":1009031,"chapter":9,"chapters":[9],"q":"По какой траектории водитель красного автомобиля выполнит разворот в соответствии с Правилами дорожного движения?","a":["По траектории «А».","По траектории «Б».","По любой траектории из показанных."],"c":1,"e":"<p>Согласно Правилам дорожного движения, при наличии трамвайных путей попутного направления, расположенных слева на одном уровне с проезжей частью дороги, поворот налево или разворот должен выполняться с этих путей, если дорожными знаками 5.8.1 «Направления движения по полосам» , 5.8.2 «Направление движения по полосе» не предписан иной порядок движения.</p> <p>Так как в показанной ситуации перед перекрёстком отсутствуют перечисленные дорожные знаки, то выполнить разворот разрешено только с трамвайных путей попутного направления.</p>","image":"assets/adrive-questions/q100903101.jpg"},{"id":100903102,"themeId":4,"group":1009031,"chapter":9,"chapters":[9],"q":"Нарушит ли Правила дорожного движения водитель красного автомобиля, выполнив поворот налево по траектории, показанной на рисунке (при отсутствии попутных трамваев)?","a":["Да, нарушит.","Нет, не нарушит."],"c":0,"e":"<p>Согласно Правилам дорожного движения, при наличии трамвайных путей попутного направления, расположенных слева на одном уровне с проезжей частью дороги, поворот налево или разворот должен выполняться с этих путей, если дорожными знаками 5.8.1 «Направления движения по полосам» , 5.8.2 «Направление движения по полосе» не предписан иной порядок движения.</p> <p>Так как в показанной ситуации перед перекрёстком отсутствуют перечисленные дорожные знаки, то выполнить разворот разрешено только с трамвайных путей попутного направления.</p>","image":"assets/adrive-questions/q100903102.jpg"},{"id":100903201,"themeId":4,"group":1009032,"chapter":9,"chapters":[9],"q":"По какой траектории водитель красного автомобиля выполнит разворот в соответствии с Правилами дорожного движения?","a":["По траектории «А».","По траектории «Б».","По любой траектории из показанных."],"c":0,"e":"<p>Согласно Правилам дорожного движения, при наличии трамвайных путей попутного направления, расположенных слева на одном уровне с проезжей частью дороги, поворот налево или разворот должен выполняться с этих путей, если дорожными знаками 5.8.1 «Направления движения по полосам» , 5.8.2 «Направление движения по полосе» не предписан иной порядок движения.</p> <p>Так как в показанной ситуации перед перекрёстком установлен дорожный знак 5.8.1 «Направления движения по полосам» , который информирует водителя о разрешённых направлениях движения по полосам, выполнить разворот разрешено только с крайней левой полосы движения.</p>","image":"assets/adrive-questions/q100903201.jpg"},{"id":100903202,"themeId":4,"group":1009032,"chapter":9,"chapters":[9],"q":"Нарушит ли Правила дорожного движения водитель жёлтого автомобиля, выполнив поворот налево по траектории, показанной на рисунке?","a":["Да, нарушит.","Нет, не нарушит."],"c":1,"e":"<p>Согласно Правилам дорожного движения, при наличии трамвайных путей попутного направления, расположенных слева на одном уровне с проезжей частью дороги, поворот налево или разворот должен выполняться с этих путей, если дорожными знаками 5.8.1 «Направления движения по полосам» , 5.8.2 «Направление движения по полосе» не предписан иной порядок движения.</p> <p>Так как в показанной ситуации перед перекрёстком установлен дорожный знак 5.8.1 «Направления движения по полосам» , который информирует водителя о разрешённых направлениях движения по полосам, выполнить поворот налево разрешено только с крайней левой полосы движения.</p>","image":"assets/adrive-questions/q100903202.jpg"},{"id":100903301,"themeId":4,"group":1009033,"chapter":9,"chapters":[9],"q":"Каким образом водитель жёлтого автомобиля должен выполнить поворот налево в показанной ситуации?","a":["С крайней левой полосы, уступив дорогу встречному трамваю и грузовому автомобилю.","С трамвайных путей попутного направления, уступив дорогу встречному трамваю и грузовому автомобилю.","С крайней левой полосы, уступив дорогу встречному трамваю, грузовому автомобилю, а также предоставив преимущество пешеходам, переходящим дорогу по пешеходному переходу.","С трамвайных путей попутного направления, уступив дорогу встречному трамваю и грузовому автомобилю, а также предоставив преимущество пешеходам, переходящим дорогу по пешеходному переходу."],"c":2,"e":"<p>При наличии трамвайных путей попутного направления, расположенных слева на одном уровне с проезжей частью дороги, поворот налево или разворот должен выполняться с этих путей, если дорожными знаками 5.8.1 «Направления движения по полосам» , 5.8.2 «Направление движения по полосе» не предписан иной порядок движения.</p> <p>Так как в показанной ситуации перед перекрёстком установлены дорожные знаки 5.8.2 «Направление движения по полосе» , которые информируют водителя о разрешённых направлениях движения по полосам, выполнить поворот налево разрешено только с крайней левой полосы движения.<br> Также необходимо предоставить преимущество пешеходам и уступить дорогу транспортным средствам, двигающимся во встречном направлении на разрешающий сигнал светофора.</p>","image":"assets/adrive-questions/q100903301.jpg"},{"id":100903302,"themeId":4,"group":1009033,"chapter":9,"chapters":[9],"q":"Должен ли водитель синего легкового автомобиля предоставить возможность водителю красного легкового автомобиля освободить трамвайный путь в случае создания препятствия для движения трамвая?","a":["Да, должен.","Нет, так как водитель синего автомобиля осуществляет движение без перестроения."],"c":0,"e":"<p>В случае создания препятствия для движения трамвая трамвайный путь по возможности должен быть освобождён. Водители транспортных средств, движущихся рядом в попутном направлении, должны предоставить возможность для этого.</p>","image":"assets/adrive-questions/q100903302.jpg"},{"id":100903401,"themeId":4,"group":1009034,"chapter":9,"chapters":[9],"q":"Кто из водителей в показанной ситуации выполняет манёвр, нарушая Правила дорожного движения?","a":["Водитель синего автомобиля.","Водитель красного автомобиля.","Водители обоих автомобилей.","Водители обоих автомобилей не нарушают Правила дорожного движения."],"c":2,"e":"<p>В показанной ситуации ввиду противоречия требований установленных дорожных знаков водители должны руководствоваться временным (установленным на проезжей части дороги) дорожным знаком 3.18.2 «Поворот налево запрещён» , который запрещает поворот налево из любой полосы движения.</p>","image":"assets/adrive-questions/q100903401.jpg"},{"id":100903402,"themeId":4,"group":1009034,"chapter":9,"chapters":[9],"q":"Кто из водителей в показанной ситуации выполняет манёвр, не нарушая Правила дорожного движения?","a":["Водитель синего автомобиля.","Водитель красного автомобиля.","Водители обоих автомобилей.","Водители обоих автомобилей нарушают Правила дорожного движения."],"c":0,"e":"<p>В показанной ситуации ввиду противоречия требований установленных дорожных знаков водители должны руководствоваться временным (установленным на проезжей части дороги) дорожным знаком 3.18.2 «Поворот налево запрещён» , который разрешает разворот, но запрещает поворот налево.</p>","image":"assets/adrive-questions/q100903402.jpg"},{"id":100903501,"themeId":4,"group":1009035,"chapter":9,"chapters":[9],"q":"Каким образом водитель зелёного автомобиля должен выполнить поворот направо в показанной ситуации?","a":["По траектории «Б».","По траектории «А», предоставив преимущество пешеходу.","По любой из указанных траекторий."],"c":1,"e":"<p>Поворот направо должен выполняться по траектории, наиболее приближенной к правому краю проезжей части дороги, чтобы исключить возможность движения (проезда) одноколейных транспортных средств справа, например мотоцикла без бокового прицепа, мопеда, велосипеда. При этом уменьшается вероятность создания препятствия для движения транспортным средствам, движущимся с других направлений.</p> <p>Также, в показанной ситуации, необходимо предоставить преимущество пешеходу, переходящему проезжую часть на разрешающий сигнал светофора.</p>","image":"assets/adrive-questions/q100903501.jpg"},{"id":100903502,"themeId":4,"group":1009035,"chapter":9,"chapters":[9],"q":"Каким образом водитель зелёного автомобиля должен выполнить поворот направо в показанной ситуации?","a":["По траектории «Б».","По траектории «А», предоставив преимущество пешеходу.","По любой из указанных траекторий поворот направо запрещён."],"c":2,"e":"<p>В показанной ситуации перед перекрёстком установлен дорожный знак 4.1.1 «Движение прямо» , который разрешает движение только прямо.</p>","image":"assets/adrive-questions/q100903502.jpg"},{"id":100903601,"themeId":4,"group":1009036,"chapter":9,"chapters":[9],"q":"Кто в показанной обстановке обязан уступить дорогу?","a":["Водитель легкового автомобиля.","Водитель грузового автомобиля, выполняющий разворот."],"c":1,"e":"<p>Согласно Правилам дорожного движения, перед разворотом вне перекрёстка водитель транспортного средства обязан уступить дорогу встречным транспортным средствам.<br> Поэтому водитель грузового автомобиля обязан уступить дорогу легковому автомобилю, движущемуся во встречном направлении.</p>","image":"assets/adrive-questions/q100903601.jpg"},{"id":100903602,"themeId":4,"group":1009036,"chapter":9,"chapters":[9],"q":"Кому в показанной обстановке обязан уступить дорогу водитель синего легкового автомобиля при выполнении разворота?","a":["Грузовому автомобилю.","Трамваю попутного направления.","Обоим транспортным средствам."],"c":2,"e":"<p>Согласно Правилам дорожного движения, перед разворотом вне перекрёстка водитель транспортного средства обязан уступить дорогу встречным транспортным средствам и попутному трамваю.</p> <p>В показанной ситуации водитель легкового автомобиля должен уступить дорогу грузовому автомобиля, движущемуся во встречном направлении, и попутному трамваю.</p>","image":"assets/adrive-questions/q100903602.jpg"},{"id":100903701,"themeId":4,"group":1009037,"chapter":9,"chapters":[9],"q":"Разрешается ли водителю синего автомобиля выполнить поворот направо так, как показано на рисунке?","a":["Да, разрешается.","Нет, не разрешается."],"c":0,"e":"<p>Согласно Правилам дорожного движения, если транспортное средство из-за своих габаритов либо по другим причинам не может выполнить разворот, поворот налево или направо с соблюдением требований пунктов 63, 65 Правил, допускается производить его с отступлением от этих требований, если это не создаст препятствия для движения других участников дорожного движения.</p> <p>В показанной ситуации водитель красного автомобиля совершил вынужденную остановку, препятствующую другим участникам дорожного движения совершить поворот направо из крайней правой полосы. Поэтому синему автомобилю разрешено выполнить поворот направо из занимаемой полосы при соблюдении необходимых мер безопасности.</p>","image":"assets/adrive-questions/q100903701.jpg"},{"id":100903702,"themeId":4,"group":1009037,"chapter":9,"chapters":[9],"q":"Разрешается ли водителю синего автомобиля выполнить поворот налево так, как показано на рисунке?","a":["Да, разрешается.","Нет, не разрешается."],"c":0,"e":"<p>Согласно Правилам дорожного движения, если транспортное средство из-за своих габаритов либо по другим причинам не может выполнить разворот, поворот налево или направо с соблюдением требований пунктов 63, 65 Правил, допускается производить его с отступлением от этих требований, если это не создаст препятствия для движения других участников дорожного движения.</p> <p>В показанной ситуации водитель красного автомобиля совершил вынужденную остановку, препятствующую другим участникам дорожного движения совершить поворот налево из крайней левой полосы. Поэтому синему автомобилю разрешено выполнить поворот налево из занимаемой полосы при соблюдении необходимых мер безопасности.</p>","image":"assets/adrive-questions/q100903702.jpg"},{"id":100903853,"themeId":4,"group":1009038,"chapter":9,"chapters":[9],"q":"Вы начинаете движение одновременно с белым автомобилем напротив, выезжая налево с места стоянки. Обязаны ли Вы уступить дорогу в показанной ситуации?","a":["Обязаны.","Не обязаны."],"c":0,"e":"<p>В данной ситуации траектории движения транспортных средств пересекаются, а очерёдность проезда не оговорена, поэтому <strong>дорогу обязаны уступить Вы</strong>, так как белый автомобиль приближается справа.</p>","image":"assets/adrive-questions/q100903853.jpg"},{"id":100903855,"themeId":4,"group":1009038,"chapter":9,"chapters":[9],"q":"Кто из водителей, двигаясь по прилегающей территории, в показанной ситуации обязан уступить дорогу?","a":["Водитель красного автомобиля.","Водитель жёлтого автомобиля."],"c":1,"e":"<p>В случаях, когда траектории движения транспортных средств пересекаются, а очерёдность проезда не оговорена Правилами дорожного движения (как в показанной ситуации), дорогу обязан уступить водитель, к которому транспортное средство приближается справа, то есть водитель жёлтого автомобиля.</p>","image":"assets/adrive-questions/q100903855.jpg"},{"id":100903872,"themeId":4,"group":1009038,"chapter":9,"chapters":[9],"q":"Водители белого и красного автомобилей одновременно начинают движение. Кто в показанной ситуации обязан уступить дорогу?","a":["Водитель белого автомобиля.","Водитель красного автомобиля."],"c":1,"e":"<p>После остановки или стоянки водитель транспортного средства, начинающего движение, обязан уступить дорогу движущимся транспортным средствам, однако в данной ситуации оба водителя начинают движение одновременно.</p> <p>В случае, когда траектории движения транспортных средств пересекаются, а очерёдность проезда не оговорена Правилами дорожного движения, дорогу обязан уступить водитель, к которому транспортное средство приближается справа.</p>","image":"assets/adrive-questions/q100903872.jpg"},{"id":100903873,"themeId":4,"group":1009038,"chapter":9,"chapters":[9],"q":"Водитель красного автомобиля поворачивает налево, двигаясь по прилегающей территории. Обязан ли он уступить дорогу водителю белого автомобиля, начинающему движение после стоянки?","a":["Да, обязан.","Нет, не обязан."],"c":1,"e":"<p>После остановки или стоянки водитель транспортного средства, начинающего движение, обязан уступить дорогу движущимся транспортным средствам, в том числе движущимся по прилегающей территории.</p> <p>Поэтому в показанной ситуации уступить дорогу обязан водитель белого автомобиля.</p>","image":"assets/adrive-questions/q100903873.jpg"},{"id":100903901,"themeId":4,"group":1009039,"chapter":9,"chapters":[9],"q":"Как в соответствии с Правилами дорожного движения водитель зелёного автомобиля должен осуществить поворот направо?","a":["Снизить скорость, повернуть направо с занимаемой полосы.","Снизить скорость, перестроиться на полосу торможения, повернуть направо.","Перестроиться на полосу торможения, снизить скорость, повернуть направо."],"c":2,"e":"<p>Согласно Правилам дорожного движения, при наличии полосы торможения водитель, намеревающийся повернуть, должен своевременно перестроиться на эту полосу и снижать скорость движения только на ней. Основная задача полосы торможения — создать на проезжей части условия (полосу движения), при которых ТС может снизить свою скорость на этой полосе, не создавая при этом препятствия для движения ТС, движущихся без изменения направления движения.</p>","image":"assets/adrive-questions/q100903901.jpg"},{"id":100903902,"themeId":4,"group":1009039,"chapter":9,"chapters":[9],"q":"Как в соответствии с Правилами дорожного движения водитель зелёного автомобиля должен осуществить поворот налево?","a":["Снизить скорость, повернуть налево с занимаемой полосы.","Снизить скорость, перестроиться на полосу торможения, повернуть налево.","Перестроиться на полосу торможения, снизить скорость, повернуть налево."],"c":2,"e":"<p>Согласно Правилам дорожного движения, при наличии полосы торможения водитель, намеревающийся повернуть, должен своевременно перестроиться на эту полосу и снижать скорость движения только на ней. Основная задача полосы торможения — создать на проезжей части условия (полосу движения), при которых ТС может снизить свою скорость на этой полосе, не создавая при этом препятствия для движения ТС, движущихся без изменения направления движения.</p>","image":"assets/adrive-questions/q100903902.jpg"},{"id":100904001,"themeId":4,"group":1009040,"chapter":9,"chapters":[9],"q":"В каком из перечисленных мест в соответствии с Правилами дорожного движения запрещается выполнить разворот?","a":["На дорогах с трамвайными путями посередине.","На перекрёстке, находясь на второстепенной дороге.","На расстоянии 10 метров за пешеходным переходом.","На расстоянии 10 метров за остановочным пунктом маршрутных транспортных средств."],"c":2,"e":"<p>Разворот запрещается:</p> <ul> <li>на пешеходных переходах, велосипедных переездах и ближе 15 метров от них с обеих сторон, кроме случая разрешённого разворота на перекрёстке;</li> <li>в местах, где видимость дороги хотя бы в одном направлении движения менее 100 метров;</li> <li>на остановочных пунктах маршрутных транспортных средств;</li> <li>на путепроводах и под ними;</li> <li>на железнодорожных переездах.</li></ul> <p>Разворот на пешеходном переходе создаёт препятствие для движения пешеходов и ограничивает обзорность его отдельных участков, по которым могут двигаться пешеходы. Выделение 15-метровой зоны по обе стороны пешеходного перехода вызвано необходимостью обеспечения безопасности пешеходов. Это достигается за счёт увеличения обзорности участка дороги, на котором находится пешеходный переход, для других водителей транспортных средств.</p>","image":null},{"id":100904002,"themeId":4,"group":1009040,"chapter":9,"chapters":[9],"q":"В каком из перечисленных мест в соответствии с Правилами дорожного движения запрещается выполнить разворот?","a":["На расстоянии 10 метров за обозначенным перекрёстком.","На расстоянии 10 метров перед железнодорожным переездом.","В месте, где видимость дороги в направлении движения составляет 80 метров.","Во всех перечисленных местах."],"c":2,"e":"<p>Разворот запрещается:</p> <ul><li>на пешеходных переходах и ближе 15 метров от них с обеих сторон, кроме случая разрешённого разворота на перекрёстке;</li> <li>в местах, где видимость дороги хотя бы в одном направлении движения менее 100 метров;</li> <li>на остановочных пунктах маршрутных транспортных средств;</li> <li>на путепроводах и под ними;</li> <li>на железнодорожных переездах.</li></ul> <p>Если видимость дороги хотя бы в одном направлении менее 100 метров, то водитель, который движется попутно или навстречу ТС, выполняющему разворот, не всегда может правильно сориентироваться при управлении, выбрать безопасную скорость и обеспечить безопасность движения.</p>","image":null},{"id":100904101,"themeId":4,"group":1009041,"chapter":9,"chapters":[9],"q":"В каком из перечисленных мест в соответствии с Правилами дорожного движения запрещается выполнить разворот?","a":["Ближе 15 метров от путепровода.","Ближе 15 метров от остановочного пункта маршрутных транспортных средств.","Ближе 15 метров от пешеходного перехода, кроме случая разрешённого разворота на перекрёстке.","Во всех перечисленных местах."],"c":2,"e":"<p>Разворот запрещается:</p> <ul> <li>на пешеходных переходах, велосипедных переездах и ближе 15 метров от них с обеих сторон, кроме случая разрешённого разворота на перекрёстке;</li> <li>в местах, где видимость дороги хотя бы в одном направлении движения менее 100 метров;</li> <li>на остановочных пунктах маршрутных транспортных средств;</li> <li>на путепроводах и под ними;</li> <li>на железнодорожных переездах.</li></ul> <p>Разворот на пешеходном переходе создаёт препятствие для движения пешеходов и ограничивает обзорность его отдельных участков, по которым могут двигаться пешеходы. Выделение 15-метровой зоны по обе стороны пешеходного перехода вызвано необходимостью обеспечения безопасности пешеходов. Это достигается за счёт увеличения обзорности участка дороги, на котором находится пешеходный переход, для других водителей транспортных средств.</p>","image":null},{"id":100904102,"themeId":4,"group":1009041,"chapter":9,"chapters":[9],"q":"В каком из перечисленных мест в соответствии с Правилами дорожного движения запрещается выполнить разворот?","a":["Под путепроводом.","Напротив выезда с прилегающей территории.","На подъёме в месте, где видимость дороги в обоих направлениях движения не менее 100 метров.","Во всех перечисленных местах."],"c":0,"e":"<p>Разворот запрещается:</p> <ul> <li>на пешеходных переходах, велосипедных переездах и ближе 15 метров от них с обеих сторон, кроме случая разрешённого разворота на перекрёстке;</li> <li>в местах, где видимость дороги хотя бы в одном направлении движения менее 100 метров;</li> <li>на остановочных пунктах маршрутных транспортных средств;</li> <li>на путепроводах и под ними;</li> <li>на железнодорожных переездах.</li></ul> <p>Сами конструкции таких инженерных сооружений, как путепроводы, выполнены таким образом, что представляют собой участок дороги со стеснёнными условиями для движения. Стеснённые условия для движения не всегда связаны с изменением числа полос или изменением их ширины. В большей степени это обусловлено особенностями самой конструкции сооружения (наличие высоких бордюров, колонн и др.). В таких условиях разворачивающееся транспортное средство имеет очень большую вероятность стать препятствием для дорожного движения.</p>","image":null},{"id":100904201,"themeId":4,"group":1009042,"chapter":9,"chapters":[9],"q":"Разрешается ли водителю красного автомобиля выполнить разворот в показанном месте?","a":["Да, разрешается.","Нет, не разрешается."],"c":0,"e":"<p>Согласно Правилам дорожного движения, разворот запрещён на железнодорожном переезде. В показанной ситуации водитель совершает разворот до границы железнодорожного переезда, поэтому такой манёвр разрешён.</p>","image":"assets/adrive-questions/q100904201.jpg"},{"id":100904202,"themeId":4,"group":1009042,"chapter":9,"chapters":[9],"q":"Разрешается ли водителю красного автомобиля выполнить разворот в показанном месте, если видимость дороги в обоих направлениях составляет не менее 100 метров?","a":["Да, разрешается.","Нет, не разрешается."],"c":0,"e":"<p>В показанной ситуации установлен дорожный знак 3.20.1 «Обгон запрещён» , который информирует водителей о начале участка дороги, где запрещён обгон. Знак не запрещает разворот. Так как видимость дороги в обоих направлениях составляет не менее 100 метров, то в показанном месте разворот будет разрешён.</p>","image":"assets/adrive-questions/q100904202.jpg"},{"id":100904301,"themeId":4,"group":1009043,"chapter":9,"chapters":[9],"q":"Разрешается ли водителю жёлтого автомобиля выполнить разворот в показанном месте?","a":["Нет, не разрешается.","Разрешается, если видимость дороги в обоих направлениях движения не менее 100 метров."],"c":1,"e":"<p>В показанной ситуации на участке дороги установлен дорожный знак 1.15 «Скользкая дорога» , который предупреждает о возможной повышенной скользкости по сравнению с предшествующим участком. Знак не запрещает разворот. Если видимость дороги составляет не менее 100 метров, то в показанном месте разворот будет разрешён.</p>","image":"assets/adrive-questions/q100904301.jpg"},{"id":100904302,"themeId":4,"group":1009043,"chapter":9,"chapters":[9],"q":"Разрешается ли Вам, управляя легковым автомобилем, выполнить разворот в показанном месте?","a":["Нет, не разрешается.","Разрешается, если видимость в направлении движения не менее 100 метров."],"c":0,"e":"<p>В показанной ситуации на дороге организованно одностороннее движение, так как установлен дорожный знак 1.19.1 «Двустороннее движение» , который предупреждает водителей о начале участка дороги со встречным движением после участка дороги с односторонним движением (в населённом пункте участок с двусторонним движением начнется через 50–100 метров, вне населённого пункта — через 150–300 метров). Таким образом, если водитель выполнит разворот в показанной обстановке, то он будет двигаться навстречу основному потоку ТС, что является нарушением Правил дорожного движения.</p>","image":"assets/adrive-questions/q100904302.jpg"},{"id":100904401,"themeId":4,"group":1009044,"chapter":9,"chapters":[9],"q":"В каком из перечисленных ответов наиболее полно перечислены места, в которых запрещён разворот?","a":["Только на пешеходных переходах.","На пешеходных переходах и ближе 15 метров перед ними, кроме случая разрешённого разворота на перекрёстке.","На пешеходных переходах и ближе 15 метров после них, кроме случая разрешённого разворота на перекрёстке.","На пешеходных переходах и ближе 15 метров от них с обеих сторон, кроме случая разрешённого разворота на перекрёстке."],"c":3,"e":"<p>Разворот запрещается:</p> <ul> <li>на пешеходных переходах, велосипедных переездах и ближе 15 метров от них с обеих сторон, кроме случая разрешённого разворота на перекрёстке;</li> <li>в местах, где видимость дороги хотя бы в одном направлении движения менее 100 метров;</li> <li>на остановочных пунктах маршрутных транспортных средств;</li> <li>на путепроводах и под ними;</li> <li>на железнодорожных переездах.</li></ul> <p>Разворот на пешеходном переходе создаёт препятствие для движения пешеходов и ограничивает обзорность его отдельных участков, по которым могут двигаться пешеходы. Выделение 15-метровой зоны по обе стороны пешеходного перехода вызвано необходимостью обеспечения безопасности пешеходов. Это достигается за счёт увеличения обзорности участка дороги, на котором находится пешеходный переход, для других водителей транспортных средств.</p>","image":null},{"id":100904402,"themeId":4,"group":1009044,"chapter":9,"chapters":[9],"q":"В соответствии с Правилами дорожного движения разворот запрещён:","a":["Только на остановочных пунктах маршрутных транспортных средств.","На остановочных пунктах маршрутных транспортных средств и ближе 15 метров перед ними.","На остановочных пунктах маршрутных транспортных средств и ближе 15 метров после них.","На остановочных пунктах маршрутных транспортных средств и ближе 15 метров от них с обеих сторон."],"c":0,"e":"<p>Разворот запрещается:</p> <ul> <li>на пешеходных переходах, велосипедных переездах и ближе 15 метров от них с обеих сторон, кроме случая разрешённого разворота на перекрёстке;</li> <li>в местах, где видимость дороги хотя бы в одном направлении движения менее 100 метров;</li> <li>на остановочных пунктах маршрутных транспортных средств;</li> <li>на путепроводах и под ними;</li> <li>на железнодорожных переездах.</li></ul> <p>При выполнении разворота в местах расположения остановочных пунктов маршрутных транспортных средств опасность для движения заключается в том, что велика вероятность появления на проезжей части пешеходов, идущих к остановившемуся маршрутному ТС или (и) от него. При остановке маршрутного ТС в первой полосе движения разворот пришлось бы выполнять в крайне стеснённых условиях при наличии препятствия для дорожного движения на проезжей части.</p>","image":null},{"id":100904501,"themeId":4,"group":1009045,"chapter":9,"chapters":[9],"q":"Нарушит ли Правила дорожного движения водитель жёлтого автомобиля, выполнив разворот по траектории, показанной на рисунке?","a":["Да, нарушит.","Нет, не нарушит."],"c":1,"e":"<p>Разворот запрещается:</p> <ul> <li>на пешеходных переходах, велосипедных переездах и ближе 15 метров от них с обеих сторон, кроме случая разрешённого разворота на перекрёстке;</li> <li>в местах, где видимость дороги хотя бы в одном направлении движения менее 100 метров;</li> <li>на остановочных пунктах маршрутных транспортных средств;</li> <li>на путепроводах и под ними;</li> <li>на железнодорожных переездах.</li></ul> <p>В показанной ситуации перед водителем перекрёсток, на котором разворот разрешён, поэтому водитель не нарушает Правила.</p>","image":"assets/adrive-questions/q100904501.jpg"},{"id":100904502,"themeId":4,"group":1009045,"chapter":9,"chapters":[9],"q":"Нарушит ли Правила дорожного движения водитель жёлтого автомобиля, выполнив разворот по траектории, показанной на рисунке?","a":["Да, нарушит.","Нет, не нарушит."],"c":0,"e":"<p>В показанной ситуации перед перекрёстком установлен дорожный знак 5.6 «Конец дороги с односторонним движением» , который информирует водителей об окончании дороги с односторонним движением. Таким образом, если водитель выполнит разворот в показанной обстановке, то он будет двигаться навстречу основному потоку ТС, что является нарушением Правил дорожного движения.</p>","image":"assets/adrive-questions/q100904502.jpg"},{"id":100904602,"themeId":4,"group":1009046,"chapter":9,"chapters":[9],"q":"Нарушит ли Правила дорожного движения водитель жёлтого автомобиля, выполнив разворот по траектории, показанной на рисунке?","a":["Да, нарушит.","Нет, не нарушит."],"c":1,"e":"<p>Согласно Правилам дорожного движения, разворот запрещается:</p> <ul> <li><strong>на пешеходных переходах, велосипедных переездах</strong> и ближе 15 метров от них с обеих сторон, кроме случая разрешённого разворота на перекрёстке;</li> <li>в местах, где видимость дороги хотя бы в одном направлении движения менее 100 метров;</li> <li>на остановочных пунктах маршрутных транспортных средств;</li> <li>на путепроводах и под ними;</li> <li>на железнодорожных переездах.</li></ul> <p>Показанный участок дороги не является ни одним из перечисленных, поэтому на этом участке дороги разворот разрешён.</p>","image":"assets/adrive-questions/q100904602.jpg"},{"id":100904603,"themeId":4,"group":1009046,"chapter":9,"chapters":[9],"q":"Разрешено ли водителю синего легкового автомобиля выполнить разворот по траектории, показанной на рисунке, если ширина проезжей части дороги недостаточна для его выполнения из крайнего левого положения?","a":["Нет, запрещено.","Разрешено, уступив дорогу попутным и встречным транспортным средствам."],"c":1,"e":"<p>Если для разворота вне перекрёстка ширина проезжей части дороги недостаточна для его выполнения из крайнего левого положения, разворот допускается производить от правого края проезжей части дороги или с правой по ходу движения обочины. При этом водитель должен уступить дорогу попутным и встречным транспортным средствам.</p>","image":"assets/adrive-questions/q100904603.jpg"},{"id":100904701,"themeId":4,"group":1009047,"chapter":9,"chapters":[9],"q":"Разрешается ли водителю красного автомобиля выполнить разворот в показанном на рисунке месте?","a":["Запрещается.","Разрешается, если видимость в обоих направлениях составляет не менее 100 метров."],"c":1,"e":"<p>Разворот запрещается:</p> <ul> <li>на пешеходных переходах, велосипедных переездах и ближе 15 метров от них с обеих сторон, кроме случая разрешённого разворота на перекрёстке;</li> <li>в местах, где видимость дороги хотя бы в одном направлении движения менее 100 метров;</li> <li>на остановочных пунктах маршрутных транспортных средств;</li> <li>на путепроводах и под ними;</li> <li>на железнодорожных переездах.</li></ul> <p>Установленный дорожный знак 5.15 «Место стоянки» информирует водителей о специальной площадке для остановки и стоянки транспортных средств и разворот не запрещает.</p>","image":"assets/adrive-questions/q100904701.jpg"},{"id":100904761,"themeId":4,"group":1009047,"chapter":9,"chapters":[9],"q":"Разрешено ли Вам выполнить разворот на показанном участке дороги?","a":["Разрешено.","Запрещено.","Разрешено только при видимости дороги не менее 100 метров в обоих направлениях."],"c":2,"e":"<p>В плохих погодных условиях следует учитывать, что при выполнении разворота видимость в обоих направлениях должна составлять <strong>не менее 100 метров</strong>.</p>","image":"assets/adrive-questions/q100904761.jpg"},{"id":100904801,"themeId":4,"group":1009048,"chapter":9,"chapters":[9],"q":"Разрешено ли Вам, управляя легковым автомобилем, выполнить разворот в показанном месте?","a":["Да, разрешено.","Нет, не разрешено."],"c":1,"e":"<p>Разворот запрещён на остановочных пунктах маршрутных транспортных средств.</p>","image":"assets/adrive-questions/q100904801.jpg"},{"id":100904802,"themeId":4,"group":1009048,"chapter":9,"chapters":[9],"q":"Разрешается ли водителю белого автомобиля развернуться после посадки пассажира в показанной ситуации?","a":["Да, разрешается, не создавая помех для движения маршрутных транспортных средств.","Нет, не разрешается."],"c":1,"e":"<p>Разворот запрещён на остановочных пунктах маршрутных транспортных средств.</p>","image":"assets/adrive-questions/q100904802.jpg"},{"id":100904901,"themeId":4,"group":1009049,"chapter":9,"chapters":[9],"q":"В каком из перечисленных мест разрешается выполнить разворот?","a":["На путепроводах.","Под путепроводами.","Под высоковольтными линиями электропередачи.","На остановочных пунктах маршрутных транспортных средств."],"c":2,"e":"<p>Разворот запрещается:</p> <ul> <li>на пешеходных переходах, велосипедных переездах и ближе 15 метров от них с обеих сторон, кроме случая разрешённого разворота на перекрёстке;</li> <li>в местах, где видимость дороги хотя бы в одном направлении движения менее 100 метров;</li> <li>на остановочных пунктах маршрутных транспортных средств;</li> <li>на путепроводах и под ними;</li> <li>на железнодорожных переездах.</li></ul> <p>Поэтому выполнить разворот под высоковольтными линиями электропередачи не запрещается.</p>","image":null},{"id":100904902,"themeId":4,"group":1009049,"chapter":9,"chapters":[9],"q":"В каком из перечисленных мест разрешается выполнить разворот?","a":["На обозначенных перекрёстках.","На нерегулируемых перекрёстках.","На перекрёстках, где главная дорога меняет направление.","Во всех перечисленных местах."],"c":3,"e":"<p>Согласно Правилам дорожного движения, разворот запрещается:</p> <ul> <li>на пешеходных переходах, велосипедных переездах и ближе 15 метров от них с обеих сторон, кроме случая разрешённого разворота на перекрёстке;</li> <li>в местах, где видимость дороги хотя бы в одном направлении движения менее 100 метров;</li> <li>на остановочных пунктах маршрутных транспортных средств;</li> <li>на путепроводах и под ними;</li> <li>на железнодорожных переездах.</li></ul> <p>В предложенных ответах ни один из вышеперечисленных пунктов не выполняется, поэтому на этих участках дороги разворот разрешён.</p>","image":null},{"id":100904933,"themeId":4,"group":1009049,"chapter":9,"chapters":[9],"q":"Разрешено ли водителю красного легкового автомобиля выполнить разворот на показанном перекрёстке?","a":["Да, разрешено.","Нет, запрещено."],"c":0,"e":"<p>Показанная ситуация не соответствует ни одному из случаев запрещения разворота, описанных в Правилах дорожного движения.</p> <p>Дорожный знак 5.8.7 «Направление движения по полосам» не запрещает разворот, если данный манёвр не запрещён другими техническими средствами организации дорожного движения (в том числе дорожной разметкой).</p>","image":"assets/adrive-questions/q100904933.jpg"},{"id":100905001,"themeId":4,"group":1009050,"chapter":9,"chapters":[9],"q":"На каком расстоянии от путепроводов запрещён разворот?","a":["Ближе 15 метров от них с обеих сторон.","Ближе 50 метров от них с обеих сторон.","Ближе 100 метров от них с обеих сторон.","Разворот запрещён только на путепроводах и под ними."],"c":3,"e":"<p>Разворот запрещён непосредственно на путепроводах и под ними. Сами конструкции таких инженерных сооружений, как путепроводы, выполнены таким образом, что представляют собой участок дороги со стеснёнными условиями для движения. Стеснённые условия для движения не всегда связаны с изменением числа полос или изменением их ширины. В большей степени это обусловлено особенностями самой конструкции сооружения (наличие высоких бордюров, колонн и др.). В таких условиях разворачивающееся транспортное средство имеет очень большую вероятность стать препятствием для дорожного движения.</p>","image":null},{"id":100905002,"themeId":4,"group":1009050,"chapter":9,"chapters":[9],"q":"На каком расстоянии от остановочных пунктов маршрутных транспортных средств запрещён разворот?","a":["Ближе 15 метров от них с обеих сторон.","Ближе 50 метров от них с обеих сторон.","Ближе 100 метров от них с обеих сторон.","Разворот запрещён только на остановочных пунктах маршрутных транспортных средств."],"c":3,"e":"<p>Согласно Правилам дорожного движения, разворот запрещён непосредственно на остановочных пунктах маршрутных транспортных средств. При выполнении разворота в местах расположения остановочных пунктов маршрутных ТС опасность для движения заключается в том, что: велика вероятность появления на проезжей части пешеходов, идущих к остановившемуся маршрутному ТС или (и) от него; при остановке маршрутного ТС в первой полосе движения разворот пришлось бы выполнять в крайне стеснённых условиях при наличии препятствия для дорожного движения на проезжей части.</p>","image":null},{"id":100905102,"themeId":4,"group":1009051,"chapter":9,"chapters":[9],"q":"Разрешается Вам выполнить разворот через прерывистую линию горизонтальной дорожной разметки, не доезжая до путепровода?","a":["Разрешается независимо от расстояния.","Разрешается только на расстоянии не менее 15 метров до путепровода."],"c":0,"e":"<p>Разворот запрещён непосредственно на путепроводах и под ними. В показанной ситуации разворот совершается, не доезжая до путепровода, поэтому такой манёвр разрешён.</p>","image":"assets/adrive-questions/q100905102.jpg"},{"id":100905201,"themeId":4,"group":1009052,"chapter":9,"chapters":[9],"q":"В каком из перечисленных мест запрещается движение задним ходом?","a":["На железнодорожных переездах.","На путепроводах и под ними.","На остановочных пунктах маршрутных транспортных средств.","На перекрёстках (кроме перекрёстков, расположенных в жилых зонах).","Во всех перечисленных местах."],"c":4,"e":"<p>Движение задним ходом запрещается:</p> <ul> <li>на пешеходных переходах, велосипедных переездах и ближе 15 метров от них с обеих сторон, кроме случая разрешённого разворота на перекрёстке;</li> <li>в местах, где видимость дороги хотя бы в одном направлении движения менее 100 метров;</li> <li>на остановочных пунктах маршрутных транспортных средств;</li> <li>на путепроводах и под ними;</li> <li>на железнодорожных переездах;</li> <li>на перекрёстках (кроме перекрёстков, расположенных в жилых зонах).</li></ul> <p>Таким образом, во всех перечисленных случаях движение задним ходом будет запрещено.</p>","image":null},{"id":100905202,"themeId":4,"group":1009052,"chapter":9,"chapters":[9],"q":"В каком из перечисленных мест запрещается движение задним ходом?","a":["На остановочных пунктах маршрутных транспортных средств.","На пешеходных переходах и ближе 15 метров от них с обеих сторон.","В местах, где видимость дороги хотя бы в одном направлении движения менее 100 метров.","Во всех перечисленных местах."],"c":3,"e":"<p>Согласно Правилам дорожного движения, движение задним ходом запрещается:</p> <ul> <li>на пешеходных переходах, велосипедных переездах и ближе 15 метров от них с обеих сторон, кроме случая разрешённого разворота на перекрёстке;</li> <li>в местах, где видимость дороги хотя бы в одном направлении движения менее 100 метров;</li> <li>на остановочных пунктах маршрутных транспортных средств;</li> <li>на путепроводах и под ними;</li> <li>на железнодорожных переездах;</li> <li>на перекрёстках (кроме перекрёстков, расположенных в жилых зонах).</li></ul> <p>Таким образом, во всех перечисленных случаях движение задним ходом будет запрещено.</p>","image":null},{"id":100905301,"themeId":4,"group":1009053,"chapter":9,"chapters":[9],"q":"Нарушит ли водитель красного автомобиля Правила дорожного движения, выполнив разворот с применением заднего хода в ситуации, показанной на рисунке?","a":["Нарушит.","Не нарушит, если эти действия не создадут препятствия для других участников дорожного движения и будет обеспечена безопасность дорожного движения."],"c":1,"e":"<p>Согласно Правилам дорожного движения, движение задним ходом запрещается на железнодорожных переездах. В показанной ситуации водитель начинает движение задним ходом вне железнодорожного переезда, поэтому такой манёвр будет разрешён при условии, что эти действия не создадут препятствия для других участников дорожного движения и будет обеспечена безопасность дорожного движения. </p>","image":"assets/adrive-questions/q100905301.jpg"},{"id":100905302,"themeId":4,"group":1009053,"chapter":9,"chapters":[9],"q":"Разрешается ли водителю белого автомобиля, «проскочившему» остановочный пункт маршрутных транспортных средств, вернуться за пассажиром, двигаясь задним ходом?","a":["Запрещается.","Разрешается, если эти действия не создадут препятствия для других участников дорожного движения и будет обеспечена безопасность дорожного движения."],"c":0,"e":"<p>Согласно Правилам дорожного движения, движение задним ходом запрещается:</p> <ul> <li>на пешеходных переходах, велосипедных переездах и ближе 15 метров от них с обеих сторон, кроме случая разрешённого разворота на перекрёстке;</li> <li>в местах, где видимость дороги хотя бы в одном направлении движения менее 100 метров;</li> <li>на остановочных пунктах маршрутных транспортных средств;</li> <li>на путепроводах и под ними;</li> <li>на железнодорожных переездах;</li> <li>на перекрёстках (кроме перекрёстков, расположенных в жилых зонах).</li></ul>","image":"assets/adrive-questions/q100905302.jpg"},{"id":100905401,"themeId":4,"group":1009054,"chapter":9,"chapters":[9],"q":"На каких перекрёстках разрешается движение задним ходом при условии, что эти действия не создадут препятствия для других участников дорожного движения и будет обеспечена безопасность дорожного движения?","a":["На перекрёстках, расположенных в жилых зонах.","На перекрёстках, расположенных в пешеходных зонах.","На нерегулируемых перекрёстках при движении по главной дороге.","На регулируемых перекрёстках при разрешающем сигнале светофора.","На всех перечисленных."],"c":0,"e":"<p>Согласно Правилам дорожного движения, движение задним ходом разрешается на перекрёстках, расположенных в жилых зонах, поскольку там, в стеснённых условиях, зачастую нет возможности совершить разворот для движения в обратном направлении.</p>","image":null},{"id":100905501,"themeId":4,"group":1009055,"chapter":9,"chapters":[9],"q":"Разрешается ли в показанной ситуации выполнить разворот с однократным включением задней передачи?","a":["Да, разрешается.","Нет, не разрешается."],"c":0,"e":"<p>В показанной ситуации автомобиль движется в жилой зоне. Согласно Правилам дорожного движения, движение задним ходом разрешается на перекрёстках, расположенных в жилых зонах, потому что на узких проездах этих территорий зачастую нет иной возможности совершить разворот, кроме как на перекрёстке.</p>","image":"assets/adrive-questions/q100905501.jpg"},{"id":100905502,"themeId":4,"group":1009055,"chapter":9,"chapters":[9],"q":"Нарушит ли Правила дорожного движения водитель синего легкового автомобиля, двигаясь задним ходом в случае затруднённого встречного разъезда на дворовой территории, прилегающей к жилой застройке?","a":["Не нарушит.","Нарушит, так как движется задним ходом по перекрёстку.","Нарушит, так как в показанной ситуации он не обязан уступать дорогу."],"c":0,"e":"<p>В показанной ситуации автомобиль движется на дворовой территории, прилегающей к жилой застройке. Согласно термину 2.21 «Жилая зона» дворовую территорию, прилегающую к жилой застройке, следует считать жилой зоной. Движение задним ходом разрешается на перекрёстках, расположенных в жилых зонах, потому что на узких проездах этих территорий зачастую нет иной возможности совершить разворот, кроме как на перекрёстке.</p>","image":"assets/adrive-questions/q100905502.jpg"},{"id":100905601,"themeId":4,"group":1009056,"chapter":9,"chapters":[9],"q":"Нарушит ли Правила дорожного движения водитель красного автомобиля, выполнив разворот, как показано на рисунке?","a":["Да, нарушит.","Не нарушит, если прибегнет к помощи других лиц, которые сигнализировали бы о складывающейся ситуации позади транспортного средства.","Не нарушит, если эти действия не создадут препятствия для других участников дорожного движения и будет обеспечена безопасность дорожного движения."],"c":0,"e":"<p>В показанной ситуации водитель легкого автомобиля находится на обозначенном перекрёстке вне жилой зоны. Согласно Правилам дорожного движения, движение задним ходом запрещается на перекрёстках (кроме перекрёстков, расположенных в жилых зонах). Движение задним ходом на перекрёстках запрещается по причине того, что определение порядка его выполнения приведёт к нарушению основополагающих принципов Правил: правостороннего движения и правила «правой руки». Фактически движение задним ходом (движение по полосе попутного направления) создаёт участникам дорожного движения опасность как на самом перекрёстке, так и на подступах к нему.</p>","image":"assets/adrive-questions/q100905601.jpg"},{"id":100905602,"themeId":4,"group":1009056,"chapter":9,"chapters":[9],"q":"Нарушит ли Правила дорожного движения водитель красного автомобиля, выполнив разворот, как показано на рисунке?","a":["Да, нарушит.","Не нарушит, если эти действия не создадут препятствия для других участников дорожного движения и будет обеспечена безопасность дорожного движения."],"c":1,"e":"<p>Согласно Правилам дорожного движения, движение задним ходом запрещается на перекрёстках (кроме перекрёстков, расположенных в жилых зонах). В показанной ситуации водитель находится на участке дороги, который не является перекрёстком, поэтому движение задним ходом разрешено при условии, что эти действия не создадут препятствия для других участников дорожного движения и будет обеспечена безопасность дорожного движения.</p>","image":"assets/adrive-questions/q100905602.jpg"},{"id":100905701,"themeId":4,"group":1009057,"chapter":9,"chapters":[9],"q":"Нарушит ли Правила дорожного движения водитель жёлтого автомобиля, выполнив разворот, как показано на рисунке?","a":["Да, нарушит.","Не нарушит, если прибегнет к помощи других лиц, которые сигнализировали бы о складывающейся ситуации позади транспортного средства.","Не нарушит, если эти действия не создадут препятствия для других участников дорожного движения и будет обеспечена безопасность дорожного движения."],"c":0,"e":"<p>В показанной ситуации водитель находится на перекрёстке (выезд с прилегающей территории является перекрёстком). Согласно Правилам дорожного движения, движение задним ходом запрещается на перекрёстках (кроме перекрёстков, расположенных в жилых зонах), поэтому такой манёвр запрещён. Движение задним ходом на перекрёстках запрещается по причине того, что определение порядка его выполнения приведёт к нарушению основополагающих принципов Правил: правостороннего движения и правила «правой руки». Фактически движение задним ходом (движение по полосе попутного направления) создаёт участникам дорожного движения опасность как на самом перекрёстке, так и на подступах к нему.</p>","image":"assets/adrive-questions/q100905701.jpg"},{"id":100905702,"themeId":4,"group":1009057,"chapter":9,"chapters":[9],"q":"Нарушит ли Правила дорожного движения водитель жёлтого автомобиля, выполнив разворот, как показано на рисунке, находясь на дворовой территории, прилегающей к жилой застройке?","a":["Да, нарушит.","Не нарушит, если эти действия не создадут препятствия для других участников дорожного движения и будет обеспечена безопасность дорожного движения."],"c":1,"e":"<p>В показанной ситуации автомобиль движется на дворовой территории, прилегающей к жилой застройке. Согласно термину 2.21 «Жилая зона» дворовую территорию, прилегающую к жилой застройке, следует считать жилой зоной. Движение задним ходом разрешается на перекрёстках, расположенных в жилых зонах, потому что на узких проездах этих территорий зачастую нет иной возможности совершить разворот, кроме как на перекрёстке.</p>","image":"assets/adrive-questions/q100905702.jpg"},{"id":100905751,"themeId":4,"group":1009057,"chapter":9,"chapters":[9],"q":"Водитель легкового автомобиля проехал въезд на стоянку. Разрешено ли ему вернуться по показанной траектории и повернуть на стоянку?","a":["Разрешено.","Запрещено.","Разрешено, если водитель прибегнет к помощи другого лица, которое сигнализировало бы об обстановке позади автомобиля."],"c":1,"e":"<p>В месте примыкания выезда с прилегающей территории образуется перекрёсток. <strong>Движение задним ходом на перекрёстках запрещено</strong>, кроме перекрёстков, расположенных в жилой зоне.</p>","image":"assets/adrive-questions/q100905751.jpg"},{"id":100905761,"themeId":4,"group":1009057,"chapter":9,"chapters":[9],"q":"Водитель жёлтого автомобиля ошибочно проехал необходимый ему поворот. Разрешено ли задним ходом вернуться к съезду, чтобы повернуть в необходимом водителю направлении?","a":["Да, разрешено.","Нет, не разрешено."],"c":1,"e":"<p>Водитель легкового автомобиля находится в пределах перекрёстка. Движение задним ходом на перекрёстках запрещено.</p>","image":"assets/adrive-questions/q100905761.jpg"},{"id":100905901,"themeId":4,"group":1009059,"chapter":9,"chapters":[9],"q":"Разрешается ли движение задним ходом на участке дороги, изображённом на рисунке?","a":["Запрещается.","Да, разрешается."],"c":1,"e":"<p>Правила дорожного движения не запрещают движение задним ходом на дороге с односторонним движением, поэтому водителю разрешено движение задним ходом в показанной ситуации при условии, что эти действия не создадут препятствия для других участников дорожного движения и будет обеспечена безопасность дорожного движения.</p>","image":"assets/adrive-questions/q100905901.jpg"},{"id":100905902,"themeId":4,"group":1009059,"chapter":9,"chapters":[9],"q":"Разрешается ли движение задним ходом на участке дороги, изображённом на рисунке?","a":["Запрещается.","Разрешается, если эти действия не создадут препятствия для других участников дорожного движения и будет обеспечена безопасность дорожного движения."],"c":1,"e":"<p>Правила дорожного движения не запрещают движение задним ходом на показанном участке дороги, поэтому водителю разрешено движение задним ходом при условии, что эти действия не создадут препятствия для других участников дорожного движения и будет обеспечена безопасность дорожного движения.</p>","image":"assets/adrive-questions/q100905902.jpg"},{"id":100906064,"themeId":4,"group":1009060,"chapter":9,"chapters":[9],"q":"Вы по ошибке заняли не ту полосу, намереваясь двигаться на перекрёстке прямо. Как Вам следует поступить при включении разрешающего сигнала?","a":["Повернуть налево.","Осторожно перестроиться на соседнюю полосу справа, не создавая препятствия другим участникам дорожного движения.","Проехать перекрёсток прямо, перестраиваясь вправо на перекрёстке, уступая дорогу транспортным средствам, движущимся по соседней полосе."],"c":0,"e":"<p>Перестроение на показанном участке перед перекрёстком запрещено. Вам следует при включении разрешающего сигнала повернуть налево.</p>","image":"assets/adrive-questions/q100906064.jpg"},{"id":100906101,"themeId":4,"group":1009061,"chapter":9,"chapters":[9],"q":"Кто из водителей, совершая маневрирование, в показанной ситуации нарушает Правила дорожного движения?","a":["Только водитель зелёного автомобиля.","Только водитель красного автомобиля.","Нарушают оба водителя."],"c":2,"e":"<p>В показанной ситуации оба водителя совершают маневрирование в зоне остановочного пункта маршрутных ТС. Согласно Правилам дорожного движения, разворот и движение задним ходом запрещается на остановочных пунктах маршрутных транспортных средств. При развороте и движении задним ходом в местах расположения остановочных пунктов маршрутных ТС опасность для движения заключается в том, что: велика вероятность появления на проезжей части пешеходов, идущих к остановившемуся маршрутному ТС или (и) от него.</p>","image":"assets/adrive-questions/q100906101.jpg"},{"id":100906102,"themeId":4,"group":1009061,"chapter":9,"chapters":[9],"q":"Кто из водителей, совершая маневрирование, в показанной ситуации нарушает Правила дорожного движения?","a":["Только водитель зелёного автомобиля.","Только водитель красного автомобиля.","Нарушают оба водителя."],"c":1,"e":"<p>В показанной ситуации водитель красного автомобиля совершает разворот в зоне остановочного пункта маршрутных ТС, а водитель зелёного автомобиля движется задним ходом перед остановочным пунктом маршрутных ТС. Согласно Правилам дорожного движения, разворот и движение задним ходом запрещается на остановочных пунктах маршрутных транспортных средств. Поэтому нарушает Правила дорожного движения только водитель красного автомобиля. При развороте и движении задним ходом в местах расположения остановочных пунктов маршрутных ТС опасность для движения заключается в том, что: велика вероятность появления на проезжей части пешеходов, идущих к остановившемуся маршрутному ТС или (и) от него.</p>","image":"assets/adrive-questions/q100906102.jpg"},{"id":100906762,"themeId":4,"group":1009067,"chapter":9,"chapters":[9],"q":"Как Вам следует поступить в показанной ситуации, управляя легковым автомобилем, при повороте направо?","a":["Повернуть направо из занимаемой полосы движения.","Перестроиться и повернуть направо из крайней правой полосы движения.","Допустимы оба варианта."],"c":2,"e":"<p>Согласно требованиям дорожных знаков «Направление движения по полосе» , Вы можете осуществлять поворот направо по любой из предложенных полос движения, учитывая дальнейшие Ваши намерения после поворота (прямолинейное движение, последующий поворот или остановка).</p>","image":"assets/adrive-questions/q100906762.jpg"},{"id":100906763,"themeId":4,"group":1009067,"chapter":9,"chapters":[9],"q":"По какой из показанных траекторий Вам разрешено осуществить поворот налево при управлении легковым автомобилем?","a":["Только по траектории «А».","Только по траектории «Б».","По любой из указанных траекторий."],"c":2,"e":"<p>Согласно требованиям дорожных знаков «Направление движения по полосе» , Вы можете осуществлять поворот налево по любой из предложенных траекторий, учитывая дальнейшие Ваши намерения после поворота (прямолинейное движение, последующий поворот или остановка), а также учитывая то, что по траектории «Б» совершает поворот колёсный трактор.</p>","image":"assets/adrive-questions/q100906763.jpg"},{"id":101000332,"themeId":4,"group":1010003,"chapter":10,"chapters":[10],"q":"Разрешено ли Вам при управлении легковым автомобилем в показанной ситуации совершить обгон?","a":["Да, разрешено.","Нет, запрещено.","Разрешено, если скорость колёсного трактора не превышает 30 км/ч."],"c":1,"e":"<p>На дороге с двусторонним движением при наличии в направлении движения двух и более полос движения запрещается выезжать на встречную полосу движения даже для обгона одиночного транспортного средства, движущегося со скоростью менее 30 км/ч.</p>","image":"assets/adrive-questions/q101000332.jpg"},{"id":101000501,"themeId":4,"group":1010005,"chapter":10,"chapters":[10],"q":"Определите количество полос движения на проезжей части дороги, по которой Вы осуществляете движение, управляя легковым автомобилем:","a":["Одна.","Две.","Четыре."],"c":1,"e":"<p>Количество полос движения для транспортных средств (за исключением трамваев и одноколейных транспортных средств) определяется при отсутствии соответствующих дорожных знаков и дорожной разметки самими водителями с учётом ширины проезжей части дороги, габаритов транспортных средств и необходимых боковых интервалов между ними.</p> <p>Исходя из показанной ситуации, очевидно, что на проезжей части дороги попутного направления две полосы движения.</p>","image":"assets/adrive-questions/q101000501.jpg"},{"id":101000502,"themeId":4,"group":1010005,"chapter":10,"chapters":[10],"q":"Требуется ли перед осуществлением движения по показанной траектории включить световой указатель правого поворота?","a":["Да, требуется.","Нет, не требуется."],"c":0,"e":"<p>В показанной ситуации перед перестроением необходимо включить световой сигнал правого поворота.</p> <p>О том, что при смещении вправо Вы будете осуществлять перестроение, информирует дорожный знак 5.8.1 «Направления движения по полосам» .</p>","image":"assets/adrive-questions/q101000502.jpg"},{"id":101000503,"themeId":4,"group":1010005,"chapter":10,"chapters":[10],"q":"Какое количество полос движения включает в себя проезжая часть дороги перед перекрёстком с показанного направления?","a":["Две полосы движения.","Три полосы движения.","Четыре полосы движения.","Восемь полос движения."],"c":2,"e":"<p>Количество полос движения для транспортных средств (за исключением одноколейных транспортных средств) определяется дорожными знаками 5.8.1 «Направления движения по полосам» .</p>","image":"assets/adrive-questions/q101000503.jpg"},{"id":101000504,"themeId":4,"group":1010005,"chapter":10,"chapters":[10],"q":"Определите количество полос движения на показанном участке дороги:","a":["Две полосы движения.","Три полосы движения.","Четыре полосы движения."],"c":2,"e":"<p>При отсутствии дорожных знаков 5.8.1 «Направления движения по полосам» , 5.8.2 «Направление движения по полосе» , 5.8.7 «Направление движения по полосам» и полноценно (а не частично) нанесённых линий дорожной разметки количество полос движения для транспортных средств определяется горизонтальной дорожной разметкой.</p> <p>В показанной ситуации нанесена горизонтальная дорожная разметка 1.3 , которая указывает на общее количество полос движения не менее трёх. Количество попутных полос движения в показанной ситуации должно определяться самими водителями с учётом ширины проезжей части дороги, габаритов транспортных средств и необходимых боковых интервалов между ними.</p> <p>Исходя из показанного изображения, делаем вывод, что общее количество полос движения равно четырём.</p>","image":"assets/adrive-questions/q101000504.jpg"},{"id":101000601,"themeId":4,"group":1010006,"chapter":10,"chapters":[10],"q":"Правильно ли водитель жёлтого автомобиля занял положение на проезжей части при движении по данной дороге?","a":["Да, правильно.","Нет, неправильно."],"c":0,"e":"<p>В показанной ситуации на дороге установлены дорожные знаки, которые запрещают движение велосипедов и гужевых транспортных средств, животных под седлом или вьюком, а также прогон скота. Согласно Правилам дорожного движения, если дорожными знаками запрещено движение велосипедистов, всадников и гужевых транспортных средств, водители транспортных средств должны вести их по возможности ближе к правому краю проезжей части дороги.</p>","image":"assets/adrive-questions/q101000601.jpg"},{"id":101000602,"themeId":4,"group":1010006,"chapter":10,"chapters":[10],"q":"Правильно ли водитель жёлтого автомобиля занял положение на проезжей части при движении по данной дороге?","a":["Да, правильно.","Нет, неправильно."],"c":1,"e":"<p>В показанной ситуации на дороге установлен дорожный знак, который разрешает движение велосипедов. Согласно Правилам дорожного движения, водители в такой ситуации должны вести транспортное средство по возможности ближе к левому краю в пределах правой крайней полосы движения.</p>","image":"assets/adrive-questions/q101000602.jpg"},{"id":101000603,"themeId":4,"group":1010006,"chapter":10,"chapters":[10],"q":"Как при управлении легковым автомобилем в показанной ситуации Вам необходимо осуществлять движение, находясь в крайней правой полосе?","a":["Ближе к правому краю проезжей части дороги.","Ближе к левому краю в пределах правой крайней полосы движения."],"c":0,"e":"<p>Если дорожными знаками запрещено движение велосипедистов, всадников и гужевых транспортных средств (а в данном случае их движение запрещено дорожным знаком 5.3 «Дорога для автомобилей») , водители транспортных средств должны вести их по возможности ближе к правому краю проезжей части дороги.</p>","image":"assets/adrive-questions/q101000603.jpg"},{"id":101000701,"themeId":4,"group":1010007,"chapter":10,"chapters":[10],"q":"Водитель какого автомобиля занял правильное положение на проезжей части при движении по дороге, на которой не запрещено движение велосипедистов, всадников и гужевых транспортных средств?","a":["Водитель красного автомобиля.","Водитель синего автомобиля."],"c":0,"e":"<p>В показанной ситуации на дороге разрешено движение велосипедистов, всадников и гужевых ТС. Согласно Правилам дорожного движения, водители в такой ситуации должны вести транспортное средство по возможности ближе к левому краю в пределах правой крайней полосы движения.</p>","image":"assets/adrive-questions/q101000701.jpg"},{"id":101000702,"themeId":4,"group":1010007,"chapter":10,"chapters":[10],"q":"Водитель зелёного автомобиля совершает поворот направо на перекрёстке. Как он должен вести автомобиль по дороге, на которой установлены показанные на рисунке запрещающие дорожные знаки?","a":["По возможности ближе к левому краю проезжей части дороги.","По возможности ближе к правому краю проезжей части дороги."],"c":1,"e":"<p>В показанной ситуации на дороге установлены дорожные знаки, которые запрещают движение велосипедов и гужевых транспортных средств, животных под седлом или вьюком, а также прогон скота. Согласно Правилам дорожного движения, если дорожными знаками запрещено движение велосипедистов, всадников и гужевых транспортных средств, водители транспортных средств должны вести их по возможности ближе к правому краю проезжей части дороги.</p>","image":"assets/adrive-questions/q101000702.jpg"},{"id":101000801,"themeId":4,"group":1010008,"chapter":10,"chapters":[10],"q":"Водитель белого легкового автомобиля, завершив опережение автобуса, должен двигаться по дороге:","a":["По возможности ближе к правому краю проезжей части дороги.","По возможности ближе к левому краю в пределах правой крайней полосы движения."],"c":0,"e":"<p>В показанной ситуации на дороге установлены дорожные знаки, которые запрещают движение велосипедов и гужевых транспортных средств, животных под седлом или вьюком, а также прогон скота. Согласно Правилам дорожного движения, если дорожными знаками запрещено движение велосипедистов, всадников и гужевых транспортных средств, водители транспортных средств должны вести их по возможности ближе к правому краю проезжей части дороги.</p>","image":"assets/adrive-questions/q101000801.jpg"},{"id":101000802,"themeId":4,"group":1010008,"chapter":10,"chapters":[10],"q":"Водитель белого легкового автомобиля, завершив опережение автобуса, должен двигаться по дороге, на которой отсутствуют дорожные знаки, запрещающие движение велосипедистов, всадников и гужевого транспорта:","a":["По возможности ближе к правому краю проезжей части дороги.","По возможности ближе к левому краю в пределах правой крайней полосы движения."],"c":1,"e":"<p>В показанной ситуации на дороге разрешено движение велосипедистов, всадников и гужевых ТС. Согласно Правилам дорожного движения, водители в такой ситуации должны вести транспортное средство по возможности ближе к левому краю в пределах правой крайней полосы движения.</p>","image":"assets/adrive-questions/q101000802.jpg"},{"id":101000901,"themeId":4,"group":1010009,"chapter":10,"chapters":[10],"q":"В каком из предложенных вариантов правильно указаны границы попутной и встречной стороны проезжей части дороги?","a":["В варианте «А».","В варианте «Б»."],"c":1,"e":"<p>При отсутствии дорожных знаков и горизонтальной дорожной разметки половина ширины проезжей части дороги, расположенная слева, считается её встречной стороной.</p> <p>В показанной ситуации фронтальный погрузчик из-за своих габаритов осуществляет движение частично по встречной стороне проезжей части.</p>","image":"assets/adrive-questions/q101000901.jpg"},{"id":101000902,"themeId":4,"group":1010009,"chapter":10,"chapters":[10],"q":"Нарушил ли Правила дорожного движения водитель синего легкового автомобиля, заняв показанное положение на проезжей части дороги для движения прямо на перекрёстке?","a":["Да, нарушил.","Нет, не нарушил, если занял показанное положение с соблюдением безопасных боковых интервалов."],"c":0,"e":"<p>В показанной ситуации количество полос движения для транспортных средств определяется дорожными знаками 5.8.1 «Направления движения по полосам» .</p> <p>Водитель синего легкового автомобиля не выполнил требования установленного перед перекрёстком дорожного знака.</p>","image":"assets/adrive-questions/q101000902.jpg"},{"id":101000903,"themeId":4,"group":1010009,"chapter":10,"chapters":[10],"q":"По какой траектории водителю чёрного легкового автомобиля следует выполнить поворот налево?","a":["По траектории «А».","По траектории «Б».","По любой из показанных траекторий."],"c":1,"e":"<p>За перекрёстком установлен дорожный знак 5.8.8 «Направление движения по полосам» , в соответствии с требованиями которого необходимо осуществлять поворот налево по траектории «Б», чтобы при выезде с перекрёстка не оказаться на встречной полосе движения.</p>","image":"assets/adrive-questions/q101000903.jpg"},{"id":101001001,"themeId":4,"group":1010010,"chapter":10,"chapters":[10],"q":"Правильно ли водитель легкового автомобиля занял полосу движения в показанной ситуации для дальнейшего движения прямо на перекрёстке вне населённого пункта?","a":["Да, правильно.","Нет, неправильно."],"c":1,"e":"<p>Водитель жёлтого легкового автомобиля осуществляет движение по дороге вне населённого пункта. В такой ситуации запрещается занимать левые полосы движения при свободных правых.</p>","image":"assets/adrive-questions/q101001001.jpg"},{"id":101001002,"themeId":4,"group":1010010,"chapter":10,"chapters":[10],"q":"По какой полосе движения может двигаться водитель жёлтого автомобиля после проезда перекрёстка вне населённого пункта в показанной ситуации?","a":["Только по крайней левой.","Только по крайней правой.","По любой полосе движения."],"c":1,"e":"<p>В показанной ситуации водитель двигается по дороге с двумя полосами в попутном направлении вне населённого пункта. При этом вне населённых пунктов запрещается занимать левые полосы движения при свободных правых. Поэтому после проезда перекрёстка водитель жёлтого автомобиля должен при свободной правой полосе перестроиться на неё.</p>","image":"assets/adrive-questions/q101001002.jpg"},{"id":101001101,"themeId":4,"group":1010011,"chapter":10,"chapters":[10],"q":"Какую полосу разрешается занимать для движения по данной дороге вне населённого пункта в показанной ситуации при условии, что все полосы движения попутного направления не заняты?","a":["Любую.","Только крайнюю правую.","Любую, кроме крайней левой."],"c":1,"e":"<p>В показанной ситуации водитель будет двигаться по дороге вне населённого пункта. Согласно Правилам дорожного движения вне населённых пунктов запрещается занимать левые полосы движения при свободных правых.</p>","image":"assets/adrive-questions/q101001101.jpg"},{"id":101001102,"themeId":4,"group":1010011,"chapter":10,"chapters":[10],"q":"Какую полосу из свободных разрешается занимать водителю зелёного легкового автомобиля для движения по данной дороге вне населённого пункта в показанной ситуации?","a":["Только среднюю.","Среднюю или крайнюю левую."],"c":0,"e":"<p>В показанной ситуации водитель намеревается выполнить опережение. Согласно Правилам дорожного движения, вне населённых пунктов запрещается занимать левые полосы движения при свободных правых. Выезжать на полосу движения, расположенную левее, разрешается лишь тогда, когда правые полосы движения заняты другими транспортными средствами.</p>","image":"assets/adrive-questions/q101001102.jpg"},{"id":101001201,"themeId":4,"group":1010012,"chapter":10,"chapters":[10],"q":"В каких случаях при движении вне населённых пунктов запрещается занимать левые полосы движения?","a":["При скорости движения менее 40 км/ч.","При свободных правых полосах движения."],"c":1,"e":"<p>Согласно Правилам дорожного движения вне населённых пунктов запрещается занимать левые полосы движения при свободных правых. Выезжать на полосу движения, расположенную левее, разрешается лишь тогда, когда правые полосы движения заняты ТС и, как правило, это связано с выполнением опережения.</p>","image":null},{"id":101001202,"themeId":4,"group":1010012,"chapter":10,"chapters":[10],"q":"В каком случае водитель легкового автомобиля нарушит Правила дорожного движения, продолжив движение в левой полосе движения по дороге вне населённого пункта?","a":["Если правая полоса движения свободна.","Если правая полоса движения занята движущимися транспортными средствами.","Нарушит в любом случае."],"c":0,"e":"<p>Согласно Правилам дорожного движения вне населённых пунктов запрещается занимать левые полосы движения при свободных правых. Выезжать на полосу движения, расположенную левее, разрешается лишь тогда, когда правые полосы движения заняты другими транспортными средствами.</p>","image":"assets/adrive-questions/q101001202.jpg"},{"id":101001203,"themeId":4,"group":1010012,"chapter":10,"chapters":[10],"q":"Какую полосу движения может занимать водитель синего легкового автомобиля после окончания опережения при условии, что попутные полосы движения свободны?","a":["Крайнюю правую.","Крайнюю левую.","Любую из попутных полос движения."],"c":0,"e":"<p>Водителям транспортных средств вне населённых пунктов запрещается занимать левые полосы движения при свободных правых.<br> При этом дорожный знак 5.24 «Начало границы населённого пункта» обозначает участок дороги, при движении по которому не действуют специальные требования Правил, устанавливающие порядок дорожного движения в населённых пунктах. Поэтому водитель синего легкового автомобиля после опережения должен перестроиться на правую полосу движения.</p>","image":"assets/adrive-questions/q101001203.jpg"},{"id":101001601,"themeId":4,"group":1010016,"chapter":10,"chapters":[10],"q":"Правильно ли водитель белого автомобиля занял полосу движения в сложившейся ситуации на перекрёстке для дальнейшего движения прямо?","a":["Да, правильно.","Нет, неправильно."],"c":1,"e":"<p>В показанной ситуации водитель на перекрёстке занял крайнюю левую полосу для дальнейшего движения прямо при свободных правых.</p> <p>Согласно Правилам дорожного движения, при трёх и более полосах движения в данном направлении занимать крайнюю левую полосу движения разрешается только тогда, когда заняты другие полосы движения, либо для опережения, объезда препятствия, поворота налево или разворота.<br> Поэтому водителю необходимо было занять первую или вторую полосу движения для движения прямо на перекрёстке.</p>","image":"assets/adrive-questions/q101001601.jpg"},{"id":101001602,"themeId":4,"group":1010016,"chapter":10,"chapters":[10],"q":"По какой из указанных траекторий разрешается произвести объезд препятствия водителю синего автомобиля?","a":["Только слева.","Только справа.","По любой из указанных траекторий."],"c":2,"e":"<p>В показанной ситуации водителю разрешено произвести объезд автомобиля, совершившего вынужденную остановку, по любой из показанных траекторий. При трёх и более полосах движения в данном направлении Правилами установлен запрет на перестроение на крайнюю правую полосу движения в целях опережения по ней. Крайнюю левую полосу движения при свободных правых Правилами разрешено занимать, в частности, для объезда препятствия.</p>","image":"assets/adrive-questions/q101001602.jpg"},{"id":101001701,"themeId":4,"group":1010017,"chapter":10,"chapters":[10],"q":"Разрешается ли водителю красного автомобиля выполнить опережение по крайней левой полосе в показанной ситуации?","a":["Разрешается.","Запрещается."],"c":0,"e":"<p>В показанной ситуации водитель намеревается выполнить опережение на участке дороге с односторонним движением с тремя полосами. Согласно Правилам дорожного движения, при трёх и более полосах движения в данном направлении занимать крайнюю левую полосу движения разрешается только тогда, когда заняты другие полосы движения, либо для опережения, объезда препятствия, поворота налево или разворота, а также для остановки, стоянки на левой стороне дороги с односторонним движением.</p>","image":"assets/adrive-questions/q101001701.jpg"},{"id":101001702,"themeId":4,"group":1010017,"chapter":10,"chapters":[10],"q":"Разрешается ли водителю синего автомобиля проехать перекрёсток прямо, двигаясь в крайней левой полосе движения?","a":["Разрешается.","Запрещается."],"c":0,"e":"<p>В показанной ситуации водитель на перекрёстке занял крайнюю левую полосу для дальнейшего движения прямо при занятых правых. Согласно Правилам дорожного движения, при трёх и более полосах движения в данном направлении занимать крайнюю левую полосу движения разрешается только тогда, когда заняты другие полосы движения, либо для опережения, объезда препятствия, поворота налево или разворота. Поэтому водителю синего легкового автомобиля разрешено продолжить движение прямо на перекрёстке из данной полосы.</p>","image":"assets/adrive-questions/q101001702.jpg"},{"id":101001703,"themeId":4,"group":1010017,"chapter":10,"chapters":[10],"q":"Разрешено ли Вам, управляя легковым автомобилем, после завершения опережения продолжать движение прямо в показанной полосе движения в населённом пункте?","a":["Да, разрешено.","Нет, запрещено."],"c":1,"e":"<p>На дороге при трёх и более полосах движения в данном направлении занимать крайнюю левую полосу движения разрешается только тогда, когда заняты другие полосы движения, либо для опережения, объезда препятствия, поворота налево или разворота.<br> Продолжать движение прямо при свободных полосах справа запрещено.</p> <p>В показанной ситуации необходимо перестроиться на соседнюю полосу движения справа.</p>","image":"assets/adrive-questions/q101001703.jpg"},{"id":101001801,"themeId":4,"group":1010018,"chapter":10,"chapters":[10],"q":"В каких направлениях разрешается продолжить движение водителю жёлтого автомобиля в показанной ситуации?","a":["Только налево.","Только налево и на разворот.","Прямо, налево и на разворот."],"c":2,"e":"<p>В показанной ситуации водитель на перекрёстке занял крайнюю левую полосу при занятых правых. Перед перекрёстком установлен дорожный знак, разрешающий движение прямо, налево и на разворот из крайней левой полосы движения. Согласно Правилам дорожного движения, при трёх и более полосах движения в данном направлении занимать крайнюю левую полосу движения разрешается только тогда, когда заняты другие полосы движения, либо для опережения, объезда препятствия, поворота налево или разворота. Так как правые полосы заняты, то водителю разрешено также продолжить движение прямо на перекрёстке по данной полосе.</p>","image":"assets/adrive-questions/q101001801.jpg"},{"id":101001802,"themeId":4,"group":1010018,"chapter":10,"chapters":[10],"q":"Разрешается ли водителю жёлтого автомобиля проехать перекрёсток в прямом направлении в показанной ситуации?","a":["Да, разрешается.","Нет, не разрешается."],"c":0,"e":"<p>В показанной ситуации водитель на перекрёстке занял крайнюю левую полосу при занятых правых. Перед перекрёстком установлен дорожный знак, разрешающий движение прямо, налево и на разворот из крайней левой полосы движения. Согласно Правилам дорожного движения, при трёх и более полосах движения в данном направлении занимать крайнюю левую полосу движения разрешается только тогда, когда заняты другие полосы движения, либо для опережения, объезда препятствия, поворота налево или разворота. Так как правые полосы заняты, то водителю разрешено также продолжить движение прямо на перекрёстке по данной полосе.</p>","image":"assets/adrive-questions/q101001802.jpg"},{"id":101002001,"themeId":4,"group":1010020,"chapter":10,"chapters":[10],"q":"По какой полосе движения Вам разрешается произвести опережение в показанной ситуации?","a":["Только по крайней правой полосе.","Только по крайней левой полосе.","По любой из указанных полос движения."],"c":1,"e":"<p>Согласно Правилам дорожного движения, при трёх и более полосах движения в данном направлении занимать крайнюю левую полосу движения разрешается только тогда, когда заняты другие полосы движения, либо для опережения, объезда препятствия, поворота налево или разворота. При этом запрещается производить перестроение на крайнюю правую полосу движения в целях опережения по ней.</p>","image":"assets/adrive-questions/q101002001.jpg"},{"id":101002002,"themeId":4,"group":1010020,"chapter":10,"chapters":[10],"q":"Разрешается ли водителю легкового автомобиля произвести опережение по показанной траектории?","a":["Да, разрешается.","Нет, не разрешается."],"c":1,"e":"<p>В показанной ситуации водитель намеревается выполнить опережение по крайней правой полосе на участке дороге с односторонним движением с тремя полосами. Согласно Правилам дорожного движения, при трёх и более полосах движения в данном направлении запрещается производить перестроение на крайнюю правую полосу движения в целях опережения по ней.</p>","image":"assets/adrive-questions/q101002002.jpg"},{"id":101002003,"themeId":4,"group":1010020,"chapter":10,"chapters":[10],"q":"Разрешено ли Вам при управлении легковым автомобилем в показанной ситуации совершить опережение грузового автомобиля, двигаясь в крайней правой полосе движения?","a":["Да, разрешено.","Нет, запрещено."],"c":0,"e":"<p>При трёх и более полосах движения в данном направлении запрещается производить перестроение на крайнюю правую полосу движения в целях опережения по ней. Это связано с ограничением обзорности вправо, а также с высокой вероятностью нахождения в крайней правой полосе движения стоящих транспортных средств или транспортных средств, движущихся с меньшей скоростью.</p> <p>Но в показанной ситуации перестроение не производится, ситуация в крайней правой полосе позволяет беспрепятственно совершить опережение.</p>","image":"assets/adrive-questions/q101002003.jpg"},{"id":101002101,"themeId":4,"group":1010021,"chapter":10,"chapters":[10],"q":"Разрешается ли Вам, управляя легковым автомобилем, произвести опережение по показанной на рисунке траектории?","a":["Да, разрешается.","Нет, не разрешается."],"c":0,"e":"<p>Согласно Правилам дорожного движения, при трёх и более полосах движения в данном направлении запрещается производить перестроение на крайнюю правую полосу движения в целях опережения по ней. В показанной ситуации Вы намерены для опережения использовать вторую полосу движения, поэтому такой манёвр не запрещён.</p>","image":"assets/adrive-questions/q101002101.jpg"},{"id":101002102,"themeId":4,"group":1010021,"chapter":10,"chapters":[10],"q":"Разрешается ли водителю жёлтого легкового автомобиля произвести опережение по показанной на рисунке траектории?","a":["Да, разрешается.","Нет, не разрешается."],"c":0,"e":"<p>Согласно Правилам дорожного движения, при трёх и более полосах движения в данном направлении запрещается производить перестроение на крайнюю правую полосу движения в целях опережения по ней. В показанной ситуации водитель намеревается выполнить опережение по крайней правой полосе на участке дороги с односторонним движением с двумя полосами, поэтому такой манёвр не запрещён.</p>","image":"assets/adrive-questions/q101002102.jpg"},{"id":101002103,"themeId":4,"group":1010021,"chapter":10,"chapters":[10],"q":"Как должны поступить водители транспортных средств, находящихся в заторе в крайней левой полосе движения?","a":["Занять в этой полосе крайнее левое положение.","Занять в этой полосе крайнее правое положение."],"c":1,"e":"<p>Для обеспечения «коридора безопасности», по которому разрешается проезд только транспортных средств оперативного назначения, водители транспортных средств, находящихся в крайней левой полосе движения, должны занять в этой полосе крайнее правое положение.</p> <p>В случае необходимости, для того, чтобы обеспечить беспрепятственный проезд указанных транспортных средств, допускается сместиться на соседнюю полосу движения при условии соблюдения безопасности дорожного движения.</p>","image":"assets/adrive-questions/q101002103.jpg"},{"id":101002301,"themeId":4,"group":1010023,"chapter":10,"chapters":[10],"q":"Автомобиль не может развить скорость свыше 40 км/ч из-за технической неисправности. По какой полосе движения в такой ситуации он может двигаться в соответствии с Правилами дорожного движения?","a":["Только по крайней правой.","По любой."],"c":0,"e":"<p>Согласно Правилам дорожного движения, транспортные средства, скорость движения которых не должна превышать 40 км/ч или которые по техническим причинам не могут развивать более высокую скорость движения по сравнению с указанной, должны двигаться по крайней правой полосе движения, кроме случаев обгона, опережения, объезда препятствия либо перестроения перед поворотом или разворотом. Невыполнение водителями этих требований способствует снижению средней скорости транспортного потока в этих полосах и, как следствие, — уменьшение пропускной способности дороги.</p>","image":"assets/adrive-questions/q101002301.jpg"},{"id":101002302,"themeId":4,"group":1010023,"chapter":10,"chapters":[10],"q":"Автомобиль не может развить скорость свыше 40 км/ч из-за технической неисправности. Разрешается ли ему опередить по второй полосе самоходную машину, движущуюся c ещё меньшей скоростью?","a":["Да, разрешается.","Нет, не разрешается."],"c":0,"e":"<p>Согласно Правилам дорожного движения, транспортные средства, скорость движения которых не должна превышать 40 км/ч или которые по техническим причинам не могут развивать более высокую скорость движения по сравнению с указанной, должны двигаться по крайней правой полосе движения, кроме случаев обгона, опережения, объезда препятствия либо перестроения перед поворотом или разворотом.</p>","image":"assets/adrive-questions/q101002302.jpg"},{"id":101002352,"themeId":4,"group":1010023,"chapter":10,"chapters":[10],"q":"Из-за технической неисправности Ваш автомобиль не может развивать скорость более 40 км/ч. По какой полосе Вам разрешено продолжить движение прямо в показанной ситуации?","a":["Только по крайней левой.","Только по крайней правой.","По любой полосе, кроме крайней левой.","По любой полосе."],"c":1,"e":"<p>Транспортные средства, которые по техническим причинам не могут развивать скорость движения более 40 км/ч, должны двигаться <strong>по крайней правой полосе движения.</strong></p>","image":"assets/adrive-questions/q101002352.jpg"},{"id":101002401,"themeId":4,"group":1010024,"chapter":10,"chapters":[10],"q":"Разрешается ли движение по трамвайным путям попутного направления при наличии конструктивно выделенной над проезжей частью дороги посадочной площадки, с которой осуществляется посадка (высадка) пассажиров в трамвай?","a":["Разрешается, если площадка оборудована ограждением для пешеходов.","Разрешается, если попутные полосы движения заняты, не создавая помех для движения трамвая.","Разрешается для объезда препятствия, которое невозможно объехать по попутным полосам движения.","Запрещается в любом случае."],"c":3,"e":"<p>Согласно Правилам дорожного движения, запрещается движение по трамвайным путям попутного направления при наличии конструктивно выделенной над проезжей частью дороги посадочной площадки, с которой осуществляется посадка (высадка) пассажиров в трамвай.</p>","image":null},{"id":101002402,"themeId":4,"group":1010024,"chapter":10,"chapters":[10],"q":"Разрешается ли водителю белого автомобиля продолжить движение по трамвайным путям попутного направления в показанной ситуации?","a":["Нет, не разрешается.","Да, разрешается, не создавая помех для движения трамваев."],"c":0,"e":"<p>Согласно Правилам дорожного движения, запрещается движение по трамвайным путям попутного направления при наличии конструктивно выделенной над проезжей частью дороги посадочной площадки, с которой осуществляется посадка (высадка) пассажиров в трамвай.</p>","image":"assets/adrive-questions/q101002402.jpg"},{"id":101002501,"themeId":4,"group":1010025,"chapter":10,"chapters":[10],"q":"Разрешается ли водителю синего автомобиля проехать перекрёсток в прямом направлении, как показано на рисунке?","a":["Да, разрешается.","Нет, не разрешается."],"c":1,"e":"<p>В показанной ситуации водитель намеревается выполнить опережение по трамвайным путям попутного направления на обозначенном перекрёстке.</p> <p>Согласно Правилам дорожного движения, движение по трамвайным путям попутного направления, расположенным слева на одном уровне с проезжей частью дороги, разрешается для опережения вне обозначенных и регулируемых перекрёстков, при условии, что все полосы движения в данном направлении заняты.</p>","image":"assets/adrive-questions/q101002501.jpg"},{"id":101002502,"themeId":4,"group":1010025,"chapter":10,"chapters":[10],"q":"По какой из показанных траекторий разрешается выполнить опережение водителю зелёного легкового автомобиля?","a":["По траектории «А».","По траектории «Б».","Запрещено по любой из показанных траекторий."],"c":0,"e":"<p>Согласно Правилам дорожного движения, движение по трамвайным путям попутного направления, расположенным слева на одном уровне с проезжей частью дороги, разрешается для опережения вне обозначенных и регулируемых перекрёстков, при условии, что все полосы движения в данном направлении заняты.</p> <p>В показанной ситуации перекрёсток не является обозначенным и регулируемым. Движение по траектории «А» будет осуществляться по трамвайным путям попутного направления, поэтому соответствует Правилам.<br> Траектория «Б» не соответствует Правилам, так как движение будет осуществляться по трамвайным путям встречного направления.</p>","image":"assets/adrive-questions/q101002502.jpg"},{"id":101002564,"themeId":4,"group":1010025,"chapter":10,"chapters":[10],"q":"Разрешено ли Вам обогнать легковой автомобиль по трамвайным путям в показанной ситуации?","a":["Разрешено.","Разрешено, если обгон будет завершён до обозначенного перекрёстка.","Запрещено."],"c":2,"e":"<p>Движение по трамвайным путям встречного направления <strong>запрещено</strong>.</p>","image":"assets/adrive-questions/q101002564.jpg"},{"id":101002602,"themeId":4,"group":1010026,"chapter":10,"chapters":[10],"q":"Разрешается ли Правилами дорожного движения водителю жёлтого автомобиля выполнить опережение по траектории, показанной на рисунке?","a":["Да, разрешается.","Нет, не разрешается."],"c":0,"e":"<p>В показанной ситуации водитель намеревается выполнить опережение по трамвайным путям попутного направления.</p> <p>Согласно Правилам дорожного движения, движение по трамвайным путям попутного направления, расположенным слева на одном уровне с проезжей частью дороги, разрешается для опережения вне обозначенных и регулируемых перекрёстков, при условии, что все полосы движения в данном направлении заняты. При этом следует учитывать, что опережение осуществляется в пределах пешеходного перехода, и, несмотря на разрешающий сигнал светофора, следует проявить осторожность, выполняя опережение.</p>","image":"assets/adrive-questions/q101002602.jpg"},{"id":101002631,"themeId":4,"group":1010026,"chapter":10,"chapters":[10],"q":"Разрешается ли Вам, управляя легковым автомобилем, выполнить опережение по траектории, показанной на рисунке?","a":["Да, разрешается.","Нет, не разрешается."],"c":0,"e":"<p>В показанной ситуации Вы намереваетесь выполнить опережение по трамвайным путям попутного направления.</p> <p>Согласно Правилам дорожного движения, движение по трамвайным путям попутного направления, расположенным слева на одном уровне с проезжей частью дороги, разрешается для опережения вне обозначенных и регулируемых перекрёстков, при условии, что все полосы движения в данном направлении заняты. При этом следует учитывать, что опережение осуществляется в пределах пешеходного перехода, и необходимо проявить осторожность, выполняя такой манёвр.</p>","image":"assets/adrive-questions/q101002631.jpg"},{"id":101002701,"themeId":4,"group":1010027,"chapter":10,"chapters":[10],"q":"По какой из показанных траекторий разрешается выполнить опережение водителю зелёного легкового автомобиля?","a":["По траектории «А».","По траектории «Б».","Запрещено по любой из показанных траекторий."],"c":2,"e":"<p>Согласно Правилам дорожного движения, движение по трамвайным путям попутного направления, расположенным слева на одном уровне с проезжей частью дороги, разрешается для опережения вне обозначенных и регулируемых перекрёстков, при условии, что все полосы движения в данном направлении заняты.</p> <p>В показанной ситуации перекрёсток является обозначенным, поэтому водителю запрещено осуществлять опережение по трамвайным путям.</p>","image":"assets/adrive-questions/q101002701.jpg"},{"id":101002702,"themeId":4,"group":1010027,"chapter":10,"chapters":[10],"q":"По какой из показанных траекторий разрешается выполнить опережение водителю жёлтого легкового автомобиля?","a":["По траектории «А».","По траектории «Б».","Запрещено по любой из показанных траекторий."],"c":2,"e":"<p>Согласно Правилам дорожного движения, движение по трамвайным путям попутного направления, расположенным слева на одном уровне с проезжей частью дороги, разрешается для опережения вне обозначенных и регулируемых перекрёстков, при условии, что все полосы движения в данном направлении заняты.</p> <p>В показанной ситуации перекрёсток является обозначенным, поэтому водителю запрещено осуществлять опережение по трамвайным путям.</p>","image":"assets/adrive-questions/q101002702.jpg"},{"id":101002801,"themeId":4,"group":1010028,"chapter":10,"chapters":[10],"q":"Разрешается ли водителю зелёного автомобиля произвести опережение по траектории, показанной на рисунке?","a":["Да, разрешается.","Нет, не разрешается."],"c":1,"e":"<p>Согласно Правилам дорожного движения, движение по трамвайным путям попутного направления, расположенным слева на одном уровне с проезжей частью дороги, разрешается для опережения вне обозначенных и регулируемых перекрёстков, при условии, что все полосы движения в данном направлении заняты.</p> <p>В показанной ситуации крайняя правая полоса не занята, поэтому водителю запрещено осуществлять опережение по трамвайным путям.</p>","image":"assets/adrive-questions/q101002801.jpg"},{"id":101002802,"themeId":4,"group":1010028,"chapter":10,"chapters":[10],"q":"Разрешается ли Вам, управляя легковым автомобилем, произвести опережение по трамвайным путям попутного направления при условии, что крайняя правая полоса движения свободна?","a":["Да, разрешается.","Нет, не разрешается."],"c":1,"e":"<p>Согласно Правилам дорожного движения, движение по трамвайным путям попутного направления, расположенным слева на одном уровне с проезжей частью дороги, разрешается при условии, что все полосы движения в данном направлении заняты.</p> <p>В показанной ситуации крайняя правая полоса не занята, поэтому Вам запрещено произвести опережение по трамвайным путям.</p>","image":"assets/adrive-questions/q101002802.jpg"},{"id":101002901,"themeId":4,"group":1010029,"chapter":10,"chapters":[10],"q":"При каком условии разрешается выезд с целью опережения на трамвайные пути, расположенные слева на одном уровне с проезжей частью дороги, вне обозначенных и регулируемых перекрёстков?","a":["Только при условии, что все полосы движения в данном направлении заняты.","Только при условии, что на ближайшем перекрёстке необходимо повернуть налево или развернуться.","При любом из перечисленных условий."],"c":0,"e":"<p>Согласно Правилам дорожного движения, движение по трамвайным путям попутного направления, расположенным слева на одном уровне с проезжей частью дороги, разрешается для опережения вне обозначенных и регулируемых перекрёстков, при условии, что все полосы движения в данном направлении заняты.</p>","image":null},{"id":101002902,"themeId":4,"group":1010029,"chapter":10,"chapters":[10],"q":"С какой целью разрешается движение по трамвайным путям, расположенным слева на одном уровне с проезжей частью дороги, при условии, что все полосы движения в данном направлении заняты?","a":["Только для объезда препятствия.","Только для опережения вне обозначенных и регулируемых перекрёстков.","В любом из перечисленных случаев."],"c":2,"e":"<p>Согласно Правилам дорожного движения, движение по трамвайным путям попутного направления, расположенным слева на одном уровне с проезжей частью дороги, разрешается только для опережения (вне обозначенных и регулируемых перекрёстков), объезда препятствия при условии, что все полосы движения в данном направлении заняты.</p>","image":null},{"id":101003001,"themeId":4,"group":1010030,"chapter":10,"chapters":[10],"q":"Разрешается ли мотоциклисту осуществлять движение так, как показано на рисунке?","a":["Разрешается только при опережении.","Разрешается только при соблюдении безопасных боковых интервалов.","Разрешается при выполнении обоих перечисленных условий.","Нет, не разрешается."],"c":3,"e":"<p>На дороге, проезжая часть которой разделена на полосы движения линиями горизонтальной дорожной разметки, движение необходимо осуществлять строго по этим полосам. Наезжать на прерывистые линии горизонтальной дорожной разметки разрешается только при маневрировании.</p>","image":"assets/adrive-questions/q101003001.jpg"},{"id":101003002,"themeId":4,"group":1010030,"chapter":10,"chapters":[10],"q":"В каких случаях Вам разрешается наезжать на прерывистые линии горизонтальной дорожной разметки?","a":["При перестроении.","При движении в тёмное время суток.","В случае если соседняя полоса не занята попутно движущимися транспортными средствами.","Во всех перечисленных случаях."],"c":0,"e":"<p>На дороге, проезжая часть которой разделена на полосы движения линиями горизонтальной дорожной разметки 1.5 , движение необходимо осуществлять строго по этим полосам.</p> <p>Наезжать на прерывистые линии горизонтальной дорожной разметки разрешается только при маневрировании.</p>","image":"assets/adrive-questions/q101003002.jpg"},{"id":101003101,"themeId":4,"group":1010031,"chapter":10,"chapters":[10],"q":"По какой из указанных траекторий водитель жёлтого автомобиля осуществит поворот направо в соответствии с Правилами дорожного движения?","a":["Только по траектории «А».","Только по траектории «Б».","По любой из показанных траекторий."],"c":0,"e":"<p>В показанной ситуации водитель выполняет поворот на дорогу с реверсивным движением. Согласно Правилам дорожного движения, при повороте на дорогу с реверсивным движением водитель должен управлять транспортным средством таким образом, чтобы при выезде с пересечения проезжих частей дорог транспортное средство заняло крайнюю правую полосу движения.</p>","image":"assets/adrive-questions/q101003101.jpg"},{"id":101003102,"themeId":4,"group":1010031,"chapter":10,"chapters":[10],"q":"По какой из указанных траекторий водитель жёлтого автомобиля осуществит поворот налево в соответствии с Правилами дорожного движения?","a":["Только по траектории «А».","Только по траектории «Б».","По любой из показанных траекторий."],"c":1,"e":"<p>В показанной ситуации водитель выполняет поворот на дорогу с реверсивным движением. Водитель, выезжающий на такую дорогу, не всегда может убедиться в том, что в данный момент по реверсивной полосе (полосам) разрешено движение в попутном направлении. Согласно Правилам дорожного движения, при повороте на дорогу с реверсивным движением водитель должен управлять транспортным средством таким образом, чтобы при выезде с пересечения проезжих частей дорог транспортное средство заняло крайнюю правую полосу движения.</p>","image":"assets/adrive-questions/q101003102.jpg"},{"id":101003201,"themeId":4,"group":1010032,"chapter":10,"chapters":[10],"q":"Нарушит ли Правила дорожного движения водитель белого автомобиля, повернув налево по траектории, обозначенной на рисунке?","a":["Да, нарушит.","Нет, не нарушит."],"c":0,"e":"<p>В показанной ситуации водитель выполняет поворот на дорогу с реверсивным движением. Водитель, выезжающий на такую дорогу, не всегда может убедиться в том, что в данный момент по реверсивной полосе (полосам) разрешено движение в попутном направлении. Согласно Правилам дорожного движения, при повороте на дорогу с реверсивным движением водитель должен управлять транспортным средством таким образом, чтобы при выезде с пересечения проезжих частей дорог транспортное средство заняло крайнюю правую полосу движения.</p>","image":"assets/adrive-questions/q101003201.jpg"},{"id":101003202,"themeId":4,"group":1010032,"chapter":10,"chapters":[10],"q":"Нарушит ли Правила дорожного движения водитель белого автомобиля, повернув налево по траектории, обозначенной на рисунке?","a":["Да, нарушит.","Нет, не нарушит."],"c":1,"e":"<p>В показанной ситуации водитель выполняет поворот на дорогу с реверсивным движением. Водитель, выезжающий на такую дорогу, не всегда может убедиться в том, что в данный момент по реверсивной полосе (полосам) разрешено движение в попутном направлении. Согласно Правилам дорожного движения, при повороте на дорогу с реверсивным движением водитель должен управлять транспортным средством таким образом, чтобы при выезде с пересечения проезжих частей дорог транспортное средство заняло крайнюю правую полосу движения.</p>","image":"assets/adrive-questions/q101003202.jpg"},{"id":101003203,"themeId":4,"group":1010032,"chapter":10,"chapters":[10],"q":"Нарушит ли Правила дорожного движения водитель белого автомобиля, повернув налево по траектории, обозначенной на рисунке?","a":["Да, нарушит.","Нет, не нарушит."],"c":0,"e":"<p>В показанной ситуации водитель выполняет поворот на дорогу с реверсивным движением. Водитель, выезжающий на такую дорогу, не всегда может убедиться в том, что в данный момент по реверсивной полосе (полосам) разрешено движение в попутном направлении. Согласно Правилам дорожного движения, при повороте на дорогу с реверсивным движением водитель должен управлять транспортным средством таким образом, чтобы при выезде с пересечения проезжих частей дорог транспортное средство заняло крайнюю правую полосу движения.</p>","image":"assets/adrive-questions/q101003203.jpg"},{"id":101003401,"themeId":4,"group":1010034,"chapter":10,"chapters":[10],"q":"Каким транспортным средствам разрешается движение по обочинам?","a":["Только самоходным машинам.","Только автомобилям с наклонной белой полосой на бортах.","Только транспортным средствам, следующим к месту стоянки или ремонта с включённой аварийной световой сигнализацией.","Всем перечисленным."],"c":1,"e":"<p>Согласно Правилам дорожного движения, допускается движение по обочинам, тротуарам, велосипедным, пешеходным дорожкам и дорожкам для всадников, транспортных средств дорожно-эксплуатационной и коммунальной служб, автомобилей с наклонной белой полосой на бортах, а также других транспортных средств, обслуживающих торговые и другие организации, расположенные непосредственно у обочин, тротуаров, велосипедных, пешеходных дорожек, дорожек для всадников или пешеходных зон, при отсутствии других возможностей подъезда.</p>","image":null},{"id":101003402,"themeId":4,"group":1010034,"chapter":10,"chapters":[10],"q":"Каким транспортным средствам разрешается движение по обочинам?","a":["Только автомобилям с наклонной белой полосой на бортах.","Только транспортным средствам дорожно-эксплуатационной и коммунальной служб.","Только транспортным средствам, обслуживающим торговые и другие организации, расположенные непосредственно у обочин, при отсутствии других возможностей подъезда.","Всем перечисленным."],"c":3,"e":"<p>Согласно Правилам дорожного движения, допускается движение по обочинам, тротуарам, велосипедным, пешеходным дорожкам и дорожкам для всадников транспортных средств дорожно-эксплуатационной и коммунальной служб, автомобилей с наклонной белой полосой на бортах, а также других транспортных средств, обслуживающих торговые и другие организации, расположенные непосредственно у обочин, тротуаров, велосипедных, пешеходных дорожек, дорожек для всадников или пешеходных зон, при отсутствии других возможностей подъезда.</p>","image":null},{"id":101003403,"themeId":4,"group":1010034,"chapter":10,"chapters":[10],"q":"Разрешается ли в показанной ситуации водителю белого легкового автомобиля осуществить объезд препятствия по тротуару?","a":["Да, разрешается.","Нет, запрещается.","Разрешается, если на тротуаре отсутствуют пешеходы и велосипедисты."],"c":1,"e":"<p>Правилами дорожного движения запрещается движение транспортных средств по обочинам, тротуарам, велосипедным, пешеходным дорожкам и дорожкам для всадников.</p> <p>Водителю белого легкового автомобиля следует осуществить объезд препятствия по встречной полосе движения, когда она станет свободна.</p>","image":"assets/adrive-questions/q101003403.jpg"},{"id":101003501,"themeId":4,"group":1010035,"chapter":10,"chapters":[10],"q":"Разрешается ли произвести опережение по обочине в показанной ситуации, если скорость впереди движущегося транспортного средства составляет 20 км/ч?","a":["Да, разрешается.","Нет, не разрешается."],"c":1,"e":"<p>Обочина может быть использована ТС для остановки, а также движения велосипедистов и гужевых ТС, если это не создаёт препятствия для движения пешеходам. Опережение по обочине запрещено.</p>","image":"assets/adrive-questions/q101003501.jpg"},{"id":101003503,"themeId":4,"group":1010035,"chapter":10,"chapters":[10],"q":"Разрешается ли в показанной ситуации водителю синего легкового автомобиля осуществить объезд препятствия по обочине?","a":["Да, разрешается.","Нет, запрещается."],"c":1,"e":"<p>Правилами дорожного движения запрещается движение транспортных средств по обочинам, тротуарам, велосипедным, пешеходным дорожкам и дорожкам для всадников.</p> <p>Водителю синего легкового автомобиля следует осуществить объезд препятствия по встречной полосе движения, когда она станет свободна.</p>","image":"assets/adrive-questions/q101003503.jpg"},{"id":101003601,"themeId":4,"group":1010036,"chapter":10,"chapters":[10],"q":"Какую дистанцию должен соблюдать водитель до движущегося впереди транспортного средства?","a":["Дистанцию не менее 15 метров в населённом пункте и не менее 40 метров вне населённого пункта.","Дистанцию, которая позволила бы избежать столкновения в случае его экстренного торможения или остановки.","Дистанцию, позволяющую обгоняющим автомобилям беспрепятственно перестроиться на ранее занимаемую полосу движения.","Дистанцию, позволяющую видеть дорожное покрытие перед транспортным средством в населённом пункте, и дистанцию, не позволяющую видеть информацию на регистрационном знаке (временном номерном знаке) впереди движущегося транспортного средства вне населённого пункта."],"c":1,"e":"<p>Согласно Правилам дорожного движения, водитель обязан соблюдать такую дистанцию до движущегося впереди транспортного средства, которая позволила бы избежать столкновения в случае его экстренного торможения или остановки. На практике установлено, что при движении в светлое время суток на дороге с сухим асфальтобетонном покрытии дистанция (в метрах) должна составлять примерно половину скорости движения (в км/ч), то есть при скорости 60 км/ч безопасная дистанция должна быть не менее 30 м. Вместе с тем, водитель обязан выбирать величину безопасной дистанции исходя из конкретной дорожно-транспортной обстановки и метеорологических условий.</p>","image":null},{"id":101100101,"themeId":4,"group":1011001,"chapter":11,"chapters":[11],"q":"Какие меры обязан предпринять водитель при обнаружении опасности или препятствия для движения?","a":["Подать звуковой сигнал для предотвращения ДТП.","Немедленно прибегнуть к экстренному торможению.","Немедленно принять меры к снижению скорости движения, вплоть до остановки транспортного средства."],"c":2,"e":"<p>Согласно Правилам дорожного движения, при возникновении препятствия или опасности для движения, которые водитель в состоянии обнаружить, он обязан немедленно принять меры к снижению скорости движения, вплоть до остановки транспортного средства. Водителю при возникновении препятствия или опасности для движения предписывается применять только торможение. Применение манёвра как способа предотвращения столкновения (наезда) при наличии неподвижного препятствия в полосе движения ТС в ряде случаев оправданно, если оно не приведёт к опасным последствиям.</p>","image":null},{"id":101100102,"themeId":4,"group":1011001,"chapter":11,"chapters":[11],"q":"Какие меры Вам следует предпринять в показанной обстановке?","a":["Объехать бегущего ребёнка.","Подать звуковой сигнал для предотвращения ДТП.","Немедленно принять меры к снижению скорости движения, вплоть до остановки транспортного средства."],"c":2,"e":"<p>В показанной ситуации на проезжую часть дороги выбегает ребёнок. Согласно Правилам дорожного движения, при возникновении препятствия или опасности для движения, которые водитель в состоянии обнаружить, он обязан немедленно принять меры к снижению скорости движения, вплоть до остановки транспортного средства. Водителю при возникновении препятствия или опасности для движения предписывается применять только торможение.</p>","image":"assets/adrive-questions/q101100102.jpg"},{"id":101100103,"themeId":4,"group":1011001,"chapter":11,"chapters":[11],"q":"Что должен учитывать водитель при выборе скорости движения?","a":["Только дорожные условия.","Только обзорность дороги.","Только ограничения скорости, установленные Правилами дорожного движения.","Только особенности и состояние транспортного средства и перевозимого им груза.","Всё вышеперечисленное."],"c":4,"e":"<p>При выборе скорости движения водитель должен учитывать все факторы, влияющие на безопасность движения, а также ограничения скорости, установленные Правилами дорожного движения и техническими средствами организации дорожного движения.</p>","image":"assets/adrive-questions/q101100103.jpg"},{"id":101100201,"themeId":4,"group":1011002,"chapter":11,"chapters":[11],"q":"Вы движетесь по дороге в населённом пункте со скоростью 60 км/ч. На незначительном расстоянии впереди на перекрёстке легковой автомобиль совершает поворот направо. Как необходимо поступить в такой ситуации?","a":["Подать звуковой сигнал для предотвращения ДТП.","Совершить обгон легкового автомобиля на перекрёстке.","Немедленно принять меры к снижению скорости движения, вплоть до остановки транспортного средства."],"c":2,"e":"<p>В показанной ситуации водитель легкового автомобиля справа нарушает Правила дорожного движения и тем самым создаёт опасность для движения.</p> <p>Согласно Правилам дорожного движения, при возникновении препятствия или опасности для движения, которые водитель в состоянии обнаружить, Вы обязаны немедленно принять меры к снижению скорости движения, вплоть до остановки транспортного средства.</p>","image":"assets/adrive-questions/q101100201.jpg"},{"id":101100202,"themeId":4,"group":1011002,"chapter":11,"chapters":[11],"q":"Как следует Вам поступить, управляя легковым автомобилем, если на занимаемую Вами полосу выехал автомобиль, не выполнив требование «Уступить дорогу»?","a":["Перестроиться на правую полосу движения.","Перестроиться на встречную полосу движения.","Принять меры к снижению скорости движения, вплоть до остановки."],"c":2,"e":"<p>При возникновении препятствия или опасности для движения водитель обязан немедленно принять меры к снижению скорости движения, вплоть до остановки транспортного средства.</p>","image":"assets/adrive-questions/q101100202.jpg"},{"id":101100301,"themeId":4,"group":1011003,"chapter":11,"chapters":[11],"q":"С какой максимальной скоростью разрешается двигаться водителю легкового автомобиля по дворовой территории, прилегающей к жилой застройке?","a":["20 км/ч.","30 км/ч.","40 км/ч.","50 км/ч.","60 км/ч."],"c":0,"e":"<p>Согласно Правилам дорожного движения, в жилых и пешеходных зонах, на прилегающих территориях разрешается движение транспортных средств со скоростью не более 20 км/ч. Такая скорость движения позволяет обеспечить безопасность пешеходов (в том числе передвигающихся на средствах персональной мобильности) и велосипедистов, учитывая, что среди них могут быть дети.</p>","image":"assets/adrive-questions/q101100301.jpg"},{"id":101100302,"themeId":4,"group":1011003,"chapter":11,"chapters":[11],"q":"Разрешается ли водителю жёлтого автомобиля двигаться в жилой зоне со скоростью более 20 км/ч, если за ним скопилось несколько автомобилей?","a":["Да, разрешается, но не более 40 км/ч.","Да, разрешается, но не более 60 км/ч.","Нет, не разрешается."],"c":2,"e":"<p>Согласно Правилам дорожного движения, в жилых и пешеходных зонах, на прилегающих территориях разрешается движение транспортных средств со скоростью не более 20 км/ч. Такая скорость движения позволяет обеспечить безопасность пешеходов (в том числе передвигающихся на средствах персональной мобильности) и велосипедистов, учитывая, что среди них могут быть дети.</p>","image":"assets/adrive-questions/q101100302.jpg"},{"id":101100401,"themeId":4,"group":1011004,"chapter":11,"chapters":[11],"q":"С какой максимальной скоростью разрешается продолжить движение в показанной ситуации?","a":["10 км/ч.","20 км/ч.","30 км/ч.","50 км/ч.","60 км/ч."],"c":1,"e":"<p>Согласно Правилам дорожного движения, в жилых и пешеходных зонах, на прилегающих территориях разрешается движение транспортных средств со скоростью не более 20 км/ч. Такая скорость движения позволяет обеспечить безопасность пешеходов (в том числе передвигающихся на средствах персональной мобильности) и велосипедистов, учитывая, что среди них могут быть дети.</p>","image":"assets/adrive-questions/q101100401.jpg"},{"id":101100402,"themeId":4,"group":1011004,"chapter":11,"chapters":[11],"q":"Водитель какого автомобиля нарушает Правила дорожного движения, если скорость движения синего автомобиля составляет 25 км/ч, а жёлтого автомобиля — 15 км/ч?","a":["Водитель синего автомобиля.","Водитель жёлтого автомобиля.","Водители обоих автомобилей.","Водители обоих автомобилей не нарушают Правила дорожного движения."],"c":0,"e":"<p>Согласно Правилам дорожного движения, в жилых и пешеходных зонах, на прилегающих территориях разрешается движение транспортных средств со скоростью не более 20 км/ч. Такая скорость движения позволяет обеспечить безопасность пешеходов (в том числе передвигающихся на средствах персональной мобильности) и велосипедистов, учитывая, что среди них могут быть дети.</p>","image":"assets/adrive-questions/q101100402.jpg"},{"id":101100501,"themeId":4,"group":1011005,"chapter":11,"chapters":[11],"q":"С какой максимальной скоростью разрешена буксировка автомобиля в жилой зоне?","a":["20 км/ч.","50 км/ч.","60 км/ч.","70 км/ч.","90 км/ч."],"c":0,"e":"<p>Согласно Правилам дорожного движения, в жилых и пешеходных зонах, на прилегающих территориях разрешается движение транспортных средств со скоростью не более 20 км/ч. Такая скорость движения позволяет обеспечить безопасность пешеходов (в том числе передвигающихся на средствах персональной мобильности) и велосипедистов, учитывая, что среди них могут быть дети.</p>","image":"assets/adrive-questions/q101100501.jpg"},{"id":101100502,"themeId":4,"group":1011005,"chapter":11,"chapters":[11],"q":"Буксировка неисправного автомобиля производится со скоростью 50 км/ч. До какого максимального значения необходимо снизить скорость при въезде на участок дороги, обозначенный таким дорожным знаком?","a":["20 км/ч.","30 км/ч.","40 км/ч.","Разрешается не снижать скорость в показанной ситуации."],"c":0,"e":"<p>В показанной ситуации установлен дорожный знак 5.38 «Жилая зона» , который информирует, что водитель будет осуществлять буксировку в жилой зоне. Согласно Правилам дорожного движения, в жилых и пешеходных зонах, на прилегающих территориях разрешается движение транспортных средств со скоростью не более 20 км/ч. Такая скорость движения позволяет обеспечить безопасность пешеходов (в том числе передвигающихся на средствах персональной мобильности) и велосипедистов, учитывая, что среди них могут быть дети.</p>","image":"assets/adrive-questions/q101100502.jpg"},{"id":101100601,"themeId":4,"group":1011006,"chapter":11,"chapters":[11],"q":"С какой максимальной скоростью разрешается буксировка прицепа в жилой зоне?","a":["20 км/ч.","50 км/ч.","60 км/ч.","70 км/ч.","90 км/ч."],"c":0,"e":"<p>Согласно Правилам дорожного движения, в жилых и пешеходных зонах, на прилегающих территориях разрешается движение транспортных средств со скоростью не более 20 км/ч. Такая скорость движения позволяет обеспечить безопасность пешеходов (в том числе передвигающихся на средствах персональной мобильности) и велосипедистов, учитывая, что среди них могут быть дети.</p>","image":"assets/adrive-questions/q101100601.jpg"},{"id":101100602,"themeId":4,"group":1011006,"chapter":11,"chapters":[11],"q":"С какой максимальной скоростью разрешается буксировка прицепа в пешеходной зоне?","a":["20 км/ч.","50 км/ч.","60 км/ч.","70 км/ч.","90 км/ч."],"c":0,"e":"<p>Согласно Правилам дорожного движения, в жилых и пешеходных зонах, на прилегающих территориях разрешается движение транспортных средств со скоростью не более 20 км/ч. Такая скорость движения позволяет обеспечить безопасность пешеходов (в том числе передвигающихся на средствах персональной мобильности) и велосипедистов, учитывая, что среди них могут быть дети.</p>","image":"assets/adrive-questions/q101100602.jpg"},{"id":101100701,"themeId":4,"group":1011007,"chapter":11,"chapters":[11],"q":"С какой максимальной скоростью разрешается движение водителю легкового автомобиля по прилегающей территории?","a":["20 км/ч.","50 км/ч.","60 км/ч.","70 км/ч.","90 км/ч."],"c":0,"e":"<p>Согласно Правилам дорожного движения, в жилых и пешеходных зонах, на прилегающих территориях разрешается движение транспортных средств со скоростью не более 20 км/ч. Такая скорость движения позволяет обеспечить безопасность пешеходов (в том числе передвигающихся на средствах персональной мобильности) и велосипедистов, учитывая, что среди них могут быть дети.</p>","image":"assets/adrive-questions/q101100701.jpg"},{"id":101100702,"themeId":4,"group":1011007,"chapter":11,"chapters":[11],"q":"С какой максимальной скоростью Вам разрешается движение по дороге, обозначенной таким дорожным знаком?","a":["20 км/ч.","50 км/ч.","60 км/ч.","70 км/ч.","90 км/ч."],"c":0,"e":"<p>В показанной ситуации установлен дорожный знак 5.38 «Жилая зона» , который информирует, что движение будет осуществляться в жилой зоне. В жилых и пешеходных зонах, на прилегающих территориях разрешается движение транспортных средств со скоростью не более 20 км/ч. Такая скорость движения позволяет обеспечить безопасность пешеходов (в том числе передвигающихся на средствах персональной мобильности) и велосипедистов, учитывая, что среди них могут быть дети.</p>","image":"assets/adrive-questions/q101100702.jpg"},{"id":101100801,"themeId":4,"group":1011008,"chapter":11,"chapters":[11],"q":"Скорость обоих автомобилей в показанной ситуации составляет 70 км/ч. Кто из водителей в данный момент нарушает Правила дорожного движения?","a":["Водитель жёлтого автомобиля.","Водитель красного автомобиля.","Водители обоих автомобилей.","Оба водителя не нарушают Правила дорожного движения."],"c":1,"e":"<p>Согласно Правилам дорожного движения, действие дорожного знака 3.24.1 «Ограничение максимальной скорости» , установленного перед населённым пунктом, обозначенным дорожным знаком 5.22.1 «Начало населённого пункта» , распространяется до этого знака. В населённых пунктах разрешается движение транспортных средств со скоростью не более 60 км/ч. В показанной ситуации водитель красного автомобиля движется в населённом пункте со скоростью 70 км/ч, поэтому нарушает. Водитель жёлтого автомобиля движется в зоне действия дорожного знака 3.24.1 «Ограничение максимальной скорости» с разрешённой скоростью.</p>","image":"assets/adrive-questions/q101100801.jpg"},{"id":101100802,"themeId":4,"group":1011008,"chapter":11,"chapters":[11],"q":"Скорость обоих автомобилей в показанной ситуации составляет 60 км/ч. Кто из водителей в данный момент нарушает Правила дорожного движения?","a":["Водитель жёлтого автомобиля.","Водитель красного автомобиля.","Водители обоих автомобилей.","Оба водителя не нарушают Правила дорожного движения."],"c":0,"e":"<p>Согласно Правилам дорожного движения, действие дорожного знака 3.24.1 «Ограничение максимальной скорости» , установленного перед населённым пунктом, обозначенным знаком 5.22.1 «Начало населённого пункта» , распространяется до этого знака. В населённых пунктах разрешается движение транспортных средств со скоростью не более 60 км/ч. В показанной ситуации водитель красного автомобиля движется в населённом пункте со скоростью 60 км/ч, поэтому не нарушает. Водитель жёлтого автомобиля движется в зоне действия дорожного знака 3.24.1 «Ограничение максимальной скорости» со скоростью 60 км/ч, поэтому он нарушает Правила дорожного движения.</p>","image":"assets/adrive-questions/q101100802.jpg"},{"id":101100901,"themeId":4,"group":1011009,"chapter":11,"chapters":[11],"q":"С какой максимальной скоростью разрешается буксировка автомобиля в населённом пункте?","a":["20 км/ч.","50 км/ч.","60 км/ч.","70 км/ч.","90 км/ч."],"c":1,"e":"<p>Согласно Правилам дорожного движения, транспортным средствам, буксирующим механические транспортные средства, разрешается движение со скоростью не более 50 км/ч.<br> Ограничение верхнего предела скорости при буксировке (независимо от вида сцепки) величиной в 50 км/ч позволяет гарантированно иметь короткий тормозной путь и обеспечить в необходимых случаях безопасность дорожного движения.</p>","image":"assets/adrive-questions/q101100901.jpg"},{"id":101100902,"themeId":4,"group":1011009,"chapter":11,"chapters":[11],"q":"Разрешается ли повысить скорость движения с 50 км/ч до 60 км/ч при буксировке автомобиля после въезда в населённый пункт?","a":["Да, разрешается.","Нет, не разрешается."],"c":1,"e":"<p>Согласно Правилам дорожного движения, транспортным средствам, буксирующим механические транспортные средства, разрешается движение со скоростью не более 50 км/ч.<br> Ограничение верхнего предела скорости при буксировке (независимо от вида сцепки) величиной в 50 км/ч позволяет гарантированно иметь короткий тормозной путь и обеспечить в необходимых случаях безопасность дорожного движения.</p>","image":"assets/adrive-questions/q101100902.jpg"},{"id":101101001,"themeId":4,"group":1011010,"chapter":11,"chapters":[11],"q":"Как следует поступить в показанной ситуации, управляя легковым автомобилем?","a":["Объехать по встречной полосе выбегающего пешехода, подав звуковой сигнал.","Съехать с дороги вправо, предотвратив таким образом дорожно-транспортное происшествие.","Немедленно принять меры к снижению скорости движения, вплоть до остановки транспортного средства."],"c":2,"e":"<p>При возникновении препятствия или опасности для движения, которые водитель в состоянии обнаружить, он обязан немедленно принять меры к снижению скорости движения, вплоть до остановки транспортного средства.<br> Объезд препятствия на высокой скорости может привести к опрокидыванию автомобиля.</p> <p>Кроме того, сложно предугадать поведение пешехода в стрессовой ситуации: он побежит или остановится, а может он попытается вернуться назад.</p>","image":"assets/adrive-questions/q101101001.jpg"},{"id":101101002,"themeId":4,"group":1011010,"chapter":11,"chapters":[11],"q":"Как Вы должны поступить в показанной ситуации, управляя легковым автомобилем?","a":["Увеличить скорость движения.","Перестроиться на правую полосу движения.","Принять меры к снижению скорости движения, вплоть до остановки.","Перестроиться на левую полосу движения, объехав пешеходов слева.","Перестроиться на правую полосу движения с увеличением скорости движения."],"c":2,"e":"<p>При возникновении препятствия или опасности для движения, которые водитель в состоянии обнаружить, он обязан немедленно принять меры к снижению скорости движения, вплоть до остановки транспортного средства.</p> <p>Резкое перестроение может спровоцировать столкновение с попутно движущимися транспортными средствами в соседних полосах движения. Кроме того, сложно предугадать возможные действия пешеходов, попавших в опасную ситуацию, особенно детей.</p>","image":"assets/adrive-questions/q101101002.jpg"},{"id":101101101,"themeId":4,"group":1011011,"chapter":11,"chapters":[11],"q":"Вы управляете легковым автомобилем, двигаясь по дороге в населённом пункте. С какой максимальной скоростью разрешается движение в показанной ситуации?","a":["20 км/ч.","50 км/ч.","60 км/ч.","70 км/ч.","90 км/ч."],"c":2,"e":"<p>Согласно Правилам дорожного движения, в населённых пунктах разрешается движение транспортных средств со скоростью не более 60 км/ч. В населённых пунктах на отдельных участках могут вводиться изменения скорости движения (уменьшения или увеличения относительно величины 60 км/ч).</p>","image":"assets/adrive-questions/q101101101.jpg"},{"id":101101102,"themeId":4,"group":1011011,"chapter":11,"chapters":[11],"q":"С какой максимальной скоростью разрешается движение мотоциклисту в показанной ситуации?","a":["20 км/ч.","50 км/ч.","60 км/ч.","70 км/ч.","90 км/ч."],"c":2,"e":"<p>В показанной ситуации водитель движется в зоне действия дорожного знака «5.22.1 Начало населённого пункта» , который информирует водителя о действии специальных Правил в населённом пункте.<br> Согласно Правилам дорожного движения, в населённых пунктах разрешается движение транспортных средств со скоростью не более 60 км/ч.</p>","image":"assets/adrive-questions/q101101102.jpg"},{"id":101101301,"themeId":4,"group":1011013,"chapter":11,"chapters":[11],"q":"С какой максимальной скоростью разрешается движение легковому автомобилю с прицепом по дороге в населённом пункте?","a":["20 км/ч.","50 км/ч.","60 км/ч.","70 км/ч.","90 км/ч."],"c":2,"e":"<p>В показанной ситуации легковой автомобиль с прицепом движется в населённом пункте.<br> Согласно Правилам дорожного движения, в населённых пунктах разрешается движение транспортных средств со скоростью не более 60 км/ч.</p>","image":"assets/adrive-questions/q101101301.jpg"},{"id":101101302,"themeId":4,"group":1011013,"chapter":11,"chapters":[11],"q":"Нарушает ли Правила дорожного движения водитель грузового автомобиля с технически допустимой общей массой не более 3.5 тонны при движении с прицепом со скоростью 60 км/ч по дороге, обозначенной таким дорожным знаком?","a":["Да, нарушает.","Нет, не нарушает."],"c":1,"e":"<p>В показанной ситуации водитель движется на грузовом автомобиле с прицепом в населённом пункте.<br> Согласно Правилам дорожного движения, в населённых пунктах разрешается движение транспортных средств со скоростью не более 60 км/ч.</p>","image":"assets/adrive-questions/q101101302.jpg"},{"id":101101401,"themeId":4,"group":1011014,"chapter":11,"chapters":[11],"q":"С какой максимальной скоростью разрешается буксировка механического транспортного средства в населённых пунктах?","a":["20 км/ч.","50 км/ч.","60 км/ч.","70 км/ч.","90 км/ч."],"c":1,"e":"<p>Согласно Правилам дорожного движения, транспортным средствам, буксирующим механические транспортные средства, разрешается движение со скоростью не более 50 км/ч. Ограничение верхнего предела скорости при буксировке (независимо от вида сцепки) величиной в 50 км/ч позволяет гарантированно иметь короткий тормозной путь и обеспечить в необходимых случаях безопасность дорожного движения.</p>","image":null},{"id":101101402,"themeId":4,"group":1011014,"chapter":11,"chapters":[11],"q":"С какой максимальной скоростью разрешается буксировка прицепа в населённых пунктах?","a":["20 км/ч.","50 км/ч.","60 км/ч.","70 км/ч.","90 км/ч."],"c":2,"e":"<p>Согласно Правилам дорожного движения, автобусам, легковым и грузовым автомобилям при их движении с прицепом, грузовым автомобилям с технически допустимой общей массой более 3.5 тонны на автомагистралях — не более 90 км/ч, на остальных дорогах — не более 70 км/ч. Однако в населённых пунктах разрешается движение транспортных средств со скоростью не более 60 км/ч. Поэтому движение с прицепом в населённом пункте разрешается со скоростью не более 60 км/ч.</p>","image":null},{"id":101101471,"themeId":4,"group":1011014,"chapter":11,"chapters":[11],"q":"Разрешено ли движение на мотоблоке с прицепом в населённом пункте так, как в показанной ситуации?","a":["Нет, не разрешено.","Разрешено, если движение не осуществляется по проезжей части дороги далее 1 метра от её правого края."],"c":1,"e":"<p>В населённых пунктах скорость движения транспортных средств не превышает 60 км/ч. Поэтому движение на мотоблоке с прицепом <strong>разрешается</strong> в светлое время суток по обочине дороги, а при отсутствии обочины — по проезжей части дороги <strong>не далее 1 метра от её правого края</strong>.</p>","image":"assets/adrive-questions/q101101471.jpg"},{"id":101101631,"themeId":4,"group":1011016,"chapter":11,"chapters":[11],"q":"Каким из показанных транспортных средств разрешается движение по автомагистрали с максимальной скоростью 120 км/ч?","a":["Только мотоциклу.","Только грузовому автомобилю с технически допустимой общей массой не более 3.5 тонны.","Грузовому автомобилю с технически допустимой общей массой более 3.5 тонны с полуприцепом, участвующему в международном движении.","Грузовому автомобилю с технически допустимой общей массой не более 3.5 тонны и мотоциклу."],"c":3,"e":"<p>Мотоциклам, легковым автомобилям и грузовым автомобилям с технически допустимой общей массой не более 3.5 тонны на автомагистралях разрешается движение со скоростью не более 120 км/ч.<br> Грузовым автомобилям с прицепом (полуприцепом) на таких дорогах разрешается движение не более 100 км/ч.<br> Ограничение верхнего предела скорости для грузовых автомобилей более 3.5 тонн, в том числе — автопоездам, величиной 100 км/ч связано с их конструктивными особенностями (относительно большие габаритные размеры, высоко расположенный центр тяжести и тому подобное).</p>","image":"assets/adrive-questions/q101101631.jpg"},{"id":101101632,"themeId":4,"group":1011016,"chapter":11,"chapters":[11],"q":"Каким из показанных транспортных средств разрешается движение по автомагистрали с максимальной скоростью 120 км/ч?","a":["Только автобусу.","Только легковому автомобилю.","Только легковому автомобилю с прицепом.","Только легковому автомобилю и автобусу.","Всем перечисленным транспортным средствам."],"c":1,"e":"<p>Мотоциклам, легковым автомобилям и грузовым автомобилям с технически допустимой общей массой не более 3.5 тонны на автомагистралях разрешается движение не более 120 км/ч.<br> Легковым автомобилям при их движении с прицепом разрешается движение на автомагистралях не более 100 км/ч. Движение с прицепом усложняет управление автомобиля.<br> С увеличением скорости движения увеличивается тормозной путь и снижается курсовая устойчивость. Ограничение верхнего предела скорости для автобусов величиной 100 км/ч связано с их конструктивными особенностями (относительно большие габаритные размеры, высоко расположенный центр тяжести и тому подобное) и большим числом пассажиров.</p>","image":"assets/adrive-questions/q101101632.jpg"},{"id":101101701,"themeId":4,"group":1011017,"chapter":11,"chapters":[11],"q":"С какой максимальной скоростью разрешается движение легковому автомобилю на участке дороги, где установлен такой дорожный знак?","a":["20 км/ч.","50 км/ч.","60 км/ч.","70 км/ч.","90 км/ч."],"c":2,"e":"<p>На показанной картинке изображён дорожный знак 5.22.2 «Начало населённого пункта» , который информирует водителя о действии специальных требований Правил дорожного движения в населённом пункте.<br> Согласно Правилам дорожного движения, в населённых пунктах разрешается движение транспортных средств со скоростью не более 60 км/ч.</p>","image":"assets/adrive-questions/q101101701.jpg"},{"id":101101702,"themeId":4,"group":1011017,"chapter":11,"chapters":[11],"q":"С какой максимальной скоростью разрешается движение легковому автомобилю на участке дороги (не являющейся дорогой для автомобилей), где установлен такой дорожный знак?","a":["50 км/ч.","60 км/ч.","70 км/ч.","90 км/ч.","110 км/ч."],"c":3,"e":"<p>Если перед населённым пунктом установлен дорожный знак «5.24 Начало границы населённого пункта» , то ограничение скорости верхним пределом 60 км/ч на этой дороге не действует. На таком участке дороги будет действовать верхний предел скорости как вне населённого пункта, то есть 90 км/ч (если это не дорога для автомобилей).</p> <p>Однако при съезде с этой дороги на другие дороги данного населённого пункта водитель транспортного средства должен придерживаться всех ограничений, которые определены Правилами дорожного движения для населённых пунктов.</p>","image":"assets/adrive-questions/q101101702.jpg"},{"id":101101761,"themeId":4,"group":1011017,"chapter":11,"chapters":[11],"q":"С какой максимальной скоростью Вам разрешается продолжить движение в показанной ситуации за дорожными знаками при управлении легковым автомобилем вне населённого пункта?","a":["60 км/ч.","70 км/ч.","90 км/ч.","120 км/ч."],"c":2,"e":"<p>Ограничение максимальной скорости, обозначенное на дорожном знаке, действует только в ночное время. Поэтому в светлое время суток Вам двигаться разрешено со скоростью <strong>до 90 км/ч</strong>. При этом с<strong>облюдайте осторожность</strong> на аварийно-опасном участке дороги.</p>","image":"assets/adrive-questions/q101101761.jpg"},{"id":101101801,"themeId":4,"group":1011018,"chapter":11,"chapters":[11],"q":"С какой максимальной скоростью разрешается двигаться по дороге (не являющейся дорогой для автомобилей), обозначенной таким дорожным знаком, грузовому автомобилю, если его технически допустимая общая масса не превышает 3.5 тонны?","a":["50 км/ч.","60 км/ч.","70 км/ч.","90 км/ч.","110 км/ч."],"c":3,"e":"<p>Если на дороге, не являющейся дорогой для автомобилей, перед населённым пунктом установлен дорожный знак 5.24 «Начало границы населённого пункта» , то ограничение скорости верхним пределом 60 км/ч на этой дороге не действует. Однако при съезде с этой дороги на другие дороги данного населённого пункта водитель транспортного средства должен придерживаться всех ограничений, которые определены Правилами дорожного движения для населённых пунктов.<br> Поэтому на таком участке дороги для грузового автомобиля с технически допустимой общей массой не более 3.5 тонны будет действовать верхний предел скорости как вне населённого пункта, то есть 90 км/ч.</p>","image":"assets/adrive-questions/q101101801.jpg"},{"id":101101802,"themeId":4,"group":1011018,"chapter":11,"chapters":[11],"q":"Нарушает ли Правила дорожного движения водитель грузового автомобиля с технически допустимой общей массой не более 3.5 тонны, двигаясь в показанной обстановке со скоростью 80 км/ч по дороге, не являющейся дорогой для автомобилей?","a":["Да, нарушает.","Нет, не нарушает."],"c":1,"e":"<p>Если на дороге, не являющейся дорогой для автомобилей, перед населённым пунктом установлен дорожный знак 5.24 «Начало границы населённого пункта» , то ограничение скорости верхним пределом 60 км/ч на этой дороге не действует. Однако при съезде с этой дороги на другие дороги данного населённого пункта водитель транспортного средства должен придерживаться всех ограничений, которые определены Правилами дорожного движения для населённых пунктов.<br> Поэтому на таком участке дороги для грузового автомобиля с технически допустимой общей массой не более 3.5 тонны будет действовать верхний предел скорости как вне населённого пункта, то есть 90 км/ч.</p>","image":"assets/adrive-questions/q101101802.jpg"},{"id":101101901,"themeId":4,"group":1011019,"chapter":11,"chapters":[11],"q":"С какой максимальной скоростью разрешается движение легковому автомобилю в показанной ситуации по дороге, не являющейся дорогой для автомобилей?","a":["50 км/ч.","60 км/ч.","70 км/ч.","90 км/ч.","110 км/ч."],"c":3,"e":"<p>Если на дороге, не являющейся дорогой для автомобилей, перед населённым пунктом установлен дорожный знак 5.24 «Начало границы населённого пункта» , то ограничение скорости верхним пределом 60 км/ч на этой дороге не действует. Однако при съезде с этой дороги на другие дороги данного населённого пункта водитель ТС должен придерживаться всех ограничений, которые определены Правилами дорожного движения для населённых пунктов.<br> Поэтому на таком участке дороги для легкового автомобиля будет действовать верхний предел скорости как вне населённого пункта, то есть 90 км/ч.</p>","image":"assets/adrive-questions/q101101901.jpg"},{"id":101101902,"themeId":4,"group":1011019,"chapter":11,"chapters":[11],"q":"Нарушает ли Правила дорожного движения водитель легкового автомобиля, двигаясь со скоростью 120 км/ч по дороге, на которую не распространяются требования, установленные для движения по автомагистралям и дорогам для автомобилей?","a":["Да, нарушает.","Нет, не нарушает."],"c":0,"e":"<p>Если перед населённым пунктом установлен дорожный знак «5.24 Начало границы населённого пункта» , то ограничение скорости до 60 км/ч на этой дороге не действует. На таком участке на дороге, не являющейся автомагистралью и дорогой для автомобилей, для легкового автомобиля будет действовать верхний предел скорости — 90 км/ч.</p> <p>Однако при съезде с этой дороги на другие дороги данного населённого пункта водитель транспортного средства должен придерживаться всех ограничений, которые определены Правилами дорожного движения для населённых пунктов.</p>","image":"assets/adrive-questions/q101101902.jpg"},{"id":101102001,"themeId":4,"group":1011020,"chapter":11,"chapters":[11],"q":"С какой максимальной скоростью разрешается движение вне населённого пункта при управлении легковым автомобилем (кроме автомагистралей и дорог для автомобилей)?","a":["50 км/ч.","60 км/ч.","70 км/ч.","90 км/ч.","110 км/ч."],"c":3,"e":"<p>В показанной ситуации Вы движетесь вне населённого пункта.<br> Согласно Правилам дорожного движения, вне населённых пунктов разрешается движение со скоростью не более 90 км/ч.</p>","image":"assets/adrive-questions/q101102001.jpg"},{"id":101102002,"themeId":4,"group":1011020,"chapter":11,"chapters":[11],"q":"Нарушает ли Правила дорожного движения водитель легкового автомобиля, двигаясь со скоростью 100 км/ч по дороге, не являющейся автомагистралью и дорогой для автомобилей?","a":["Да, нарушает.","Нет, не нарушает."],"c":0,"e":"<p>В показанной ситуации водитель легкового автомобиля движется вне населённого пункта.<br> Согласно Правилам дорожного движения, вне населённых пунктов разрешается движение со скоростью не более 90 км/ч.</p>","image":"assets/adrive-questions/q101102002.jpg"},{"id":101102062,"themeId":4,"group":1011020,"chapter":11,"chapters":[11],"q":"С какой максимальной скоростью Вам при управлении легковым автомобилем разрешается движение после проезда показанного дорожного знака?","a":["50 км/ч.","60 км/ч.","70 км/ч.","90 км/ч."],"c":3,"e":"<p>Вы выезжаете из населённого пункта. Далее на показанной дороге, двигаясь на легковом автомобиле, Вам следует не превышать скорость <strong>90 км/ч</strong>.</p>","image":"assets/adrive-questions/q101102062.jpg"},{"id":101102101,"themeId":4,"group":1011021,"chapter":11,"chapters":[11],"q":"Водитель какого автомобиля нарушает Правила дорожного движения, двигаясь в показанной обстановке по автомагистрали со скоростью 110 км/ч?","a":["Водитель легкового автомобиля.","Водитель легкового автомобиля с прицепом.","Водитель грузового автомобиля с технически допустимой общей массой не более 3.5 тонны.","Водители всех транспортных средств нарушают Правила дорожного движения, двигаясь с указанной скоростью.","Никто из водителей не нарушает Правила дорожного движения, двигаясь с указанной скоростью."],"c":1,"e":"<p>Согласно Правилам дорожного движения, легковым автомобилям и грузовым автомобилям с технически допустимой общей массой не более 3.5 тонны на автомагистралях разрешается движение не более 120 км/ч. Легковым автомобилям при их движении с прицепом разрешается движение на автомагистралях не более 100 км/ч. Движение с прицепом усложняет управление автомобиля. С увеличением скорости движения увеличивается тормозной путь и снижается курсовая устойчивость по сравнению с одиночным (без прицепа) механическим ТС.</p>","image":"assets/adrive-questions/q101102101.jpg"},{"id":101102132,"themeId":4,"group":1011021,"chapter":11,"chapters":[11],"q":"Водитель какого транспортного средства нарушает Правила дорожного движения, двигаясь в показанной обстановке по автомагистрали со скоростью 100 км/ч?","a":["Водитель мотоцикла.","Водитель легкового автомобиля.","Водитель грузового автомобиля с технически допустимой общей массой не более 3.5 тонны.","Водитель мотоцикла и водитель грузового автомобиля с технически допустимой общей массой не более 3.5 тонны.","Никто из водителей не нарушает Правила дорожного движения, двигаясь с указанной скоростью."],"c":4,"e":"<p>Мотоциклам, легковым автомобилям и грузовым автомобилям с технически допустимой общей массой не более 3.5 тонны на автомагистралях разрешается движение не более 120 км/ч.</p>","image":"assets/adrive-questions/q101102132.jpg"},{"id":101102201,"themeId":4,"group":1011022,"chapter":11,"chapters":[11],"q":"С какой максимальной скоростью разрешается движение легкового автомобиля с прицепом по дороге, не являющейся дорогой для автомобилей, на которой установлен такой дорожный знак?","a":["50 км/ч.","60 км/ч.","70 км/ч.","90 км/ч.","120 км/ч."],"c":2,"e":"<p>Если на дороге, не являющейся дорогой для автомобилей, перед населённым пунктом установлен дорожный знак 5.24 «Начало границы населённого пункта» , то ограничение скорости верхним пределом 60 км/ч на этой дороге не действует. Однако при съезде с этой дороги на другие дороги данного населённого пункта водитель транспортного средства должен придерживаться всех ограничений, которые определены Правилами для населённых пунктов.<br> Поэтому на таком участке дороги будет действовать верхний предел скорости как вне населённого пункта для движения легкового автомобиля с прицепом, то есть 70 км/ч.</p>","image":"assets/adrive-questions/q101102201.jpg"},{"id":101102202,"themeId":4,"group":1011022,"chapter":11,"chapters":[11],"q":"С какой максимальной скоростью разрешается движение легкового автомобиля при буксировке прицепа по дороге, не являющейся дорогой для автомобилей, на которой установлен такой дорожный знак?","a":["50 км/ч.","60 км/ч.","70 км/ч.","90 км/ч.","120 км/ч."],"c":2,"e":"<p>Если перед населённым пунктом установлен дорожный знак 5.24 «Начало границы населённого пункта» , то ограничение скорости верхним пределом 60 км/ч на этой дороге не действует. Однако при съезде с этой дороги на другие дороги данного населённого пункта водитель транспортного средства должен придерживаться всех ограничений, которые определены Правилами для населённых пунктов.<br> Поэтому на таком участке дороги, не являющейся дорогой для автомобилей, будет действовать верхний предел скорости как вне населённого пункта для движения легкового автомобиля с прицепом, то есть 70 км/ч.</p>","image":"assets/adrive-questions/q101102202.jpg"},{"id":101102401,"themeId":4,"group":1011024,"chapter":11,"chapters":[11],"q":"Кто из водителей нарушает Правила дорожного движения, двигаясь по дороге, обозначенной таким дорожным знаком, со скоростью 80 км/ч?","a":["Мотоциклист.","Водитель легкового автомобиля с прицепом.","Водитель грузового автомобиля с технически допустимой общей массой не более 3.5 тонны.","Никто из водителей не нарушает Правила дорожного движения."],"c":3,"e":"<p>Согласно Правилам дорожного движения мотоциклам, легковым автомобилям и грузовым автомобилям с технически допустимой общей массой не более 3.5 тонны на автомагистралях разрешается движение не более 120 км/ч.<br> Легковым автомобилям при их движении с прицепом разрешается движение на автомагистралях не более 100 км/ч.</p>","image":"assets/adrive-questions/q101102401.jpg"},{"id":101102432,"themeId":4,"group":1011024,"chapter":11,"chapters":[11],"q":"Нарушает ли кто-нибудь из водителей  в показанной ситуации Правила дорожного движения, двигаясь по дороге, обозначенной таким дорожным знаком, со скоростью 120 км/ч?","a":["Только мотоциклист.","Только водитель легкового автомобиля.","Только водитель грузового автомобиля с технически допустимой общей массой не более 3.5 тонны.","Нарушают все водители.","Никто из водителей не нарушает Правила дорожного движения."],"c":4,"e":"<p>Мотоциклам, легковым автомобилям и грузовым автомобилям с технически допустимой общей массой не более 3.5 тонны на автомагистралях разрешается движение не более 120 км/ч.</p>","image":"assets/adrive-questions/q101102432.jpg"},{"id":101102631,"themeId":4,"group":1011026,"chapter":11,"chapters":[11],"q":"С какой максимальной скоростью разрешается движение легковому автомобилю по автомагистрали, если максимальная скорость, определённая его технической характеристикой, составляет 160 км/ч?","a":["90 км/ч.","100 км/ч.","110 км/ч.","120 км/ч.","160 км/ч."],"c":3,"e":"<p>Легковым автомобилям на автомагистралях разрешается движение со скоростью не более 120 км/ч.</p>","image":null},{"id":101102632,"themeId":4,"group":1011026,"chapter":11,"chapters":[11],"q":"С какой максимальной скоростью разрешается движение грузовому автомобилю с технически допустимой общей массой не более 3.5 тонны по автомагистрали?","a":["60 км/ч.","70 км/ч.","90 км/ч.","110 км/ч.","120 км/ч."],"c":4,"e":"<p>Грузовым автомобилям с технически допустимой общей массой не более 3.5 тонны на автомагистралях разрешается движение со скоростью не более 120 км/ч.</p>","image":"assets/adrive-questions/q101102632.jpg"},{"id":101102633,"themeId":4,"group":1011026,"chapter":11,"chapters":[11],"q":"С какой максимальной скоростью разрешается двигаться по дороге, обозначенной дорожным знаком «Дорога для автомобилей», водителю легкового автомобиля в показанной ситуации?","a":["90 км/ч.","100 км/ч.","110 км/ч.","120 км/ч."],"c":3,"e":"<p>Легковым автомобилям на автомагистралях и дорогах для автомобилей разрешено осуществлять движение со скоростью не более 120 км/ч.</p>","image":"assets/adrive-questions/q101102633.jpg"},{"id":101102634,"themeId":4,"group":1011026,"chapter":11,"chapters":[11],"q":"С какой максимальной скоростью разрешается движение грузовому автомобилю с технически допустимой общей массой не более 3.5 тонны в показанной ситуации?","a":["70 км/ч.","80 км/ч.","90 км/ч.","110 км/ч.","120 км/ч."],"c":4,"e":"<p>Грузовым автомобилям с технически допустимой общей массой не более 3.5 тонны на автомагистралях и дорогах для автомобилей разрешается движение со скоростью не более 120 км/ч.</p>","image":"assets/adrive-questions/q101102634.jpg"},{"id":101102731,"themeId":4,"group":1011027,"chapter":11,"chapters":[11],"q":"Каким из нижеперечисленных транспортных средств разрешено движение по автомагистрали со скоростью 120 км/ч?","a":["Автобусам.","Легковым автомобилям при движении с прицепом.","Грузовым автомобилям с технически допустимой общей массой не более 3.5 тонны.","Грузовым автомобилям с технически допустимой общей массой не более 3.5 тонны при движении с прицепом.","Запрещено всем перечисленным."],"c":2,"e":"<p>Мотоциклам, легковым автомобилям и грузовым автомобилям с технически допустимой общей массой не более 3.5 тонны на автомагистралях разрешается движение со скоростью не более 120 км/ч.<br> Легковым автомобилям при их движении с прицепом разрешается движение на автомагистралях — не более 100 км/ч. Движение с прицепом усложняет управление автомобилем. С увеличением скорости движения увеличивается тормозной путь и снижается курсовая устойчивость.<br> Автобусам на таких дорогах разрешается движение со скоростью не более 100 км/ч.</p>","image":null},{"id":101102732,"themeId":4,"group":1011027,"chapter":11,"chapters":[11],"q":"Каким из нижеперечисленных транспортных средств разрешено движение по автомагистрали со скоростью 120 км/ч?","a":["Автобусам.","Мотоциклам с боковым прицепом.","Легковым автомобилям при движении с прицепом.","Грузовым автомобилям с технически допустимой общей массой не более 3.5 тонны при движении с прицепом.","Запрещено всем перечисленным."],"c":1,"e":"<p>Мотоциклам разрешается осуществлять движение по автомагистрали со скоростью не более 120 км/ч. Наличие или отсутствие бокового прицепа у мотоцикла не имеет значения.</p> <p>Автобусам на таких дорогах разрешается движение со скоростью не более 100 км/ч.</p> <p>Легковым и грузовым автомобилям при их движении с прицепом разрешается движение на автомагистралях со скоростью не более 100 км/ч. Движение с прицепом усложняет управление автомобилем.</p>","image":null},{"id":101102903,"themeId":4,"group":1011029,"chapter":11,"chapters":[11],"q":"С какой максимальной скоростью Вам, управляя легковым автомобилем, разрешено осуществлять движение по дороге, не являющейся автомагистралью, если Ваш водительский стаж составляет менее двух лет?","a":["50 км/ч.","60 км/ч.","70 км/ч.","80 км/ч.","90 км/ч."],"c":2,"e":"<p>Механическим транспортным средствам, управляемым водителями с водительским стажем до двух лет, движение по дорогам разрешено со скоростью не более 70 км/ч.</p>","image":"assets/adrive-questions/q101102903.jpg"},{"id":101102932,"themeId":4,"group":1011029,"chapter":11,"chapters":[11],"q":"С какой максимальной скоростью разрешается движение по автомагистрали легкового автомобиля, управляемого водителем с водительским стажем более двух лет?","a":["60 км/ч.","70 км/ч.","90 км/ч.","110 км/ч.","120 км/ч."],"c":4,"e":"<p>Легковым автомобилям на автомагистралях разрешается движение со скоростью не более 120 км/ч.</p>","image":null},{"id":101103101,"themeId":4,"group":1011031,"chapter":11,"chapters":[11],"q":"Каким из перечисленных транспортных средств разрешается движение по автомагистрали со скоростью 90 км/ч?","a":["Только мотоциклам.","Только легковым автомобилям.","Только грузовым автомобилям с технически допустимой общей массой не более 3.5 тонны.","Всем перечисленным."],"c":3,"e":"<p>Все перечисленные транспортные средства могут осуществлять движение по автомагистрали со скоростью 90 км/ч.</p>","image":null},{"id":101103102,"themeId":4,"group":1011031,"chapter":11,"chapters":[11],"q":"Каким из перечисленных транспортных средств разрешается движение по автомагистрали со скоростью 100 км/ч?","a":["Только легковым автомобилям.","Только легковым автомобилям при их движении с прицепом.","Только грузовым автомобилям с технически допустимой общей массой не более 3.5 тонны.","Всем перечисленным."],"c":3,"e":"<p>Согласно Правилам дорожного движения мотоциклам, легковым автомобилям и грузовым автомобилям с технически допустимой общей массой не более 3.5 тонны на автомагистралях разрешается движение не более 120 км/ч, легковым автомобилям при их движении с прицепом на автомагистралях — не более 100 км/ч.<br> Поэтому все перечисленные транспортные средства могут осуществлять движение по автомагистрали со скоростью 100 км/ч.</p>","image":null},{"id":101103202,"themeId":4,"group":1011032,"chapter":11,"chapters":[11],"q":"Каким из перечисленных транспортных средств разрешается движение по автомагистрали со скоростью 100 км/ч?","a":["Только легковым автомобилям.","Только легковым автомобилям при их движении с прицепом.","Только грузовым автомобилям с технически допустимой общей массой не более 3.5 тонны при их движении с прицепом.","Всем перечисленным."],"c":3,"e":"<p>Все перечисленные транспортные средства могут осуществлять движение по автомагистрали со скоростью 100 км/ч.</p>","image":null},{"id":101103231,"themeId":4,"group":1011032,"chapter":11,"chapters":[11],"q":"Каким из перечисленных транспортных средств разрешается движение по автомагистрали с максимальной скоростью 100 км/ч?","a":["Мотоциклам.","Легковым автомобилям с прицепом.","Грузовым автомобилям с технически допустимой общей массой не более 3.5 тонны.","Всем перечисленным."],"c":1,"e":"<p>Максимальная скорость движения по автомагистрали в 100 км/ч установлена для автопоездов, в том числе для легковых автомобилей с прицепом. Мотоциклам, легковым автомобилям и грузовым автомобилям с технически допустимой общей массой не более 3.5 тонны на автомагистралях разрешается движение с максимальной скоростью до 120 км/ч.</p>","image":null},{"id":101103301,"themeId":4,"group":1011033,"chapter":11,"chapters":[11],"q":"С какой максимальной скоростью разрешено движение мотоциклисту по дороге вне населённых пунктов (за исключением автомагистралей и дорог для автомобилей)?","a":["60 км/ч.","70 км/ч.","90 км/ч.","110 км/ч.","120 км/ч."],"c":2,"e":"<p>Мотоциклам в описанных условиях разрешается движение со скоростью не более 90 км/ч. Ограничение максимальной скорости для мотоциклов введено из-за сложности управления ими при больших скоростях, а также из-за их низкой устойчивости в случае экстренного торможения или возникшего заноса.</p>","image":"assets/adrive-questions/q101103301.jpg"},{"id":101103302,"themeId":4,"group":1011033,"chapter":11,"chapters":[11],"q":"Нарушает ли мотоциклист Правила дорожного движения, двигаясь по дороге, не являющейся ни автомагистралью, ни дорогой для автомобилей, вне населённого пункта со скоростью 100 км/ч?","a":["Да, нарушает.","Нет, не нарушает."],"c":0,"e":"<p>Мотоциклам в описанных условиях разрешается движение со скоростью не более 90 км/ч. Ограничение максимальной скорости для мотоциклов введено из-за сложности управления ими при больших скоростях, а также из-за их низкой устойчивости в случае экстренного торможения или возникшего заноса.</p>","image":"assets/adrive-questions/q101103302.jpg"},{"id":101103303,"themeId":4,"group":1011033,"chapter":11,"chapters":[11],"q":"С какой максимальной скоростью разрешается осуществлять движение водителю мотоцикла с боковым прицепом по дороге, не являющейся автомагистралью и дорогой для автомобилей, вне населённого пункта?","a":["70 км/ч.","80 км/ч.","90 км/ч.","110 км/ч.","120 км/ч."],"c":2,"e":"<p>Вне населённых пунктов мотоциклам разрешается движение со скоростью не более 90 км/ч, как одиночным, так и с боковым прицепом.</p>","image":"assets/adrive-questions/q101103303.jpg"},{"id":101103431,"themeId":4,"group":1011034,"chapter":11,"chapters":[11],"q":"С какой максимальной скоростью разрешено движение мотоциклисту по дороге, обозначенной таким дорожным знаком?","a":["60 км/ч.","70 км/ч.","90 км/ч.","110 км/ч.","120 км/ч."],"c":4,"e":"<p>В показанной ситуации мотоциклист движется по автомагистрали.<br> Мотоциклам на автомагистрали разрешается движение со скоростью не более 120 км/ч.</p>","image":"assets/adrive-questions/q101103431.jpg"},{"id":101103432,"themeId":4,"group":1011034,"chapter":11,"chapters":[11],"q":"Нарушает ли мотоциклист Правила дорожного движения, двигаясь по дороге, обозначенной таким дорожным знаком, со скоростью 110 км/ч?","a":["Да, нарушает.","Нет, не нарушает."],"c":1,"e":"<p>В показанной ситуации мотоциклист движется по автомагистрали.<br> Мотоциклам на автомагистрали разрешается движение со скоростью не более 120 км/ч.</p>","image":"assets/adrive-questions/q101103432.jpg"},{"id":101103501,"themeId":4,"group":1011035,"chapter":11,"chapters":[11],"q":"Кто из водителей нарушает Правила дорожного движения, двигаясь по дороге, на которую не действуют требования, установленные для движения по автомагистрали, вне населённого пункта со скоростью 80 км/ч?","a":["Мотоциклист.","Водитель легкового автомобиля с прицепом.","Оба водителя не нарушают Правила дорожного движения."],"c":1,"e":"<p>Согласно Правилам дорожного движения, легковым автомобилям при их движении с прицепом вне населённых пунктов разрешено движение не более 70 км/ч, мотоциклам вне населённого пункта разрешается движение не более 90 км/ч. Движение с прицепом усложняет управление автомобиля. С увеличением скорости движения увеличивается тормозной путь и снижается курсовая устойчивость по сравнению с одиночным (без прицепа) механическим ТС.</p>","image":"assets/adrive-questions/q101103501.jpg"},{"id":101103502,"themeId":4,"group":1011035,"chapter":11,"chapters":[11],"q":"Нарушает ли кто из водителей Правила дорожного движения, двигаясь по дороге, на которую не действуют требования, установленные для движения по автомагистралям и дорогам для автомобилей, вне населённого пункта со скоростью 80 км/ч?","a":["Мотоциклист.","Водитель легкового автомобиля.","Оба водителя не нарушают Правила дорожного движения."],"c":2,"e":"<p>Согласно Правилам дорожного движения, мотоциклам вне населённого пункта разрешается движение не более 90 км/ч.<br> Легковым автомобилям вне населённых пунктов разрешается движение со скоростью не более 90 км/ч.</p>","image":"assets/adrive-questions/q101103502.jpg"},{"id":101103601,"themeId":4,"group":1011036,"chapter":11,"chapters":[11],"q":"С какой максимальной скоростью разрешается движение легкового автомобиля с прицепом по автомагистрали?","a":["70 км/ч.","90 км/ч.","100 км/ч.","120 км/ч."],"c":2,"e":"<p>Согласно Правилам дорожного движения, легковым автомобилям при их движении с прицепом разрешается движение на автомагистралях не более 100 км/ч.</p> <p>Движение с прицепом усложняет управление автомобилем. С увеличением скорости движения увеличивается тормозной путь и снижается курсовая устойчивость по сравнению с одиночным (без прицепа) механическим транспортным средством.</p>","image":"assets/adrive-questions/q101103601.jpg"},{"id":101103602,"themeId":4,"group":1011036,"chapter":11,"chapters":[11],"q":"Нарушает ли Правила дорожного движения водитель легкового автомобиля с прицепом, двигаясь по автомагистрали со скоростью 110 км/ч?","a":["Да, нарушает.","Нет, не нарушает."],"c":0,"e":"<p>Согласно Правилам дорожного движения, легковым автомобилям при их движении с прицепом разрешается движение на автомагистралях не более 100 км/ч. Движение с прицепом усложняет управление автомобиля. С увеличением скорости движения увеличивается тормозной путь и снижается курсовая устойчивость по сравнению с одиночным (без прицепа) механическим транспортным средством.</p>","image":"assets/adrive-questions/q101103602.jpg"},{"id":101103701,"themeId":4,"group":1011037,"chapter":11,"chapters":[11],"q":"С какой максимальной скоростью разрешается движение грузового автомобиля с технически допустимой общей массой не более 3.5 тонны при его движении с прицепом по автомагистрали?","a":["60 км/ч.","70 км/ч.","90 км/ч.","100 км/ч."],"c":3,"e":"<p>Согласно Правилам дорожного движения, грузовым автомобилям при их движении с прицепом разрешается движение на автомагистралях не более 100 км/ч.</p> <p>Движение с прицепом усложняет управление автомобилем. С увеличением скорости движения увеличивается тормозной путь и снижается курсовая устойчивость по сравнению с одиночным (без прицепа) механическим транспортным средством.</p>","image":"assets/adrive-questions/q101103701.jpg"},{"id":101103702,"themeId":4,"group":1011037,"chapter":11,"chapters":[11],"q":"Нарушает ли Правила дорожного движения водитель грузового автомобиля с технически допустимой общей массой не более 3.5 тонны при его движении с прицепом по автомагистрали со скоростью 110 км/ч?","a":["Да, нарушает.","Нет, не нарушает."],"c":0,"e":"<p>Согласно Правилам дорожного движения, грузовым автомобилям при их движении с прицепом разрешается движение на автомагистралях не более 100 км/ч. Движение с прицепом усложняет управление автомобиля. С увеличением скорости движения увеличивается тормозной путь и снижается курсовая устойчивость по сравнению с одиночным (без прицепа) механическим транспортным средством.</p>","image":"assets/adrive-questions/q101103702.jpg"},{"id":101103801,"themeId":4,"group":1011038,"chapter":11,"chapters":[11],"q":"Водители каких автомобилей не нарушают Правила дорожного движения, если все автомобили двигаются в показанной ситуации со скоростью 110 км/ч?","a":["Только водитель легкового автомобиля без прицепа.","Только водитель легкового автомобиля с прицепом.","Только водитель грузового автомобиля с технически допустимой общей массой не более 3.5 тонны.","Водители легкового автомобиля без прицепа и грузового автомобиля с технически допустимой общей массой не более 3.5 тонны.","Нарушают Правила дорожного движения водители всех автомобилей."],"c":3,"e":"<p>Согласно Правилам дорожного движения, легковым автомобилям и грузовым автомобилям с технически допустимой общей массой не более 3.5 тонны на автомагистралях разрешается движение со скоростью не более 120 км/ч, легковым автомобилям при их движении с прицепом разрешается движение на автомагистралях не более 100 км/ч. Движение с прицепом усложняет управление автомобиля. С увеличением скорости движения увеличивается тормозной путь и снижается курсовая устойчивость по сравнению с одиночным (без прицепа) механическим транспортным средством.</p>","image":"assets/adrive-questions/q101103801.jpg"},{"id":101103802,"themeId":4,"group":1011038,"chapter":11,"chapters":[11],"q":"Кто из водителей не нарушает Правила дорожного движения, двигаясь по дороге, на которую не действуют требования, установленные для движения по автомагистралям и дорогам для автомобилей, вне населённого пункта со скоростью 80 км/ч?","a":["Только водитель легкового автомобиля.","Только водитель легкового автомобиля с прицепом.","Только водитель грузового автомобиля с технически допустимой общей массой не более 3.5 тонны.","Только водители легкового автомобиля и грузового автомобиля с технически допустимой общей массой не более 3.5 тонны.","Водители всех автомобилей не нарушают Правила дорожного движения."],"c":3,"e":"<p>Согласно Правилам дорожного движения, вне населённых пунктов разрешается движение со скоростью легковым автомобилям и грузовым автомобилям с технически допустимой общей массой не более 3.5 тонны не более 90 км/ч, легковым автомобилям при их движении с прицепом разрешается движение вне населённого пункта не более 70 км/ч. Движение с прицепом усложняет управление автомобиля. С увеличением скорости движения увеличивается тормозной путь и снижается курсовая устойчивость по сравнению с одиночным (без прицепа) механическим ТС.</p>","image":"assets/adrive-questions/q101103802.jpg"},{"id":101103901,"themeId":4,"group":1011039,"chapter":11,"chapters":[11],"q":"С какой максимальной скоростью разрешается движение легковому автомобилю с прицепом, управляемому водителем с водительским стажем до двух лет, по автомагистрали?","a":["60 км/ч.","70 км/ч.","90 км/ч.","110 км/ч."],"c":1,"e":"<p>Согласно Правилам дорожного движения, легковым автомобилям с прицепом на автомагистралях разрешается движение со скоростью не более 100 км/ч. Однако водители со стажем управления менее 2 лет не имеют права превышать скорость движения более 70 км/ч. Водители со стажем до 2 лет составляют совсем небольшую долю от общего числа водителей, однако являются виновниками совершения до 20% ДТП.</p>","image":null},{"id":101103902,"themeId":4,"group":1011039,"chapter":11,"chapters":[11],"q":"С какой максимальной скоростью разрешается движение грузовому автомобилю с технически допустимой общей массой не более 3.5 тонны, управляемому водителем с водительским стажем до двух лет, по дороге вне населённого пункта?","a":["60 км/ч.","70 км/ч.","90 км/ч.","110 км/ч."],"c":1,"e":"<p>Согласно Правилам дорожного движения, водители со стажем управления менее 2 лет не имеют права превышать скорость движения более 70 км/ч. Водители со стажем до 2 лет составляют совсем небольшую долю от общего числа водителей, однако являются виновниками совершения до 20% ДТП.</p>","image":null},{"id":101103931,"themeId":4,"group":1011039,"chapter":11,"chapters":[11],"q":"С какой максимальной скоростью разрешается двигаться по дороге, обозначенной дорожным знаком «Дорога для автомобилей», водителю легкового автомобиля с водительским стажем до двух лет в показанной ситуации?","a":["70 км/ч.","90 км/ч.","100 км/ч.","110 км/ч.","120 км/ч."],"c":0,"e":"<p>Автомобилям, управляемым водителями с водительским стажем до двух лет, разрешается движение по дорогам со скоростью не более 70 км/ч.</p>","image":"assets/adrive-questions/q101103931.jpg"},{"id":101104001,"themeId":4,"group":1011040,"chapter":11,"chapters":[11],"q":"С какой максимальной скоростью разрешается движение автомобилей при осуществлении буксировки вне населённого пункта?","a":["20 км/ч.","50 км/ч.","60 км/ч.","70 км/ч.","90 км/ч."],"c":1,"e":"<p>Согласно Правилам дорожного движения, транспортным средствам, буксирующим механические транспортные средства, разрешается движение со скоростью не более 50 км/ч.<br> Ограничение верхнего предела скорости при буксировке (независимо от вида сцепки) величиной в 50 км/ч позволяет гарантированно иметь короткий тормозной путь и обеспечить в необходимых случаях безопасность дорожного движения.</p>","image":"assets/adrive-questions/q101104001.jpg"},{"id":101104002,"themeId":4,"group":1011040,"chapter":11,"chapters":[11],"q":"С какой максимальной скоростью разрешается движение автомобилей при буксировке в показанной ситуации?","a":["20 км/ч.","50 км/ч.","60 км/ч.","70 км/ч.","90 км/ч."],"c":1,"e":"<p>Согласно Правилам дорожного движения, транспортным средствам, буксирующим механические транспортные средства, разрешается движение со скоростью не более 50 км/ч.<br> Ограничение верхнего предела скорости при буксировке (независимо от вида сцепки) величиной в 50 км/ч позволяет гарантированно иметь короткий тормозной путь и обеспечить в необходимых случаях безопасность дорожного движения.</p>","image":"assets/adrive-questions/q101104002.jpg"},{"id":101104201,"themeId":4,"group":1011042,"chapter":11,"chapters":[11],"q":"С какой максимальной скоростью разрешается движение автомобилей при буксировке вне населённого пункта в показанной ситуации?","a":["20 км/ч.","50 км/ч.","60 км/ч.","70 км/ч.","90 км/ч."],"c":1,"e":"<p>Согласно Правилам дорожного движения, транспортным средствам, буксирующим механические транспортные средства, разрешается движение со скоростью не более 50 км/ч.<br> Ограничение верхнего предела скорости при буксировке (независимо от вида сцепки) величиной в 50 км/ч позволяет гарантированно иметь короткий тормозной путь и обеспечить в необходимых случаях безопасность дорожного движения. Причём это ограничение сохраняется повсеместно, включая населённые пункты, а также участки дорог, где дорожными знаками 3.24.1, 3.24.2 «Ограничение максимальной скорости» установлен более высокий предел скорости движения.</p>","image":"assets/adrive-questions/q101104201.jpg"},{"id":101104202,"themeId":4,"group":1011042,"chapter":11,"chapters":[11],"q":"С какой максимальной скоростью разрешается движение автомобилей при буксировке вне населённого пункта в показанной ситуации?","a":["20 км/ч.","50 км/ч.","60 км/ч.","70 км/ч.","90 км/ч."],"c":1,"e":"<p>Согласно Правилам дорожного движения, транспортным средствам, буксирующим механические транспортные средства, разрешается движение со скоростью не более 50 км/ч.<br> Ограничение верхнего предела скорости при буксировке (независимо от вида сцепки) величиной в 50 км/ч позволяет гарантированно иметь короткий тормозной путь и обеспечить в необходимых случаях безопасность дорожного движения. Причём это ограничение сохраняется повсеместно, включая населённые пункты, а также участки дорог, где дорожными знаками 3.24.1, 3.24.2 «Ограничение максимальной скорости» установлен более высокий предел скорости движения.</p>","image":"assets/adrive-questions/q101104202.jpg"},{"id":101104401,"themeId":4,"group":1011044,"chapter":11,"chapters":[11],"q":"С какой максимальной скоростью разрешается движение мотоциклисту в населённом пункте в показанной ситуации?","a":["60 км/ч.","70 км/ч.","80 км/ч.","90 км/ч."],"c":2,"e":"<p>В показанной ситуации водитель мотоцикла двигается в населённом пункте по дороге, где установлен дорожный знак 3.24.1 «Ограничение максимальной скорости» со значением 80 км/ч. Соответственно максимальная скорость на этом участке дороги составляет 80 км/ч.</p>","image":"assets/adrive-questions/q101104401.jpg"},{"id":101104402,"themeId":4,"group":1011044,"chapter":11,"chapters":[11],"q":"С какой максимальной скоростью разрешается продолжать движение Вам, управляя легковым автомобилем вне населённого пункта в показанной ситуации?","a":["60 км/ч.","70 км/ч.","90 км/ч.","100 км/ч.","110 км/ч."],"c":3,"e":"<p>В показанной ситуации на дороге установлен дорожный знак 3.24.1 «Ограничение максимальной скорости» со значением 100 км/ч в сочетании с табличкой 7.4.3 «Вид транспортного средства» . Данное сочетание дорожных знаков действует на легковые автомобили, а также на грузовые автомобили с технически допустимой общей массой до 3.5 тонны включительно. Соответственно максимальная скорость на этом участке дороги для легкового автомобиля составляет 100 км/ч.</p>","image":"assets/adrive-questions/q101104402.jpg"},{"id":101104501,"themeId":4,"group":1011045,"chapter":11,"chapters":[11],"q":"С какой максимальной скоростью разрешается движение легковому автомобилю с прицепом в показанной ситуации, если максимальная скорость движения прицепа, определённая его технической характеристикой, составляет 90 км/ч?","a":["60 км/ч.","70 км/ч.","80 км/ч.","90 км/ч."],"c":2,"e":"<p>Согласно Правилам дорожного движения, с учётом дорожных условий и обеспечения безопасности дорожного движения скорость движения может быть изменена (понижена или повышена) применением дорожных знаков 3.24.1, 3.24.2 «Ограничение максимальной скорости» . При этом водитель должен учитывать максимальную скорость, установленную технической характеристикой прицепа, которую превышать запрещено. Как правило, максимальная конструктивная скорость прицепа к легковому автомобилю не менее 85 км/ч.</p>","image":"assets/adrive-questions/q101104501.jpg"},{"id":101104502,"themeId":4,"group":1011045,"chapter":11,"chapters":[11],"q":"Разрешается ли водителю легкового автомобиля с прицепом двигаться со скоростью, указанной на дорожном знаке, по дороге, не являющейся автомагистралью или дорогой для автомобилей?","a":["Да, разрешается в любом случае.","Разрешается только в случае, если максимальная скорость движения прицепа, определённая его технической характеристикой, не меньше указанной на знаке.","Нет, не разрешается."],"c":1,"e":"<p>При управлении легковым автомобилем с прицепом водитель продолжит движение в зоне действия запрещающего дорожного знака 3.24.1 «Ограничение максимальной скорости» , который разрешает движение со скоростью не более 100 км/ч. На этом участке дороги условия обеспечивают безопасность движения с более высокими скоростями, чем указано в пунктах Правил, поэтому разрешённая скорость повышена соответствующим дорожным знаком. При этом водитель должен учитывать максимальную скорость, установленную технической характеристикой прицепа.</p>","image":"assets/adrive-questions/q101104502.jpg"},{"id":101104601,"themeId":4,"group":1011046,"chapter":11,"chapters":[11],"q":"Каким образом разрешённая Правилами дорожного движения скорость движения может быть изменена (понижена или повышена)?","a":["Нанесением значения скорости на проезжую часть дороги.","Применением световых табло со значением разрешённой скорости.","Применением дорожных знаков «Ограничение минимальной скорости».","Применением дорожных знаков «Ограничение максимальной скорости»."],"c":3,"e":"<p>Согласно Правилам дорожного движения, с учётом дорожных условий и обеспечения безопасности дорожного движения скорость движения может быть изменена (понижена или повышена) применением дорожных знаков 3.24.1, 3.24.2 «Ограничение максимальной скорости» .</p>","image":null},{"id":101104602,"themeId":4,"group":1011046,"chapter":11,"chapters":[11],"q":"Какому транспортному средству из перечисленных ниже показанный дорожный знак повышает разрешённую скорость движения на данном участке дороги вне населённого пункта?","a":["Только мотоциклу.","Только легковому автомобилю при движении с прицепом.","Только грузовому автомобилю с технически допустимой общей массой не более 3.5 тонны.","Всем перечисленным транспортным средствам."],"c":1,"e":"<p>Согласно Правилам дорожного движения, вне населённого пункта легковому автомобилю при движении с прицепом разрешено движение со скоростью не более 70 км/ч, грузовым автомобилям с технически допустимой общей массой не более 3.5 тонны и мотоциклам — не более 90 км/ч. Показанный дорожный знак 3.24.1 «Ограничение максимальной скорости» запрещает движение со скоростью более 80 км/ч. Таким образом, именно для легкового автомобиля при движении с прицепом скорость движения повышается с 70 км/ч до 80 км/ч. Для остальных ТС максимальная скорость движения понижается с 90 км/ч до 80 км/ч.</p>","image":"assets/adrive-questions/q101104602.jpg"},{"id":101104603,"themeId":4,"group":1011046,"chapter":11,"chapters":[11],"q":"Каким транспортным средствам из перечисленных показанный дорожный знак повышает разрешённую скорость движения на данном участке дороги в населённом пункте?","a":["Только мотоциклу.","Только легковому автомобилю при движении с прицепом.","Только грузовому автомобилю с технически допустимой общей массой не более 3.5 тонны.","Всем перечисленным транспортным средствам."],"c":3,"e":"<p>Согласно Правилам дорожного движения, в населённом пункте разрешено движение с максимальной скоростью 60 км/ч. С учётом дорожных условий и обеспечения безопасности дорожного движения разрешённого пунктами 88 и 89 Правил скорость движения может быть изменена (понижена или повышена) применением дорожных знаков «Ограничение максимальной скорости». Показанный дорожный знак 3.24.1 «Ограничение максимальной скорости» запрещает движение со скоростью более 80 км/ч. Таким образом, показанный дорожный знак повышает разрешённую скорость движения на данном участке дороги всем перечисленным транспортным средствам.</p>","image":"assets/adrive-questions/q101104603.jpg"},{"id":101104801,"themeId":4,"group":1011048,"chapter":11,"chapters":[11],"q":"Разрешается ли превышать максимальную скорость движения, определённую технической характеристикой транспортного средства?","a":["Разрешается, если создаётся препятствие для движения других транспортных средств.","Разрешается в зоне действия дорожного знака «Ограничение минимальной скорости».","Разрешается с учётом дорожных условий и обеспечения безопасности дорожного движения.","Запрещается."],"c":3,"e":"<p>Согласно Правилам дорожного движения, водителю запрещается превышать максимальную скорость движения, определённую технической характеристикой транспортного средства.</p> <p>Ограничение скорости движения изготовителем транспортного средства может диктоваться рядом соображений, в частности обеспечением заявленного срока гарантийного обслуживания, соображениями надёжности, долговечности или безопасности, работоспособности установленного технологического оборудования и тому подобным.</p>","image":null},{"id":101104802,"themeId":4,"group":1011048,"chapter":11,"chapters":[11],"q":"Разрешается ли водителю легкового автомобиля двигаться со скоростью 120 км/ч, если максимальная скорость прицепа, определённая технической характеристикой, составляет 110 км/ч?","a":["Да, разрешается.","Разрешается только при движении по автомагистрали.","Нет, не разрешается."],"c":2,"e":"<p>Согласно Правилам дорожного движения, водителю запрещается превышать максимальную скорость движения, определённую технической характеристикой транспортного средства.</p> <p>Кроме того, \"повышающий знак\" действует на легковые автомобили без прицепа.</p>","image":"assets/adrive-questions/q101104802.jpg"},{"id":101104901,"themeId":4,"group":1011049,"chapter":11,"chapters":[11],"q":"Разрешается ли мотоциклисту совершить обгон легкового автомобиля, движущегося со скоростью 90 км/ч, на данном участке дороги?","a":["Да, разрешается.","Нет, не разрешается."],"c":1,"e":"<p>Очевидно, что показанная дорога не является ни автомагистралью, ни дорогой для автомобилей.<br> Согласно Правилам дорожного движения, вне населённых пунктов движение мотоциклам разрешается со скоростью не более 90 км/ч.</p>","image":"assets/adrive-questions/q101104901.jpg"},{"id":101104902,"themeId":4,"group":1011049,"chapter":11,"chapters":[11],"q":"Нарушит ли в показанной обстановке Правила дорожного движения водитель легкового автомобиля, опередив автобус, движущийся со скоростью 60 км/ч?","a":["Нет, не нарушит.","Не нарушит, опередив после проезда пешеходного перехода.","Да, нарушит."],"c":2,"e":"<p>В показанной ситуации водитель легкового автомобиля движется в населённом пункте. Согласно Правилам дорожного движения, в населённых пунктах разрешается движение транспортных средств со скоростью не более 60 км/ч.</p>","image":"assets/adrive-questions/q101104902.jpg"},{"id":101105032,"themeId":4,"group":1011050,"chapter":11,"chapters":[11],"q":"С какой максимальной скоростью разрешается движение легковому автомобилю, управляемому водителем с водительским стажем до двух лет, в показанной ситуации?","a":["70 км/ч.","90 км/ч.","110 км/ч.","120 км/ч."],"c":0,"e":"<p>Механическим транспортным средствам, управляемым водителями с водительским стажем до двух лет, разрешается движение со скоростью не более 70 км/ч.</p>","image":"assets/adrive-questions/q101105032.jpg"},{"id":101105101,"themeId":4,"group":1011051,"chapter":11,"chapters":[11],"q":"Нарушит ли водитель красного автомобиля Правила дорожного движения, если увеличит скорость с 90 км/ч до 100 км/ч в показанной ситуации, двигаясь по второй полосе движения по дороге, на которой не действуют правила, установленные для движения по автомагистрали?","a":["Да, нарушит.","Нет, не нарушит."],"c":0,"e":"<p>С учётом дорожных условий и обеспечения безопасности дорожного движения разрешённая скорость движения может быть повышена применением дорожных знаков 3.24.1 , 3.24.2 «Ограничение максимальной скорости».</p> <p>Однако в показанной ситуации данный дорожный знак 3.24.1 «Ограничение максимальной скорости» , установленный совместно с табличкой 7.14 «Полоса движения» , действует только на крайнюю левую полосу движения. Повышать скорость движения, оставаясь во второй полосе движения, запрещено.</p>","image":"assets/adrive-questions/q101105101.jpg"},{"id":101105102,"themeId":4,"group":1011051,"chapter":11,"chapters":[11],"q":"Нарушит ли водитель красного автомобиля Правила дорожного движения, перестроившись в крайнюю левую полосу движения, чтобы увеличить скорость до 100 км/ч?","a":["Да, нарушит.","Нет, не нарушит."],"c":1,"e":"<p>При трёх и более полосах движения в данном направлении занимать крайнюю левую полосу движения разрешается только тогда, когда заняты другие полосы движения, либо для опережения, объезда препятствия, поворота налево или разворота.</p> <p>Так как полосы движения впереди заняты, и водитель красного автомобиля, двигаясь с более высокой скоростью, будет совершать опережение и не нарушит Правила дорожного движения в показанной ситуации.</p>","image":"assets/adrive-questions/q101105102.jpg"},{"id":101105201,"themeId":4,"group":1011052,"chapter":11,"chapters":[11],"q":"Нарушит ли водитель в перечисленных случаях Правила дорожного движения?","a":["Нарушит, двигаясь со скоростью большей, чем определено технической характеристикой транспортного средства.","Нарушит, двигаясь со скоростью большей, чем указано на дорожном знаке «Ограничение максимальной скорости».","Нарушит, двигаясь без вынужденной необходимости с малой скоростью, создавая препятствие для дорожного движения.","Нарушит во всех перечисленных случаях."],"c":3,"e":"<p>Согласно Правилам дорожного движения, водителю запрещается:</p> <ul><li>превышать максимальную скорость движения, определённую технической характеристикой транспортного средства;</li> <li>превышать скорость движения, установленную дорожными знаками 3.24.1, 3.24.2 «Ограничение максимальной скорости» ;</li> <li>создавать препятствие для дорожного движения, двигаясь без вынужденной необходимости с малой скоростью, а также двигаться с меньшей скоростью, чем установлено дорожным знаком 4.7 «Ограничение минимальной скорости» ;</li> <li>резко тормозить, если это не требуется для предотвращения дорожно-транспортного происшествия.</li></ul>","image":null},{"id":101105202,"themeId":4,"group":1011052,"chapter":11,"chapters":[11],"q":"В каком из перечисленных случаев водитель не нарушит Правила дорожного движения?","a":["Двигаясь со скоростью большей, чем определено технической характеристикой транспортного средства.","Двигаясь без вынужденной необходимости с малой скоростью, создавая препятствие для дорожного движения.","Двигаясь с малой скоростью из-за технической неисправности к месту ремонта с соблюдением мер предосторожности.","Нарушит во всех перечисленных случаях."],"c":2,"e":"<p>Если возникает техническая неисправность транспортного средства, водитель обязан выполнить условия безопасности по доставке транспортного средства к месту ремонта и (или) стоянки, в том числе снизить скорость до безопасной в данных условиях, исходя из технического состояния транспортного средства.</p>","image":null},{"id":101105301,"themeId":4,"group":1011053,"chapter":11,"chapters":[11],"q":"В каком случае водителю разрешается резко тормозить?","a":["Для предотвращения дорожно-транспортного происшествия.","Перед искусственной неровностью.","Перед «стоп-линией».","В любом перечисленном случае."],"c":0,"e":"<p>Резкое торможение способно спровоцировать попутное столкновение, а также способствовать повреждению перевозимого груза, травмированию пассажиров, возникновению бокового заноса и опрокидыванию автомобиля. Поэтому водителю разрешено резко тормозить только для предотвращения дорожно-транспортного происшествия.</p>","image":null},{"id":101210101,"themeId":4,"group":1012101,"chapter":12,"chapters":[12],"q":"Разрешено ли Вам, управляя легковым автомобилем, приступить к выполнению обгона в показанной ситуации?","a":["Да, разрешено.","Разрешено только если скорость обгоняемого автомобиля менее 30 км/ч.","Нет, не разрешено."],"c":0,"e":"<p>До начала обгона водитель должен убедиться в том, что полоса движения, на которую он намерен выехать, свободна, и своими действиями он не создаст угрозу безопасности дорожного движения, не заставит участников дорожного движения изменить направление и (или) снизить скорость движения.</p> <p>В показанной ситуации все перечисленные условия соблюдены, поэтому обгон не запрещён.</p>","image":"assets/adrive-questions/q101210101.jpg"},{"id":101210102,"themeId":4,"group":1012101,"chapter":12,"chapters":[12],"q":"Разрешено ли Вам, управляя легковым автомобилем, в показанной ситуации приступить к выполнению обгона?","a":["Да, разрешено.","Нет, не разрешено."],"c":1,"e":"<p>До начала обгона водитель должен убедиться в том, что полоса движения, на которую он намерен выехать, свободна. В тёмное время суток это связано с целым рядом затруднений ввиду ограниченной обзорности дороги, из-за чего водитель может быть введён в заблуждение и считать, что полоса свободна (в тёмное время суток в свете фар не видно, что через 150 метров дорога делает поворот или впереди — вершина холма).</p> <p>В данной же ситуации отчётливо видны фары встречного транспортного средства, а в их свете угадывается силуэт идущего по краю проезжей части дороги пешехода.<br> В таких условиях приступать к обгону, безусловно, запрещено.</p>","image":"assets/adrive-questions/q101210102.jpg"},{"id":101210301,"themeId":4,"group":1012103,"chapter":12,"chapters":[12],"q":"Разрешено ли Вам, управляя легковым автомобилем, выполнить обгон в показанной ситуации?","a":["Да, разрешено.","Нет, запрещено."],"c":1,"e":"<p>До начала обгона водитель должен убедиться в том, что полоса движения, на которую он собирается перестроиться, свободна.</p> <p>В показанной ситуации полоса занята встречным автомобилем. Расстояние до встречного автомобиля недостаточно для выполнения безопасного обгона и может привести к появлению угрозы безопасности дорожного движения.</p>","image":"assets/adrive-questions/q101210301.jpg"},{"id":101210302,"themeId":4,"group":1012103,"chapter":12,"chapters":[12],"q":"Разрешено ли Вам, управляя легковым автомобилем, выполнить обгон в показанной ситуации?","a":["Да, разрешено.","Нет, запрещено."],"c":1,"e":"<p>До начала обгона водитель должен убедиться в том, что полоса движения, на которую он собирается перестроиться, свободна.</p> <p>В показанной ситуации полоса занята попутно движущимся автомобилем, завершающим обгон. Выполнение обгона вслед за другим транспортным средством (так называемым «паровозиком») является опасным манёвром и часто приводит к дорожно-транспортным происшествиям.</p>","image":"assets/adrive-questions/q101210302.jpg"},{"id":101210303,"themeId":4,"group":1012103,"chapter":12,"chapters":[12],"q":"Разрешено ли водителю синего легкового автомобиля выполнить обгон в показанной ситуации, если водитель красного автомобиля частично выехал на встречную полосу движения?","a":["Да, разрешено.","Нет, запрещено."],"c":1,"e":"<p>Полоса движения, на которую намерен выехать водитель синего легкового автомобиля в показанной ситуации, частично занята автомобилем, выехавшим на перекрёсток для поворота налево.<br> В таких условиях обгон запрещён, даже если с данного направления перекрёсток не обозначен знаком приоритета.</p>","image":"assets/adrive-questions/q101210303.jpg"},{"id":101210501,"themeId":4,"group":1012105,"chapter":12,"chapters":[12],"q":"Разрешено ли Вам в показанной ситуации приступить к обгону легкового автомобиля?","a":["Да, разрешено.","Разрешено только если скорость обгоняемого автомобиля менее 30 км/ч.","Нет, запрещено."],"c":2,"e":"<p>В показанной ситуации, видимо ввиду определённых затруднений, велосипедист движется не по обочине, а по краю проезжей части дороги. Следовательно, встречная полоса движения не считается свободной, и следует воздержаться от выполнения обгона до завершения встречного разъезда с велосипедистом.</p>","image":"assets/adrive-questions/q101210501.jpg"},{"id":101210502,"themeId":4,"group":1012105,"chapter":12,"chapters":[12],"q":"Разрешено ли водителю синего легкового автомобиля выполнить обгон в показанной ситуации?","a":["Да, разрешено.","Нет, запрещено."],"c":1,"e":"<p>До начала обгона водитель должен убедиться в том, что полоса движения, на которую он собирается перестроиться, свободна.</p> <p>В показанной ситуации по встречной полосе движется мотоцикл. Выполнение обгона в таких условиях может привести к появлению угрозы безопасности дорожного движения.</p>","image":"assets/adrive-questions/q101210502.jpg"},{"id":101210703,"themeId":4,"group":1012107,"chapter":12,"chapters":[12],"q":"Разрешено ли водителю красного легкового автомобиля приступить к выполнению обгона на показанном участке дороги?","a":["Да, разрешено.","Нет, запрещено."],"c":0,"e":"<p>До начала обгона водитель должен убедиться в том, что полоса движения, на которую он намерен выехать, свободна, и своими действиями он не создаст угрозу безопасности дорожного движения, не заставит участников дорожного движения изменить направление и (или) снизить скорость движения.</p> <p>В показанной ситуации все эти условия соблюдены, в направлении движения всего одна полоса, поэтому обгон на таком участке дороги разрешён.</p>","image":"assets/adrive-questions/q101210703.jpg"},{"id":101210732,"themeId":4,"group":1012107,"chapter":12,"chapters":[12],"q":"Разрешено ли Вам, управляя легковым автомобилем, выполнить обгон в показанной ситуации?","a":["Да, разрешено.","Разрешено только если скорость движения колёсного трактора составляет менее 30 км/ч.","Нет, не разрешено."],"c":2,"e":"<p>Полоса движения, на которую Вы намерены выехать, свободна, и водитель встречного автомобиля не намерен на неё перестраиваться. Однако линию горизонтальной дорожной разметки 1.3 пересекать запрещается.</p>","image":"assets/adrive-questions/q101210732.jpg"},{"id":101210851,"themeId":4,"group":1012108,"chapter":12,"chapters":[12],"q":"Вы движетесь к месту ремонта по дороге вне населённого пункта с неисправностью, которая не позволяет двигаться со скоростью более 25 км/ч. Позади скопились транспортные средства, которым Вы затрудняете выполнение обгона. Как Вам следует поступить в сложившейся ситуации?","a":["Двигаться как можно правее.","Остановиться на обочине и пропустить скопившиеся позади транспортные средства.","Продолжать движение к месту ремонта на максимально возможной скорости."],"c":1,"e":"<p>Вне населённых пунктов водитель транспортного средства, техническое состояние которого затрудняют его обгон, должен занять положение на дороге как можно правее, а при необходимости и остановиться, чтобы пропустить скопившиеся за ним транспортные средства.</p> <p>Занять крайнее правое положение на проезжей части дороги будет недостаточно для того, чтобы пропустить скопившиеся сзади транспортные средства, так как встречная полоса занята, а попутная полоса достаточно узкая. Движение по обочине запрещено. Поэтому, чтобы пропустить скопившиеся транспортные средства, <strong>необходимо съехать на обочину и остановиться</strong>.</p>","image":"assets/adrive-questions/q101210851.jpg"},{"id":101210901,"themeId":4,"group":1012109,"chapter":12,"chapters":[12],"q":"Разрешено ли Вам, управляя легковым автомобилем, в показанной ситуации произвести обгон транспортной колонны, состоящей из трёх автобусов?","a":["Разрешено, убедившись, что такой обгон не создаст угрозу безопасности дорожного движения.","Разрешено, только если скорость движения транспортной колонны не превышает 30 км/ч.","Разрешено только при имеющейся возможности поочерёдного обгона каждого автобуса с возвращением в ранее занимаемую полосу движения.","Нет, запрещено."],"c":0,"e":"<p>Водителю не запрещено начать обгон одного или нескольких транспортных средств, убедившись в том, что полоса движения, на которую он намерен выехать, свободна, и своими действиями он не создаст угрозу безопасности дорожного движения, не заставит участников дорожного движения изменить направление и (или) снизить скорость движения.<br> При этом обгон был бы запрещён, если бы транспортная колонна была организованной.</p>","image":"assets/adrive-questions/q101210901.jpg"},{"id":101211101,"themeId":4,"group":1012111,"chapter":12,"chapters":[12],"q":"В каком из перечисленных случаев водитель не нарушит Правила дорожного движения, приступая к совершению обгона?","a":["Если водитель транспортного средства, движущегося впереди по той же полосе движения, подал сигнал левого поворота.","Если водитель транспортного средства, движущегося впереди по той же полосе движения, подал сигнал правого поворота.","Если своими действиями водитель заставит водителя встречного транспортного средства съехать на обочину.","Если своими действиями водитель заставит водителя транспортного средства, движущегося по той же полосе движения, съехать на обочину.","Водитель нарушит Правила дорожного движения во всех перечисленных случаях."],"c":1,"e":"<p>Согласно Правилам дорожного движения, водителю запрещается выполнять обгон, если водитель транспортного средства, движущегося впереди по той же полосе движения, подал сигнал левого поворота. Сигнал левого поворота, поданный водителем ТС, движущегося по той же полосе движения, свидетельствует о том, что он намерен совершить или обгон, или поворот налево, или разворот. Также возможно, что он будет объезжать слева препятствие в полосе движения.</p>","image":null},{"id":101211102,"themeId":4,"group":1012111,"chapter":12,"chapters":[12],"q":"В каких случаях водитель нарушит Правила дорожного движения, приступая к совершению обгона?","a":["Только если водитель своими действиями заставит снизить скорость движения водителя транспортного средства, движущегося по той же полосе движения.","Только если водитель своими действиями заставит съехать на обочину водителя транспортного средства, движущегося по той же полосе движения.","Только если водитель транспортного средства, движущегося впереди по той же полосе движения, подал сигнал левого поворота.","Водитель нарушит Правила дорожного движения во всех перечисленных случаях."],"c":3,"e":"<p>Согласно Правилам дорожного движения, водителю запрещается выполнять обгон, если водитель транспортного средства, движущегося впереди по той же полосе движения, подал сигнал левого поворота. До начала обгона водитель должен убедиться в том, что полоса движения, на которую он намерен выехать, свободна и своими действиями он не создаст угрозу безопасности дорожного движения, не заставит участников дорожного движения изменить направление и (или) снизить скорость движения. Водитель перед выполнением обгона должен спрогнозировать действия участников дорожного движения, движущихся сзади, впереди, навстречу и попутно. Он должен оценить скорости транспортных средств и требуемое время для выполнения обгона.</p>","image":null},{"id":101211103,"themeId":4,"group":1012111,"chapter":12,"chapters":[12],"q":"В каких условиях из перечисленных водитель нарушит Правила дорожного движения, приступая к выполнению обгона?","a":["Если водитель собирается выполнить обгон двух автомобилей подряд без возвращения в ранее занимаемую полосу после обгона первого автомобиля.","Если водитель транспортного средства, движущегося впереди по той же полосе движения, подал сигнал правого поворота.","Если водитель транспортного средства, движущегося впереди по той же полосе движения, из-за действий водителя, совершавшего обгон, был вынужден снизить скорость.","Если водитель транспортного средства, движущегося впереди по той же полосе движения, из-за действий водителя, совершавшего обгон, был вынужден повысить внимание."],"c":2,"e":"<p>Согласно Правилам дорожного движения, до начала обгона водитель должен убедиться в том, что полоса движения, на которую он намерен выехать, свободна и своими действиями он не создаст угрозу безопасности дорожного движения, не заставит участников дорожного движения изменить направление и (или) снизить скорость движения. Водитель перед выполнением обгона должен спрогнозировать действия участников дорожного движения, движущихся сзади, впереди, навстречу и попутно. Он должен оценить скорости транспортных средств и требуемое время для выполнения обгона.</p>","image":null},{"id":101211301,"themeId":4,"group":1012113,"chapter":12,"chapters":[12],"q":"В каком из перечисленных случаев водитель не нарушит правила обгона?","a":["Если водитель транспортного средства, движущегося впереди по той же полосе движения, подал сигнал левого поворота.","Если водитель транспортного средства, движущегося впереди по той же полосе движения, из-за действий водителя, совершавшего обгон, был вынужден снизить скорость.","Если водитель обгоняемого транспортного средства с учётом дорожно-транспортной обстановки стал двигаться ближе к правому краю проезжей части дороги.","Водитель во всех перечисленных случаях нарушит правила обгона."],"c":2,"e":"<p>Согласно Правилам дорожного движения, водитель обгоняемого транспортного средства обязан с учётом дорожно-транспортной обстановки двигаться ближе к правому краю проезжей части дороги и не препятствовать обгону увеличением скорости движения или иными действиями. Требование направлено на обеспечение безопасности дорожного движения и запрещает водителю обгоняемого ТС увеличивать скорость, приступать к совершению обгона или выполнять иные действия, следствием выполнения которых на траектории движения обгоняющего ТС может явиться препятствие для его движения.</p>","image":null},{"id":101211501,"themeId":4,"group":1012115,"chapter":12,"chapters":[12],"q":"В чём Вы должны убедиться, управляя легковым автомобилем, до начала обгона?","a":["В том, что при возвращении на ранее занимаемую полосу не будет создано препятствия обгоняемому транспортному средству.","В том, что при возвращении на ранее занимаемую полосу не придётся выполнять следующий обгон.","В том, что не будет создано препятствия для возвращения в ранее занимаемую полосу из-за действий водителя обгоняемого автомобиля."],"c":0,"e":"<p>До начала обгона водитель должен убедиться в том, он не создаст угрозу безопасности дорожного движения, не заставит участников дорожного движения изменить направление и (или) снизить скорость движения.</p> <p>Недостаточная дистанция между попутно движущимися транспортными средствами может стать причиной того, что водитель, совершающий обгон, при возвращении в ранее занимаемую полосу создаст препятствие для движения обгоняемому транспортному средству.</p>","image":"assets/adrive-questions/q101211501.jpg"},{"id":101211502,"themeId":4,"group":1012115,"chapter":12,"chapters":[12],"q":"В чём должен убедиться водитель красного легкового автомобиля до начала обгона при отсутствии встречных и движущихся позади транспортных средств?","a":["В том, что своими действиями он не создаст угрозу безопасности дорожного движения.","В том, что своими действиями он не заставит участников дорожного движения изменить направление движения.","В том, что своими действиями он не заставит участников дорожного движения снизить скорость движения.","Во всём перечисленном."],"c":3,"e":"<p>До начала обгона водитель должен убедиться в том, он не создаст угрозу безопасности дорожного движения, не заставит участников дорожного движения изменить направление и (или) снизить скорость движения.</p> <p>Для начинающего водителя правильное прогнозирование развития дорожной ситуации является проблемой ввиду отсутствия опыта вождения. Также плохую роль может сыграть нерешительность при выполнении обгона, что ведёт к слишком долгому нахождению на встречной полосе движения.</p>","image":"assets/adrive-questions/q101211502.jpg"},{"id":101211503,"themeId":4,"group":1012115,"chapter":12,"chapters":[12],"q":"В чём должен убедиться водитель красного легкового автомобиля до начала обгона?","a":["В том, что полоса движения, на которую он намерен выехать, не занята встречными транспортными средствами.","В том, что полоса движения, на которую он намерен выехать, не занята попутно движущимися транспортными средствами.","В том, что полоса движения, на которую он намерен выехать, не занята стоящими транспортными средствами.","Во всём перечисленном."],"c":3,"e":"<p>До начала обгона водитель должен убедиться в том, что полоса движения, на которую он собирается перестроиться, свободна как от встречных транспортных средств, так и от попутно движущихся, совершающих обгон.<br> Выполнение обгона вслед за другим транспортным средством (так называемым «паровозиком») является опасным манёвром и часто приводит к дорожно-транспортным происшествиям.</p> <p>Стоящие на встречной полосе (стороне дороги) транспортные средства также могут стать препятствием для безопасного выполнения обгона.</p>","image":"assets/adrive-questions/q101211503.jpg"},{"id":101211701,"themeId":4,"group":1012117,"chapter":12,"chapters":[12],"q":"Разрешено ли Вам выполнить обгон автобуса в показанной ситуации?","a":["Да, разрешено.","Нет, не разрешено.","Разрешено только в том случае, если скорость автобуса составляет менее 30 км/ч."],"c":1,"e":"<p>Согласно Правилам дорожного движения, водителю запрещается выполнять обгон, если водитель транспортного средства, движущегося впереди по той же полосе движения, подал сигнал левого поворота. Сигнал левого поворота, поданный водителем ТС, движущегося по той же полосе движения, свидетельствует о том, что он намерен совершить или обгон, или поворот налево, или разворот. Также возможно, что он будет объезжать слева препятствие в полосе движения.</p>","image":"assets/adrive-questions/q101211701.jpg"},{"id":101211702,"themeId":4,"group":1012117,"chapter":12,"chapters":[12],"q":"Разрешено ли Вам выполнить обгон автобуса в показанной ситуации?","a":["Нет, не разрешено.","Разрешено только после того, как убедитесь в том, что полоса движения, на которую намерены выехать, свободна."],"c":0,"e":"<p>Согласно Правилам дорожного движения, водителю запрещается выполнять обгон, если водитель транспортного средства, движущегося впереди по той же полосе движения, подал сигнал левого поворота. Сигнал левого поворота, поданный водителем ТС, движущегося по той же полосе движения, свидетельствует о том, что он намерен совершить или обгон, или поворот налево, или разворот. Также возможно, что он будет объезжать слева препятствие в полосе движения.</p>","image":"assets/adrive-questions/q101211702.jpg"},{"id":101211703,"themeId":4,"group":1012117,"chapter":12,"chapters":[12],"q":"Разрешено ли Вам, управляя легковым автомобилем, выполнить обгон в показанной ситуации?","a":["Да, разрешено.","Нет, запрещено."],"c":1,"e":"<p>Водитель автомобиля, движущегося впереди с включённой аварийной световой сигнализацией, показывает рукой сигнал поворота налево. В такой ситуации обгон запрещён.</p>","image":"assets/adrive-questions/q101211703.jpg"},{"id":101211901,"themeId":4,"group":1012119,"chapter":12,"chapters":[12],"q":"Разрешено ли Вам, управляя легковым автомобилем, выполнить обгон двух транспортных средств в показанной ситуации?","a":["Да, разрешено.","Нет, запрещено."],"c":1,"e":"<p>Водителю запрещается выполнять обгон, если водитель транспортного средства, движущегося впереди по той же полосе движения, подал сигнал левого поворота.</p> <p>В показанной ситуации водитель грузового автомобиля подал сигнал левого поворота, поэтому обгон в показанной ситуации запрещён.</p> <p>Сложность принятия правильного решения состоит в том, что водитель больше уделяет внимания первому обгоняемому автомобилю, и может вовремя не заметить включённый сигнал поворота на втором автомобиле, также погодные условия могут воспрепятствовать своевременному восприятию поданного сигнала поворота.</p>","image":"assets/adrive-questions/q101211901.jpg"},{"id":101211902,"themeId":4,"group":1012119,"chapter":12,"chapters":[12],"q":"Разрешено ли водителю зелёного автомобиля приступить к выполнению обгона в показанной ситуации?","a":["Да, разрешено.","Разрешено только вслед за красным автомобилем.","Нет, не разрешено."],"c":2,"e":"<p>Водителю запрещается выполнять обгон, если водитель транспортного средства, движущегося впереди по той же полосе движения, подал сигнал левого поворота. При этом не важно, с какой целью был подан сигнал поворота: для обгона, для объезда препятствия, разворота, поворота налево или остановки на левой стороне дороги.</p> <p>Водители транспортных средств, ограничивающих обзорность, могут подавать сигнал левого поворота для предупреждения о том, что выполнение обгона в данный момент опасно.</p>","image":"assets/adrive-questions/q101211902.jpg"},{"id":101211903,"themeId":4,"group":1012119,"chapter":12,"chapters":[12],"q":"Разрешено ли Вам, управляя легковым автомобилем, выполнить обгон в показанной ситуации?","a":["Да, разрешено при условии соблюдения безопасного бокового интервала до мотоцикла.","Нет, не разрешено."],"c":1,"e":"<p>Водителю запрещается выполнять обгон, если водитель транспортного средства, движущегося впереди по той же полосе движения, подал сигнал левого поворота.</p> <p>Кроме того, водителю запрещается выполнять обгон транспортного средства, производящего обгон или объезд препятствия.</p>","image":"assets/adrive-questions/q101211903.jpg"},{"id":101212101,"themeId":4,"group":1012121,"chapter":12,"chapters":[12],"q":"Разрешено ли водителю легкового автомобиля выполнить обгон автобуса в показанной ситуации?","a":["Нет, не разрешено.","Разрешено, если скорость автобуса не превышает 50 км/ч."],"c":0,"e":"<p>Согласно Правилам дорожного движения, водителю запрещается выполнять обгон, если водитель транспортного средства, движущегося впереди по той же полосе движения, подал сигнал левого поворота. Сигнал левого поворота, поданный водителем ТС, движущегося по той же полосе движения, свидетельствует о том, что он намерен совершить или обгон, или поворот налево, или разворот. Также возможно, что он будет объезжать слева препятствие в полосе движения.</p>","image":"assets/adrive-questions/q101212101.jpg"},{"id":101212102,"themeId":4,"group":1012121,"chapter":12,"chapters":[12],"q":"Разрешено ли мотоциклисту выполнить обгон автобуса в показанной ситуации?","a":["Нет, не разрешено.","Разрешено только после того, как мотоциклист убедится в том, что полоса движения, на которую он намерен выехать, свободна."],"c":0,"e":"<p>Согласно Правилам дорожного движения, водителю запрещается выполнять обгон, если водитель транспортного средства, движущегося впереди по той же полосе движения, подал сигнал левого поворота. Сигнал левого поворота, поданный водителем ТС, движущегося по той же полосе движения, свидетельствует о том, что он намерен совершить или обгон, или поворот налево, или разворот. Также возможно, что он будет объезжать слева препятствие в полосе движения.</p>","image":"assets/adrive-questions/q101212102.jpg"},{"id":101212103,"themeId":4,"group":1012121,"chapter":12,"chapters":[12],"q":"Разрешено ли водителю легкового автомобиля выполнить обгон троллейбуса в показанной ситуации?","a":["Нет, не разрешено.","Разрешено только в том случае, если скорость легкового автомобиля при совершении обгона не превысит 70 км/ч."],"c":0,"e":"<p>Согласно Правилам дорожного движения, водителю запрещается выполнять обгон, если водитель транспортного средства, движущегося впереди по той же полосе движения, подал сигнал левого поворота. Сигнал левого поворота, поданный водителем ТС, движущегося по той же полосе движения, свидетельствует о том, что он намерен совершить или обгон, или поворот налево, или разворот. Также возможно, что он будет объезжать слева препятствие в полосе движения.</p>","image":"assets/adrive-questions/q101212103.jpg"},{"id":101212301,"themeId":4,"group":1012123,"chapter":12,"chapters":[12],"q":"Разрешено ли водителю синего легкового автомобиля приступить к выполнению обгона в показанной ситуации?","a":["Разрешено, если после подачи сигнала левого поворота водителем синего автомобиля водитель чёрного автомобиля предоставит возможность выполнить обгон.","Нет, запрещено."],"c":1,"e":"<p>Водителю запрещается выполнять обгон, если следующие за ним водители начали обгон.<br> Запрещено также препятствовать выполнению обгона.</p>","image":"assets/adrive-questions/q101212301.jpg"},{"id":101212302,"themeId":4,"group":1012123,"chapter":12,"chapters":[12],"q":"Как должен поступить в данной ситуации водитель жёлтого автомобиля, собирающийся выполнить обгон?","a":["Выполнить обгон с увеличением скорости движения до его обгона зелёным автомобилем.","Выполнить обгон вслед за зелёным автомобилем, не дожидаясь окончания им обгона чёрного автомобиля.","Приступить к выполнению обгона только после завершения обгона водителем зелёного автомобиля."],"c":2,"e":"<p>Водителю запрещается выполнять обгон, если следующие за ним водители начали обгон.<br> Запрещено также препятствовать выполнению обгона.</p>","image":"assets/adrive-questions/q101212302.jpg"},{"id":101212303,"themeId":4,"group":1012123,"chapter":12,"chapters":[12],"q":"Разрешается ли Вам, управляя легковым автомобилем, приступить к выполнению обгона, не посмотрев в зеркало заднего вида или иным образом не проконтролировав обстановку сзади управляемого транспортного средства?","a":["Нет, не разрешается.","Разрешается в случае движения с максимально разрешённой скоростью на участке дороги."],"c":0,"e":"<p>Согласно Правилам дорожного движения, водителю запрещается выполнять обгон, если следующие за ним водители начали обгон. Водитель перед выполнением обгона должен спрогнозировать действия участников дорожного движения, движущихся сзади, впереди, навстречу и попутно. Он должен оценить скорости транспортных средств и требуемое время для выполнения обгона.</p>","image":"assets/adrive-questions/q101212303.jpg"},{"id":101212501,"themeId":4,"group":1012125,"chapter":12,"chapters":[12],"q":"Грузовой автомобиль подал сигнал левого поворота и приступил к выполнению манёвра. С какой стороны разрешается выполнить его объезд водителю мотоцикла?","a":["Только справа.","Только слева.","С любой стороны."],"c":0,"e":"<p>Согласно Правилам дорожного движения, объезд транспортного средства, водитель которого подал сигнал поворота налево и приступил к выполнению манёвра, производится с правой стороны. Требование направлено на исключение неоправданных задержек ТС в крайней левой полосе движения.</p>","image":"assets/adrive-questions/q101212501.jpg"},{"id":101212502,"themeId":4,"group":1012125,"chapter":12,"chapters":[12],"q":"Нарушит ли Правила дорожного движения водитель синего автомобиля, совершив объезд жёлтого автомобиля на перекрёстке таким образом?","a":["Да, нарушит.","Нет, не нарушит."],"c":1,"e":"<p>Согласно Правилам дорожного движения, объезд транспортного средства, водитель которого подал сигнал поворота налево и приступил к выполнению манёвра, производится с правой стороны. Требование направлено на исключение неоправданных задержек ТС в крайней левой полосе движения.</p>","image":"assets/adrive-questions/q101212502.jpg"},{"id":101212503,"themeId":4,"group":1012125,"chapter":12,"chapters":[12],"q":"Как следует поступить Вам в показанной ситуации, управляя легковым автомобилем, если Вы намерены продолжать движение прямо?","a":["Объехать остановившийся легковой автомобиль справа с соблюдением безопасного бокового интервала.","Подать звуковой сигнал, чтобы водитель синего автомобиля быстрее завершил манёвр."],"c":0,"e":"<p>Объезд транспортного средства, водитель которого подал сигнал поворота налево и приступил к выполнению манёвра, производится с правой стороны. Это правило введено с целью увеличения пропускной способности перекрёстков.</p>","image":"assets/adrive-questions/q101212503.jpg"},{"id":101212701,"themeId":4,"group":1012127,"chapter":12,"chapters":[12],"q":"Как следует Вам поступить в показанной ситуации, управляя легковым автомобилем, если Вы намерены продолжать движение прямо?","a":["Объехать остановившееся транспортное средство по траектории «А».","Объехать остановившееся транспортное средство по траектории «Б».","Объехать остановившееся транспортное средство по любой из показанных траекторий.","Дождаться, пока справа от транспортного средства освободится расстояние, достаточное для проезда в пределах проезжей части дороги, после чего объехать его справа."],"c":3,"e":"<p>Объезд транспортного средства, водитель которого подал сигнал поворота налево и приступил к выполнению манёвра, производится с правой стороны. Это правило введено с целью увеличения пропускной способности перекрёстков.</p> <p>Движение по обочине с целью объезда препятствия запрещено.</p> <p>Поэтому следует объехать автомобиль, дождавшись, когда справа от транспортного средства освободится расстояние, достаточное для проезда в пределах проезжей части дороги.</p>","image":"assets/adrive-questions/q101212701.jpg"},{"id":101212702,"themeId":4,"group":1012127,"chapter":12,"chapters":[12],"q":"Как следует Вам поступить в показанной ситуации, управляя легковым автомобилем, если Вы намерены продолжать движение прямо (на светофоре включился жёлтый сигнал)?","a":["Объехать остановившийся мотоцикл справа с соблюдением безопасного бокового интервала.","Остановиться перед «стоп-линией»."],"c":1,"e":"<p>На светофоре загорелся запрещающий сигнал. Поэтому необходимо остановиться и дождаться разрешающего сигнала. При этом расстояние позволяет остановиться перед линией горизонтальной дорожной разметки 1.12 «стоп-линия» , не прибегая к экстренному торможению.<br> Также продолжать движение опасно ввиду предстоящего выхода пешеходов на проезжую часть дороги.</p>","image":"assets/adrive-questions/q101212702.jpg"},{"id":101212703,"themeId":4,"group":1012127,"chapter":12,"chapters":[12],"q":"Разрешено ли Вам, управляя легковым автомобилем, выполнить слева объезд автомобиля, начинающего разворот, в показанной ситуации?","a":["Да, разрешено.","Нет, запрещено."],"c":1,"e":"<p>В показанной ситуации водитель белого автомобиля сместился вправо с включённым левым поворотом и повернул управляемые колёса влево (для выполнения разворота от правого края проезжей части дороги).</p> <p>Объезд транспортного средства, водитель которого подал сигнал поворота налево и приступил к выполнению манёвра, производится с правой стороны, слева его объезжать запрещено.<br> Справа по обочине его объехать также запрещается (движение по обочине в этом случае запрещено).</p> <p>Поэтому необходимо дождаться, когда справа от белого автомобиля на проезжей части дороги освободится достаточно места для продолжения движения.</p>","image":"assets/adrive-questions/q101212703.jpg"},{"id":101212901,"themeId":4,"group":1012129,"chapter":12,"chapters":[12],"q":"Нарушит ли Правила дорожного движения водитель легкового автомобиля, увеличив скорость до 90 км/ч, если водитель грузового автомобиля приступил к выполнению обгона?","a":["Да, нарушит.","Нет, не нарушит."],"c":0,"e":"<p>Согласно Правилам дорожного движения, водитель обгоняемого транспортного средства обязан с учётом дорожно-транспортной обстановки двигаться ближе к правому краю проезжей части дороги и не препятствовать обгону увеличением скорости движения или иными действиями. Требование направлено на обеспечение безопасности дорожного движения и запрещает водителю обгоняемого ТС увеличивать скорость.</p>","image":"assets/adrive-questions/q101212901.jpg"},{"id":101212902,"themeId":4,"group":1012129,"chapter":12,"chapters":[12],"q":"Нарушит ли Правила дорожного движения водитель легкового автомобиля, увеличив скорость до 90 км/ч, если водитель грузового автомобиля приступил к выполнению опережения?","a":["Да, нарушит.","Нет, не нарушит."],"c":1,"e":"<p>В показанной ситуации водитель грузового автомобиля выполняет опережение, не связанное с выездом на встречную полосу движения, поэтому водителю легкового автомобиля разрешается увеличить скорость.</p>","image":"assets/adrive-questions/q101212902.jpg"},{"id":101212903,"themeId":4,"group":1012129,"chapter":12,"chapters":[12],"q":"Какие из перечисленных действий водителя обгоняемого автомобиля противоречат Правилам дорожного движения?","a":["Увеличение скорости движения.","Переключение дальнего света фар на ближний свет.","Смещение вправо к линии, обозначающей край проезжей части дороги.","Всё вышеперечисленное."],"c":0,"e":"<p>Согласно Правилам дорожного движения, водитель обгоняемого транспортного средства обязан с учётом дорожно-транспортной обстановки двигаться ближе к правому краю проезжей части дороги и не препятствовать обгону увеличением скорости движения или иными действиями. Требование направлено на обеспечение безопасности дорожного движения и запрещает водителю обгоняемого ТС увеличивать скорость, приступать к совершению обгона или выполнять иные действия, следствием выполнения которых на траектории движения обгоняющего ТС может явиться препятствие для его движения.</p>","image":null},{"id":101213101,"themeId":4,"group":1012131,"chapter":12,"chapters":[12],"q":"Что из перечисленного ниже не входит в обязанности водителя обгоняемого автомобиля?","a":["Не препятствовать обгону увеличением скорости движения.","С учётом дорожно-транспортной обстановки снизить скорость движения.","С учётом дорожно-транспортной обстановки двигаться ближе к правому краю проезжей части дороги.","Всё вышеперечисленное."],"c":1,"e":"<p>Согласно Правилам дорожного движения, водитель обгоняемого транспортного средства обязан с учётом дорожно-транспортной обстановки двигаться ближе к правому краю проезжей части дороги и не препятствовать обгону увеличением скорости движения или иными действиями. Требование направлено на обеспечение безопасности дорожного движения и запрещает водителю обгоняемого ТС увеличивать скорость, приступать к совершению обгона или выполнять иные действия, следствием выполнения которых на траектории движения обгоняющего ТС может явиться препятствие для его движения.</p>","image":null},{"id":101213102,"themeId":4,"group":1012131,"chapter":12,"chapters":[12],"q":"Что из перечисленного обязан выполнить водитель обгоняемого автомобиля?","a":["Не препятствовать обгону увеличением скорости движения или иными действиями.","С учётом дорожно-транспортной обстановки двигаться ближе к правому краю проезжей части дороги.","Всё вышеперечисленное."],"c":2,"e":"<p>Согласно Правилам дорожного движения, водитель обгоняемого транспортного средства обязан с учётом дорожно-транспортной обстановки двигаться ближе к правому краю проезжей части дороги и не препятствовать обгону увеличением скорости движения или иными действиями. Требование направлено на обеспечение безопасности дорожного движения и запрещает водителю обгоняемого ТС увеличивать скорость, приступать к совершению обгона или выполнять иные действия, следствием выполнения которых на траектории движения обгоняющего ТС может явиться препятствие для его движения.</p>","image":"assets/adrive-questions/q101213102.jpg"},{"id":101213103,"themeId":4,"group":1012131,"chapter":12,"chapters":[12],"q":"Какие из перечисленных действий водителя обгоняемого автомобиля противоречат Правилам дорожного движения?","a":["Увеличение скорости движения.","Включение светового указателя левого поворота.","Смещение влево к линии, разделяющей транспортные потоки противоположных направлений.","Все вышеперечисленные."],"c":3,"e":"<p>Согласно Правилам дорожного движения, водитель обгоняемого транспортного средства обязан с учётом дорожно-транспортной обстановки двигаться ближе к правому краю проезжей части дороги и не препятствовать обгону увеличением скорости движения или иными действиями. Требование направлено на обеспечение безопасности дорожного движения и запрещает водителю обгоняемого ТС увеличивать скорость, приступать к совершению обгона или выполнять иные действия, следствием выполнения которых на траектории движения обгоняющего ТС может явиться препятствие для его движения.</p>","image":null},{"id":101213301,"themeId":4,"group":1012133,"chapter":12,"chapters":[12],"q":"На каком участке дороги, обозначенном таким дорожным знаком, разрешён обгон?","a":["При прохождении первого поворота.","При прохождении второго поворота.","На обоих участках дороги обгон запрещён."],"c":2,"e":"<p>Согласно Правилам дорожного движения, обгон запрещается на поворотах дороги, обозначенных дорожными знаками 1.11.1, 1.11.2 «Опасный поворот» , 1.12.1, 1.12.2 «Опасные повороты» . Как правило, на таких участках применяются дорожные знаки, в зоне действия которых обгон запрещается.</p>","image":"assets/adrive-questions/q101213301.jpg"},{"id":101213354,"themeId":4,"group":1012133,"chapter":12,"chapters":[12],"q":"Нарушит ли Правила дорожного движения водитель красного легкового автомобиля, если он выполнит обгон на повороте, превысив скорость, указанную на дорожном знаке?","a":["Да, нарушит.","Нет, не нарушит."],"c":0,"e":"<p>Обгон запрещается на поворотах дороги, обозначенных дорожными знаками 1.11.1, 1.11.2 «Опасный поворот» . Иными словами, до и после поворота обгон не запрещён (на показанном участке дороги со скоростью до 90 км/ч), а на самом повороте обгон запрещается при любых условиях.</p> <p>Дорожный знак 5.18.1 «Рекомендуемая скорость» носит рекомендательный характер. Превышать рекомендуемую скорость при выполнении обгона не запрещено на участках дорог, где не запрещён обгон.</p>","image":"assets/adrive-questions/q101213354.jpg"},{"id":101213501,"themeId":4,"group":1012135,"chapter":12,"chapters":[12],"q":"На каком участке дороги, обозначенном таким дорожным знаком, разрешён обгон?","a":["В начале подъёма.","До конца подъёма.","До начала подъёма."],"c":2,"e":"<p>Обгон запрещается на подъёмах, обозначенных дорожным знаком 1.14 «Крутой подъём» . При этом обгон не запрещён до начала обозначенного таким знаком подъёма.</p>","image":"assets/adrive-questions/q101213501.jpg"},{"id":101213502,"themeId":4,"group":1012135,"chapter":12,"chapters":[12],"q":"Разрешается ли выполнить обгон на изображённом участке дороги при условии, что он будет завершён до начала подъёма?","a":["Да, разрешается.","Нет, не разрешается."],"c":0,"e":"<p>Согласно Правилам дорожного движения, обгон запрещается на подъёмах, обозначенных дорожным знаком 1.14 «Крутой подъём» . Как правило, на таких участках применяются дорожные знаки, в зоне действия которых обгон запрещается.</p>","image":"assets/adrive-questions/q101213502.jpg"},{"id":101213503,"themeId":4,"group":1012135,"chapter":12,"chapters":[12],"q":"Разрешается ли выполнить обгон на подъёме дороги при условии, что он будет завершён до конца подъёма?","a":["Да, разрешается.","Нет, не разрешается."],"c":1,"e":"<p>Согласно Правилам дорожного движения, обгон запрещается на подъёмах, обозначенных дорожным знаком 1.14 «Крутой подъём» .</p>","image":"assets/adrive-questions/q101213503.jpg"},{"id":101213701,"themeId":4,"group":1012137,"chapter":12,"chapters":[12],"q":"Разрешено ли Вам, управляя легковым автомобилем, произвести обгон колёсного трактора, движущегося со скоростью не более 25 км/ч, на показанном участке дороги?","a":["Да, разрешено.","Разрешено только если водитель колёсного трактора включением правого светового указателя поворота проинформирует о безопасности обгона на показанном участке дороги.","Нет, запрещено."],"c":2,"e":"<p>Обгон запрещён в конце подъёмов и на других участках дорог с ограниченной обзорностью.</p>","image":"assets/adrive-questions/q101213701.jpg"},{"id":101213901,"themeId":4,"group":1012139,"chapter":12,"chapters":[12],"q":"Разрешено ли водителю легкового автомобиля произвести обгон грузового автомобиля на участке с ограниченной обзорностью в конце подъёма дороги, если скорость движения грузового автомобиля менее 30 км/ч, а подъём не обозначен дорожным знаком «Крутой подъём»?","a":["Запрещено.","Да, разрешено."],"c":0,"e":"<p>Согласно Правилам дорожного движения, обгон запрещается в конце подъёмов и на других участках дорог с ограниченной обзорностью дороги. В конце подъёма обзорность дороги ограничена преломлением продольного профиля дороги. Как правило, на таких участках применяются дорожные знаки, в зоне действия которых обгон запрещается.</p>","image":"assets/adrive-questions/q101213901.jpg"},{"id":101213902,"themeId":4,"group":1012139,"chapter":12,"chapters":[12],"q":"Разрешено ли Вам, управляя легковым автомобилем, в показанной ситуации выполнить обгон грузового автомобиля в конце незначительного подъёма, не обозначенного дорожным знаком «Крутой подъём»?","a":["Запрещено.","Да, разрешено.","Разрешено, если скорость движения грузового автомобиля менее 30 км/ч."],"c":0,"e":"<p>Согласно Правилам дорожного движения, обгон запрещается в конце подъёмов и на других участках дорог с ограниченной обзорностью дороги. В конце подъёма обзорность дороги ограничена преломлением продольного профиля дороги.</p>","image":"assets/adrive-questions/q101213902.jpg"},{"id":101214101,"themeId":4,"group":1012141,"chapter":12,"chapters":[12],"q":"На каких участках подъёма, обозначенного дорожным знаком «Крутой подъём», запрещено выполнить обгон (знак установлен непосредственно в начале подъёма)?","a":["На участке «В».","На участках «Б» и «В».","На участке «А».","Обгон запрещён на протяжении всего подъёма."],"c":3,"e":"<p>Согласно Правилам дорожного движения, обгон запрещается на подъёмах, обозначенных дорожным знаком 1.14 «Крутой подъём» .</p> <p>В конце подъёма обзорность дороги ограничена преломлением продольного профиля дороги. Как правило, на таких участках применяются дорожные знаки, в зоне действия которых обгон запрещается.</p>","image":"assets/adrive-questions/q101214101.jpg"},{"id":101214301,"themeId":4,"group":1012143,"chapter":12,"chapters":[12],"q":"Запрещён ли обгон на участке дороги, обозначенном таким дорожным знаком?","a":["Да, запрещён.","Нет, не запрещён.","Запрещён, если это участок дороги с ограниченной обзорностью."],"c":2,"e":"<p>Согласно Правилам дорожного движения, обгон запрещается на участках дорог с ограниченной обзорностью дороги.</p>","image":"assets/adrive-questions/q101214301.jpg"},{"id":101214302,"themeId":4,"group":1012143,"chapter":12,"chapters":[12],"q":"На каком участке подъёма, обозначенного таким дорожным знаком, запрещён обгон?","a":["В конце подъёма.","В начале подъёма.","На всём протяжении подъёма."],"c":2,"e":"<p>Согласно Правилам дорожного движения, обгон запрещается на подъёмах, обозначенных дорожным знаком 1.14 «Крутой подъём» . Как правило, на таких участках применяются дорожные знаки, в зоне действия которых обгон запрещается.</p>","image":"assets/adrive-questions/q101214302.jpg"},{"id":101214501,"themeId":4,"group":1012145,"chapter":12,"chapters":[12],"q":"Разрешается ли водителю легкового автомобиля совершить обгон в показанной ситуации?","a":["Да, разрешается.","Нет, не разрешается."],"c":1,"e":"<p>В показанной ситуации водитель выполняет обгон на обозначенном перекрёстке.</p> <p>Согласно Правилам дорожного движения, обгон запрещается на обозначенных и (или) регулируемых перекрёстках.</p>","image":"assets/adrive-questions/q101214501.jpg"},{"id":101214502,"themeId":4,"group":1012145,"chapter":12,"chapters":[12],"q":"Разрешается ли водителю легкового автомобиля совершить обгон в показанной ситуации?","a":["Да, разрешается.","Нет, не разрешается."],"c":1,"e":"<p>В показанной ситуации водитель выполняет обгон на обозначенном перекрёстке.</p> <p>Согласно Правилам дорожного движения, обгон запрещается на обозначенных и (или) регулируемых перекрёстках. Перекрёсток характеризуется большим числом конфликтных точек, поскольку на нём пересекаются траектории движения как ТС, так и ТС и пешеходов. Для уменьшения числа конфликтных точек устанавливается (при помощи дорожных знаков приоритета) очерёдность движения участников дорожного движения. Такой перекрёсток называется обозначенным.</p>","image":"assets/adrive-questions/q101214502.jpg"},{"id":101214503,"themeId":4,"group":1012145,"chapter":12,"chapters":[12],"q":"В каких случаях из перечисленных запрещается обгон?","a":["При движении по главной дороге на необозначенных и нерегулируемых перекрёстках.","При движении по второстепенной дороге на необозначенных и нерегулируемых перекрёстках.","При движении по равнозначной дороге на перекрёстках, обозначенных дорожным знаком «Пересечение равнозначных дорог».","Во всех перечисленных случаях обгон запрещается."],"c":2,"e":"<p>Согласно Правилам дорожного движения, обгон запрещается на обозначенных и (или) регулируемых перекрёстках.</p> <p>Перекрёсток характеризуется большим числом конфликтных точек, поскольку на нём пересекаются траектории движения как ТС, так и ТС и пешеходов. Для уменьшения числа конфликтных точек устанавливается (при помощи дорожных знаков приоритета) очерёдность движения участников дорожного движения. Такой перекрёсток называется обозначенным.</p>","image":null},{"id":101214701,"themeId":4,"group":1012147,"chapter":12,"chapters":[12],"q":"Разрешается ли выполнить обгон в показанном месте?","a":["Да, разрешается.","Нет, не разрешается."],"c":1,"e":"<p>В показанной ситуации водитель намеревается выполнить обгон на обозначенном перекрёстке. Согласно Правилам дорожного движения, обгон запрещается на обозначенных и (или) регулируемых перекрёстках. Перекрёсток характеризуется большим числом конфликтных точек, поскольку на нём пересекаются траектории движения как ТС, так и ТС и пешеходов. Для уменьшения числа конфликтных точек устанавливается (при помощи дорожных знаков приоритета) очерёдность движения участников дорожного движения.</p>","image":"assets/adrive-questions/q101214701.jpg"},{"id":101214702,"themeId":4,"group":1012147,"chapter":12,"chapters":[12],"q":"Разрешается ли выполнить обгон в показанном месте?","a":["Да, разрешается.","Нет, не разрешается."],"c":1,"e":"<p>В показанной ситуации водитель намеревается выполнить обгон на обозначенном перекрёстке. Согласно Правилам дорожного движения, обгон запрещается на обозначенных и (или) регулируемых перекрёстках. Перекрёсток характеризуется большим числом конфликтных точек, поскольку на нём пересекаются траектории движения как ТС, так и ТС и пешеходов. Для уменьшения числа конфликтных точек устанавливается (при помощи дорожных знаков приоритета или светофоров) очерёдность движения участников дорожного движения.</p>","image":"assets/adrive-questions/q101214702.jpg"},{"id":101214901,"themeId":4,"group":1012149,"chapter":12,"chapters":[12],"q":"На каких из перечисленных участков дорог запрещён обгон?","a":["На перекрёстке, обозначенном знаком «Главная дорога».","На перекрёстке при движении на зелёный сигнал светофора.","На перекрёстке при движении на разрешающий сигнал регулировщика.","На всех перечисленных участках дорог обгон запрещён."],"c":3,"e":"<p>Согласно Правилам дорожного движения, обгон запрещается на обозначенных и (или) регулируемых перекрёстках.</p> <p>Перекрёсток характеризуется большим числом конфликтных точек, поскольку на нём пересекаются траектории движения как ТС, так и ТС и пешеходов. Для уменьшения числа конфликтных точек устанавливается (при помощи дорожных знаков приоритета) очерёдность движения участников дорожного движения. Такой перекрёсток называется обозначенным.</p> <p>Перекрёсток, на котором очерёдность движения определяется сигналами регулировщика или светофора, является регулируемым.</p>","image":null},{"id":101214902,"themeId":4,"group":1012149,"chapter":12,"chapters":[12],"q":"Разрешается ли выполнить обгон водителю синего автомобиля на перекрёстке, изображённом на рисунке?","a":["Да, разрешается.","Нет, не разрешается."],"c":1,"e":"<p>Согласно Правилам дорожного движения, обгон запрещается на обозначенных и (или) регулируемых перекрёстках. Перекрёсток, на котором очерёдность движения определяется сигналами регулировщика или светофора, является регулируемым.</p>","image":"assets/adrive-questions/q101214902.jpg"},{"id":101214903,"themeId":4,"group":1012149,"chapter":12,"chapters":[12],"q":"Разрешается ли выполнить обгон водителю жёлтого автомобиля на перекрёстке, изображённом на рисунке?","a":["Да, разрешается.","Нет, не разрешается."],"c":1,"e":"<p>Согласно Правилам дорожного движения, обгон запрещается на обозначенных и (или) регулируемых перекрёстках. Перекрёсток, на котором очерёдность движения определяется сигналами регулировщика или светофора, является регулируемым.</p>","image":"assets/adrive-questions/q101214903.jpg"},{"id":101215101,"themeId":4,"group":1012151,"chapter":12,"chapters":[12],"q":"Нарушит ли Правила дорожного движения водитель легкового автомобиля, совершив обгон в показанной ситуации?","a":["Да, нарушит.","Нет, не нарушит."],"c":1,"e":"<p>В показанной ситуации водитель выполняет обгон на необозначенном и нерегулируемом перекрёстке.</p> <p>Согласно Правилам дорожного движения, обгон запрещается на обозначенных и (или) регулируемых перекрёстках.</p>","image":"assets/adrive-questions/q101215101.jpg"},{"id":101215102,"themeId":4,"group":1012151,"chapter":12,"chapters":[12],"q":"Водитель какого легкового автомобиля совершает обгон в соответствии с Правилами дорожного движения?","a":["Водитель жёлтого автомобиля.","Водитель красного автомобиля.","Водители обоих автомобилей.","Водители обоих автомобилей нарушают правила обгона."],"c":2,"e":"<p>В показанной ситуации водитель жёлтого легкового автомобиля выполняет обгон на необозначенном и нерегулируемом перекрёстке.<br> Водитель красного легкового автомобиля выполняет обгон на пересечении проезжей части дороги с трамвайными путями, оборудованными на обособленной полосе земли.</p> <p>Пересечение проезжей части дороги с трамвайной линией железнодорожным переездом или перекрёстком не является. Согласно Правилам дорожного движения, обгон запрещается на обозначенных и (или) регулируемых перекрёстках, на железнодорожных переездах.</p> <p>Данная задача приведена для того, чтобы показать, что <strong>обгон даже в местах, разрешённых Правилами, не является безопасным манёвром</strong> (последовательностью выполняемых манёвров). В показанной обстановке, выполняя обгон, водители легковых автомобилей с высокой вероятностью могут попасть в аварийную ситуацию, так как не видят друг друга. Принимая решение на выполнение обгона, необходимо быть абсолютно уверенным в его безопасности.</p>","image":"assets/adrive-questions/q101215102.jpg"},{"id":101215301,"themeId":4,"group":1012153,"chapter":12,"chapters":[12],"q":"В каких случаях водитель жёлтого автомобиля нарушит Правила дорожного движения?","a":["Нарушит, начав обгон в точке «А».","Нарушит, начав обгон в точке «Б».","Нарушит, начав обгон в точке «В».","Начав обгон в любой из точек, водитель нарушит Правила дорожного движения."],"c":3,"e":"<p>Согласно Правилам дорожного движения, обгон запрещается на пешеходных переходах и ближе 50 метров от них в обе стороны.<br> Запрещение обгона на пешеходных переходах и перед ними преследует цель обеспечить лучшую обзорность дороги в границах пешеходного перехода, а также возможность видеть пешеходов, которые подходят к пешеходному переходу.</p>","image":"assets/adrive-questions/q101215301.jpg"},{"id":101215302,"themeId":4,"group":1012153,"chapter":12,"chapters":[12],"q":"Нарушит ли Правила дорожного движения водитель белого автомобиля, приступив к выполнению обгона сразу после проезда пешеходного перехода?","a":["Да, нарушит.","Нет, не нарушит."],"c":0,"e":"<p>Согласно Правилам дорожного движения, обгон запрещается на пешеходных переходах и ближе 50 метров от них в обе стороны.<br> Запрещение обгона на пешеходных переходах и перед ними преследует цель обеспечить лучшую обзорность дороги в границах пешеходного перехода, а также возможность видеть пешеходов, которые подходят к пешеходному переходу.</p>","image":"assets/adrive-questions/q101215302.jpg"},{"id":101215303,"themeId":4,"group":1012153,"chapter":12,"chapters":[12],"q":"Водитель автопоезда, движущегося впереди, подал сигнал правого поворота. Разрешено ли Вам, управляя легковым автомобилем, приступить к выполнению обгона в показанной ситуации?","a":["Да, разрешено.","Нет, не разрешено."],"c":1,"e":"<p>Обгон запрещён на пешеходных переходах и ближе 50 метров от них в обе стороны. Очевидно, что в показанной ситуации при выполнении обгона автопоезда это правило будет нарушено, так как впереди по ходу движения расположен пешеходный переход, обозначенный только дорожными знаками.</p>","image":"assets/adrive-questions/q101215303.jpg"},{"id":101215304,"themeId":4,"group":1012153,"chapter":12,"chapters":[12],"q":"Какие ограничения, связанные с обгоном, действуют на пешеходных переходах, велосипедных переездах и вблизи них?","a":["Обгон запрещён только на пешеходных переходах и велосипедных переездах.","Обгон запрещён только на пешеходных переходах, велосипедных переездах и ближе 50 метров перед ними.","Обгон запрещён на пешеходных переходах, велосипедных переездах и ближе 50 метров от них в обе стороны."],"c":2,"e":"<p>Согласно Правилам дорожного движения, обгон запрещается на пешеходных переходах, велосипедных переездах и ближе 50 метров от них в обе стороны.<br> Запрещение обгона на пешеходных переходах, велосипедных переездах и перед ними преследует цель обеспечить лучшую обзорность дороги в границах пешеходного перехода, а также возможность видеть пешеходов, которые подходят к пешеходному переходу, велосипедистов и водителей средств персональной мобильности, приближающихся к велопереезду.</p>","image":null},{"id":101215501,"themeId":4,"group":1012155,"chapter":12,"chapters":[12],"q":"Разрешено ли мотоциклисту произвести обгон транспортных средств в ситуации, показанной на рисунке?","a":["Да, разрешено при условии соблюдения безопасного бокового интервала до легкового автомобиля, производящего обгон колёсного трактора.","Нет, не разрешено."],"c":1,"e":"<p>Водителю запрещается выполнять обгон транспортного средства, производящего обгон или объезд препятствия.<br> Кроме того, водителю запрещается выполнять обгон, если водитель транспортного средства, движущегося впереди по той же полосе движения, подал сигнал левого поворота.</p>","image":"assets/adrive-questions/q101215501.jpg"},{"id":101215502,"themeId":4,"group":1012155,"chapter":12,"chapters":[12],"q":"Разрешено ли водителю легкового автомобиля произвести обгон транспортных средств в ситуации, показанной на рисунке?","a":["Да, разрешено при условии соблюдения безопасного бокового интервала до мотоцикла, производящего обгон колёсного трактора.","Нет, не разрешено."],"c":1,"e":"<p>Водителю запрещается выполнять обгон транспортного средства, производящего обгон или объезд препятствия.<br> Кроме того, водителю запрещается выполнять обгон, если водитель транспортного средства, движущегося впереди по той же полосе движения, подал сигнал левого поворота.</p>","image":"assets/adrive-questions/q101215502.jpg"},{"id":101215504,"themeId":4,"group":1012155,"chapter":12,"chapters":[12],"q":"Разрешено ли водителю синего легкового автомобиля произвести обгон белого автомобиля, осуществляющего объезд препятствия?","a":["Да, разрешено при условии соблюдения безопасного бокового интервала.","Нет, запрещено."],"c":1,"e":"<p>Водителю запрещается выполнять обгон транспортного средства, производящего обгон или объезд препятствия.</p> <p>Кроме того, водителю запрещается выполнять обгон, если водитель транспортного средства, движущегося впереди по той же полосе движения, подал сигнал левого поворота.</p>","image":"assets/adrive-questions/q101215504.jpg"},{"id":101215701,"themeId":4,"group":1012157,"chapter":12,"chapters":[12],"q":"Разрешено ли Вам, управляя легковым автомобилем, выполнить обгон в показанных дорожных условиях?","a":["Да, разрешено.","Разрешено выполнить обгон только тихоходного транспортного средства.","Нет, не разрешено."],"c":2,"e":"<p>Водителю запрещается выполнять обгон в условиях недостаточной видимости (видимость дороги в направлении движения менее 300 метров, обусловленная погодными (метеорологическими) условиями — дождь, снег и иные атмосферные осадки — и другими факторами, снижающими прозрачность атмосферы — пыль, дым, туман, смог).</p>","image":"assets/adrive-questions/q101215701.jpg"},{"id":101215702,"themeId":4,"group":1012157,"chapter":12,"chapters":[12],"q":"На каких из перечисленных участков дорог запрещён обгон?","a":["На участках дорог с ограниченной обзорностью.","На участках дорог при недостаточной видимости дороги.","Ближе 50 метров перед пешеходным переходом, оборудованным дорожными светофорами, при разрешающем для водителя сигнале светофора.","На всех перечисленных участках дорог обгон запрещён."],"c":3,"e":"<p>Согласно Правилам дорожного движения, обгон запрещается:</p> <ul> <li>в зоне действия дорожных знаков 3.20.1, 3.20.2, 3.20.3 «Обгон запрещён» , 3.22 «Обгон грузовым автомобилям запрещён» , на поворотах дороги, обозначенных дорожными знаками 1.11.1, 1.11.2 «Опасный поворот» , 1.12.1, 1.12.2 «Опасные повороты» , на подъёмах, обозначенных дорожным знаком 1.14 «Крутой подъём» , а также при наличии дорожной разметки 1.1 (за исключением обгона одиночного транспортного средства, движущегося со скоростью менее 30 км/ч), в конце подъёмов и на других участках дорог с ограниченной обзорностью дороги;</li> <li>на обозначенных и (или) регулируемых перекрёстках;</li> <li>на пешеходных переходах, велосипедных переездах и ближе 50 метров от них в обе стороны;</li> <li>транспортного средства, производящего обгон или объезд препятствия;</li> <li>при недостаточной видимости дороги;</li> <li>на путепроводах и под ними;</li> <li>на железнодорожных переездах и ближе чем за 100 метров перед ними.</li></ul>","image":null},{"id":101215851,"themeId":4,"group":1012158,"chapter":12,"chapters":[12],"q":"Разрешено ли Вам на подъёме, обозначенном дорожным знаком «1.14 Крутой подъём», перестроиться на полосу, расположенную левее, для опережения грузового автомобиля?","a":["Запрещено.","Разрешено."],"c":1,"e":"<p>Правилами дорожного движения <strong>не запрещено опережение</strong> на подъёме, обозначенном дорожным знаком «Крутой подъём», если при этом не будет совершено выезда на встречную полосу. Т.е. в таких местах запрещён только обгон.</p>","image":"assets/adrive-questions/q101215851.jpg"},{"id":101216101,"themeId":4,"group":1012161,"chapter":12,"chapters":[12],"q":"Разрешено ли Вам, управляя легковым автомобилем, выполнить обгон в показанной ситуации?","a":["Да, разрешено.","Нет, запрещено.","Разрешено при условии, что обгон будет завершён до железнодорожного переезда."],"c":1,"e":"<p>Запрещается выполнять обгон на железнодорожных переездах и ближе чем за 100 метров перед ними.</p> <p>Дорожный знак 1.2 «Железнодорожный переезд без шлагбаума» устанавливается в населённых пунктах на расстоянии 50–100 метров до железнодорожного переезда, соответственно обгон в показанной ситуации произвести запрещено.</p>","image":"assets/adrive-questions/q101216101.jpg"},{"id":101216102,"themeId":4,"group":1012161,"chapter":12,"chapters":[12],"q":"Разрешено ли Вам, управляя легковым автомобилем, выполнить обгон в показанной ситуации?","a":["Да, разрешено.","Нет, запрещено.","Разрешено при условии, что обгон будет завершён на расстоянии не менее, чем за 100 метров до железнодорожного переезда."],"c":2,"e":"<p>Запрещается выполнять обгон на железнодорожных переездах и ближе чем за 100 метров перед ними.</p> <p>Дорожный знак 1.2 «Железнодорожный переезд без шлагбаума» устанавливается вне населённых пунктов на расстоянии 150–300 метров до железнодорожного переезда, соответственно обгон в показанной ситуации произвести разрешено при условии, что обгон будет завершён на расстоянии не менее чем за 100 метров до железнодорожного переезда.</p>","image":"assets/adrive-questions/q101216102.jpg"},{"id":101216103,"themeId":4,"group":1012161,"chapter":12,"chapters":[12],"q":"Разрешается ли Вам в показанной обстановке обогнать автомобиль, движущийся перед Вами с небольшой скоростью?","a":["Да, разрешается.","Нет, не разрешается."],"c":1,"e":"<p>В показанной ситуации установлен предупреждающий дорожный знак 1.4.3 «Приближение к железнодорожному переезду» , который информирует водителя о железнодорожном переезде без шлагбаума через 20–50 метров.<br> Согласно Правилам дорожного движения, обгон запрещается на железнодорожных переездах и ближе чем за 100 метров перед ними. Запрещение обгона на железнодорожных переездах преследует цель обеспечения обзорности дороги с места водителя для своевременного обнаружения приближающегося (к переезду) железнодорожного ТС.</p>","image":"assets/adrive-questions/q101216103.jpg"},{"id":101216104,"themeId":4,"group":1012161,"chapter":12,"chapters":[12],"q":"Нарушит ли Правила дорожного движения водитель синего автомобиля, совершив такой манёвр на показанном участке дороги?","a":["Да, нарушит.","Нет, не нарушит."],"c":1,"e":"<p>В показанной ситуации водитель легкового автомобиля выполняет опережение, не связанное с выездом на встречную полосу движения.</p>","image":"assets/adrive-questions/q101216104.jpg"},{"id":101216301,"themeId":4,"group":1012163,"chapter":12,"chapters":[12],"q":"Разрешается ли водителю легкового автомобиля произвести обгон в показанной ситуации?","a":["Да, разрешается.","Нет, не разрешается."],"c":0,"e":"<p>Согласно Правилам дорожного движения, обгон запрещается на железнодорожных переездах и ближе чем за 100 метров перед ними. После проезда железнодорожного переезда обгон не запрещён при выполнении мер безопасности.</p>","image":"assets/adrive-questions/q101216301.jpg"},{"id":101216302,"themeId":4,"group":1012163,"chapter":12,"chapters":[12],"q":"Разрешается ли Вам, управляя легковым автомобилем, произвести обгон в показанной ситуации?","a":["Да, разрешается.","Нет, не разрешается."],"c":1,"e":"<p>Согласно Правилам дорожного движения, обгон запрещается на железнодорожных переездах и ближе чем за 100 метров перед ними. Запрещение обгона на железнодорожных переездах преследует цель обеспечения обзорности дороги с места водителя для своевременного обнаружения приближающегося (к переезду) железнодорожного ТС.</p>","image":"assets/adrive-questions/q101216302.jpg"},{"id":101216303,"themeId":4,"group":1012163,"chapter":12,"chapters":[12],"q":"Разрешается ли Вам в показанной обстановке сразу за железнодорожным переездом обогнать автомобиль, движущийся перед Вами с небольшой скоростью?","a":["Да, разрешается.","Нет, не разрешается."],"c":0,"e":"<p>Согласно Правилам дорожного движения, обгон запрещается на железнодорожных переездах и ближе чем за 100 метров перед ними.<br> В показанной ситуации Вы уже проехали железнодорожный переезд, следовательно обгон не запрещён.</p>","image":"assets/adrive-questions/q101216303.jpg"},{"id":101216304,"themeId":4,"group":1012163,"chapter":12,"chapters":[12],"q":"Нарушит ли Правила дорожного движения водитель синего автомобиля, совершив обгон на показанном участке дороги?","a":["Да, нарушит.","Нет, не нарушит."],"c":1,"e":"<p>Пересечение проезжей части дороги с трамвайной линией железнодорожным переездом не является.<br> Согласно Правилам дорожного движения, обгон запрещается на железнодорожных переездах и ближе чем за 100 метров перед ними.</p>","image":"assets/adrive-questions/q101216304.jpg"},{"id":101216501,"themeId":4,"group":1012165,"chapter":12,"chapters":[12],"q":"Какие ограничения, связанные с обгоном, действуют на железнодорожных переездах и вблизи них?","a":["Обгон запрещён только на железнодорожных переездах.","Обгон запрещён на железнодорожных переездах и ближе 100 метров перед ними.","Обгон запрещён на железнодорожных переездах и ближе 50 метров от них в обе стороны.","Обгон запрещён на железнодорожных переездах и ближе 100 метров от них в обе стороны."],"c":1,"e":"<p>Согласно Правилам дорожного движения, обгон запрещается на железнодорожных переездах и ближе чем за 100 метров перед ними. Запрещение обгона на железнодорожных переездах преследует цель обеспечения обзорности дороги с места водителя для своевременного обнаружения приближающегося (к переезду) железнодорожного ТС.</p>","image":null},{"id":101216502,"themeId":4,"group":1012165,"chapter":12,"chapters":[12],"q":"В каких из перечисленных мест не запрещён обгон при отсутствии дорожных знаков и горизонтальной дорожной разметки, запрещающих обгон?","a":["Под путепроводом.","Ближе 50 метров после пешеходного перехода.","Ближе 50 метров после железнодорожного переезда.","Во всех перечисленных местах обгон запрещён."],"c":2,"e":"<p>Согласно Правилам дорожного движения, обгон запрещается:</p> <ul> <li>в зоне действия дорожных знаков 3.20.1, 3.20.2, 3.20.3 «Обгон запрещён» , 3.22 «Обгон грузовым автомобилям запрещён» , на поворотах дороги, обозначенных дорожными знаками 1.11.1, 1.11.2 «Опасный поворот» , 1.12.1, 1.12.2 «Опасные повороты» , на подъёмах, обозначенных дорожным знаком 1.14 «Крутой подъём» , а также при наличии дорожной разметки 1.1 (за исключением обгона одиночного транспортного средства, движущегося со скоростью менее 30 км/ч), в конце подъёмов и на других участках дорог с ограниченной обзорностью дороги;</li> <li>на обозначенных и (или) регулируемых перекрёстках;</li> <li>на пешеходных переходах, велосипедных переездах и ближе 50 метров от них в обе стороны;</li> <li>транспортного средства, производящего обгон или объезд препятствия;</li> <li>при недостаточной видимости дороги;</li> <li>на путепроводах и под ними;</li> <li>на железнодорожных переездах и ближе чем за 100 метров перед ними.</li></ul>","image":null},{"id":101216503,"themeId":4,"group":1012165,"chapter":12,"chapters":[12],"q":"На каких из перечисленных участков дорог запрещён обгон?","a":["Ближе 50 метров после велосипедного переезда.","Ближе 50 метров после железнодорожного переезда.","На не обозначенном знаками приоритета выезде из жилой зоны.","На всех перечисленных участках дорог обгон запрещён."],"c":0,"e":"<p>Согласно Правилам дорожного движения, обгон запрещается:</p> <ul><li>в зоне действия дорожных знаков 3.20.1, 3.20.2, 3.20.3 «Обгон запрещён» , 3.22 «Обгон грузовым автомобилям запрещён» , на поворотах дороги, обозначенных дорожными знаками 1.11.1, 1.11.2 «Опасный поворот» , 1.12.1, 1.12.2 «Опасные повороты» , на подъёмах, обозначенных дорожным знаком 1.14 «Крутой подъём» , а также при наличии дорожной разметки 1.1 (за исключением обгона одиночного транспортного средства, движущегося со скоростью менее 30 км/ч), в конце подъёмов и на других участках дорог с ограниченной обзорностью дороги;</li> <li>на обозначенных и (или) регулируемых перекрёстках;</li> <li>на пешеходных переходах, велосипедных переездах и ближе 50 метров от них в обе стороны;</li> <li>транспортного средства, производящего обгон или объезд препятствия;</li> <li>при недостаточной видимости дороги;</li> <li>на путепроводах и под ними;</li> <li>на железнодорожных переездах и ближе чем за 100 метров перед ними.</li></ul>","image":null},{"id":101216701,"themeId":4,"group":1012167,"chapter":12,"chapters":[12],"q":"В каких из перечисленных мест не запрещён обгон при отсутствии дорожных знаков и горизонтальной дорожной разметки, запрещающих обгон?","a":["Ближе 15 метров после путепровода.","Ближе 15 метров после железнодорожного переезда.","В зоне остановочного пункта маршрутных транспортных средств.","Во всех перечисленных местах обгон разрешён."],"c":3,"e":"<p>Согласно Правилам дорожного движения, обгон запрещается:</p> <ul> <li>в зоне действия дорожных знаков 3.20.1, 3.20.2, 3.20.3 «Обгон запрещён» , 3.22 «Обгон грузовым автомобилям запрещён» , на поворотах дороги, обозначенных дорожными знаками 1.11.1, 1.11.2 «Опасный поворот» , 1.12.1, 1.12.2 «Опасные повороты» , на подъёмах, обозначенных дорожным знаком 1.14 «Крутой подъём» , а также при наличии дорожной разметки 1.1 (за исключением обгона одиночного транспортного средства, движущегося со скоростью менее 30 км/ч), в конце подъёмов и на других участках дорог с ограниченной обзорностью дороги;</li> <li>на обозначенных и (или) регулируемых перекрёстках;</li> <li>на пешеходных переходах, велосипедных переездах и ближе 50 метров от них в обе стороны;</li> <li>транспортного средства, производящего обгон или объезд препятствия;</li> <li>при недостаточной видимости дороги;</li> <li>на путепроводах и под ними;</li> <li>на железнодорожных переездах и ближе чем за 100 метров перед ними.</li></ul>","image":null},{"id":101216702,"themeId":4,"group":1012167,"chapter":12,"chapters":[12],"q":"На каких из перечисленных участков дорог запрещён обгон?","a":["На путепроводах.","Под путепроводами.","Ближе чем за 100 метров перед железнодорожными переездами.","На всех перечисленных участках дорог обгон запрещён."],"c":3,"e":"<p>Обгон запрещается:</p> <ul><li>на путепроводах и под ними;</li> <li>на железнодорожных переездах и ближе чем за 100 метров перед ними.</li></ul>","image":null},{"id":101216703,"themeId":4,"group":1012167,"chapter":12,"chapters":[12],"q":"В каких из перечисленных мест не запрещён обгон при отсутствии дорожных знаков и горизонтальной дорожной разметки, запрещающих обгон?","a":["На участках дорог со скользким покрытием.","На спусках дорог, обозначенных дорожным знаком «Крутой спуск».","Ближе 15 метров перед остановочным пунктом маршрутных транспортных средств.","Во всех перечисленных местах обгон не запрещён, если действия водителя не создадут угрозу безопасности дорожного движения."],"c":3,"e":"<p>Согласно Правилам дорожного движения, обгон запрещается:</p> <ul> <li>в зоне действия дорожных знаков 3.20.1, 3.20.2, 3.20.3 «Обгон запрещён» , 3.22 «Обгон грузовым автомобилям запрещён» , на поворотах дороги, обозначенных дорожными знаками 1.11.1, 1.11.2 «Опасный поворот» , 1.12.1, 1.12.2 «Опасные повороты» , на подъёмах, обозначенных дорожным знаком 1.14 «Крутой подъём» , а также при наличии дорожной разметки 1.1 (за исключением обгона одиночного транспортного средства, движущегося со скоростью менее 30 км/ч), в конце подъёмов и на других участках дорог с ограниченной обзорностью дороги;</li> <li>на обозначенных и (или) регулируемых перекрёстках;</li> <li>на пешеходных переходах, велосипедных переездах и ближе 50 метров от них в обе стороны;</li> <li>транспортного средства, производящего обгон или объезд препятствия;</li> <li>при недостаточной видимости дороги;</li> <li>на путепроводах и под ними;</li> <li>на железнодорожных переездах и ближе чем за 100 метров перед ними.</li></ul>","image":null},{"id":101216901,"themeId":4,"group":1012169,"chapter":12,"chapters":[12],"q":"Как Вам необходимо поступить в показанной ситуации при объезде препятствия для дорожного движения?","a":["Проехать узкий участок дороги первым.","Уступить дорогу встречному автомобилю."],"c":1,"e":"<p>Согласно Правилам дорожного движения, если встречный разъезд транспортных средств затруднён, то водитель, на стороне которого имеется препятствие для дорожного движения, обязан уступить дорогу. Под препятствием подразумевается объект, который находится на пути участника дорожного движения.</p>","image":"assets/adrive-questions/q101216901.jpg"},{"id":101216902,"themeId":4,"group":1012169,"chapter":12,"chapters":[12],"q":"Кто из водителей в показанной ситуации обязан уступить дорогу (дорожный знак установлен непосредственно в начале подъёма)?","a":["Водитель жёлтого автомобиля.","Водитель красного автомобиля."],"c":1,"e":"<p>Согласно Правилам дорожного движения, на уклонах, обозначенных дорожными знаками 1.13 «Крутой спуск» , 1.14 «Крутой подъём» , при наличии препятствия для дорожного движения уступить дорогу обязан водитель транспортного средства, движущегося на спуск. Под препятствием подразумевается объект, который находится на пути участника дорожного движения.</p>","image":"assets/adrive-questions/q101216902.jpg"},{"id":101216903,"themeId":4,"group":1012169,"chapter":12,"chapters":[12],"q":"Кто из водителей в показанной ситуации обязан уступить дорогу (дорожный знак установлен непосредственно в начале спуска)?","a":["Водитель жёлтого автомобиля.","Водитель красного автомобиля."],"c":0,"e":"<p>Согласно Правилам дорожного движения, на уклонах, обозначенных дорожными знаками 1.13 «Крутой спуск» , 1.14 «Крутой подъём» , при наличии препятствия для дорожного движения уступить дорогу обязан водитель транспортного средства, движущегося на спуск. Под препятствием подразумевается объект, который находится на пути участника дорожного движения.</p>","image":"assets/adrive-questions/q101216903.jpg"},{"id":101216952,"themeId":4,"group":1012169,"chapter":12,"chapters":[12],"q":"В показанной ситуации Вы:","a":["Обязаны уступить дорогу встречному грузовому автомобилю.","Имеете преимущество и можете продолжить движение."],"c":1,"e":"<p>Препятствие находится на полосе, по которой двигался грузовой автомобиль, поэтому он обязан Вам уступить дорогу. <strong>Вы имеете преимущество</strong> в показанной ситуации.</p>","image":"assets/adrive-questions/q101216952.jpg"},{"id":101217101,"themeId":4,"group":1012171,"chapter":12,"chapters":[12],"q":"Водитель зелёного автомобиля в показанной ситуации, двигаясь на спуск:","a":["Обязан уступить дорогу красному автомобилю.","Имеет преимущество перед красным автомобилем."],"c":0,"e":"<p>Согласно Правилам дорожного движения, на уклонах, обозначенных дорожными знаками 1.13 «Крутой спуск» , 1.14 «Крутой подъём» , при наличии препятствия для дорожного движения уступить дорогу обязан водитель транспортного средства, движущегося на спуск. Под препятствием подразумевается объект, который находится на пути участника дорожного движения.</p>","image":"assets/adrive-questions/q101217101.jpg"},{"id":101217102,"themeId":4,"group":1012171,"chapter":12,"chapters":[12],"q":"Водитель зелёного автомобиля в показанной ситуации, двигаясь на подъём:","a":["Обязан уступить дорогу красному автомобилю.","Имеет преимущество перед красным автомобилем."],"c":1,"e":"<p>Согласно Правилам дорожного движения, на уклонах, обозначенных дорожными знаками 1.13 «Крутой спуск» , 1.14 «Крутой подъём» , при наличии препятствия для дорожного движения уступить дорогу обязан водитель транспортного средства, движущегося на спуск. Под препятствием подразумевается объект, который находится на пути участника дорожного движения.</p>","image":"assets/adrive-questions/q101217102.jpg"},{"id":101217302,"themeId":4,"group":1012173,"chapter":12,"chapters":[12],"q":"Обязаны ли вы, управляя легковым автомобилем, в показанной ситуации уступить дорогу автобусу?","a":["Да, обязаны.","Нет, не обязаны."],"c":1,"e":"<p>Согласно Правилам дорожного движения, если встречный разъезд транспортных средств затруднён, то водитель, на стороне которого имеется препятствие для дорожного движения, обязан уступить дорогу. Под препятствием подразумевается объект, который находится на пути участника дорожного движения.</p> <p>Однако в показанной ситуации мы имеем дело не с затруднённым встречным разъездом, а с проездом перекрёстка. При повороте налево водитель автобуса обязан уступить дорогу встречному транспортному средству, движущемуся прямо.</p>","image":"assets/adrive-questions/q101217302.jpg"},{"id":101217331,"themeId":4,"group":1012173,"chapter":12,"chapters":[12],"q":"Как Вы должны поступить, поворачивая налево на подъёме дороги, обозначенном дорожным знаком «Крутой подъём»?","a":["Уступить дорогу встречному автомобилю.","Пользуясь преимуществом, проехать перекрёсток первым."],"c":0,"e":"<p>Согласно Правилам дорожного движения, если встречный разъезд транспортных средств затруднён, то водитель, на стороне которого имеется препятствие для дорожного движения, обязан уступить дорогу. Под препятствием подразумевается объект, который находится на пути участника дорожного движения.</p> <p>Однако в показанной ситуации мы имеем дело не с затруднённым встречным разъездом, а с проездом перекрёстка. А при повороте налево необходимо уступить дорогу встречному транспортному средству, движущемуся прямо.</p>","image":"assets/adrive-questions/q101217331.jpg"},{"id":101900101,"themeId":4,"group":1019001,"chapter":19,"chapters":[19],"q":"Разрешается ли водителю легкового автомобиля при высадке пассажира в показанной ситуации не съезжать на обочину?","a":["Запрещается.","Разрешается при условии, что не будет создано помех для движущихся транспортных средств."],"c":0,"e":"<p>Согласно Правилам дорожного движения, остановка и стоянка транспортных средств разрешаются на правой по ходу движения обочине, а при отсутствии обочины или невозможности остановиться на ней — у края проезжей части дороги параллельно ему, за исключением тех мест, где с помощью дорожных знаков или дорожной разметки допускается иное расположение транспортных средств (вне населённых пунктов разрешается только остановка транспортных средств).<br> При наличии обочины, примыкающей к проезжей части, останавливать транспортное средство на проезжей части нельзя.</p>","image":"assets/adrive-questions/q101900101.jpg"},{"id":101900102,"themeId":4,"group":1019001,"chapter":19,"chapters":[19],"q":"Разрешается ли водителю легкового автомобиля в показанной ситуации не съезжать на обочину при высадке пассажира, которому необходимо перейти на левую сторону дороги?","a":["Да, разрешается.","Нет, не разрешается."],"c":1,"e":"<p>Согласно Правилам дорожного движения, остановка и стоянка транспортных средств разрешаются на правой по ходу движения обочине, а при отсутствии обочины или невозможности остановиться на ней — у края проезжей части дороги параллельно ему, за исключением тех мест, где с помощью дорожных знаков или дорожной разметки допускается иное расположение транспортных средств (вне населённых пунктов разрешается только остановка транспортных средств).<br> При наличии обочины, примыкающей к проезжей части, останавливать транспортное средство на проезжей части нельзя.</p>","image":"assets/adrive-questions/q101900102.jpg"},{"id":101900172,"themeId":4,"group":1019001,"chapter":19,"chapters":[19],"q":"Правильно ли водители легковых автомобилей поставили их на стоянку?","a":["Правильно только водитель красного автомобиля.","Правильно оба водителя.","Неправильно оба водителя."],"c":2,"e":"<p>Табличка «7.6.1 Способ постановки транспортного средства на стоянку» под дорожным знаком «5.15 Место стоянки» указывает, что все транспортные средства должны быть поставлены вдоль тротуара (бордюрного камня).</p>","image":"assets/adrive-questions/q101900172.jpg"},{"id":101900201,"themeId":4,"group":1019002,"chapter":19,"chapters":[19],"q":"Разрешается ли Вам при движении по дороге, не являющейся автомагистралью и дорогой для автомобилей, вне населённого пункта съехать на обочину?","a":["Запрещается.","Разрешается для остановки.","Разрешается для остановки и стоянки."],"c":1,"e":"<p>Согласно Правилам дорожного движения, остановка и стоянка транспортных средств разрешаются на правой по ходу движения обочине, при этом, вне населённых пунктов разрешается только остановка транспортных средств.</p>","image":"assets/adrive-questions/q101900201.jpg"},{"id":101900202,"themeId":4,"group":1019002,"chapter":19,"chapters":[19],"q":"Разрешается ли Вам в показанной ситуации при движении по дороге вне населённого пункта съехать на обочину?","a":["Запрещается.","Разрешается для остановки.","Разрешается для остановки и стоянки."],"c":1,"e":"<p>Согласно Правилам дорожного движения, остановка и стоянка транспортных средств разрешаются на правой по ходу движения обочине. При этом, вне населённых пунктов разрешается только остановка транспортных средств.</p>","image":"assets/adrive-questions/q101900202.jpg"},{"id":101900301,"themeId":4,"group":1019003,"chapter":19,"chapters":[19],"q":"Правильно ли поставил водитель свой автомобиль, совершив остановку как показано на рисунке?","a":["Да, правильно.","Нет, неправильно."],"c":0,"e":"<p>В показанной ситуации водитель совершил остановку у края проезжей части дороги возле тротуара.<br> Согласно Правилам дорожного движения, остановка и стоянка транспортных средств разрешаются на правой по ходу движения обочине, а при отсутствии обочины или невозможности остановиться на ней — у края проезжей части дороги параллельно ему, за исключением тех мест, где с помощью дорожных знаков или дорожной разметки допускается иное расположение транспортных средств (вне населённых пунктов разрешается только остановка транспортных средств).</p>","image":"assets/adrive-questions/q101900301.jpg"},{"id":101900302,"themeId":4,"group":1019003,"chapter":19,"chapters":[19],"q":"Правильно ли водитель совершил остановку в показанной ситуации?","a":["Да, правильно.","Нет, неправильно."],"c":1,"e":"<p>В показанной ситуации водитель совершил остановку на проезжей части дороги возле обочины.<br> Согласно Правилам дорожного движения, остановка и стоянка транспортных средств разрешаются на правой по ходу движения обочине, а при отсутствии обочины или невозможности остановиться на ней — у края проезжей части дороги параллельно ему, за исключением тех мест, где с помощью дорожных знаков или дорожной разметки допускается иное расположение транспортных средств (вне населённых пунктов разрешается только остановка транспортных средств).<br> При наличии обочины, примыкающей к проезжей части, останавливать транспортное средство на проезжей части нельзя.</p>","image":"assets/adrive-questions/q101900302.jpg"},{"id":101900303,"themeId":4,"group":1019003,"chapter":19,"chapters":[19],"q":"Нарушил ли водитель жёлтого автомобиля Правила дорожного движения, совершив остановку на обочине в показанной ситуации?","a":["Да, нарушил.","Нет, не нарушил."],"c":1,"e":"<p>Зона действия дорожного знака 3.27 «Остановка запрещена» в показанной ситуации распространяется до конца населённого пункта. Поэтому водитель жёлтого автомобиля, совершив остановку вне населённого пункта, не нарушил Правила дорожного движения.</p>","image":"assets/adrive-questions/q101900303.jpg"},{"id":101900402,"themeId":4,"group":1019004,"chapter":19,"chapters":[19],"q":"Разрешается ли совершить остановку у края проезжей части дороги параллельно ему при отсутствии в таком месте обочины?","a":["Да, разрешается.","Нет, не разрешается. Необходимо подыскать другое место для остановки."],"c":0,"e":"<p>Согласно Правилам дорожного движения, остановка и стоянка транспортных средств разрешаются на правой по ходу движения обочине, а при отсутствии обочины или невозможности остановиться на ней — у края проезжей части дороги параллельно ему, за исключением тех мест, где с помощью дорожных знаков или дорожной разметки допускается иное расположение транспортных средств (вне населённых пунктов разрешается только остановка транспортных средств).</p>","image":null},{"id":101900403,"themeId":4,"group":1019004,"chapter":19,"chapters":[19],"q":"В каких случаях разрешается остановка транспортных средств у края проезжей части дороги параллельно ему?","a":["Только при отсутствии обочины.","Только при невозможности остановиться на обочине.","Разрешается в обоих случаях."],"c":2,"e":"<p>Согласно Правилам дорожного движения, остановка и стоянка транспортных средств разрешаются на правой по ходу движения обочине, а <strong>при отсутствии обочины или невозможности остановиться на ней</strong> — <strong>у края проезжей части дороги параллельно ему</strong>, за исключением тех мест, где с помощью дорожных знаков или дорожной разметки допускается иное расположение транспортных средств (вне населённых пунктов разрешается только остановка транспортных средств).</p>","image":null},{"id":101900461,"themeId":4,"group":1019004,"chapter":19,"chapters":[19],"q":"Разрешено ли водителю красного автомобиля высадить пассажира в показанном месте у края проезжей части дороги?","a":["Разрешено.","Запрещено."],"c":1,"e":"<p>Показанная ситуация <strong>не относится</strong> к описанному в ПДД случаю <strong>невозможности остановиться на обочине</strong>, что подтверждают стоящие на ней автомобили.</p> <p>В показанной ситуации водитель может <strong>проехать дальше</strong> и поискать место для парковки, может применить задний ход и занять свободное место или <strong>развернуться и остановиться</strong> на противоположной обочине.</p>","image":"assets/adrive-questions/q101900461.jpg"},{"id":101900482,"themeId":4,"group":1019004,"chapter":19,"chapters":[19],"q":"Разрешено ли Вам, управляя легковым автомобилем, совершить остановку у края проезжей части дороги, так как съезд на обочину в показанной ситуации невозможен?","a":["Разрешено.","Запрещено."],"c":0,"e":"<p>Остановка в показанной ситуации у правого края проезжей части дороги <strong>разрешена</strong>, так как <strong>съезд на обочину невозможен</strong> из-за неубранного после очистки проезжей части дороги снега.</p>","image":"assets/adrive-questions/q101900482.jpg"},{"id":101900501,"themeId":4,"group":1019005,"chapter":19,"chapters":[19],"q":"Разрешается ли водителю остановиться на показанном участке дороги?","a":["Запрещается.","Разрешается с любой стороны.","Разрешается только слева у тротуара."],"c":1,"e":"<p>Согласно Правилам дорожного движения, остановка и стоянка транспортных средств разрешаются на правой по ходу движения обочине, а при отсутствии обочины или невозможности остановиться на ней — у края проезжей части дороги параллельно ему.</p> <p>Остановка и стоянка транспортных средств на левой стороне дороги в населённом пункте разрешаются на дороге с одной полосой движения для каждого направления без трамвайных путей посередине на обочине или у края проезжей части при наличии тротуара, непосредственно прилегающего к нему. Выезд на левую сторону должен выполняться с соблюдением всех требований Правил.</p>","image":"assets/adrive-questions/q101900501.jpg"},{"id":101900541,"themeId":4,"group":1019005,"chapter":19,"chapters":[19],"q":"Разрешено ли водителю жёлтого автомобиля в показанной обстановке остановиться у левого края проезжей части дороги в населённом пункте?","a":["Разрешено только на дороге с односторонним движением.","Разрешено только на дороге с двусторонним движением.","Разрешено в любом перечисленном случае.","Запрещено в любом перечисленном случае."],"c":3,"e":"<p>Остановка и стоянка транспортных средств в населённых пунктах разрешаются на левой стороне дороги у края проезжей части при наличии там тротуара, непосредственно прилегающего к нему, если на дороге имеется только по одной полосе движения для каждого направления без трамвайных путей посередине.</p> <p>В показанной ситуации слева тротуар отделён газоном от проезжей части дороги, поэтому остановиться слева в показанной ситуации запрещено.</p>","image":"assets/adrive-questions/q101900541.jpg"},{"id":101900542,"themeId":4,"group":1019005,"chapter":19,"chapters":[19],"q":"Разрешается ли Вам, управляя легковым автомобилем, остановиться на показанном участке дороги с двусторонним движением по причинам, не связанным с посадкой (высадкой) пассажиров?","a":["Да, разрешается только справа.","Да, разрешается как справа, так и слева.","Нет, не разрешается."],"c":0,"e":"<p>Остановка и стоянка транспортных средств в населённых пунктах разрешаются на левой стороне дороги у края проезжей части при наличии там тротуара, непосредственно прилегающего к нему, если на дороге имеется только по одной полосе движения для каждого направления без трамвайных путей посередине.</p> <p>В показанной ситуации слева тротуар отсутствует, поэтому остановиться слева в показанной ситуации запрещено.</p> <p>Остановка справа у края проезжей части дороги разрешена.</p>","image":"assets/adrive-questions/q101900542.jpg"},{"id":101900543,"themeId":4,"group":1019005,"chapter":19,"chapters":[19],"q":"Разрешено ли Вам поставить свой легковой автомобиль на ночную стоянку на показанном участке дороги за знаком?","a":["Да, только у правого края проезжей части дороги.","Да, только у левого края проезжей части дороги.","Да, как у правого, так и у левого края проезжей части дороги.","Нет, не разрешено."],"c":1,"e":"<p>Стоянка за знаком у правого края проезжей части дороги в ночное время запрещена, но на левую сторону дороги показанный знак не действует.</p> <p>Стоянка транспортных средств в населённых пунктах разрешается на левой стороне дороги у края проезжей части при наличии там тротуара, непосредственно прилегающего к нему, если на дороге имеется только по одной полосе движения для каждого направления без трамвайных путей посередине.</p>","image":"assets/adrive-questions/q101900543.jpg"},{"id":101900571,"themeId":4,"group":1019005,"chapter":19,"chapters":[19],"q":"Водитель голубого автомобиля остановился в показанном месте, чтобы открыть ворота для заезда во двор своего дома. Нарушил ли он Правила дорожного движения?","a":["Да, нарушил.","Нет, не нарушил, если не будет создано препятствия для движения."],"c":0,"e":"<p>Водитель остановился в зоне действия дорожного знака «Остановка запрещена», что <strong>является нарушением ПДД</strong>.</p>","image":"assets/adrive-questions/q101900571.jpg"},{"id":101900601,"themeId":4,"group":1019006,"chapter":19,"chapters":[19],"q":"Разрешается ли Вам, управляя легковым автомобилем, остановиться на показанном участке дороги?","a":["Запрещается.","Разрешается с любой стороны.","Разрешается только справа у тротуара."],"c":2,"e":"<p>В показанной ситуации у левого края проезжей части дороги отсутствует тротуар.</p> <p>Согласно Правилам дорожного движения, остановка и стоянка транспортных средств разрешаются у левого края проезжей части дороги с односторонним движением параллельно ему при наличии там тротуара, непосредственно прилегающего к проезжей части дороги.</p>","image":"assets/adrive-questions/q101900601.jpg"},{"id":101900602,"themeId":4,"group":1019006,"chapter":19,"chapters":[19],"q":"Разрешается ли водителю остановиться на показанном участке дороги?","a":["Запрещается.","Разрешается с любой стороны.","Разрешается только слева у тротуара."],"c":1,"e":"<p>Согласно Правилам дорожного движения, остановка и стоянка транспортных средств разрешаются на правой по ходу движения обочине, а при отсутствии обочины или невозможности остановиться на ней — у края проезжей части дороги параллельно ему. Поэтому остановка справа разрешена.</p> <p>У левого края проезжей части дороги имеется тротуар.</p> <p>Остановка и стоянка транспортных средств разрешаются у левого края проезжей части дороги с односторонним движением параллельно ему при наличии там тротуара, непосредственно прилегающего к проезжей части дороги.</p>","image":"assets/adrive-questions/q101900602.jpg"},{"id":101900603,"themeId":4,"group":1019006,"chapter":19,"chapters":[19],"q":"Правильно ли водители поставили свои автомобили на стоянку в показанном месте?","a":["Правильно поставил на стоянку водитель красного автомобиля.","Правильно поставил на стоянку водитель жёлтого автомобиля.","Правильно поставили на стоянку водители обоих автомобилей.","Неправильно поставили на стоянку водители обоих автомобилей."],"c":2,"e":"<p>Остановка и стоянка разрешаются у края проезжей части дороги параллельно ему.</p> <p>Дорожный знак 5.8.8 «Направление движения по полосам» ни в коей мере не ограничивает остановку (стоянку) транспортных средств, а указывает количество попутных и встречных полос на показанном участке дороги. Прерывистая и сплошная линия на знаке разделяют попутные и встречные полосы соответственно и не являются аналогами линий разметки. Горизонтальная дорожная разметка наносится на проезжую часть дороги, а не на дорожные знаки.</p>","image":"assets/adrive-questions/q101900603.jpg"},{"id":101900662,"themeId":4,"group":1019006,"chapter":19,"chapters":[19],"q":"Разрешено ли Вам, управляя легковым автомобилем, произвести остановку в указанном месте (до пешеходного перехода более 15 метров) на дороге с односторонним движением в населённом пункте?","a":["Разрешено.","Запрещено."],"c":1,"e":"<p>При отсутствии обочины слева на дороге с односторонним движением остановиться на левой стороне разрешается <strong>только при наличии тротуара</strong>, примыкающего к проезжей части. В показанной ситуации слева тротуара нет.</p>","image":"assets/adrive-questions/q101900662.jpg"},{"id":101900664,"themeId":4,"group":1019006,"chapter":19,"chapters":[19],"q":"В каком из показанных мест Вам, управляя легковым автомобилем (кроме автомобиля-такси) на дороге с односторонним движением, разрешено остановиться для высадки пассажира, находящегося на заднем сиденье?","a":["Разрешено только в месте, обозначенном буквой «Б».","Разрешено только в месте, обозначенном буквой «В».","Разрешено в местах, обозначенных буквами «Б» или «В».","Разрешено во всех обозначенных местах.","Запрещено во всех обозначенных местах."],"c":0,"e":"<p>В показанной ситуации для высадки пассажира разрешается остановиться справа после окончания зоны действия дорожного знака «3.27 Остановка запрещена» , то есть в месте, обозначенном буквой «Б».</p> <p>Остановка слева на дороге с односторонним движением при отсутствии тротуара, прилегающего к проезжей части (в данном случае тротуар отделён газоном), запрещена.</p>","image":"assets/adrive-questions/q101900664.jpg"},{"id":101900701,"themeId":4,"group":1019007,"chapter":19,"chapters":[19],"q":"Кто из водителей правильно совершил остановку у тротуара в месте, не обозначенном дорожным знаком 5.15 «Место стоянки»?","a":["Только водитель автомобиля «А».","Водители автомобилей «А» и «Б».","Водители всех автомобилей."],"c":0,"e":"<p>Остановка в показанной ситуации разрешена <strong>у края проезжей части дороги параллельно ему</strong>.</p> <p>Таким способом остановился <strong>только водитель автомобиля «А»</strong>.</p>","image":"assets/adrive-questions/q101900701.jpg"},{"id":101900702,"themeId":4,"group":1019007,"chapter":19,"chapters":[19],"q":"Нарушил ли Правила дорожного движения водитель чёрного легкового автомобиля, остановившись показанным способом для высадки пассажира?","a":["Да, нарушил.","Не нарушил, если габариты автомобиля не выходят за пределы крайней правой полосы движения."],"c":0,"e":"<p>Остановка в показанной ситуации разрешена <strong>у края проезжей части дороги параллельно ему</strong>.</p> <p>Остановка транспортных средств <strong>иным способом в показанном месте запрещена</strong>.</p>","image":"assets/adrive-questions/q101900702.jpg"},{"id":101900703,"themeId":4,"group":1019007,"chapter":19,"chapters":[19],"q":"Кто из водителей правильно совершил остановку при наличии обочины?","a":["Только водитель автомобиля «В».","Водители автомобилей «А» и «В».","Водители всех автомобилей."],"c":0,"e":"<p>Остановка в показанной ситуации разрешена на правой по ходу движения обочине (вне населённых пунктов разрешается только остановка транспортных средств).</p> <p>Водители автомобилей «А» и «Б» не использовали всю ширину обочины, сместившись на проезжую часть дороги, поэтому они нарушили Правила дорожного движения.</p>","image":"assets/adrive-questions/q101900703.jpg"},{"id":101900801,"themeId":4,"group":1019008,"chapter":19,"chapters":[19],"q":"Разрешено ли водителю остановиться у левого края проезжей части (при наличии тротуара, непосредственно прилегающего к проезжей части дороги) на показанном участке дороги для высадки пассажира?","a":["Разрешено только в населённом пункте.","Разрешено как в населённом пункте, так и вне его.","Запрещено."],"c":1,"e":"<p>В показанной ситуации у левого края проезжей части дороги имеется тротуар.</p> <p>Согласно Правилам дорожного движения, остановка транспортных средств разрешается у левого края проезжей части дороги с односторонним движением параллельно ему при наличии там тротуара, непосредственно прилегающего к проезжей части дороги.</p>","image":"assets/adrive-questions/q101900801.jpg"},{"id":101900901,"themeId":4,"group":1019009,"chapter":19,"chapters":[19],"q":"Кто из водителей в показанной ситуации нарушил Правила дорожного движения?","a":["Водитель жёлтого автомобиля, совершивший остановку на левой обочине.","Водитель синего автомобиля, поставивший автомобиль на стоянку на правой обочине.","Водители обоих автомобилей нарушили Правила дорожного движения.","Водители обоих автомобилей не нарушили Правила дорожного движения."],"c":1,"e":"<p>В показанной ситуации водитель синего автомобиля осуществляет стоянку, а водитель жёлтого автомобиля совершил остановку вне населённого пункта.</p> <p>Согласно Правилам дорожного движения, стоянка, вне специально обозначенных мест, транспортных средств вне населённых пунктов запрещена. Остановка транспортных средств разрешается на левой обочине дороги с односторонним движением.</p>","image":"assets/adrive-questions/q101900901.jpg"},{"id":101900902,"themeId":4,"group":1019009,"chapter":19,"chapters":[19],"q":"Кто из водителей в показанной ситуации нарушил Правила дорожного движения?","a":["Водитель синего автомобиля, совершивший остановку на левой обочине.","Водитель жёлтого автомобиля, совершивший остановку у правого края проезжей части дороги.","Водители обоих автомобилей нарушили Правила дорожного движения.","Водители обоих автомобилей не нарушили Правила дорожного движения."],"c":3,"e":"<p>В показанной ситуации оба водители совершили остановку.</p> <p>Согласно Правилам дорожного движения, остановка транспортных средств разрешается на правой по ходу движения обочине, а при отсутствии обочины или невозможности остановиться на ней — у края проезжей части дороги параллельно ему, а также на левой обочине дороги с односторонним движением.</p>","image":"assets/adrive-questions/q101900902.jpg"},{"id":101900903,"themeId":4,"group":1019009,"chapter":19,"chapters":[19],"q":"Кто из водителей в показанной ситуации нарушил Правила дорожного движения?","a":["Водитель синего автомобиля, совершивший остановку у левого края проезжей части дороги.","Водитель жёлтого автомобиля, совершивший остановку у правого края проезжей части дороги.","Водители обоих автомобилей нарушили Правила дорожного движения.","Водители обоих автомобилей не нарушили Правила дорожного движения."],"c":0,"e":"<p>В показанной ситуации оба водители совершили остановку.</p> <p>Остановка и стоянка транспортных средств при отсутствии справа обочины или невозможности остановиться на ней разрешаются <strong>у края проезжей части дороги параллельно ему</strong>.</p> <p>На дороге с односторонним движением при отсутствии обочины у левого края остановка и стоянка разрешены <strong>у тротуара, непосредственно прилегающего к проезжей части дороги</strong>. В показанной ситуации тротуар слева отделён от проезжей части дороги газоном. Поэтому <strong>слева остановка запрещена</strong>.</p>","image":"assets/adrive-questions/q101900903.jpg"},{"id":101901001,"themeId":4,"group":1019010,"chapter":19,"chapters":[19],"q":"Разрешено ли на показанном участке дороги вне населённого пункта поставить автомобиль на стоянку?","a":["Запрещено.","Разрешено только на правой обочине.","Разрешено как на правой, так и на левой обочине."],"c":0,"e":"<p>Стоянка транспортных средств на обочине вне населённых пунктов запрещается.</p>","image":"assets/adrive-questions/q101901001.jpg"},{"id":101901002,"themeId":4,"group":1019010,"chapter":19,"chapters":[19],"q":"Кто из водителей нарушил Правила дорожного движения, поставив свой автомобиль на стоянку в показанной ситуации?","a":["Водитель жёлтого автомобиля.","Водитель красного автомобиля.","Водители обоих автомобилей нарушили Правила дорожного движения.","Водители обоих автомобилей не нарушили Правила дорожного движения."],"c":0,"e":"<p>В показанной ситуации водитель жёлтого автомобиля поставил свой автомобиль на стоянку вне населённого пункта.<br> Стоянка транспортных средств на обочине вне населённых пунктов запрещается.<br> Водитель красного автомобиля поставил на стоянку свой автомобиль в населённом пункте. Остановка и стоянка транспортных средств разрешаются на левой обочине дороги в населённом пункте на дороге с одной полосой движения для каждого направления без трамвайных путей посередине.</p>","image":"assets/adrive-questions/q101901002.jpg"},{"id":101901061,"themeId":4,"group":1019010,"chapter":19,"chapters":[19],"q":"Разрешено ли Вам, управляя легковым автомобилем, остановиться на обочине в показанной ситуации в населённом пункте?","a":["Разрешено только справа.","Разрешено с любой стороны.","Запрещено."],"c":1,"e":"<p>В населённом пункте на дороге, имеющей по одной полосе движения в каждом направлении, <strong>разрешена остановка как на правой обочине, так и на левой</strong>.</p>","image":"assets/adrive-questions/q101901061.jpg"},{"id":101901062,"themeId":4,"group":1019010,"chapter":19,"chapters":[19],"q":"Нарушил ли водитель легкового автомобиля Правила дорожного движения, выполнив остановку в показанной ситуации вне населённого пункта?","a":["Нарушил.","Не нарушил."],"c":0,"e":"<p>На дороге с двухсторонним движением вне населённого пункта остановка транспортных средств разрешается <strong>только на правой стороне</strong> (на обочине или при её отсутствии — у края проезжей части).</p>","image":"assets/adrive-questions/q101901062.jpg"},{"id":101901101,"themeId":4,"group":1019011,"chapter":19,"chapters":[19],"q":"По какой траектории разрешается подъехать к краю проезжей части дороги с целью посадки пассажира в показанной ситуации?","a":["Только по траектории «А».","Только по траектории «Б».","По любой из обозначенных траекторий."],"c":1,"e":"<p>В пределах населённых пунктов остановка разрешается на левой стороне на дорогах с одной полосой движения для каждого направления без трамвайных путей посередине.<br> Так как на рисунке изображена дорога с трамвайными путями посередине, то движение к пассажиру по траектории «А» запрещено.</p>","image":"assets/adrive-questions/q101901101.jpg"},{"id":101901102,"themeId":4,"group":1019011,"chapter":19,"chapters":[19],"q":"По какой траектории разрешается подъехать к краю проезжей части дороги с целью посадки пассажира в показанной ситуации?","a":["Только по траектории «А».","Только по траектории «Б».","По любой из обозначенных траекторий."],"c":2,"e":"<p>Показанная на рисунке дорога имеет по одной полосе движения в каждом направлении без трамвайных путей посередине.<br> В соответствии с Правилами, водитель может остановиться в указанном месте, подъехав по любой из показанных траекторий. При этом выезд на левую сторону должен выполняться с соблюдением всех правил маневрирования.</p>","image":"assets/adrive-questions/q101901102.jpg"},{"id":101901151,"themeId":4,"group":1019011,"chapter":19,"chapters":[19],"q":"Двигаясь по какой из указанных траекторий, водитель красного легкового автомобиля может совершить остановку для посадки пассажира в показанной ситуации на дороге с двухсторонним движением?","a":["Только по траектории «А».","Только по траектории «Б».","По любой из указанных траекторий."],"c":1,"e":"<p>Пешеход ожидает посадки в автомобиль на левом тротуаре <strong>до начала населённого пункта</strong>.</p> <p>В этом месте вне населённого пункта остановка слева у тротуара (по траектории «А») не допускается, поэтому <strong>необходимо развернуться </strong>и после разворота тротуар будет справа от водителя (по траектории «Б»). <strong>Остановка справа у тротуара вне населённого пункта разрешена</strong>.</p>","image":"assets/adrive-questions/q101901151.jpg"},{"id":101901161,"themeId":4,"group":1019011,"chapter":19,"chapters":[19],"q":"По какой траектории разрешается подъехать к краю проезжей части дороги с целью посадки пассажира в показанной ситуации, не создавая препятствия для движения маршрутных транспортных средств?","a":["Только по траектории «А».","Только по траектории «Б».","По любой из обозначенных траекторий."],"c":0,"e":"<p>В показанной ситуации водитель находится на дороге с двусторонним движением с двумя полосами для движения.<br> Остановка и стоянка транспортных средств разрешаются у левого края проезжей части дороги параллельно ему на дороге с одной полосой движения для каждого направления без трамвайных путей посередине при наличии там тротуара, непосредственно прилегающего к проезжей части дороги.<br> Разворот в зоне остановочного пункта маршрутных ТС запрещён.<br> Поэтому соответствует Правилам только траектория «А».</p>","image":"assets/adrive-questions/q101901161.jpg"},{"id":101901201,"themeId":4,"group":1019012,"chapter":19,"chapters":[19],"q":"По какой траектории разрешается подъехать к краю проезжей части дороги с целью посадки пассажира в показанной ситуации?","a":["Только по траектории «А».","Только по траектории «Б».","По любой из обозначенных траекторий."],"c":1,"e":"<p>В показанной ситуации водитель находится на дороге с двусторонним движением с тремя полосами для движения.<br> Согласно Правилам дорожного движения, остановка и стоянка транспортных средств разрешаются у левого края проезжей части дороги параллельно ему на дороге с одной полосой движения для каждого направления без трамвайных путей посередине.<br> Поэтому соответствует Правилам только траектория «Б».</p>","image":"assets/adrive-questions/q101901201.jpg"},{"id":101901301,"themeId":4,"group":1019013,"chapter":19,"chapters":[19],"q":"Разрешается ли остановка на обочине дороги с односторонним движением вне населённого пункта?","a":["Разрешается только на правой по ходу движения обочине.","Разрешается как на правой, так и на левой по ходу движения обочине.","Остановка вне населённого пункта на обочине запрещена."],"c":1,"e":"<p>Согласно Правилам дорожного движения, остановка транспортных средств разрешается <strong>на левой и правой обочине дороги с односторонним движением</strong>.</p>","image":null},{"id":101901302,"themeId":4,"group":1019013,"chapter":19,"chapters":[19],"q":"Разрешается ли стоянка на обочине дороги с односторонним движением вне населённого пункта?","a":["Разрешается только на правой по ходу движения обочине.","Разрешается как на правой, так и на левой по ходу движения обочине.","Стоянка вне населённого пункта на обочине запрещена."],"c":2,"e":"<p>Стоянка транспортных средств на обочине вне населённых пунктов запрещается.</p>","image":null},{"id":101901401,"themeId":4,"group":1019014,"chapter":19,"chapters":[19],"q":"Разрешается ли оставлять работающим двигатель при разгрузке автомобиля?","a":["Запрещается.","Разрешается на время не более 5 минут.","Разрешается на время не более 10 минут.","Разрешается на всё время, связанное с разгрузкой автомобиля."],"c":1,"e":"<p>Согласно Правилам дорожного движения, остановка на время более 5 минут и стоянка транспортного средства, в том числе в местах, специально отведённых для отдыха, должна осуществляться с неработающим двигателем транспортного средства.<br> Требование направлено на снижение выбросов вредных веществ из двигателя внутреннего сгорания в окружающую атмосферу и улучшение экологической обстановки, а также предупреждает возможность отравления угарным газом отдыхающих в местах, специально оборудованных для ночлега и отдыха.<br> Выполнение требования позволяет исключить самопроизвольное движение механического ТС в случае, если водитель покидает своё место, контролируя процесс погрузки (выгрузки) груза, посадки (высадки) пассажиров.</p>","image":null},{"id":101901402,"themeId":4,"group":1019014,"chapter":19,"chapters":[19],"q":"Должен ли водитель заглушить двигатель при высадке пассажиров во дворе жилого дома?","a":["Да, должен.","Не должен.","Должен в случае, если высадка пассажиров займёт более 5 минут."],"c":2,"e":"<p>Согласно Правилам дорожного движения, остановка на время более 5 минут и стоянка транспортного средства, в том числе в местах, специально отведённых для отдыха, должна осуществляться с неработающим двигателем транспортного средства.<br> Требование направлено на снижение выбросов вредных веществ из двигателя внутреннего сгорания в окружающую атмосферу и улучшение экологической обстановки, а также предупреждает возможность отравления угарным газом отдыхающих в местах, специально оборудованных для ночлега и отдыха.<br> Выполнение требования позволяет исключить самопроизвольное движение механического ТС в случае, если водитель покидает своё место, контролируя процесс погрузки (выгрузки) груза, посадки (высадки) пассажиров.</p>","image":null},{"id":101901501,"themeId":4,"group":1019015,"chapter":19,"chapters":[19],"q":"Разрешается ли водителю грузового автомобиля с технически допустимой общей массой не более 3.5 тонны приступить к разгрузке автомобиля, не выключив двигатель?","a":["Запрещается.","Разрешается, если остановка займёт не более 5 минут."],"c":1,"e":"<p>Согласно Правилам дорожного движения, остановка на время более 5 минут и стоянка транспортного средства, в том числе в местах, специально отведённых для отдыха, должна осуществляться с неработающим двигателем транспортного средства.<br> Требование направлено на снижение выбросов вредных веществ из двигателя внутреннего сгорания в окружающую атмосферу и улучшение экологической обстановки, а также предупреждает возможность отравления угарным газом отдыхающих в местах, специально оборудованных для ночлега и отдыха.<br> Выполнение требования позволяет исключить самопроизвольное движение механического ТС в случае, если водитель покидает своё место, контролируя процесс погрузки (выгрузки) груза, посадки (высадки) пассажиров.</p>","image":"assets/adrive-questions/q101901501.jpg"},{"id":101901502,"themeId":4,"group":1019015,"chapter":19,"chapters":[19],"q":"Разрешается ли водителю грузового автомобиля с технически допустимой общей массой не более 3.5 тонны приступить к разгрузке автомобиля, не выключив двигатель, если по времени разгрузка займёт более 5 минут?","a":["Запрещается.","Разрешается."],"c":0,"e":"<p>Согласно Правилам дорожного движения, остановка на время более 5 минут и стоянка транспортного средства, в том числе в местах, специально отведённых для отдыха, должна осуществляться с неработающим двигателем транспортного средства.<br> Требование направлено на снижение выбросов вредных веществ из двигателя внутреннего сгорания в окружающую атмосферу и улучшение экологической обстановки, а также предупреждает возможность отравления угарным газом отдыхающих в местах, специально оборудованных для ночлега и отдыха.<br> Выполнение требования позволяет исключить самопроизвольное движение механического ТС в случае, если водитель покидает своё место, контролируя процесс погрузки (выгрузки) груза, посадки (высадки) пассажиров.</p>","image":null},{"id":101901601,"themeId":4,"group":1019016,"chapter":19,"chapters":[19],"q":"Разрешается ли осуществлять остановку с работающим двигателем?","a":["Запрещается.","Разрешается на время не более 5 минут.","Разрешается в местах, специально отведённых для отдыха, в холодное время года.","Разрешается в случае посадки (высадки) пассажиров или погрузки (разгрузки) транспортного средства."],"c":1,"e":"<p>Согласно Правилам дорожного движения, остановка на время более 5 минут и стоянка транспортного средства, в том числе в местах, специально отведённых для отдыха, должна осуществляться с неработающим двигателем транспортного средства.<br> Требование направлено на снижение выбросов вредных веществ из двигателя внутреннего сгорания в окружающую атмосферу и улучшение экологической обстановки, а также предупреждает возможность отравления угарным газом отдыхающих в местах, специально оборудованных для ночлега и отдыха.<br> Выполнение требования позволяет исключить самопроизвольное движение механического ТС в случае, если водитель покидает своё место, контролируя процесс погрузки (выгрузки) груза, посадки (высадки) пассажиров.</p>","image":null},{"id":101901602,"themeId":4,"group":1019016,"chapter":19,"chapters":[19],"q":"Разрешается ли осуществлять остановку с работающим двигателем?","a":["Запрещается.","Разрешается, кроме жилых зон.","Разрешается в холодное время года.","Разрешается на время не более 5 минут."],"c":3,"e":"<p>Согласно Правилам дорожного движения, остановка на время более 5 минут и стоянка транспортного средства, в том числе в местах, специально отведённых для отдыха, должна осуществляться с неработающим двигателем транспортного средства.<br> Требование направлено на снижение выбросов вредных веществ из двигателя внутреннего сгорания в окружающую атмосферу и улучшение экологической обстановки, а также предупреждает возможность отравления угарным газом отдыхающих в местах, специально оборудованных для ночлега и отдыха.<br> Выполнение требования позволяет исключить самопроизвольное движение механического ТС в случае, если водитель покидает своё место, контролируя процесс погрузки (выгрузки) груза, посадки (высадки) пассажиров.</p>","image":null},{"id":101901701,"themeId":4,"group":1019017,"chapter":19,"chapters":[19],"q":"Разрешается ли стоянка механического транспортного средства с работающим двигателем?","a":["Запрещается.","Разрешается, кроме жилых зон.","Разрешается в местах, специально отведённых для отдыха водителей, в холодное время года."],"c":0,"e":"<p>Согласно Правилам дорожного движения, остановка на время более 5 минут и стоянка транспортного средства, в том числе в местах, специально отведённых для отдыха, должна осуществляться с неработающим двигателем транспортного средства.<br> Требование направлено на снижение выбросов вредных веществ из двигателя внутреннего сгорания в окружающую атмосферу и улучшение экологической обстановки, а также предупреждает возможность отравления угарным газом отдыхающих в местах, специально оборудованных для ночлега и отдыха.</p>","image":null},{"id":101901702,"themeId":4,"group":1019017,"chapter":19,"chapters":[19],"q":"В каком случае водитель не нарушит Правила дорожного движения, поставив автомобиль на стоянку с работающим двигателем?","a":["Если это необходимо для работы отопителя салона в холодное время года.","Если это связано с затруднённым запуском двигателя в холодное время года.","Не нарушит в обоих перечисленных случаях.","Нарушит в обоих перечисленных случаях."],"c":3,"e":"<p>Согласно Правилам дорожного движения, остановка на время более 5 минут и стоянка транспортного средства, в том числе в местах, специально отведённых для отдыха, должна осуществляться с неработающим двигателем транспортного средства.<br> Требование направлено на снижение выбросов вредных веществ из двигателя внутреннего сгорания в окружающую атмосферу и улучшение экологической обстановки, а также предупреждает возможность отравления угарным газом отдыхающих в местах, специально оборудованных для ночлега и отдыха.</p>","image":null},{"id":101901801,"themeId":4,"group":1019018,"chapter":19,"chapters":[19],"q":"Правильно ли водители автомобилей «А» и «Б» поставили свои транспортные средства на стоянку?","a":["Да, правильно при условии рационального использования места для стоянки.","Нет, неправильно."],"c":1,"e":"<p>Транспортные средства разрешается ставить на стоянку с соблюдением требований дорожных знаков и горизонтальной дорожной разметки.<br> Линии горизонтальной дорожной разметки 1.1 , применённые для обозначения границ мест стоянки транспортных средств, разрешено пересекать только при постановке транспортного средства на стоянку или при выезде с неё.</p>","image":"assets/adrive-questions/q101901801.jpg"},{"id":101901871,"themeId":4,"group":1019018,"chapter":19,"chapters":[19],"q":"Нарушил ли Правила дорожного движения водитель зелёного автомобиля, поставив его на стоянку так, как на показанном  рисунке?","a":["Нарушил.","Не нарушил, если не было создано препятствия для доступа к находящимся на парковке другим транспортным средствам и их последующего движения."],"c":0,"e":"<p>Водитель зелёного автомобиля должен был поставить своё транспортное средство в соответствии с нанесёнными линиями горизонтальной дорожной разметки. Показанный <strong>островок не может быть использован для стоянки</strong>.</p>","image":"assets/adrive-questions/q101901871.jpg"},{"id":101901872,"themeId":4,"group":1019018,"chapter":19,"chapters":[19],"q":"Есть ли нарушения в том, как водители поставили свои автомобили на стоянку, если водитель зелёного автомобиля парковался вторым?","a":["Нарушил Правила дорожного движения только водитель чёрного автомобиля.","Нарушил Правила дорожного движения только водитель зелёного автомобиля.","Оба водителя нарушили Правила дорожного движения.","Оба водителя не нарушили Правила дорожного движения."],"c":2,"e":"<p><strong>Водители обоих автомобилей нарушили</strong> дорожную разметку, обозначающую границы мест стоянки. Нарушение Правил дорожного движения одним его участником не даёт права другому участнику также нарушать ПДД, даже если остальные места для стоянки заняты.</p>","image":"assets/adrive-questions/q101901872.jpg"},{"id":101901901,"themeId":4,"group":1019019,"chapter":19,"chapters":[19],"q":"Разрешается ли устранять возникшие технические неисправности при вынужденной остановке на проезжей части дороги при имеющейся возможности вывести транспортное средство за пределы проезжей части дороги?","a":["Запрещается.","Разрешается устранять незначительные неисправности, если время работ займёт не более 5 минут."],"c":0,"e":"<p>Согласно Правилам дорожного движения, при вынужденной остановке транспортного средства на проезжей части дороги и в местах, где остановка запрещена, водитель должен принять все возможные меры для выведения его за пределы проезжей части дороги.<br> Устранять возникшие технические неисправности транспортного средства по возможности необходимо вне проезжей части дороги.<br> В случае устранения технических неисправностей транспортного средства на проезжей части дороги лица, выполняющие такие работы, должны находиться в одежде повышенной видимости со световозвращающими элементами.<br> При вынужденной остановке водитель должен понимать, что его ТС представляет собой неподвижное препятствие для дорожного движения, и его действия не должны приводить к возникновению опасности для других участников дорожного движения.</p>","image":null},{"id":101901932,"themeId":4,"group":1019019,"chapter":19,"chapters":[19],"q":"Разрешается ли водителю красного автомобиля устранять возникшие технические неисправности в показанной ситуации на проезжей части дороги?","a":["Запрещается.","Разрешается, если нет возможности вывести автомобиль за пределы проезжей части дороги, при этом он должен находиться в одежде повышенной видимости со световозвращающими элементами."],"c":1,"e":"<p>При вынужденной остановке транспортного средства на проезжей части дороги и в местах, где остановка запрещена, водитель должен принять все возможные меры для выведения его за пределы проезжей части дороги.<br> Устранять возникшие технические неисправности транспортного средства по возможности необходимо вне проезжей части дороги.<br> В случае устранения технических неисправностей транспортного средства на проезжей части дороги лица, выполняющие такие действия, должны находиться в одежде повышенной видимости со световозвращающими элементами даже в светлое время суток.<br> При вынужденной остановке водитель должен понимать, что его ТС представляет собой неподвижное препятствие для дорожного движения, и его действия не должны приводить к возникновению опасности для других участников дорожного движения.</p>","image":"assets/adrive-questions/q101901932.jpg"},{"id":101902001,"themeId":4,"group":1019020,"chapter":19,"chapters":[19],"q":"Согласно Правилам дорожного движения устранять возникшие технические неисправности транспортного средства необходимо:","a":["Обязательно вне проезжей части дороги.","По возможности вне проезжей части дороги.","Обязательно вне проезжей части дороги только на участках, где невозможно организовать объезд остановившегося транспортного средства."],"c":1,"e":"<p>Согласно Правилам дорожного движения, при вынужденной остановке транспортного средства на проезжей части дороги и в местах, где остановка запрещена, водитель должен принять все возможные меры для выведения его за пределы проезжей части дороги.<br> Устранять возникшие технические неисправности транспортного средства по возможности необходимо вне проезжей части дороги.<br> В случае устранения технических неисправностей транспортного средства на проезжей части дороги лица, выполняющие такие работы, должны находиться в одежде повышенной видимости со световозвращающими элементами.<br> При вынужденной остановке водитель должен понимать, что его ТС представляет собой неподвижное препятствие для дорожного движения, и его действия не должны приводить к возникновению опасности для других участников дорожного движения.</p>","image":null},{"id":101902032,"themeId":4,"group":1019020,"chapter":19,"chapters":[19],"q":"Что согласно Правилам дорожного движения должны выполнить лица, устраняющие технические неисправности транспортного средства, находящегося на проезжей части дороги?","a":["Заглушить двигатель.","Затормозить автомобиль стояночным тормозом.","При подъёме автомобиля домкратом установить подставки под кузов автомобиля.","Находиться в одежде повышенной видимости со световозвращающими элементами."],"c":3,"e":"<p>Согласно Правилам дорожного движения, в случае устранения технических неисправностей транспортного средства на проезжей части дороги лица, выполняющие такие действия, должны находиться в одежде повышенной видимости со световозвращающими элементами.<br> При вынужденной остановке водитель должен понимать, что его ТС представляет собой неподвижное препятствие для дорожного движения, и его действия не должны приводить к возникновению опасности для других участников дорожного движения.<br> Остальные перечисленные действия обусловлены выполнением правил техники безопасности при выполнении работ и не упоминаются в тексте Правил дорожного движения.</p>","image":null},{"id":101902101,"themeId":4,"group":1019021,"chapter":19,"chapters":[19],"q":"Разрешается ли толкать транспортные средства по проезжей части дороги?","a":["Разрешается толкать мотоцикл с боковым прицепом.","Разрешается толкать легковой автомобиль для выведения его за пределы проезжей части дороги.","Разрешается в обоих перечисленных случаях.","Запрещается."],"c":1,"e":"<p>Согласно Правилам дорожного движения, транспортные средства, за исключением велосипеда, средства персональной мобильности, мопеда, мотоцикла без бокового прицепа, толкать по проезжей части дороги запрещается (за исключением случая выведения их за пределы проезжей части дороги).<br> Толкать по проезжей части велосипед, средство персональной мобильности, мопед, мотоцикл без бокового прицепа можно при соблюдении требований Правил дорожного движения, предъявляемых к пешеходам.</p> <p>Выведение транспортных средств за пределы проезжей части регламентируется соображениями безопасности. Перемещение ТС по проезжей части путём толкания представляет серьёзную опасность для дорожного движения и для физических лиц, которые выполняют такое действие.</p>","image":null},{"id":101902102,"themeId":4,"group":1019021,"chapter":19,"chapters":[19],"q":"Разрешается ли толкать транспортные средства по проезжей части дороги?","a":["Разрешается толкать мотоцикл без бокового прицепа.","Разрешается толкать автомобиль для выведения его за пределы проезжей части дороги.","Разрешается в обоих перечисленных случаях.","Запрещается."],"c":2,"e":"<p>Согласно Правилам дорожного движения, транспортные средства, за исключением велосипеда, средства персональной мобильности, мопеда, мотоцикла без бокового прицепа, толкать по проезжей части дороги запрещается (за исключением случая выведения их за пределы проезжей части дороги).<br> Толкать по проезжей части велосипед, средство персональной мобильности, мопед, мотоцикл без бокового прицепа можно при соблюдении требований Правил дорожного движения, предъявляемых к пешеходам.</p> <p>Выведение транспортных средств за пределы проезжей части регламентируется соображениями безопасности. Перемещение ТС по проезжей части путём толкания представляет серьёзную опасность для дорожного движения и для физических лиц, которые выполняют такое действие.</p>","image":null},{"id":101902103,"themeId":4,"group":1019021,"chapter":19,"chapters":[19],"q":"Какие транспортные средства разрешается толкать по проезжей части дороги?","a":["Велосипед или средство персональной мобильности.","Мотоцикл без бокового прицепа.","Автомобиль при выведении его за пределы проезжей части дороги.","Все перечисленные транспортные средства."],"c":3,"e":"<p>Согласно Правилам дорожного движения, транспортные средства, за исключением велосипеда, средства персональной мобильности, мопеда, мотоцикла без бокового прицепа, толкать по проезжей части дороги запрещается (за исключением случая выведения их за пределы проезжей части дороги).<br> Толкать по проезжей части велосипед, средство персональной мобильности, мопед, мотоцикл без бокового прицепа можно при соблюдении требований Правил дорожного движения, предъявляемых к пешеходам, если иное не определено Правилами.<br> Выведение транспортных средств за пределы проезжей части регламентируется соображениями безопасности. Перемещение ТС по проезжей части путём толкания представляет серьёзную опасность для дорожного движения и для физических лиц, которые выполняют такое действие.</p>","image":null},{"id":101902201,"themeId":4,"group":1019022,"chapter":19,"chapters":[19],"q":"Какое минимальное расстояние от сплошной линии горизонтальной дорожной разметки до остановившегося транспортного средства должно быть, чтобы остановка транспортного средства в показанной ситуации не противоречила Правилам дорожного движения?","a":["2.5 метра.","3 метра.","3.5 метра.","4 метра."],"c":1,"e":"<p>Согласно Правилам дорожного движения, остановка и стоянка транспортных средств запрещаются в местах, где расстояние между сплошной линией горизонтальной дорожной разметки (кроме обозначающей край проезжей части дороги) и остановившимся транспортным средством составляет менее 3 метров.<br> Ширина полосы движения в 3 метра является минимальной для проезда транспортных средств с учётом необходимости обеспечения бокового интервала.<br> Остановившееся в таком месте ТС фактически перекрывает полосу для движения.</p>","image":"assets/adrive-questions/q101902201.jpg"},{"id":101902202,"themeId":4,"group":1019022,"chapter":19,"chapters":[19],"q":"Нарушил ли водитель синего автомобиля Правила дорожного движения, совершив остановку в показанном месте?","a":["Да, нарушил.","Нет, не нарушил."],"c":0,"e":"<p>Согласно Правилам дорожного движения, остановка и стоянка транспортных средств запрещаются в местах, где расстояние между сплошной линией горизонтальной дорожной разметки (кроме обозначающей край проезжей части дороги) и остановившимся транспортным средством составляет менее 3 метров.<br> Ширина полосы движения в 3 метра является минимальной для проезда транспортных средств с учётом необходимости обеспечения бокового интервала.<br> Остановившееся в таком месте ТС фактически перекрывает полосу для движения.</p>","image":"assets/adrive-questions/q101902202.jpg"},{"id":101902251,"themeId":4,"group":1019022,"chapter":19,"chapters":[19],"q":"Разрешено ли Вам, управляя легковым автомобилем, остановиться на проезжей части в указанном месте, если ширина полосы движения составляет 3.5 метра?","a":["Разрешено.","Запрещено."],"c":1,"e":"<p>В показанном месте <strong>остановка запрещена</strong>, так как расстояние между сплошной линией горизонтальной дорожной разметки и остановившимся Вашим автомобилем составит <strong>менее 3 метров</strong> (учитывая ширину автомобиля).</p>","image":"assets/adrive-questions/q101902251.jpg"},{"id":101902301,"themeId":4,"group":1019023,"chapter":19,"chapters":[19],"q":"Нарушил ли водитель красного автомобиля Правила дорожного движения, совершив остановку в показанном месте, если ширина полосы движения составляет 3 метра?","a":["Да, нарушил.","Нет, не нарушил."],"c":1,"e":"<p>Согласно Правилам дорожного движения, остановка и стоянка транспортных средств запрещаются в местах, где расстояние между сплошной линией горизонтальной дорожной разметки (кроме обозначающей край проезжей части дороги) и остановившимся транспортным средством составляет менее 3 метров.<br> В показанной ситуации автомобиль находится на обочине, не являясь препятствием для дорожного движения.</p>","image":"assets/adrive-questions/q101902301.jpg"},{"id":101902401,"themeId":4,"group":1019024,"chapter":19,"chapters":[19],"q":"В каком из ответов наиболее полно перечислены действия, которые запрещены водителю красного автомобиля в указанном месте?","a":["Обгон.","Остановка и стоянка.","Разворот и движение задним ходом.","Обгон, остановка, стоянка и разворот.","Обгон, остановка, стоянка, разворот и движение задним ходом."],"c":4,"e":"<p>Согласно Правилам дорожного движения, на пешеходных переходах, велосипедных переездах и ближе 15 метров от них на дороге в обе стороны запрещается обгон (ближе 50 метров), остановка, стоянка, разворот и движение задним ходом.</p>","image":"assets/adrive-questions/q101902401.jpg"},{"id":101902402,"themeId":4,"group":1019024,"chapter":19,"chapters":[19],"q":"Кто из водителей в показанной ситуации нарушает Правила дорожного движения?","a":["Водитель жёлтого автомобиля, высаживающий пассажира на пешеходном переходе.","Водитель красного автомобиля, объезжающий препятствие на пешеходном переходе.","Водители обоих автомобилей."],"c":0,"e":"<p>Согласно Правилам дорожного движения, остановка и стоянка транспортных средств запрещаются на пешеходных переходах и ближе 15 метров от них на дороге в обе стороны.<br> Требование относится к наземным пешеходным переходам и направлено на обеспечение безопасности пешеходов. При этом для водителей движущихся транспортных средств достигается достаточная обзорность пешеходного перехода и движущихся по нему пешеходов.<br> Водитель красного автомобиля совершает объезд препятствия и в показанной ситуации ПДД не нарушает.</p>","image":"assets/adrive-questions/q101902402.jpg"},{"id":101902501,"themeId":4,"group":1019025,"chapter":19,"chapters":[19],"q":"Разрешено ли водителю жёлтого автомобиля остановиться у края тротуара, двигаясь по траекториям, показанным на рисунке?","a":["Разрешено остановиться по траектории «А».","Разрешено остановиться по траектории «Б».","Разрешено остановиться по траектории «В».","Запрещено."],"c":3,"e":"<p>Согласно Правилам дорожного движения, остановка и стоянка транспортных средств запрещаются на пешеходных переходах и ближе 15 метров от них на дороге в обе стороны.<br> Требование относится к наземным пешеходным переходам и направлено на обеспечение безопасности пешеходов. При этом для водителей движущихся транспортных средств достигается достаточная обзорность пешеходного перехода и движущихся по нему пешеходов.<br> Разворот на пешеходном переходе и ближе 15 метров от него также запрещён.</p>","image":"assets/adrive-questions/q101902501.jpg"},{"id":101902502,"themeId":4,"group":1019025,"chapter":19,"chapters":[19],"q":"Кто из водителей в показанной ситуации нарушает Правила дорожного движения?","a":["Водитель красного автомобиля, осуществляя разворот.","Водитель жёлтого автомобиля, двигаясь задним ходом ближе 15 метров от пешеходного перехода.","Водитель синего автомобиля, осуществляя высадку пассажира ближе 15 метров от пешеходного перехода.","Водители всех автомобилей."],"c":3,"e":"<p>Согласно Правилам дорожного движения, разворот, движение задним ходом, остановка и стоянка транспортных средств запрещаются на пешеходных переходах и ближе 15 метров от них на дороге в обе стороны.<br> Требование относится к наземным пешеходным переходам и направлено на обеспечение безопасности пешеходов. При этом для водителей движущихся ТС достигается достаточная обзорность пешеходного перехода и движущихся по нему пешеходов.</p>","image":"assets/adrive-questions/q101902502.jpg"},{"id":101902601,"themeId":4,"group":1019026,"chapter":19,"chapters":[19],"q":"Кто из водителей в показанной обстановке не нарушил правила стоянки?","a":["Только водитель жёлтого автомобиля.","Водители жёлтого и зелёного автомобилей.","Водители жёлтого, зелёного и синего автомобилей.","Водители всех автомобилей не нарушили Правила дорожного движения.","Водители всех автомобилей нарушили Правила дорожного движения."],"c":1,"e":"<p>Согласно Правилам дорожного движения, остановка и стоянка транспортных средств запрещаются на пешеходных переходах и ближе 15 метров от них на дороге в обе стороны.<br> Требование относится к наземным пешеходным переходам и направлено на обеспечение безопасности пешеходов. При этом для водителей движущихся ТС достигается достаточная обзорность пешеходного перехода и движущихся по нему пешеходов.</p>","image":"assets/adrive-questions/q101902601.jpg"},{"id":101902602,"themeId":4,"group":1019026,"chapter":19,"chapters":[19],"q":"Водители красного и жёлтого автомобилей совершили стоянку в соответствии с Правилами дорожного движения?","a":["Только водитель красного автомобиля.","Только водитель жёлтого автомобиля.","Водители обоих автомобилей совершили стоянку в соответствии с Правилами дорожного движения.","Водители обоих автомобилей нарушили Правила дорожного движения."],"c":3,"e":"<p>Согласно Правилам дорожного движения, остановка и стоянка транспортных средств запрещаются на пешеходных переходах и ближе 15 метров от них на дороге в обе стороны.<br> Требование относится к наземным пешеходным переходам и направлено на обеспечение безопасности пешеходов. При этом для водителей движущихся транспортных средств достигается достаточная обзорность пешеходного перехода и движущихся по нему пешеходов.</p>","image":"assets/adrive-questions/q101902602.jpg"},{"id":101902741,"themeId":4,"group":1019027,"chapter":19,"chapters":[19],"q":"Разрешено ли водителю синего легкового автомобиля остановиться для высадки пассажира в месте, обозначенном показанными дорожными знаками и дорожной разметкой?","a":["Да, разрешено.","Нет, не разрешено."],"c":1,"e":"<p>Остановка и стоянка транспортных средств запрещаются в местах, предназначенных для стоянки транспортных средств с опознавательным знаком «Инвалид», за исключением транспортных средств с опознавательным знаком «Инвалид» .</p>","image":"assets/adrive-questions/q101902741.jpg"},{"id":101902801,"themeId":4,"group":1019028,"chapter":19,"chapters":[19],"q":"Разрешено ли водителю белого автомобиля совершить остановку в указанном месте?","a":["Да, разрешено.","Нет, не разрешено."],"c":1,"e":"<p>В показанной ситуации водитель намеревается совершить остановку на трёхстороннем перекрёстке напротив бокового проезда, не имеющем сплошной линии горизонтальной разметки.<br> Согласно Правилам дорожного движения, остановка и стоянка транспортных средств запрещаются на перекрёстках и ближе 15 метров от края пересекаемой проезжей части дороги (кроме жилых зон), за исключением стороны напротив бокового проезда трёхсторонних перекрёстков, имеющих сплошную линию горизонтальной дорожной разметки или сплошную разделительную полосу.</p>","image":"assets/adrive-questions/q101902801.jpg"},{"id":101902802,"themeId":4,"group":1019028,"chapter":19,"chapters":[19],"q":"Разрешено ли водителю белого автомобиля совершить остановку в указанном месте?","a":["Да, разрешено.","Нет, не разрешено.","Разрешено в случае, если расстояние от автомобиля до трамвайного пути составит не менее 3 метров."],"c":1,"e":"<p>В показанной ситуации водитель намеревается совершить остановку на трёхстороннем перекрёстке напротив бокового проезда, не имеющем сплошной линии горизонтальной разметки и сплошной разделительной полосы.<br> Согласно Правилам дорожного движения, остановка и стоянка транспортных средств запрещаются на перекрёстках и ближе 15 метров от края пересекаемой проезжей части дороги (кроме жилых зон), за исключением стороны напротив бокового проезда трёхсторонних перекрёстков, имеющих сплошную линию горизонтальной дорожной разметки или сплошную разделительную полосу.</p>","image":"assets/adrive-questions/q101902802.jpg"},{"id":101902803,"themeId":4,"group":1019028,"chapter":19,"chapters":[19],"q":"Разрешено ли водителю белого автомобиля совершить остановку в указанном месте?","a":["Да, разрешено.","Нет, не разрешено.","Разрешено в случае, если расстояние от автомобиля до сплошной линии дорожной разметки составит не менее 3 метров."],"c":2,"e":"<p>В показанной ситуации водитель намеревается совершить остановку на трёхстороннем перекрёстке напротив бокового проезда, имеющем сплошную линию горизонтальной разметки.</p> <p>Согласно Правилам дорожного движения, остановка и стоянка транспортных средств запрещаются на перекрёстках и ближе 15 метров от края пересекаемой проезжей части дороги (кроме жилых зон), за исключением стороны напротив бокового проезда трёхсторонних перекрёстков, имеющих сплошную линию горизонтальной дорожной разметки или сплошную разделительную полосу, а также, где расстояние между сплошной линией горизонтальной дорожной разметки (кроме обозначающей край проезжей части дороги) и остановившимся транспортным средством составляет не менее 3 метров.</p>","image":"assets/adrive-questions/q101902803.jpg"},{"id":101903001,"themeId":4,"group":1019030,"chapter":19,"chapters":[19],"q":"На каком минимальном расстоянии от края пересекаемой проезжей части дороги (кроме жилых зон) разрешается остановка транспортных средств?","a":["5 метров.","10 метров.","15 метров.","20 метров.","40 метров."],"c":2,"e":"<p>Согласно Правилам дорожного движения, остановка и стоянка транспортных средств запрещаются на перекрёстках и ближе 15 метров от края пересекаемой проезжей части дороги (кроме жилых зон).</p>","image":"assets/adrive-questions/q101903001.jpg"},{"id":101903002,"themeId":4,"group":1019030,"chapter":19,"chapters":[19],"q":"Разрешается ли в пешеходной зоне остановка транспортных средств ближе 15 метров от края пересекаемой проезжей части дороги?","a":["Да, разрешается.","Нет, не разрешается."],"c":1,"e":"<p>Согласно Правилам дорожного движения, остановка и стоянка транспортных средств запрещаются на перекрёстках и ближе 15 метров от края пересекаемой проезжей части дороги (кроме жилых зон).</p>","image":null},{"id":101903101,"themeId":4,"group":1019031,"chapter":19,"chapters":[19],"q":"Какие из перечисленных действий запрещены на необозначенных и нерегулируемых перекрёстках (кроме жилых зон)?","a":["Остановка и стоянка.","Обгон, остановка и стоянка.","Остановка, стоянка и движение задним ходом.","Обгон, остановка, стоянка и движение задним ходом.","Обгон, остановка, стоянка, разворот и движение задним ходом."],"c":2,"e":"<p>Согласно Правилам дорожного движения, на перекрёстках и ближе 15 метров от края пересекаемой проезжей части дороги (кроме жилых зон) запрещаются остановка, стоянка и движение задним ходом транспортных средств.</p>","image":null},{"id":101903102,"themeId":4,"group":1019031,"chapter":19,"chapters":[19],"q":"Какие из перечисленных действий запрещены на обозначенных перекрёстках (кроме жилых зон)?","a":["Остановка и стоянка.","Обгон, остановка и стоянка.","Остановка, стоянка и движение задним ходом.","Обгон, остановка, стоянка и движение задним ходом.","Обгон, остановка, стоянка, разворот и движение задним ходом."],"c":3,"e":"<p>Согласно Правилам дорожного движения, на обозначенных перекрёстках и ближе 15 метров от края пересекаемой проезжей части дороги (кроме жилых зон) запрещаются обгон, остановка, стоянка и движение задним ходом транспортных средств.</p>","image":null},{"id":101903301,"themeId":4,"group":1019033,"chapter":19,"chapters":[19],"q":"Разрешено ли Вам, управляя легковым автомобилем, совершить остановку у левого края проезжей части дороги в показанной ситуации?","a":["Разрешено только в месте, обозначенном буквой «А».","Разрешено только в месте, обозначенном буквой «Б».","Разрешено в любом из показанных мест.","Запрещено."],"c":3,"e":"<p>Остановка на левой стороне дороги с двусторонним движением запрещена, если хотя бы в одном направлении имеется более одной полосы движения.</p>","image":"assets/adrive-questions/q101903301.jpg"},{"id":101903302,"themeId":4,"group":1019033,"chapter":19,"chapters":[19],"q":"Разрешено ли Вам, управляя легковым автомобилем, совершить остановку у левого края проезжей части дороги в показанной ситуации?","a":["Разрешено.","Запрещено."],"c":1,"e":"<p>Остановка на левой стороне дороги с двусторонним движением запрещена, если хотя бы в одном направлении имеется более одной полосы движения.</p>","image":"assets/adrive-questions/q101903302.jpg"},{"id":101903401,"themeId":4,"group":1019034,"chapter":19,"chapters":[19],"q":"Какое из перечисленных действий не запрещено водителю белого автомобиля на показанном участке дороги?","a":["Стоянка.","Разворот.","Движение задним ходом.","Остановка для посадки пассажиров, если это не создаст препятствия для движения маршрутных транспортных средств."],"c":3,"e":"<p>Согласно Правилам дорожного движения, остановка и стоянка транспортных средств запрещаются на остановочных пунктах маршрутных транспортных средств и ближе 15 метров от них, кроме случаев остановки для посадки (высадки) пассажиров, если это не создаст препятствия для движения маршрутных транспортных средств.<br> Остальные перечисленные действия в зоне остановочного пункта маршрутных транспортных средств запрещены.</p>","image":"assets/adrive-questions/q101903401.jpg"},{"id":101903402,"themeId":4,"group":1019034,"chapter":19,"chapters":[19],"q":"Какое из перечисленных действий не запрещено водителю белого автомобиля на показанном участке дороги?","a":["Обгон.","Стоянка.","Разворот.","Движение задним ходом."],"c":0,"e":"<p>Согласно Правилам дорожного движения, в зоне остановочного пункта маршрутных транспортных средств обгон не запрещён.<br> Остальные перечисленные действия в зоне остановочного пункта маршрутных ТС запрещены.</p>","image":"assets/adrive-questions/q101903402.jpg"},{"id":101903501,"themeId":4,"group":1019035,"chapter":19,"chapters":[19],"q":"Разрешено ли Вам, управляя легковым автомобилем, произвести высадку пассажира в указанном месте?","a":["Запрещено.","Разрешено, если это не создаст препятствия для движения маршрутных транспортных средств."],"c":1,"e":"<p>Согласно Правилам дорожного движения, остановка и стоянка транспортных средств запрещаются на остановочных пунктах маршрутных транспортных средств и ближе 15 метров от них, кроме случаев остановки для посадки (высадки) пассажиров, если это не создаст препятствия для движения маршрутных транспортных средств.</p>","image":"assets/adrive-questions/q101903501.jpg"},{"id":101903502,"themeId":4,"group":1019035,"chapter":19,"chapters":[19],"q":"Разрешено ли Вам, управляя легковым автомобилем, произвести высадку пассажира в указанном месте?","a":["Запрещено.","Разрешено, если это не создаст препятствия для движения маршрутных транспортных средств."],"c":0,"e":"<p>В показанной ситуации за остановочным пунктом маршрутных транспортных средств установлены дорожные знаки 3.27 «Остановка запрещена» и 7.2.4 «Зона действия» , которые запрещают остановку и стоянку транспортных средств перед знаками и после них.</p>","image":"assets/adrive-questions/q101903502.jpg"},{"id":101903503,"themeId":4,"group":1019035,"chapter":19,"chapters":[19],"q":"Разрешено ли Вам, управляя легковым автомобилем, совершить остановку для высадки пассажира у левого края проезжей части дороги?","a":["Разрешено, не создавая препятствия для движения маршрутных транспортных средств.","Нет, не разрешено."],"c":0,"e":"<p>В показанной ситуации остановка на левой стороне дороги не запрещена, но, учитывая место расположения остановочного пункта маршрутных транспортных средств, такая остановка не должна создавать препятствия для движения маршрутных транспортных средств. Кроме того, высадка пассажира должна быть осуществлена со стороны тротуара.</p>","image":"assets/adrive-questions/q101903503.jpg"},{"id":101903602,"themeId":4,"group":1019036,"chapter":19,"chapters":[19],"q":"На каком минимальном расстоянии от зоны остановочного пункта маршрутных транспортных средств разрешена остановка транспортных средств (кроме случая посадки (высадки) пассажиров, не создавая помех для движения маршрутных транспортных средств)?","a":["5 метров.","10 метров.","15 метров.","20 метров.","40 метров."],"c":2,"e":"<p>Согласно Правилам дорожного движения, остановка и стоянка транспортных средств запрещаются на остановочных пунктах маршрутных транспортных средств и ближе 15 метров от них, кроме случаев остановки для посадки (высадки) пассажиров, если это не создаст препятствия для движения маршрутных транспортных средств.</p>","image":null},{"id":101903701,"themeId":4,"group":1019037,"chapter":19,"chapters":[19],"q":"Кто из водителей поставил свой автомобиль на стоянку в населённом пункте в соответствии с Правилами дорожного движения?","a":["Только водитель красного автомобиля.","Водители синего и красного автомобилей.","Водители всех автомобилей.","Водители всех автомобилей нарушили Правила дорожного движения."],"c":0,"e":"<p>Согласно Правилам дорожного движения, остановка и стоянка транспортных средств запрещаются на остановочных пунктах маршрутных транспортных средств и ближе 15 метров от них, кроме случаев остановки для посадки (высадки) пассажиров, если это не создаст препятствия для движения маршрутных транспортных средств.</p>","image":"assets/adrive-questions/q101903701.jpg"},{"id":101903702,"themeId":4,"group":1019037,"chapter":19,"chapters":[19],"q":"Кто из водителей в соответствии с Правилами дорожного движения осуществляет посадку пассажиров, не создавая препятствия для движения маршрутных транспортных средств?","a":["Только водитель красного автомобиля.","Водители синего и красного автомобилей.","Водители всех автомобилей.","Водители всех автомобилей нарушили Правила дорожного движения."],"c":2,"e":"<p>В показанной ситуации нет приближающихся маршрутных транспортных средств, поэтому водители белого и синего автомобилей не создают препятствие для их движения, осуществляя посадку пассажиров, а водитель красного автомобиля остановился далее 15 метров от остановочного пункта.</p>","image":"assets/adrive-questions/q101903702.jpg"},{"id":101903801,"themeId":4,"group":1019038,"chapter":19,"chapters":[19],"q":"В каком из ответов наиболее полно перечислены действия, запрещённые на путепроводах?","a":["Остановка и стоянка.","Обгон, остановка и стоянка.","Разворот и движение задним ходом.","Обгон, остановка, стоянка, разворот и движение задним ходом."],"c":3,"e":"<p>На путепроводах и под ними запрещаются обгон, остановка, стоянка (кроме специально оборудованных мест для стоянки), разворот и движение задним ходом транспортных средств.<br> В таких условиях ТС становится препятствием для дорожного движения и создаёт опасность для движения транспортных средств.</p>","image":"assets/adrive-questions/q101903801.jpg"},{"id":101903802,"themeId":4,"group":1019038,"chapter":19,"chapters":[19],"q":"В каком из ответов указано действие, разрешённое на путепроводах?","a":["Обгон.","Разворот.","Остановка.","Опережение.","Запрещены все перечисленные действия."],"c":3,"e":"<p>На путепроводах запрещаются обгон, остановка и разворот транспортных средств.</p> <p>Опережение, не связанное с выездом на встречную полосу движения, не запрещено.</p>","image":null},{"id":101903803,"themeId":4,"group":1019038,"chapter":19,"chapters":[19],"q":"Имеется ли в вариантах ответов действие, разрешённое на путепроводах?","a":["Разрешён обгон.","Разрешён разворот.","Разрешена остановка.","Разрешено движение задним ходом.","Запрещены все перечисленные действия."],"c":4,"e":"<p>На путепроводах запрещаются обгон, остановка, стоянка, разворот и движение задним ходом транспортных средств.</p>","image":null},{"id":101903901,"themeId":4,"group":1019039,"chapter":19,"chapters":[19],"q":"В каком из ответов наиболее полно перечислены действия, запрещённые под путепроводами?","a":["Стоянка.","Обгон, остановка, стоянка и разворот.","Разворот, обгон и движение задним ходом.","Обгон, остановка, стоянка, разворот и движение задним ходом."],"c":3,"e":"<p>На путепроводах и под ними запрещаются обгон, остановка, стоянка (кроме специально оборудованных мест для стоянки), разворот и движение задним ходом транспортных средств.<br> В таких условиях ТС может стать препятствием для дорожного движения и создать опасность для движения транспортных средств.</p>","image":"assets/adrive-questions/q101903901.jpg"},{"id":101903902,"themeId":4,"group":1019039,"chapter":19,"chapters":[19],"q":"В каком из ответов перечислены действия, разрешённые под путепроводами?","a":["Обгон.","Разворот.","Остановка.","Перестроение.","Запрещены все перечисленные действия."],"c":3,"e":"<p>Под путепроводами запрещаются обгон, остановка, стоянка (кроме специально оборудованных мест для стоянки) и разворот транспортных средств.<br> В таких условиях ТС становится препятствием для дорожного движения и создаёт опасность для движения транспортных средств.</p> <p>При этом перестроение, не связанное с выполнением обгона, под путепроводом не запрещено.</p>","image":null},{"id":101903954,"themeId":4,"group":1019039,"chapter":19,"chapters":[19],"q":"Разрешена ли стоянка транспортных средств под путепроводами?","a":["Разрешена.","Запрещена.","Разрешена только в местах, специально оборудованных для стоянки."],"c":2,"e":"<p>Если под путепроводом имеется <strong>специально оборудованное место</strong> для стоянки, то <strong>стоянка транспортных средств</strong> в таком месте безусловно <strong>разрешена</strong> с учётом требований дорожной разметки и дорожных знаков при их наличии на парковке.</p>","image":"assets/adrive-questions/q101903954.jpg"},{"id":101904001,"themeId":4,"group":1019040,"chapter":19,"chapters":[19],"q":"Кто из водителей совершил остановку в показанной ситуации, нарушив Правила дорожного движения?","a":["Только водитель синего автомобиля.","Только водитель жёлтого автомобиля.","Только водитель красного автомобиля.","Водители всех автомобилей нарушили Правила дорожного движения."],"c":3,"e":"<p>Согласно Правилам дорожного движения, остановка и стоянка транспортных средств запрещаются <strong>на путепроводах и под ними</strong> (синий и жёлтый автомобиль), а также <strong>на полосах разгона и торможения</strong> (красный автомобиль остановился на полосе торможения перед съездом), съездах транспортных развязок в разных уровнях и въездах на них.</p>","image":"assets/adrive-questions/q101904001.jpg"},{"id":101904002,"themeId":4,"group":1019040,"chapter":19,"chapters":[19],"q":"Кто из водителей совершил остановку в показанной ситуации, нарушив Правила дорожного движения?","a":["Только водитель белого автомобиля.","Только водитель жёлтого автомобиля.","Только водитель зелёного автомобиля.","Водители всех автомобилей нарушили Правила дорожного движения."],"c":3,"e":"<p>Согласно Правилам дорожного движения, остановка и стоянка транспортных средств запрещаются на путепроводах и под ними, а также на полосах разгона и торможения, съездах транспортных развязок в разных уровнях и въездах на них.<br> В таких условиях транспортное средство становится препятствием для дорожного движения и создаёт опасность для движения транспортных средств.</p>","image":"assets/adrive-questions/q101904002.jpg"},{"id":101904003,"themeId":4,"group":1019040,"chapter":19,"chapters":[19],"q":"Разрешено ли Вам, управляя автомобилем, осуществить остановку в показанном месте для высадки пассажира, если расстояние до перекрёстка составляет более 15 метров?","a":["Да, разрешено.","Нет, запрещено."],"c":1,"e":"<p>Остановка транспортных средств запрещена на полосах разгона и торможения, съездах транспортных развязок в разных уровнях и въездах на них.</p> <p>Поэтому в показанном месте произвести остановку запрещено.</p>","image":"assets/adrive-questions/q101904003.jpg"},{"id":101904101,"themeId":4,"group":1019041,"chapter":19,"chapters":[19],"q":"В каком из ответов правильно и наиболее полно перечислены действия, запрещённые ближе 50 метров перед железнодорожным переездом вне населённого пункта в тёмное время суток?","a":["Остановка и стоянка.","Обгон, остановка и стоянка.","Разворот, обгон, остановка и стоянка.","Разворот, движение задним ходом, обгон, остановка и стоянка."],"c":1,"e":"<p>Согласно Правилам дорожного движения, ближе 50 метров перед железнодорожным переездом запрещаются обгон, остановка и стоянка.<br> В таких условиях ТС становится препятствием для дорожного движения и (или) создаёт опасность для движения транспортных средств.</p>","image":null},{"id":101904102,"themeId":4,"group":1019041,"chapter":19,"chapters":[19],"q":"В каком из ответов правильно и наиболее полно перечислены действия, запрещённые ближе 50 метров за железнодорожным переездом вне населённого пункта в тёмное время суток?","a":["Остановка и стоянка.","Обгон, остановка и стоянка.","Разворот, обгон, остановка и стоянка.","Разворот, движение задним ходом, обгон, остановка и стоянка."],"c":0,"e":"<p>Согласно Правилам дорожного движения, остановка и стоянка транспортных средств запрещаются на железнодорожных переездах и ближе 50 метров от них в обе стороны.<br> В таких условиях ТС становится препятствием для дорожного движения и создаёт опасность для движения транспортных средств.</p>","image":null},{"id":101904201,"themeId":4,"group":1019042,"chapter":19,"chapters":[19],"q":"На каком минимальном расстоянии от железнодорожного переезда разрешена остановка транспортных средств?","a":["15 метров.","20 метров.","40 метров.","50 метров.","100 метров."],"c":3,"e":"<p>Согласно Правилам дорожного движения, остановка и стоянка транспортных средств запрещаются на железнодорожных переездах и ближе 50 метров от них в обе стороны.<br> В таких условиях ТС ограничивает обзорность железнодорожного пути.</p>","image":null},{"id":101904202,"themeId":4,"group":1019042,"chapter":19,"chapters":[19],"q":"На каком минимальном расстоянии от железнодорожного переезда разрешена стоянка транспортных средств на обочине в населённом пункте?","a":["15 метров.","20 метров.","40 метров.","50 метров.","100 метров."],"c":3,"e":"<p>Согласно Правилам дорожного движения, остановка и стоянка транспортных средств запрещаются на железнодорожных переездах и ближе 50 метров от них в обе стороны.<br> В таких условиях ТС ограничивает обзорность железнодорожного пути.</p>","image":null},{"id":101904301,"themeId":4,"group":1019043,"chapter":19,"chapters":[19],"q":"В каком из ответов правильно и наиболее полно перечислены действия, не запрещённые ближе 50 метров за железнодорожным переездом?","a":["Обгон.","Обгон и разворот.","Обгон, разворот и движение задним ходом.","Обгон, разворот, остановка, стоянка и движение задним ходом."],"c":2,"e":"<p>Согласно Правилам дорожного движения, ближе 50 метров за железнодорожным переездом запрещаются только остановка и стоянка.<br> Поэтому обгон, разворот и движение задним ходом на таком участке дороге не запрещены.</p>","image":null},{"id":101904302,"themeId":4,"group":1019043,"chapter":19,"chapters":[19],"q":"В каком из ответов наиболее полно перечислены действия, не запрещённые ближе 50 метров перед железнодорожным переездом?","a":["Обгон.","Перестроение, остановка и стоянка.","Обгон, разворот и движение задним ходом.","Перестроение, разворот и движение задним ходом.","Обгон, разворот, остановка, стоянка и движение задним ходом."],"c":3,"e":"<p>Согласно Правилам дорожного движения, ближе 50 метров перед железнодорожным переездом запрещаются обгон, остановка и стоянка.<br> В таких условиях транспортное средство становится препятствием для дорожного движения и (или) создаёт опасность для движения транспортных средств.</p>","image":null},{"id":101904401,"themeId":4,"group":1019044,"chapter":19,"chapters":[19],"q":"Разрешено ли водителю красного автомобиля высадить пассажира вблизи железнодорожного переезда?","a":["Разрешено в месте, обозначенном буквой «А».","Разрешено в месте, обозначенном буквой «Б».","Разрешено в обоих обозначенных буквами местах.","В обоих обозначенных буквами местах высадка пассажира запрещена."],"c":3,"e":"<p>Согласно Правилам дорожного движения, остановка и стоянка транспортных средств запрещаются на железнодорожных переездах и ближе 50 метров от них в обе стороны.<br> В таких условиях транспортное средство становится препятствием для дорожного движения и создаёт опасность для движения транспортных средств.</p>","image":"assets/adrive-questions/q101904401.jpg"},{"id":101904402,"themeId":4,"group":1019044,"chapter":19,"chapters":[19],"q":"Разрешено ли водителю зелёного автомобиля осуществить посадку пассажира в показанной ситуации?","a":["Разрешено, двигаясь по траектории «А».","Разрешено, двигаясь по траектории «Б».","Разрешено, двигаясь по траектории «А» или «Б».","Посадка пассажира запрещена в обоих случаях."],"c":3,"e":"<p>Согласно Правилам дорожного движения, остановка и стоянка транспортных средств запрещаются на железнодорожных переездах и ближе 50 метров от них в обе стороны.<br> В таких условиях транспортное средство может стать препятствием для дорожного движения, ограничить обзорность железнодорожного переезда.</p>","image":"assets/adrive-questions/q101904402.jpg"},{"id":101904501,"themeId":4,"group":1019045,"chapter":19,"chapters":[19],"q":"Разрешается ли водителю белого автомобиля совершить остановку в показанной обстановке, если видимость дороги в направлении движения в условиях недостаточной видимости составляет менее 100 метров?","a":["Да, разрешается.","Разрешается только для посадки (высадки) пассажиров.","Запрещается."],"c":2,"e":"<p>Согласно Правилам дорожного движения, остановка и стоянка транспортных средств запрещаются, где видимость дороги менее 100 метров хотя бы в одном направлении движения.</p> <p>Регламентируемое минимальное расстояние в 100 м определяется тем, что при скорости движения транспортного средства 90 км/ч обеспечивает возможность не только его остановки при экстренном торможении, но и снижения скорости транспортного средства для безопасного объезда возникшего препятствия для движения.<br> За такой промежуток времени водитель приближающегося транспортного средства имеет возможность оценить обстановку и принять правильное решение в складывающейся дорожно-транспортной ситуации.</p>","image":"assets/adrive-questions/q101904501.jpg"},{"id":101904502,"themeId":4,"group":1019045,"chapter":19,"chapters":[19],"q":"Разрешается ли водителю красного автомобиля совершить остановку на участке дороги, обозначенном таким дорожным знаком, если видимость дороги в направлении движения составляет менее 100 метров?","a":["Да, разрешается на обочине.","Запрещается."],"c":1,"e":"<p>Согласно Правилам дорожного движения, остановка и стоянка транспортных средств запрещаются, где видимость дороги менее 100 метров хотя бы в одном направлении движения.</p> <p>Регламентируемое минимальное расстояние в 100 м определяется тем, что при скорости движения транспортного средства 90 км/ч обеспечивает возможность не только его остановки при экстренном торможении, но и снижения скорости транспортного средства для безопасного объезда возникшего препятствия для движения.<br> За такой промежуток времени водитель приближающегося транспортного средства имеет возможность оценить обстановку и принять правильное решение в складывающейся дорожно-транспортной ситуации.</p>","image":"assets/adrive-questions/q101904502.jpg"},{"id":101904503,"themeId":4,"group":1019045,"chapter":19,"chapters":[19],"q":"Разрешено ли Вам, управляя легковым автомобилем, остановиться на показанном участке дороги для посадки пассажира?","a":["Разрешено только если видимость дороги в направлении движения составляет не менее 300 метров.","Разрешено только если видимость дороги в обоих направлениях составляет не менее 100 метров.","Запрещено."],"c":1,"e":"<p>Остановка транспортных средств запрещается в местах, где видимость дороги менее 100 метров <strong>хотя бы в одном направлении</strong> движения.</p> <p>Поэтому при выборе места остановки необходимо учитывать<strong> не только видимость в направлении движения</strong>, но и <strong>видимость дороги в обратном направлении</strong>.</p>","image":"assets/adrive-questions/q101904503.jpg"},{"id":101904601,"themeId":4,"group":1019046,"chapter":19,"chapters":[19],"q":"Разрешается ли водителю легкового автомобиля остановиться на повороте дороги, обозначенном таким дорожным знаком, если видимость дороги в обоих направлениях составляет более 100 метров?","a":["Да, разрешается на обочине.","Запрещается."],"c":1,"e":"<p>Согласно Правилам дорожного движения, остановка и стоянка транспортных средств запрещаются на поворотах дороги, обозначенных дорожными знаками 1.11.1, 1.11.2 «Опасный поворот» , 1.12.1, 1.12.2 «Опасные повороты» .</p>","image":"assets/adrive-questions/q101904601.jpg"},{"id":101904602,"themeId":4,"group":1019046,"chapter":19,"chapters":[19],"q":"Разрешается ли водителю синего автомобиля остановиться на повороте дороги, не обозначенном предупреждающими дорожными знаками?","a":["Разрешается, если видимость дороги хотя бы в одном направлении составляет менее 100 метров.","Разрешается, если видимость дороги хотя бы в одном направлении составляет более 100 метров.","Разрешается, если видимость дороги в обоих направлениях составляет более 100 метров.","Запрещается."],"c":2,"e":"<p>Согласно Правилам дорожного движения, остановка и стоянка транспортных средств запрещаются, где видимость дороги менее 100 метров хотя бы в одном направлении движения.</p> <p>Регламентируемое минимальное расстояние в 100 м определяется тем, что при скорости движения транспортного средства 90 км/ч обеспечивает возможность не только его остановки при экстренном торможении, но и снижении скорости транспортного средства для безопасного объезда возникшего препятствия для движения.<br> За такой промежуток времени водитель приближающегося транспортного средства имеет возможность оценить обстановку и принять правильное решение в складывающейся дорожно-транспортной ситуации.</p>","image":"assets/adrive-questions/q101904602.jpg"},{"id":101904701,"themeId":4,"group":1019047,"chapter":19,"chapters":[19],"q":"Нарушил ли Правила дорожного движения водитель белого автомобиля, совершив остановку напротив стоящего на противоположной стороне дороги грузового автомобиля в показанной ситуации?","a":["Да, нарушил.","Нет, не нарушил."],"c":1,"e":"<p>В показанной ситуации дорога имеет три полосы.</p> <p>Согласно Правилам дорожного движения, остановка и стоянка транспортных средств <strong>запрещаются</strong> на проезжей части двухполосной дороги напротив стоящего на противоположной стороне дороги транспортного средства.</p>","image":"assets/adrive-questions/q101904701.jpg"},{"id":101904702,"themeId":4,"group":1019047,"chapter":19,"chapters":[19],"q":"Нарушил ли Правила дорожного движения водитель зелёного автомобиля, совершив остановку напротив стоящего на противоположной стороне дороги красного автомобиля в показанной ситуации?","a":["Да, нарушил.","Нет, не нарушил."],"c":0,"e":"<p>В показанной ситуации дорога имеет две полосы.</p> <p>Согласно Правилам дорожного движения, остановка и стоянка транспортных средств запрещаются на проезжей части двухполосной дороги напротив стоящего на противоположной стороне дороги транспортного средства.<br> Остановившиеся друг напротив друга транспортные средства ограничивают размеры проезжей части, создают затруднения для водителей движущихся транспортных средств.</p>","image":"assets/adrive-questions/q101904702.jpg"},{"id":101904703,"themeId":4,"group":1019047,"chapter":19,"chapters":[19],"q":"Нарушил ли Правила дорожного движения водитель синего автомобиля, совершив остановку напротив стоящего на противоположной стороне дороги жёлтого автомобиля в показанной ситуации?","a":["Да, нарушил.","Нет, не нарушил."],"c":1,"e":"<p>В показанной ситуации дорога имеет две полосы.</p> <p>Водитель синего автомобиля совершил остановку на обочине, тем самым он не ограничивает размеры проезжей части.</p> <p>Согласно Правилам дорожного движения, остановка и стоянка транспортных средств запрещаются на проезжей части двухполосной дороги напротив стоящего на противоположной стороне дороги транспортного средства.<br> Остановившиеся друг напротив друга на проезжей части дороги транспортные средства ограничивают размеры проезжей части, создают затруднения для водителей движущихся транспортных средств при определении приоритета в движении в ходе встречного разъезда.</p>","image":"assets/adrive-questions/q101904703.jpg"},{"id":101904801,"themeId":4,"group":1019048,"chapter":19,"chapters":[19],"q":"Разрешается ли остановка на газонах и других участках с зелёными насаждениями?","a":["Разрешается на дворовой территории при отсутствии свободных мест для стоянки.","Разрешается в лесу при сборе ягод и грибов при отсутствии оборудованных мест для стоянки.","Разрешается при проведении праздников при отсутствии предусмотренных мест для стоянки.","Запрещается."],"c":3,"e":"<p>Согласно Правилам дорожного движения, остановка и стоянка транспортных средств запрещаются на газонах и других участках с зелёными насаждениями.<br> Требование направлено на создание здоровой экологической обстановки.</p>","image":null},{"id":101904802,"themeId":4,"group":1019048,"chapter":19,"chapters":[19],"q":"Разрешается ли водителю совершить остановку на участке земли, не имеющем сплошного газона, но с отдельными зелёными насаждениями?","a":["Да, разрешается.","Нет, не разрешается."],"c":1,"e":"<p>Согласно Правилам дорожного движения, остановка и стоянка транспортных средств запрещаются на газонах и других участках с зелёными насаждениями.<br> Требование направлено на создание здоровой экологической обстановки.</p>","image":null},{"id":101904803,"themeId":4,"group":1019048,"chapter":19,"chapters":[19],"q":"Водители синего и чёрного легковых автомобилей совершили остановку на дороге вне населённого пункта. Нарушили они Правила дорожного движения, поставив свои автомобили так, как показано на рисунке?","a":["Нарушил только водитель синего автомобиля.","Нарушил только водитель чёрного автомобиля.","Нарушили водители обоих автомобилей.","Не нарушили водители обоих автомобилей."],"c":1,"e":"<p>Остановка транспортного средства с заездом на газон запрещена.</p>","image":"assets/adrive-questions/q101904803.jpg"},{"id":101904804,"themeId":4,"group":1019048,"chapter":19,"chapters":[19],"q":"Нарушили ли водители синего и чёрного автомобилей Правила дорожного движения, поставив вне населённого пункта свои автомобили на стоянку так, как показано на рисунке?","a":["Нарушил только водитель синего автомобиля.","Нарушил только водитель чёрного автомобиля.","Нарушили водители обоих автомобилей.","Не нарушили водители обоих автомобилей."],"c":2,"e":"<p>Стоянка на обочине вне населённого пункта запрещена.</p>","image":"assets/adrive-questions/q101904804.jpg"},{"id":101904871,"themeId":4,"group":1019048,"chapter":19,"chapters":[19],"q":"Допускается ли стоянка мотоцикла на тротуаре вне обозначенных дорожными знаками (дорожной разметкой) мест для стоянки?","a":["Не допускается.","Допускается, если это не создаст препятствия и опасности для дорожного движения."],"c":0,"e":"<p><strong>Остановка и стоянка транспортных средств запрещаются на тротуарах</strong>, кроме специально отведённых мест, обозначенных дорожным знаком «Место стоянки» («Место стоянки такси»). <strong>Допускается остановка и стоянка велосипедов и средств персональной мобильности</strong>, если это не создаст препятствия и опасности для дорожного движения.</p>","image":"assets/adrive-questions/q101904871.jpg"},{"id":101904872,"themeId":4,"group":1019048,"chapter":19,"chapters":[19],"q":"Разрешается ли использовать тротуар для стоянки велосипеда?","a":["Да, если не будет создано препятствия и опасности для дорожного движения.","Нет, не разрешается."],"c":0,"e":"<p>Велосипедист имеет право поставить <strong>велосипед на стоянку на тротуаре</strong>, если это не создаст препятствия и опасности для дорожного движения.</p>","image":"assets/adrive-questions/q101904872.jpg"},{"id":101904931,"themeId":4,"group":1019049,"chapter":19,"chapters":[19],"q":"Кто из водителей нарушил Правила дорожного движения, остановившись для высадки пассажиров так, как показано на рисунке?","a":["Только водитель белого автомобиля.","Только водитель жёлтого автомобиля.","Оба водителя нарушили Правила дорожного движения."],"c":1,"e":"<p>Водитель жёлтого автомобиля остановился <strong>на тротуаре</strong>, к тому же <strong>перекрыл частично въезд во двор</strong>.<br> Водитель белого автомобиля ПДД не нарушил, так как со стороны жилой застройки <strong>остановка не запрещена</strong>, запрещена только стоянка.</p>","image":"assets/adrive-questions/q101904931.jpg"},{"id":101904932,"themeId":4,"group":1019049,"chapter":19,"chapters":[19],"q":"Кто из водителей нарушил Правила дорожного движения, поставив автомобиль на стоянку так, как показано на рисунке?","a":["Только водитель синего автомобиля.","Только водитель зелёного автомобиля.","Оба водителя нарушили Правила дорожного движения."],"c":2,"e":"<p><strong>Стоянка транспортных средств запрещаются на проездах во дворах со стороны, прилегающей к жилой застройке.</strong><br> Остановка и стоянка транспортных средств запрещаются в местах, где стоящее транспортное средство создаст препятствие для движения, работы транспортных средств коммунальной службы (въезды во дворы и выезды из них, проезды в арках, узкие местные проезды, <strong>места размещения контейнеров для сбора бытовых отходов</strong> и др.).</p> <p>Поэтому <strong>оба водителя нарушили</strong> правила стоянки.</p>","image":"assets/adrive-questions/q101904932.jpg"},{"id":101904941,"themeId":4,"group":1019049,"chapter":19,"chapters":[19],"q":"В каком из показанных мест разрешено остановиться для высадки пассажиров, находящихся на заднем сиденье?","a":["Только в «А».","Только в «Б».","В любом из показанных мест."],"c":2,"e":"<p>Остановка и стоянка транспортных средств в населённых пунктах разрешаются на левой стороне дороги у края проезжей части при наличии там тротуара, непосредственно прилегающего к нему, если на дороге имеется только по одной полосе движения для каждого направления без трамвайных путей посередине.</p> <p>На проездах во дворах со стороны, прилегающей к жилой застройке, запрещена только стоянка, остановка не запрещена.</p>","image":"assets/adrive-questions/q101904941.jpg"},{"id":101904961,"themeId":4,"group":1019049,"chapter":19,"chapters":[19],"q":"Что из перечисленного запрещается на проездах во дворах со стороны, прилегающей к жилой застройке?","a":["Только стоянка.","Только остановка.","Остановка и стоянка."],"c":0,"e":"<p>На проездах во дворах со стороны, прилегающей к жилой застройке, <strong>запрещена стоянка, остановка не запрещена</strong>.</p>","image":"assets/adrive-questions/q101904961.jpg"},{"id":101904971,"themeId":4,"group":1019049,"chapter":19,"chapters":[19],"q":"Водителю легкового автомобиля в показанной ситуации:","a":["Разрешена только остановка.","Разрешены остановка и стоянка.","Запрещены остановка и стоянка."],"c":2,"e":"<p>В местах размещения контейнеров для сбора бытовых отходов <strong>запрещены остановка и стоянка</strong> транспортных средств.</p>","image":"assets/adrive-questions/q101904971.jpg"},{"id":101905001,"themeId":4,"group":1019050,"chapter":19,"chapters":[19],"q":"Какой водитель поставил свой автомобиль на стоянку в жилой зоне в соответствии с Правилами дорожного движения?","a":["Только водитель жёлтого автомобиля.","Только водители жёлтого и синего автомобилей.","Водители всех автомобилей.","Водители всех автомобилей нарушили Правила дорожного движения."],"c":0,"e":"<p>Водитель красного автомобиля нарушил Правила дорожного движения, так как стоянка транспортных средств запрещаются на проездах во дворах со стороны, прилегающей к жилой застройке.<br> Требование направлено на обеспечение пространства, достаточного для проезда транспортных средств оперативного назначения непосредственно к подъезду дома. Также обеспечивается безопасность пешеходов, особенно детей, поскольку пространство между зданием и проездом во дворе не ограничивает обзорность самого проезда, что позволяет водителю своевременно принять меры.</p> <p>Водитель синего автомобиля остановился на тротуаре, что также запрещено.</p> <p>Водитель жёлтого автомобиля не нарушил Правила дорожного движения, так как в жилых зонах ближе 15 метров от края пересекаемой проезжей части дороги стоянка разрешена.</p>","image":"assets/adrive-questions/q101905001.jpg"},{"id":101905002,"themeId":4,"group":1019050,"chapter":19,"chapters":[19],"q":"Водители каких автомобилей поставили их на стоянку в соответствии с Правилами дорожного движения?","a":["Только водитель зелёного автомобиля.","Только водители зелёного и белого автомобилей.","Водители всех автомобилей.","Водители всех автомобилей нарушили Правила дорожного движения."],"c":1,"e":"<p>Транспортные средства разрешается ставить на стоянку с соблюдением требований дорожных знаков и горизонтальной дорожной разметки, а при их отсутствии — при условии рационального использования места стоянки, <strong>не создавая препятствия для доступа к находящимся на нём другим транспортным средствам и их последующего движения</strong>.</p> <p>Водитель грузового автомобиля остановился в месте, в котором <strong>создал препятствие для движения зелёного легкового автомобиля</strong>.</p> <p>Водитель белого автомобиля стал на стоянку на проезде <strong>со стороны, противоположной от жилой застройки</strong>, что не является нарушением.</p>","image":"assets/adrive-questions/q101905002.jpg"},{"id":101905131,"themeId":4,"group":1019051,"chapter":19,"chapters":[19],"q":"В каком из перечисленных мест не запрещена стоянка?","a":["Ближе 15 метров за путепроводом.","Ближе 15 метров за пешеходным переходом.","На полосах разгона и торможения, съездах транспортных развязок в разных уровнях и въездах на них.","На проездах во дворах со стороны, прилегающей к жилой застройке.","Стоянка запрещена во всех перечисленных местах."],"c":0,"e":"<p>Стоянка транспортных средств запрещается:</p> <ul><li>на путепроводах и под ними, кроме специально оборудованных мест для стоянки;</li> <li>на пешеходных переходах, велосипедных переездах и ближе 15 метров от них на дороге в обе стороны;</li> <li>на полосах разгона и торможения, съездах транспортных развязок в разных уровнях и въездах на них;</li> <li>на проездах во дворах со стороны, прилегающей к жилой застройке.</li></ul> <p>Запрещение стоянки транспортных средств в определённых местах и в определённых случаях определяется необходимостью обеспечения безопасности дорожного движения и рациональной организации дорожного движения.</p>","image":null},{"id":101905132,"themeId":4,"group":1019051,"chapter":19,"chapters":[19],"q":"В каком из перечисленных мест не запрещена остановка?","a":["На проездах во дворах со стороны жилой застройки.","В непосредственной близости от трамвайных путей, если это не создаст препятствие для движения трамваев.","На остановочных пунктах маршрутных транспортных средств для посадки (высадки) пассажиров, не создавая препятствия для движения маршрутных транспортных средств.","Остановка не запрещена во всех перечисленных местах.","Остановка запрещена во всех перечисленных местах."],"c":3,"e":"<p>Остановка и стоянка транспортных средств запрещаются на трамвайных путях и в непосредственной близости от них, если это создаст препятствие для движения трамваев, а также на остановочных пунктах маршрутных транспортных средств и ближе 15 метров от них, кроме случаев остановки для посадки (высадки) пассажиров, если это не создаст препятствия для движения маршрутных транспортных средств.<br> На проездах во дворах со стороны, прилегающей к жилой застройке, запрещается только стоянка транспортных средств.</p>","image":null},{"id":101905171,"themeId":4,"group":1019051,"chapter":19,"chapters":[19],"q":"В каком из перечисленных мест разрешено поставить средство персональной мобильности на стоянку?","a":["На тротуаре, если не будет создано препятствия и опасности для дорожного движения.","На проезжей части дороги, если не будет создано препятствия и опасности для дорожного движения.","Разрешено в обоих перечисленных местах.","Запрещено в обоих перечисленных местах."],"c":0,"e":"<p>Разрешено поставить средство персональной мобильности <strong>на стоянку на тротуаре</strong>, если это не создаст препятствия и опасности для дорожного движения.</p> <p>При этом, <strong>запрещается стоянка велосипедов и средств персональной мобильности на проезжей части дороги</strong>.</p>","image":"assets/adrive-questions/q101905171.jpg"},{"id":101905201,"themeId":4,"group":1019052,"chapter":19,"chapters":[19],"q":"На каком минимальном расстоянии от служебных дверей магазинов, через которые проводятся погрузочно-разгрузочные работы, разрешается поставить автомобиль на стоянку?","a":["3 метра.","5 метров.","10 метров.","15 метров."],"c":2,"e":"<p>Стоянка транспортных средств запрещается ближе 10 метров от служебных дверей магазинов, через которые производятся погрузочно-разгрузочные работы, закрытых ворот, в том числе ворот гаражей.<br> Требование направлено на обеспечение своевременного, удобного и ритмичного обслуживания населения и организаций, а также с целью обеспечения противопожарной безопасности (для проезда к воротам транспортных средств оперативного назначения, предназначенных для тушения пожара).</p>","image":"assets/adrive-questions/q101905201.jpg"},{"id":101905202,"themeId":4,"group":1019052,"chapter":19,"chapters":[19],"q":"На каком минимальном расстоянии от закрытых ворот гаражей разрешается поставить автомобиль на стоянку?","a":["3 метра.","5 метров.","10 метров.","15 метров."],"c":2,"e":"<p>Стоянка транспортных средств запрещается ближе 10 метров от закрытых ворот, в том числе ворот гаражей.</p>","image":null},{"id":101905331,"themeId":4,"group":1019053,"chapter":19,"chapters":[19],"q":"Водители каких автомобилей нарушили Правила дорожного движения в показанной на рисунке ситуации?","a":["Только водитель красного автомобиля, поставивший его на стоянку у служебных дверей магазина, через которые производятся погрузочно-разгрузочные работы.","Только водитель зелёного автомобиля, остановившись у подъезда жилого дома для высадки пассажира.","Водители обоих легковых автомобилей нарушили Правила дорожного движения.","Водители обоих легковых автомобилей не нарушили Правила дорожного движения."],"c":0,"e":"<p>Стоянка транспортных средств запрещается ближе 10 метров от служебных дверей магазинов, через которые производятся погрузочно-разгрузочные работы. Поэтому <strong>водитель красного автомобиля нарушил</strong> правила стоянки.</p> <p>На проездах во дворах со стороны, прилегающей к жилой застройке, запрещается только стоянка транспортных средств, остановка не запрещена. <strong>Водитель зелёного автомобиля не является нарушителем.</strong></p>","image":"assets/adrive-questions/q101905331.jpg"},{"id":101905332,"themeId":4,"group":1019053,"chapter":19,"chapters":[19],"q":"Нарушил ли Правила дорожного движения водитель белого автомобиля, поставивший его на стоянку так, как показано на рисунке?","a":["Да, нарушил.","Нет, не нарушил."],"c":0,"e":"<p>Стоянка транспортных средств запрещается ближе 10 метров от ворот гаражей.<br> Требование направлено на обеспечение возможности беспрепятственного въезда (выезда) транспортных средств, а также с целью обеспечения противопожарной безопасности.</p>","image":"assets/adrive-questions/q101905332.jpg"},{"id":101905341,"themeId":4,"group":1019053,"chapter":19,"chapters":[19],"q":"Разрешено ли водителю синего легкового автомобиля остановиться для высадки пассажира ближе 10 метров от служебных дверей магазина в показанной обстановке?","a":["Да, разрешено.","Нет, не разрешено."],"c":0,"e":"<p>Стоянка запрещается ближе 10 метров от служебных дверей магазинов, через которые производятся погрузочно-разгрузочные работы, закрытых ворот, в том числе ворот гаражей.</p> <p>Остановка при этом в перечисленных местах разрешена, если стоящее транспортное средство не создаст препятствие для движения, работы транспортных средств оперативного назначения и транспортных средств дорожно-эксплуатационной и коммунальной служб.</p>","image":"assets/adrive-questions/q101905341.jpg"},{"id":101905401,"themeId":4,"group":1019054,"chapter":19,"chapters":[19],"q":"Кто из водителей поставил транспортное средство на стоянку вне населённого пункта в соответствии с Правилами дорожного движения?","a":["Только водитель грузового автомобиля.","Только водитель легкового автомобиля.","Водители обоих автомобилей.","Водители обоих автомобилей нарушили Правила дорожного движения."],"c":0,"e":"<p>Согласно Правилам дорожного движения, стоянка транспортных средств вне населённых пунктов на проезжей части дороги и на обочине запрещается.</p> <p>Разрешается стоянка транспортных средств в специально отведённом месте, обозначенном дорожным знаком 5.15 «Место стоянки» (6.11 «Место отдыха» ).</p>","image":"assets/adrive-questions/q101905401.jpg"},{"id":101905402,"themeId":4,"group":1019054,"chapter":19,"chapters":[19],"q":"Кто из водителей поставил транспортное средство на стоянку в показанной ситуации с нарушением Правил дорожного движения?","a":["Только водитель белого автомобиля.","Только водитель чёрного автомобиля.","Водители обоих автомобилей.","Водители обоих автомобилей не нарушили Правила дорожного движения."],"c":2,"e":"<p>В показанной ситуации водители поставили транспортные средства на стоянку вне населённого пункта.</p> <p>Согласно Правилам дорожного движения, стоянка транспортных средств вне населённых пунктов на проезжей части дороги и на обочине запрещается.</p> <p>Разрешается стоянка транспортных средств в специально отведённом месте, обозначенном дорожным знаком 5.15 «Место стоянки» (6.11 «Место отдыха» ).</p>","image":"assets/adrive-questions/q101905402.jpg"},{"id":101905467,"themeId":4,"group":1019054,"chapter":19,"chapters":[19],"q":"Водитель какого автомобиля нарушил Правила дорожного движения в показанной ситуации?","a":["Водитель синего автомобиля, совершивший остановку на обочине.","Водитель красного автомобиля, совершивший стоянку на обочине.","Оба водителя не нарушили.","Оба водителя нарушили."],"c":1,"e":"<p>В показанной ситуации у края проезжей части дороги нанесена дорожная разметка 1.2 , которую разрешается пересекать только для остановки транспортного средства на обочине.</p> <p>Пересекать указанную линию разметки для осуществления стоянки запрещено.</p>","image":"assets/adrive-questions/q101905467.jpg"},{"id":101905501,"themeId":4,"group":1019055,"chapter":19,"chapters":[19],"q":"Нарушил ли Правила дорожного движения водитель чёрного автомобиля, совершив остановку в показанной ситуации?","a":["Да, нарушил.","Нет, не нарушил."],"c":0,"e":"<p>Остановка запрещена в местах, где транспортное средство закроет от других водителей дорожные знаки или другие технические средства организации дорожного движения.</p>","image":"assets/adrive-questions/q101905501.jpg"},{"id":101905571,"themeId":4,"group":1019055,"chapter":19,"chapters":[19],"q":"Нарушил ли Правила дорожного движения водитель легкового автомобиля, выполнив остановку на трамвайных путях по окончании движения трамваев согласно расписания?","a":["Нарушил.","Не нарушил."],"c":0,"e":"<p>Остановка может быть разрешена у правого края проезжей части дороги, <strong>но не на трамвайных путях</strong>, кроме того, <strong>движение по трамвайным путям встречного направления запрещено</strong>.<br> Даже если по расписанию трамваи уже не осуществляют движение, в ночное время могут осуществлять движение дежурные трамваи, трамваи ремонтных служб, коммунальные и ремонтные службы могут проводить работы на трамвайных путях.</p>","image":"assets/adrive-questions/q101905571.jpg"},{"id":101906271,"themeId":4,"group":1019062,"chapter":19,"chapters":[19],"q":"Водитель какого автомобиля нарушил Правила дорожного движения, оставив двери транспортного средства открытыми в показанной ситуации?","a":["Только водитель жёлтого автомобиля.","Только водитель синего автомобиля.","Оба водителя нарушили.","Оба водителя не нарушили."],"c":1,"e":"<p>Запрещается держать двери транспортного средства открытыми, если это создаст препятствие для движения других участников дорожного движения.</p> <p>В показанной ситуации открытые <strong>двери жёлтого автомобиля не препятствуют</strong> движению пешеходов и велосипедистов, а открытые <strong>двери синего автомобиля — препятствуют</strong>.</p>","image":"assets/adrive-questions/q101906271.jpg"}];